window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-005.json"] = [{"name":"皱脸秃鹫","english_name":"Lappet-faced Vulture","scientific_name":"Torgos tracheliotos","overview":"皱脸秃鹫（英文名：Lappet-faced Vulture，学名：Torgos tracheliotos），是鹰形目鹰科皱脸秃鹫属的鸟类。体型庞大的旧大陆鹫，本属唯一成员。别称肉垂秃鹫、努比亚秃鹫。以裸露头部两侧的粉色肉垂而著称，能够撕开猎物的毛皮，是非洲荒漠草原上数量较多的大型鹫。体长可达115厘米，展翼宽度2.7米，体重在4.4至9.4公斤之间。分布于非洲广泛区域，以及以色列、阿拉伯半岛南部和西部。","appearance":"皱脸秃鹫背部羽毛呈现黑色与褐色条纹交错，尾部呈楔形，腹部覆盖着大量的白色绒羽。成鸟具有棕色和白色相间的胸部条纹，以及白色的腿部羽毛。幼鸟全身棕色，头部带有少量绒毛，喙色暗淡，下体无浅色区域。两种亚种在肉垂的发达程度、头部裸露情况、喙和腿部颜色上有差异。","call":"通常较为沉默，发出的高音快节奏的叽喳声或尖叫偶尔由处于劣势地位的个体在尸体附近发出，巢穴中也会发出各种嘶嘶声和咯咯声。","habits":"栖息于开阔的草原、沙漠地带，偏好干燥环境，比其他鹫类栖息地更干旱。活动范围广泛，有时可达200公里，觅食时利用宽大的翅膀低负载的优势，进行较早的上升和缓慢的搜索飞行。以腐肉为主食，偶尔猎杀小型动物，可能从其他猛禽处抢夺食物。群体狩猎现象罕见，如曾观察到集体猎杀火烈鸟雏鸟。在较大尸体或水源处，最多可聚集50个个体。","breeding":"繁殖季节在旱季，筑巢于短小的灌木树上，如金合欢树，巢由枯枝构成，内部铺垫干草。每窝产一枚蛋，极少数产两枚，孵化期54至56天，幼鸟两次换羽，首次为白色绒羽，第二次为灰色绒羽，离巢期125至135天，可能在离巢一年后仍被父母喂养。六岁前不繁殖。","identification":"与同域的其他鹫类相比，皱脸秃鹫头部裸露、肉垂明显，喙部巨大，腿部羽毛白色，飞行时翼下边缘和翼尖的白色线条是其显著特征。","protection":"IUCN：EN（濒危）","distribution":"非洲分布广泛，包括塞内加尔、马里、尼日尔、乍得、苏丹、埃及、埃塞俄比亚等地。阿拉伯半岛分布于也门、阿曼、阿拉伯联合酋长国和沙特阿拉伯。在以色列已灭绝，阿拉伯半岛的种群估计在500只左右。","other":"全球种群估计最少8500只，面临多种威胁，包括栖息地破坏、农药中毒、人类迫害等。"},{"name":"蛇雕","english_name":"Crested Serpent Eagle","scientific_name":"Spilornis cheela","overview":"蛇雕（英文名：Crested Serpent Eagle，学名：Spilornis cheela），是鹰形目鹰科蛇雕属的鸟类。以其独特的黑色冠羽和鲜黄的眼前裸皮著称，体型中等，偏好森林边缘和开阔地带，广泛分布于热带亚洲，主要以蛇类为食。","appearance":"蛇雕是一种体态结实的森林性大型褐色猛禽，体长可达50至75厘米，翼展109至169厘米。成鸟具有短而圆的黑色与白色相间的扇形颈背冠羽，给予其厚颈外观。面部皮肤与脚为黄色，腹部布满白色斑点。幼鸟头部白色较多，脸部暗色如戴面罩。翅膀宽大，尾部和翼下有宽大的黑白条纹。","call":"蛇雕会发出响亮、尖锐且熟悉的三或两音节叫声，尤其是在繁殖季节的空中展示期间。","habits":"蛇雕广泛分布于热带和亚热带森林环境，包括干湿原始森林、河岸画廊森林、稀树草原、红树林、退化半开放混合森林、茶园和柚木种植园，以及农田和村庄边缘。它们通常避免茂密的森林内部，偏好次生或部分开放的森林、空地、林缘。它们主要在低海拔至2000米处活动，偶尔在不丹和尼泊尔高达3000米以上。","breeding":"蛇雕的繁殖期随地理位置而异，通常在旱季。筑巢高度6至25米，巢由树枝搭建，内部铺草和绿叶。一窝产一枚蛋，孵化期约40天，仅由雌鸟承担。幼鸟孵化后，由双亲喂养，约64天后离巢。","identification":"蛇雕与其他蛇雕属物种的区别在于大小、颜色和地理分布。例如，最小的subsp. minimus与最大的指名亚种在体型上有显著差异。","protection":"IUCN：LC（无危）；CITES: II（濒危野生动植物种国际贸易公约附录二）","distribution":"蛇雕广泛分布于东洋界，包括印度次大陆、东南亚和东亚。在中国大陆，蛇雕主要分布在南方的山地森林及其边缘。","other":"蛇雕的一些亚种可能被视为独立物种，尤其是一些岛屿上的亚种，它们的全球范围和数量可能较小。"},{"name":"尼岛蛇雕","english_name":"Great Nicobar Serpent Eagle","scientific_name":"Spilornis klossi","appearance":"尼科巴蛇雕的体长在38至42厘米之间，翼展约85至95厘米。这是一种小型、隐秘但大胆的蛇雕，头部较大，翅膀和尾巴看起来较短。雌鸟比雄鸟大12%左右。全身裸露部分呈黄色，幼鸟的腿部为脏黄色。幼鸟的冠羽、背部、上翼和尾羽覆羽边缘有宽阔的淡白色，且有更多条纹。","call":"尼科巴蛇雕的声音和鸣叫行为尚未被描述。","habits":"尼科巴蛇雕生活在混合常绿森林中，主要在树冠层活动，也会出现在草地和再生的生境。它们从海平面到100米的高度都有记录，最高可达600米。这种鸟似乎是定居的。它们的饮食研究较少，已知会捕食蜥蜴、老鼠、绿翅金鸠和小型鸟类。","breeding":"关于繁殖的信息不可得。似乎没有展示飞行的行为，因为在一个最近的猛禽调查中，即3月至4月期间，这个物种被认为正在繁殖，但没有观察到飞行。","identification":"与蛇雕（各种形态）相比，尼科巴蛇雕的尾巴有更细的条带。雌鸟比雄鸟显著大。","protection":"IUCN：EN（濒危）。尼科巴蛇雕拥有极小的分布范围，且据信数量正在减少。虽然其数量可能不像最初担心的那样稀少，但人类在岛屿上的定居可能会对其自然栖息地造成压力，从而影响物种生存。","distribution":"尼科巴蛇雕分布在印度的大尼科巴岛（尼科巴群岛南部）。在大尼科巴岛（包括Pulo Kunji）、小尼科巴岛、Menchal、Pilo Milo和Treis等地有记录。","other":"蛇雕捕蛇和吃蛇的方式独特。它们会从高处落下，用双爪抓住蛇体，利嘴钳住蛇头，翅膀张开，以保持平稳。"},{"name":"山蛇雕","english_name":"Mountain Serpent Eagle","scientific_name":"Spilornis kinabaluensis","overview":"山蛇雕（英文名：Mountain Serpent Eagle，学名：Spilornis kinabaluensis），是鹰形目鹰科蛇雕属的鸟类。小型但引人注目的鹰科鸟类，广泛分布在北婆罗洲的山地森林中。其最显著的外部特征是宽大的圆形翅膀，以及在飞行中明显的白色翼带和尾基部。相较于相似的蛇雕，山蛇雕整体颜色更深，飞行时翼展更长。在北婆罗洲的山林地带，经常可以看到它们翱翔于山脊之上。","appearance":"山蛇雕体长约为51至58厘米，翼展可达118至129厘米，拥有大头和宽翅，全身呈深色。与蛇雕相比，山蛇雕整体颜色更深，翼展更长，叫声明显不同。比同域的蛇雕 pallidus更大，翼展更长，且尾部中央的白色条纹更为明显。雌鸟略大于雄鸟，裸露部分全为黄色。幼鸟的描述尚未详尽。","call":"其叫声类似于蛇雕，但具有独特性，包括尖锐的哨声和描述中的单一哀怨的长音，类似大蓝八色鸫的叫声，以及由三个柔和的短音‘kwick’组成的复杂叫声，紧接着是‘kele’（首音节略低）和拉长的‘liffliíííiiii’。","habits":"山蛇雕主要栖息在山地和亚山地常绿森林，偏好山顶森林，通常位于海拔1500米至2500米之间，高于同域的蛇雕 pallidus所居住的低地。在基纳巴卢山记录到低至1000米的高度。生活方式似乎定居不动，主要以蛇和蜥蜴为食。","breeding":"巢穴和蛋的情况未知，但在11月初的克罗克山脉观察到两只成鸟带着两只离巢的幼鸟。","identification":"与蛇雕相比，山蛇雕整体颜色更深，翼展更长，叫声不同。马来鹰雕上部全黑，有更长且无标记的冠羽，下部黑白相间。","protection":"IUCN：NT（近危）","distribution":"山蛇雕主要分布在北婆罗洲的山区，包括文莱、沙巴、砂拉越和加里曼丹的部分地区，具体范围可能从基纳巴卢山南延至乌鲁帕达斯、木鲁山和文莱边境山脉，以及木鲁山。在加里曼丹的南部边界尚不明确。","other":"山蛇雕受到栖息地丧失的威胁，尤其是在较低海拔地区，由于农业扩张和强化导致森林覆盖率迅速下降。然而，它们在基纳巴卢国家公园、木鲁国家公园和特姆布龙/吉隆坡贝拉龙国家公园（文莱）以及普隆陶国家公园（木鲁山）内有所分布。"},{"name":"苏拉蛇雕","english_name":"Sulawesi Serpent Eagle","scientific_name":"Spilornis rufipectus","appearance":"成年苏拉威西蛇雕具有短而竖立的冠羽，头部黑色并伴有黄色面部皮肤，背部呈巧克力棕色，下体锈色，覆盖着广泛的白色斑点。飞行时，其外观呈现黑色，翅膀和尾巴后部有一条显眼的宽白色横带。幼鸟颜色较淡，面部有深色面罩，下体大胆条纹，上身颜色较暗。两性相似，但雌鸟平均比雄鸟大5%-15%。","call":"发出尖锐的“kew”叫声，有时带有音调变化：“kew-di-lew”。","habits":"苏拉威西蛇雕生活在森林边缘、椰林、树木花园、次生林和草原，海拔高度从海平面到1000米。它们似乎过着定居的生活，但幼鸟可能会扩散到邻近岛屿。它们会受到草地火灾的吸引，常在开阔的草地上觅食。","breeding":"幼鸟在五月离巢，估计在1月到2月间产卵。单个或成对的苏拉威西蛇雕会在高空盘旋飞行，伴随大量的叫声，这可能是求偶飞行的一部分。关于繁殖的更多信息尚未可知。","identification":"成年苏拉威西蛇雕可以通过锈色带斑的下体和尾部的白色横带与其它当地猛禽区分开，而幼鸟则通过深色面罩进行识别。","protection":"IUCN：LC（无危）。被列入CITES II附录。在苏拉威西岛的Dumoga Bone国家公园等地方广泛且常见，显示出对一定程度的栖息地改变的容忍性。","distribution":"主要分布于印尼的苏拉威西岛，包括Banggai和Sula群岛。"},{"name":"菲律宾蛇雕","english_name":"Philippine Serpent Eagle","scientific_name":"Spilornis holospilus","overview":"菲律宾蛇雕（英文名：Philippine Serpent Eagle，学名：Spilornis holospilus），是鹰形目鹰科蛇雕属的鸟类。常见于菲律宾主要岛屿的森林和开阔林地，从低地至较低山脉均有分布。以暗褐色为主，头顶和上体有白色斑点，下体红棕色带有大块白色斑点，脸部灰白，眼睛黄色，喙眼间有裸露的黄色皮肤，这在同类中独一无二。","appearance":"体长47-53厘米，翼展105-120厘米，雄鸟体重603-672克，雌鸟691-1600克，雌鸟平均比雄鸟大6-16%。头部有短而蓬松的冠羽，翅膀相对短小，尾巴较长，虹膜和面部裸皮黄色。幼鸟与幼年蛇雕相似。所谓亚种panayensis体型较小，颜色较淡，但差异可能源于个体变异。","call":"常发出一系列哨声后接‘pheeeeuw-pheeeeuw’的叫声。","habits":"栖息于河流森林、森林边缘和树木茂密的山丘，也出现在散树的开阔地带和耕作区，主要生活在海拔1500米以下，最高可达2500米。以蛇为主要食物，饮食习惯可能与蛇雕类似。","breeding":"繁殖信息极少，已知雌鸟在4月携带卵管中的卵。具体繁殖细节未知。","identification":"与其他蛇雕种类的区别在于更清晰定义的下体和翅膀上的斑点，虹膜和面部裸皮黄色，尾部和飞羽上有宽阔的淡色条纹。","protection":"IUCN：LC（无危）。CITES II级。虽然普遍分布，但缺乏关于种群趋势和规模的可靠数据。","distribution":"分布于菲律宾群岛，从吕宋岛南至棉兰老岛（不包括从卡拉米安群岛至巴拉望西部岛屿）。","other":"尽管在其有限范围内广泛发生森林砍伐，但其适应开放和次生栖息地的能力似乎意味着该物种并未受到严重威胁。"},{"name":"安达曼蛇雕","english_name":"Andaman Serpent Eagle","scientific_name":"Spilornis elgini","overview":"安达曼蛇雕（英文名：Andaman Serpent Eagle，学名：Spilornis elgini），是鹰形目鹰科蛇雕属的鸟类。又称: 安达曼群岛蛇雕，仅在印度的安达曼群岛发现。以独特的亮黄色眼周裸斑和斑点状的下体羽毛著称，分布于中南半岛和中国的东南沿海地区，包括缅甸、越南、老挝、柬埔寨、泰国以及中国的东南沿海地区、香港、海南岛。","appearance":"安达曼蛇雕体长51-59厘米，体重790-1000克，翼展115-135厘米。全身呈深棕色，下体有细小的白色斑点，上体斑点较少。头部较短，具有一顶微小的冠羽。幼鸟头部颜色较浅，成年鸟具有黄色的眼睛、蜡膜、额部和脚爪。飞行时，翅膀展现出黑白相间的窄条纹，尾巴有厚实的黑色横带。","call":"其叫声由一系列4-5个短促、类似啾啾声的哨音组成，与同属的其他物种有明显区别。","habits":"通常在森林内部的开阔地带活动，有时也在海拔从海平面到700米的开放山坡上，带有零星树木的地方。传统上认为与同域的蛇雕 davisoni生态位分离，后者倾向于沿海森林，而安达曼蛇雕则更多地出现在内陆。它们似乎定居，以各种猎物为食，包括鸟类、青蛙、蜥蜴、鼠类和蛇类。狩猎方式是在树上等待，然后突然俯冲捕捉猎物。","breeding":"关于繁殖行为的信息有限。已知会进行复杂的空中求偶展示，但具体的繁殖习性、筑巢地点和育雏细节尚待研究。","identification":"与蛇雕相比，安达曼蛇雕的尾巴有多条淡色条纹，成年鸟的面部、蜡膜、额部和脚爪均为黄色。幼鸟的头部颜色较淡，虹膜呈灰褐色。","protection":"IUCN：VU（易危）。CITES II。安达曼蛇雕是安达曼群岛特有种，面临栖息地退化和猎杀的威胁，全球估计成熟个体数量为1000-4000只，数量正在缓慢至中等速率下降。","distribution":"繁殖区域：安达曼群岛。安达曼蛇雕广泛分布于安达曼群岛的各个岛屿，即使是最小的岛屿也有其踪迹，偏好较大岛屿和内陆地区。","other":"安达曼蛇雕的生态研究相对匮乏，对其行为和生态的理解仍需进一步探索。"},{"name":"菲律宾雕","english_name":"Philippine Eagle","scientific_name":"Pithecophaga jefferyi","overview":"菲律宾雕（英文名：Philippine Eagle，学名：Pithecophaga jefferyi），是鹰形目鹰科菲律宾雕属的鸟类。被誉为“鹰中之虎”，是菲律宾的国鸟，体型庞大，翼展宽广，身披深褐色与白色相间的羽毛，头顶着带有黑色条纹的黄色冠羽。分布于菲律宾的吕宋岛、萨马岛、莱特岛和棉兰老岛，栖息于低山至开阔的草原地带，面临森林砍伐和偷猎的严重威胁。","appearance":"菲律宾雕体型庞大，体长可达90-100厘米，翼展184-202厘米，体重在4700-8000克之间，拥有约30年的寿命。其上半身呈深褐色，下半身则是浅黄色或带有白色条纹。头部后方簇立着许多柳叶状的黄色冠羽，带有斑点，眼睛呈灰蓝色，喙部灰黑色，喉咙处有白色条纹，大腿部位覆盖着羽毛。幼鸟与成鸟相似，但背部和翅膀上的羽毛边缘更多白色，略呈鳞片状。","call":"菲律宾雕发出响亮高音的口哨声，结尾处音调下降，尽管对于如此庞大的鸟类来说，叫声显得相对微弱。","habits":"栖息于低山至开阔的草原地带，主要猎食树栖动物，如猫猴、蝙蝠、蛇、蜥蜴、犀鸟、灵猫、猕猴及小型哺乳动物。狩猎时，一对菲律宾雕会合作，一方吸引猎物注意力，另一方从背后发动突袭。","breeding":"繁殖季节从九月开始，筑巢于岩壁、乔木或灌木丛中，巢由枯枝和芦苇等编织而成，内部铺设兽毛和草。产卵期通常在4-5月，每次产2枚卵，孵化期为60天，幼鸟孵化后105天开始学习飞行，直到8月底离巢独立。","identification":"菲律宾雕与其他大型鹰类的区别在于其庞大的体型、独特的羽毛颜色组合和头部的黄色冠羽。与其他菲律宾鹰属成员相比，其独特的体型和羽色模式易于辨认。","protection":"IUCN：CR（极危）。全球仅剩约180-500只成熟个体，分布于菲律宾特定岛屿，面临森林砍伐和非法猎杀的双重威胁。","distribution":"分布在菲律宾的吕宋岛、萨马岛东部、莱特岛和棉兰老岛（菲律宾北部、中东部、南部）。","other":"菲律宾雕自1960年代以来就被列为极度濒危物种，政府采取了法律保护、科学研究、公众教育和人工繁殖等措施，以确保这一珍稀物种的生存。"},{"name":"短趾雕","english_name":"Short-toed Snake Eagle","scientific_name":"Circaetus gallicus","overview":"短趾雕（英文名：Short-toed Snake Eagle，学名：Circaetus gallicus），是鹰形目鹰科短趾雕属的鸟类。中型猛禽，体长62-70厘米。体态略显笨拙，具长而宽的翅膀、短尾和大头，飞行时头部与深褐色上体形成鲜明对比的白色腹部是其显著特征。广泛分布于非洲、古北界、印度、中国北部及小巽他群岛，偏好开放地带捕食，尤其以蛇类为主食。","appearance":"成年短趾雕体长62-70厘米，体重雄鸟1200-2000克，雌鸟1300-2300克，翼展166-188厘米。体型较大，尾中等长度，身体相对较小，头部突出，翅膀宽大。羽毛颜色变异较大，但整体偏淡；典型特征是深色头部与白色下体形成对比，程度从非常明显到几乎不存在不等。所有年龄段的个体羽毛都显得有些凌乱。停栖时，可以看到类似鸮的圆脸和无毛的腿。成鸟头部和上胸部暗色，亚成鸟下体大部分为白色。","call":"发出两种常见叫声，飞行和停栖时都能听到，一是清晰的哨音“kyo-kyo-kyo”（雌鸟声音更少音乐性和清脆），二是哀怨的“mee-ok”。","habits":"栖息于森林边缘及次生灌丛，偏爱温暖温带和热带地区的多种栖息地，从开放林地到半沙漠环境。偏好开阔地带，要求有一定植被覆盖的石质区域、牧场、灌木丛，同时也需要树木作为栖息和筑巢之用。从平原、丘陵到山区，狩猎高度可达树线以上。在欧洲，秋季迁往北非撒哈拉以南地区，春季返回，而印度、巴基斯坦和小巽他群岛的种群全年留驻。","breeding":"繁殖期在欧洲南部和摩洛哥为4月至10月中旬，在北伊拉克为4月至5月，在印度次大陆为12月至次年2月。每窝产一枚白色卵，平均大小为73.5毫米×57.8毫米，孵化期约45-47天，主要由雌鸟承担。雏鸟出生时被白色绒毛覆盖，约70-80天后离巢独立。繁殖成功率在意大利中部为每对0.75只雏鸟成功飞离。","identification":"与西非短趾雕在非繁殖季节重叠区域的区分在于前者羽毛总体更淡，与黑胸短趾雕相比羽毛明显更浅，很少混淆。成鸟头部和上胸部的暗色是鉴别特征，而亚成鸟下体主要为白色。","protection":"IUCN：LC（无危）；CITES II；在中国属于国家二级保护动物。","distribution":"繁殖于欧亚，从欧洲西南部至亚洲中部，中国西北部和印度，小巽他群岛。非繁殖期分布于非洲东部、中部、西部，亚洲南部和东南部。在欧洲，秋季迁往北非撒哈拉以南地区过冬，春季返回繁殖地。","other":"历史上，由于农业和土地利用的变化，短趾雕在欧洲的数量和分布范围急剧下降，目前在一些国家仍处于稀有且持续减少的状态。在中东和远东部分范围，该物种尚未受到威胁。"},{"name":"西非短趾雕","english_name":"Beaudouin's Snake Eagle","scientific_name":"Circaetus beaudouini","overview":"西非短趾雕（英文名：Beaudouin's Snake Eagle，学名：Circaetus beaudouini），是鹰形目鹰科短趾雕属的鸟类。","appearance":"这种大型蛇鹰翼展可达170厘米，上体灰褐色，头胸部同样色系，与棕色条纹的白色下体形成鲜明对比，腹部白色，两翼下方有棕色条纹。它拥有黑色喙，大而明亮的黄色眼睛，腿长且淡灰色无羽。幼鸟全身暗色。","call":"被认为通常沉默，但在繁殖季节的叫声可能与短趾雕和黑胸蛇鹰相似，具体细节未知。","habits":"开放的林地、树丛草原和耕作区是其主要栖息地，甚至在降雨后更为干旱的地带也能生存。它主要以蛇为食，也会捕食小型哺乳动物、一些鸟类和蜥蜴，必要时会吃昆虫。狩猎方式通常是从显眼的栖木上等待，偶尔在翱翔飞行中盘旋。","breeding":"繁殖期在11月至翌年3月，西非地区湿季期间筑巢，可能在接近赤道的东部地区繁殖周期更长。巢建于树冠，高度从6米到25米以上，每窝产1枚蛋，孵化期约45天，雏鸟离巢期可能长达70天。","identification":"与短趾雕相比，西非短趾雕上体颜色更深，腹部条纹更细，下翼前部在飞行中看起来无条纹。幼鸟与短趾雕和黑胸蛇鹰的幼鸟相似，但可通过下翼的赤褐色斑块识别。","protection":"IUCN：VU（易危）","distribution":"分布于从几内亚比绍、塞内加尔和冈比亚穿过马里南部、布基纳法索、尼日尔、尼日利亚北部和喀麦隆，乍得南部、中非共和国和南苏丹。肯尼亚西北部和乌干达也有记录，但其在肯尼亚的地位不确定。","other":"与黑胸蛇鹰一起，常被视为短趾鹰的亚种，因为有杂交配对的报道，且西非短趾雕的羽毛介于短趾鹰和黑胸蛇鹰之间。然而，羽毛差异显著，目前三者被视为单独物种，属于同一超种。"},{"name":"黑胸短趾雕","english_name":"Black-chested Snake Eagle","scientific_name":"Circaetus pectoralis","overview":"黑胸短趾雕（英文名：Black-chested Snake Eagle，学名：Circaetus pectoralis），是鹰形目鹰科短趾雕属的鸟类。特征为头部和胸部深褐色至黑色，腹部白色无斑点，黄色的眼睛和灰色的腿脚，广泛分布于东非和南部非洲，从苏丹东部和埃塞俄比亚至南非，常见于开阔的草原和半沙漠地带。","appearance":"成年黑胸短趾雕体型较大，翼展可达160-185厘米，头颈部厚实，翅膀长而宽，站立时几乎触及尾尖。成鸟上体及头部为暗色，下体白色，与头部和眼睛的黄色形成鲜明对比。幼鸟体色较暗，呈深棕色，下体和头部偏肉桂色，随时间逐渐褪色至淡黄色。成年雌鸟比雄鸟平均大4%左右。","call":"繁殖季节发出尖锐高亢的‘kaa-rrr’或‘shreeee-ee-ee’声，以及类似‘kwo-kwo-kwo...kweeu-kweeu-kweeu’的叫声，声音清脆悦耳。","habits":"栖息于开阔的草原、灌木平原和半沙漠地带，避免森林密集区。高度游荡性，可能进行非洲内部迁移。以蛇类（包括毒蛇）、蜥蜴为主食，偶尔捕食小型哺乳动物、两栖动物、昆虫甚至小鸟。白天狩猎，有时夜间在人工照明区域活动。","breeding":"繁殖期主要在干季，筑巢于Acacia或Euphorbia树冠，巢由细枝构成，内衬绿叶，高3.5-24米。每窝产一枚纯白色的蛋，孵化期约51-52天，仅雌鸟孵化，雄鸟提供食物。雏鸟孵化后约89-90天离巢。","identification":"与短趾蛇雕和博杜因蛇雕相似，但后者腹部有暗纹或条纹，而黑胸短趾雕腹部全白。与武力鹰相比，体型较小，下体无斑点，下翼白色。","protection":"IUCN：LC（无危）","distribution":"分布于东非和南部非洲，从苏丹东部和埃塞俄比亚至南非。在繁殖区域和非繁殖区域均有记录，但在苏丹和前德兰士瓦主要为繁殖访客。","other":"在某些地区，如刚果，记录数量较少。"},{"name":"褐短趾雕","english_name":"Brown Snake Eagle","scientific_name":"Circaetus cinereus","overview":"褐短趾雕（英文名：Brown Snake Eagle，学名：Circaetus cinereus），是鹰形目鹰科短趾雕属的鸟类。又名: 灰短趾雕，大型猛禽。拥有黄眼、大而方正的头部、淡色腿以及棕色带状尾巴。在非洲的西、东和南部广泛分布，偏好开阔林地和灌木草原生境。","appearance":"体型中等偏大，全长71-78厘米，体重1500-2500克，翼展可达160-185厘米。头部呈块状，颈部粗壮，腿长适中，跗跖和趾部具明显鳞片。成鸟体羽深褐色，尾部长，具四条窄淡色横纹。雌鸟比雄鸟约大2%，虹膜黄色至橙黄色，蜡膜和脚灰色至灰白色。幼鸟比成鸟略淡，至第一次和第二次换羽间，下体具少量白色斑点和横纹。","call":"在繁殖季节较为活跃，发出沙哑的“hok hok hok”声以回应入侵者，以及在伴侣间交流柔和的“kwee-oo”音。","habits":"栖息于开阔的林地和稀树草原，包括干燥的荆棘灌木丛、低丘陵地带、半干旱草原、河岸带以及偶尔出现在农田边缘和村庄附近。活动范围广泛，从海平面至海拔约3400米。通常单独生活，极少结群，可能进行季节性迁徙或游荡。主要猎食蛇类，包括大型及有毒品种，偶尔捕食蜥蜴、啮齿类、本地雉鸡（如Francolinus、Numida）和家鸡。","breeding":"繁殖期在西非和刚果民主共和国东北部为11月至次年2月，在东非和中部非洲为2月至5月，在南非为7月至次年3月。巢建于树冠、肉质植物、寄生植物、水牛织巢鸟巢或罕见地在电线杆上，通常利用旧巢。巢宽60-70厘米，深15-30厘米，距离地面3.5-12米。每次产一枚蛋，孵化期48-50天，雏鸟白色绒羽，离巢时间97-113天。","identification":"与幼年的黑胸蛇鹰（Black-breasted Snake-Eagle）相似，但后者颜色为赤褐色而非棕色，且下翼图案不同。雌雄差异不大，主要通过体型大小区分。","protection":"IUCN：LC（无危）","distribution":"分布于西非的毛里塔尼亚南部、塞内加尔、冈比亚、几内亚比绍、几内亚、塞拉利昂、利比里亚内陆、科特迪瓦、加纳、多哥、贝宁、尼日利亚、马里内陆、尼日尔内陆、乍得南部、苏丹南部、南苏丹、厄立特里亚内陆、埃塞俄比亚北部和中部、索马里南部、肯尼亚大部分地区、乌干达、刚果民主共和国南部、纳米比亚约一半地区、博茨瓦纳全境、津巴布韦、南非东北部和东部。","other":"尽管自然状态下数量不多，但由于广泛的分布，被列为IUCN红色名录中的‘无危’物种。"},{"name":"斑短趾雕","english_name":"Southern Banded Snake Eagle","scientific_name":"Circaetus fasciolatus","overview":"斑短趾雕（英文名：Southern Banded Snake Eagle，学名：Circaetus fasciolatus），是鹰形目鹰科短趾雕属的鸟类。分布于非洲东部的次撒哈拉地区，自索马里南部至南非东北部，主要栖息于沿海森林及河流附近的茂密森林地带。体型偏小，羽毛呈灰褐色，腹部有条纹，尾部有三道白色横带，头圆而大，喙似兜帽，以蛇类为主要食物。","appearance":"斑短趾雕体型健壮，长约54至60厘米，雌鸟较雄鸟大，体重在908至1110克之间，翼展约119至128厘米。头部灰褐色，上身深棕色，下身有条纹，腹部和大腿有条纹，翅膀下方亦有条纹。成年鸟尾部长有三道白色横带，与小斑短趾雕成年鸟明显不同。虹膜颜色从奶油色到淡黄色不等，蜡膜和脚黄色。幼鸟上半身深棕色，下半身白色，有棕褐色斑点和黑色条纹。亚成鸟的换羽情况尚未详细描述。","call":"斑短趾雕叫声独特，常发出快速的高音'ko-ko-ko-ko-kaw'声，有时也会发出响亮的'kowaaaa'声和类似公鸡的'kurk-urr'声，通常在栖息或飞翔时发出。","habits":"斑短趾雕主要栖息于密集的沿海和河岸森林，偶尔出现在湿地和泛滥平原旁的稀树草原。偏好森林覆盖，但也可能在农作物区和草地的孤立树木上显眼地栖息，特别是在清晨。有时会在异域桉树林中筑巢，但更倾向于选择未受干扰的森林环境。活动范围从海平面至海拔1500米。主要以小型蛇类和蜥蜴为食，也捕食鼠类、两栖动物、节肢动物和鸟类。狩猎时多隐秘于树冠层，较少在开阔地活动，变换栖息地频率低，很少在森林上方翱翔。","breeding":"繁殖期在东非为7月至10月，在津巴布韦为8月至10月，在莫桑比克为8月至12月。巢由小树枝构成，建于森林树的上部叉枝中，藏于树冠深处，通常被藤蔓植物遮掩，内衬绿叶。巢高8至13米，直径58至80厘米，深18至24厘米。每窝产一枚蛋，尺寸约为64.5×52.6毫米和65.4×52.5毫米。关于孵化和离巢期的信息尚不明确。","identification":"斑短趾雕与Banded Snake-Eagle（学名不明）相似，但由于分布范围不重叠，故容易区分。与非洲鹃隼相比，体型更大，更粗壮，头部深棕色而非灰色。幼鸟与成鸟在羽毛上有明显区别，成鸟有条纹腹部和尾部的白带，而幼鸟上半身深棕色，下半身白色，有斑点和条纹。","protection":"IUCN：NT（近危）, CITES II（华盛顿公约二级保护物种）。斑短趾雕全球数量估计在1000至3000只之间，相当于大约670至2000只成熟个体。面临的主要威胁是栖息地丧失和退化，尤其是沿河的沿海森林遭到破坏，导致种群数量下降。","distribution":"斑短趾雕分布在非洲东部沿海地区，从索马里南部至南非东北部，内陆沿塔纳河、萨维河等主要河流延伸至坦桑尼亚乌萨马拉山脉。","other":"斑短趾雕在全球范围内被认为接近受到威胁，需要定期监测其种群数量，以及森林砍伐和退化的速率。应增加整个分布区内的保护区面积，以应对栖息地的退化和碎片化问题。"},{"name":"小斑短趾雕","english_name":"Western Banded Snake Eagle","scientific_name":"Circaetus cinerascens","overview":"小斑短趾雕（英文名：Western Banded Snake Eagle，学名：Circaetus cinerascens），是鹰形目鹰科短趾雕属的鸟类。体长约60厘米，雄鸟比雌鸟略小。该鸟以暗褐色为主，腹部具条纹，头部和胸部有明显的橙黄色喙基，尾部有一道宽阔的白色横带，这一特征在飞行中尤为显眼。分布于非洲北部热带地区，自塞内加尔和冈比亚向东至埃塞俄比亚，然后向南至安哥拉南部和津巴布韦。","appearance":"小斑短趾雕拥有结实的体态，体长可达60厘米，体重约1126克，翼展约114厘米。成鸟的上体呈深褐色，下体有条纹，喙基橙黄色显著，尾部有一道明亮的横带。雌鸟通常比雄鸟颜色更深，幼鸟则为上体棕色，尾部白色，下体白色，随着成长逐渐变为深褐色。个体间颜色和条纹变异大。","call":"小斑短趾雕发出独特的声音，包括响亮快速的“kok-kok-kok-kok-ko-ho”声，结尾下降，以及哀怨的“ko-waaa”声。幼鸟也会发出响亮的求食叫声。","habits":"小斑短趾雕栖息于河流森林、画廊森林和与河流系统相关的林地，但不会进入低地雨林。它们在栽培区和荆棘丛中觅食，海拔高度从海平面至2000米。通常在森林线性生境内定居，但在特定季节会移动至东非或西非的几内亚林地。","breeding":"繁殖期在赞比亚为12月至4月，在马拉维为2月至4月，在津巴布韦为12月至3月。它们在树冠中筑巢，通常位于高9至18米处，巢由树枝构成，内部铺有绿叶，形状为浅碟状。每窝仅产一枚蛋，孵化期约为46天，雏鸟约在56天后离巢。","identification":"与斑短趾雕相比，小斑短趾雕具有更粗壮的外观，尾部单一道白色横带。与褐短趾雕的区别在于后者体型更大，头部灰色而非暗褐色，蜡膜和腿黄色。","protection":"IUCN：LC（无危）。列入CITES II附录。局部地区常见，但分布零散。在纳米比亚东北部，河岸生境退化导致其数量减少，目前估计仅有14对存在。","distribution":"小斑短趾雕分布于非洲北部热带地区，自塞内加尔和冈比亚向东至埃塞俄比亚，然后向南至安哥拉南部和津巴布韦，主要在河流和森林边缘地带生活。"},{"name":"刚果蛇雕","english_name":"Congo Serpent Eagle","scientific_name":"Dryotriorchis spectabilis","overview":"刚果蛇雕（英文名：Congo Serpent Eagle，学名：Dryotriorchis spectabilis），是鹰形目鹰科 Dryotriorchis 属的鸟类。独特的森林猛禽，以蛇为主要食物。头部较大，中等体型，分布于西非至中非的热带雨林中，拥有棕色背部、锈色颈背圈、白色胸部及条纹侧面，使其在其范围内独树一帜。西部个体喉部白色，东部个体喉部具黑斑点。与非洲鹰雕相似，但体型较小，喉部中央有黑色线条，头部显得更大。","appearance":"刚果蛇雕体长50-60厘米，翼展94-106厘米，翅膀短圆，尾巴长而圆，与鵟鹰类相似。上体深巧克力棕色，下体白色，带有变化的锈色痕迹和多个大圆形黑斑。喉部颜色随地理位置不同而异，西部个体为白色，东部个体为带黑斑点。D. s. batesi亚种背部更棕更淡，仅侧腹有斑点，且斑点随年龄增长而消失。","call":"在森林中频繁鸣叫，发出一系列类似号角的‘HOW, how, HOW, how’叫声，有时被比作犀鸟的叫声。","habits":"栖息于低地热带雨林的下层，海拔高度从海平面至900米。主要以蛇、变色龙、蜥蜴和蟾蜍为食，偶尔捕食小型哺乳动物。狩猎时从栖木上俯冲，捕获藏匿于植被或地面下的猎物，有时会像鹭鹰一样连续用脚攻击猎物。","breeding":"繁殖信息未详，但在加蓬的10月至12月以及扎伊尔的6月至11月间观察到繁殖迹象。鸣叫活跃，可能与繁殖有关。","identification":"与非洲鹰雕外观相似，但体型更小，喉部有黑色线条，头部显得更大。D. s. spectabilis与幼年非洲鹰雕更相似，而D. s. batesi则与成年非洲鹰雕相似。","protection":"IUCN：LC（无危）；CITES: II级附录。","distribution":"分布于西非至中非的热带雨林，包括几内亚、利比里亚、科特迪瓦、加纳、尼日利亚、中非共和国、刚果民主共和国、加蓬、刚果共和国和安哥拉北部。","other":"已知刚果蛇雕的种群数量因森林砍伐而下降，但由于其广泛分布和较大的总体数量，目前被列为无危物种。"},{"name":"短尾雕","english_name":"Bateleur","scientific_name":"Terathopius ecaudatus","overview":"短尾雕（英文名：Bateleur，学名：Terathopius ecaudatus），是鹰形目鹰科短尾雕属的鸟类。中等体型的鹰科猛禽，可能是津巴布韦国家象征津巴布韦鸟的起源。其特征为极短的尾巴和长初级飞羽，雄鸟体长55-70厘米，翼展168-190厘米，体重1820-2950克。羽毛主要为黑色，具栗色的背部、尾部和灰色肩部。面部、喙和脚均为醒目的红色。广泛分布在撒哈拉以南的非洲，从西非至东非，南至南非，以及阿拉伯西南部。","appearance":"短尾雕拥有非常独特的外观，成年个体大部分为黑色，背部、尾部为栗色，肩部为灰色。面部皮肤、喙和脚呈现鲜艳的红色。雄鸟与雌鸟的区别在于飞行时，雌鸟的黑色翼带更宽。亚成体呈均匀的暗褐色，面部皮肤和腿为蓝绿色。成年后，雄鸟和雌鸟的羽毛颜色相似，但雌鸟体型略大，次级飞羽有灰色边缘。幼鸟头部和下体为浅棕色，上体为深棕色，眼睛棕色，腿和脚蓝灰色。","call":"短尾雕通常沉默，但在求偶或感到不安或愤怒时发出响亮的“shaaaaa-aw”和“kow-aw”叫声，叫声粗犷且传播远。","habits":"短尾雕栖息于开阔的灌木丛生的草原和树木稀疏的萨瓦纳地带，高度范围从海平面到4500米，主要在3000米以下。它们白天在空中翱翔，飞行速度快，可达每小时80公里。它们展现出复杂的飞行技巧，经常进行低空摇摆飞行，翅膀呈明显的倾斜姿态。短尾雕偏好在开阔地带的大树上栖息。","breeding":"繁殖季节在西非为9月至次年5月，东非全年均可繁殖，但高峰在2月至3月。筑巢于大树的叉枝间，巢由中等大小的树枝构成，直径约60厘米，深度约30厘米，内部铺有树叶。每次仅产一枚白色蛋，孵化期为52-59天。雏鸟孵化后极度无助，全身覆盖奶油色绒毛，约90-125天后离巢。","identification":"短尾雕与其他鹰类的最大区别在于其极短的尾巴和长初级飞羽，以及鲜艳的红色面部、喙和脚。成年个体与幼鸟的颜色差异显著，幼鸟呈均匀的暗褐色。在飞行中，其低空摇摆的飞行方式也是一大识别特征。","protection":"IUCN：EN（濒危）","distribution":"分布于撒哈拉以南的非洲，从西非的塞内加尔至东非的苏丹、埃塞俄比亚，南至纳米比亚和南非，以及阿拉伯西南部。","other":"短尾雕在非洲文化中占有重要地位，可能成为津巴布韦国家象征津巴布韦鸟的原型。"},{"name":"食蝠鸢","english_name":"Bat Hawk","scientific_name":"Macheiramphus alcinus","overview":"食蝠鸢（英文名：Bat Hawk，学名：Macheiramphus alcinus），是鹰形目鹰科食蝠鸢属的鸟类。体型类似小型秃鹫，以其独特的捕食蝙蝠的能力而著称。分布于撒哈拉沙漠以南非洲、马达加斯加、中南半岛、印度次大陆及印度尼西亚诸岛。整体黑色，胸部有少许白斑，拥有大嘴裂，能够在飞行中迅速吞食猎物。","appearance":"食蝠鸢体重介于600-650克，成鸟上体棕黑色，眼周有白色斑点，胸喉部白色，饰有黑色竖纹。眼睛呈亮黄色，喙蜡质黑色，腿脚淡蓝灰色。亚成鸟斑纹更斑驳，颜色较浅，尾基及胸部有更多的白色。飞行时展现细长翅膀，似大猎鹰剪影，停息时几乎全黑，鲜黄色大眼是其显著特征。","call":"在巢附近时发出弱化的猎鹰式‘kek-kek-kek...’声，或尖锐的‘kwik-kwik-kwik-kwik’声（雌鸟更尖锐），还有‘chuk-chik-chuk’、‘woot-woot-woot’等音调，新几内亚地区叫声更为丰富，类似典型鹰的‘kee-kee-kee-kee-kee’。","habits":"食蝠鸢栖息环境多样，从茂密热带森林至半干旱灌木草原皆可见其踪迹。主要捕食蝙蝠，也猎食燕子、雨燕、金丝燕及小型鸟类、昆虫。所有猎物在空中捕捉，不落地取食，常在黄昏至黎明活动，利用敏锐视觉和飞行技巧追捕猎物。","breeding":"繁殖季节，食蝠鸢会在空中进行复杂的追逐和飞行特技，雌雄共同筑巢于大树枝间，巢由小树枝搭建，宽约3英尺，深1英尺。仅雌鸟孵卵，孵化期约为一个月，父母共同喂养雏鸟，时间约35-40天。","identification":"与相似体型的艾氏隼和烟色隼相比，食蝠鸢翼展更宽且钝，且具有明显的白色喉侧和胸部斑纹。不同亚种间主要区别在于羽色深浅、白色下体范围及头部羽冠长度。","protection":"IUCN：LC（无危）","distribution":"分布于非洲、东洋界、澳新界，广泛存在于撒哈拉沙漠以南非洲，延伸至缅甸、婆罗洲和新几内亚。","other":"食蝠鸢能够快速吞食猎物，平均6秒即可将猎物送入胃中，展现出极高的捕食效率。"},{"name":"新几内亚角雕","english_name":"Papuan Eagle","scientific_name":"Harpyopsis novaeguineae","overview":"新几内亚角雕（英文名：Papuan Eagle，学名：Harpyopsis novaeguineae），是鹰形目鹰科新几内亚角雕属的鸟类。体型巨大，拥有灰褐色羽毛和奶油色腹部，以独特的头部羽冠和面部围脖著称。广泛分布在新几内亚岛的原始森林中，主要栖息于海拔2000米以下的成熟雨林。","appearance":"新几内亚角雕体长可达72至90厘米，体重介于1.6到2.4千克之间，翼展范围在121至157厘米。雄鸟与雌鸟的外观相似，但雌鸟体型更大，最大差异可达34%，且可能更重。眼睛颜色为淡棕色或橙色，喙黑色，腿呈棕灰色至暗橙色。幼鸟与成鸟相似，但下体泛棕色，眼睛较暗，喙色更灰。成年鸟的胸部无条纹，这是与多氏鹰等其他物种区分的重要特征。","call":"其叫声独特而响亮，被描述为低沉、断续的‘uumpph’声，类似打嗝或绷紧的弓弦，有时会跟随深沉的‘buk-buk-buk’声或鸡鸣般的叫声。","habits":"新几内亚角雕主要栖息在新几内亚岛未受干扰的热带雨林中，偶尔出现在画廊森林、干林和季风灌木丛。它们通常在树冠层中搜索猎物，利用一系列的停栖点进行观察，然后迅速飞向新的停栖点，距离可达1500米。它们在地面上奔跑和跳跃追逐猎物，也能在树上搜寻并抓住猎物。","breeding":"繁殖季节似乎从雨季晚期到旱季（大约4月至11月）。它们在高大的树木上建造大型巢穴，如Eugenia、Syzygium或Aglaia等，高度可达30米以上。已知的巢穴大小惊人，高达3米。每两年可能只繁殖一次，每次只有一只幼鸟。","identification":"与长尾鵟和多氏鹰相比，新几内亚角雕体型更为庞大，喙部更厚实，胸部斑纹较少。雌鸟比雄鸟大，眼色随年龄增长而变得更鲜艳。","protection":"IUCN：VU（易危）","distribution":"新几内亚角雕主要分布于新几内亚岛，从印尼巴布亚半岛到巴布亚新几内亚全国都有发现。它们在海拔2000米以下的成熟雨林中最为常见，偶尔在3200至3700米的高海拔地区也有记录。","other":"新几内亚角雕面临的主要威胁包括非法狩猎和栖息地破坏。由于其稀少的种群数量和不断下降的趋势，已被 IUCN 列为易危物种。"},{"name":"冠雕","english_name":"Crested Eagle","scientific_name":"Morphnus guianensis","overview":"冠雕（英文名：Crested Eagle，学名：Morphnus guianensis），是鹰形目鹰科冠雕属的鸟类。大型的鹰科鸟类，仅见于新热带地区的广阔成熟低地森林和山麓森林，自危地马拉延伸至阿根廷东北部。其显著特征包括单尖头冠和鲜明的羽色变异，分布区域广泛但密度极低。","appearance":"成年冠雕体型庞大，长度可达89厘米，翼展可达176厘米，体重最高3千克。头部、背部和胸部通常呈浅棕色或灰褐色，喉部白色，头部有黑色斑点和小暗面具。存在深色型，整体呈炭灰色，腹部有白色横纹。幼鸟全身白色，背部和翅膀有大理石般的灰色图案，随年龄增长变为沙灰色。深色型幼鸟则自幼呈深棕色。","habits":"冠雕居住在潮湿的低地森林，偏好老生长热带雨林，偶尔在河岸或森林峡谷地带发现。它们主要以小型哺乳动物、啮齿类、蛇类和小鸟为食，常长时间静立于树冠中观察猎物。","breeding":"繁殖季节从3月到4月开始，筑巢于大树主枝叉处，巢大而隐蔽，通常只孵化一只幼鸟。雄鸟主要负责觅食，雌鸟则负责孵卵和照顾幼鸟。","identification":"与更大的角雕相比，冠雕体型稍小，形状更瘦长，有单一尖顶状头冠，腹部有横纹。幼鸟与角雕幼鸟相似，但体型和比例不同。","protection":"IUCN：NT（近危）","distribution":"分布于中美洲至南美洲，从危地马拉向南延伸至阿根廷东北部，包括亚马逊盆地和巴西的大西洋沿海森林。"},{"name":"角雕","english_name":"Harpy Eagle","scientific_name":"Harpia harpyja","overview":"角雕（英文名：Harpy Eagle，学名：Harpia harpyja），是鹰形目鹰科角雕属的鸟类。是新热带区最大的猛禽之一，以其力量和体型著称。与新几内亚的巴布亚角雕相区别，角雕主要栖息于热带雨林的上层树冠，分布自墨西哥南部至阿根廷东北部，因栖息地破坏而在许多地区几乎消失。","appearance":"角雕上身羽毛呈灰黑色，下身主要为白色，胸部有明显的黑色条纹，头部为淡灰色，具双冠。雄鸟和雌鸟在外表上相似，但雌鸟显著更大。爪子长度可达13厘米，雌性角雕平均体长108厘米，翼展可达200厘米，体重在6.5至9公斤之间。雄鸟体型较小，体重约为3.8至5.4公斤。","call":"在巢穴附近，成年角雕发出穿透力强、微弱而忧郁的尖叫声。雄鸟的叫声被描述为‘飘渺的尖叫或哀号’，而雌鸟的叫声虽然类似，但音调更低。","habits":"角雕主要栖息在热带低地森林的上冠层，偏好低海拔环境，偶尔出现在高达2000米的高度。它们以树栖哺乳动物为主食，如吼猴、长鼻浣熊和树懒，也会捕食鸟类如金刚鹦鹉。它们的捕猎技巧和力量惊人，能携带重量为其体重三分之二的猎物。","breeding":"角雕通常在高大的树木中建造大型的巢穴，每2-3年繁殖一次，每次产两枚白色蛋，但通常只抚养一只幼鸟。幼鸟在出生后6个月开始换羽，但父母会继续喂养幼鸟6到10个月。","identification":"角雕与同类大小的冠雕容易混淆，但可以通过角雕的双冠、更长的尾羽和明显的黑色胸带进行区分。","protection":"IUCN：VU（易危）","distribution":"角雕分布于中美洲至南美洲，从墨西哥南部至阿根廷东北部，包括巴西的亚马逊盆地。","other":"角雕是巴拿马的国鸟，也是多个保护项目的目标，旨在恢复其种群数量。"},{"name":"凤头鹰雕","english_name":"Changeable Hawk-Eagle","scientific_name":"Nisaetus cirrhatus","overview":"凤头鹰雕（英文名：Changeable Hawk-Eagle，学名：Nisaetus cirrhatus），是鹰形目鹰科鹰雕属的鸟类。大型猛禽，此物种又被称为‘沼泽鹰雕’或‘印度凤头鹰雕’，其显著特征为覆盖腿上的羽毛，这是热带地区之外的猛禽所不具备的。凤头鹰雕展现出广泛的羽毛颜色变异，从淡色到深色，随着年龄和换羽而变化，由此得名‘变色’。分布于印度次大陆及中国的西南地区，远东至大巽他群岛和菲律宾。","appearance":"凤头鹰雕体型中等偏大，身长可达51至82厘米，翼展100至160厘米，体重1.36至1.6千克。其头部相对较小，上体呈深褐色，下体白色或淡色，布满深色条纹。成鸟眼睛黄色至橙黄色，虹膜颜色随年龄变化。幼鸟的羽毛更为浅淡，头颈部分有明显的黑色条纹，腹部和腿部有更深的条纹。存在淡色和深色两种形态，深色形态全身暗色，仅翼尖和尾部有灰色。成鸟的腿羽不会延伸到脚趾之间，这是与其他亚洲Nisaetus物种的主要区别。","call":"凤头鹰雕在繁殖季节较为活跃，发出一系列尖锐的哨音，最后音调上升，描述为“kwip-kwip-kwip-kwi-kweee”。也会发出连续的单个尖锐哨音，有时后跟两三个较柔和的音符。","habits":"凤头鹰雕栖息于落叶林和常绿林，也见于次生林、画廊森林、稀树草原、有树木的村庄、茶园和柚木种植园，通常在低地和丘陵地带，海拔从海平面至2200米，但主要在1500米以下。它们主要生活在森林边缘和开阔的林地，而非密林深处。","breeding":"繁殖季节变化，一般在12月至5月在婆罗洲、苏门答腊、斯里兰卡和马来半岛；11月至5月在印度；4月至8月在爪哇；10月在苏门答腊观察到幼鸟。巢由成对的凤头鹰雕共同建造，位于大树冠层或高枝叉处，巢直径95至105厘米，深度35至120厘米。每窝产一枚白色卵，卵的尺寸为62.2至67.3毫米×48.3至52.8毫米。孵化期约为50天，由雌鸟为主承担。幼鸟在68天左右离巢。","identification":"凤头鹰雕与鹰雕的主要区别在于，凤头鹰雕的枕部冠羽较短，腿羽不会延伸过中趾基部；而鹰雕的枕部冠羽较长，腿羽会覆盖中趾基部。","protection":"IUCN：LC（无危）。《华盛顿公约》CITES附录II。尽管广泛分布，但在某些岛屿群体如安达曼群岛和vanheurni亚种，因范围小而可能具有相应的小种群规模。","distribution":"分布于喜马拉雅山脉、印度中部、南部和斯里兰卡，向东南延伸至大巽他群岛和菲律宾。在中国大陆，主要分布在西南地区。","other":"凤头鹰雕的食性广泛，包括小型和大型鸟类、蛇、蛙、蜥蜴和哺乳动物，如松鼠、鼠类、野兔，偶尔猴子和鼩鼱。"},{"name":"费氏鹰雕","english_name":"Flores Hawk-Eagle","scientific_name":"Nisaetus floris","overview":"费氏鹰雕（英文名：Flores Hawk-Eagle，学名：Nisaetus floris），是鹰形目鹰科鹰雕属的鸟类。大型猛禽，是印度尼西亚小巽他群岛的特有种，曾在分类上被认为是凤头鹰雕的亚种，但遗传学证据确认其为独立物种。因其独特的白头和下体，巧克力棕色背部和上尾部而易于识别，主要栖息于热带低地和山麓森林。","appearance":"成年费氏鹰雕具有深褐色上体，带六条横纹的褐色尾巴，翼上有可见的白色斑块，下体和头部为白色，冠部有细微的褐色条纹。体型较大，全长通常报道为75至79厘米，但可能在71至82厘米之间。尾部有6条而非4至5条横纹，翅膀长度为430至462毫米。雌雄相似，无明显区别。","call":"已知的一种叫声为响亮、尖锐、高音的哨声。","habits":"费氏鹰雕主要栖息于热带低地和亚山地湿润森林，海拔高度从海平面到约1700米。它们通常在完整的原生森林中或附近活动，偶尔也会在森林村庄和红树林中狩猎，利用次生林、桉树灌木丛和农业区。","breeding":"繁殖信息极少，已知在3月、4月、5月和8月有活跃的筑巢记录，但巢和蛋的描述未知。","identification":"与未成年的棕腹隼雕相比，体型更大，尾纹更粗，头部和下体全白，翅膀内侧有明显的隆起，不同于棕腹隼雕。与短趾雕的区别在于前翅下侧缺乏暗色标记，下体干净白色。","protection":"IUCN：EN（濒危）","distribution":"分布于小巽他群岛（龙目岛、松巴哇岛、弗洛雷斯岛和阿洛尔岛）。","other":"由于栖息地丧失和退化，非法狩猎以及因捕食家禽而遭受的迫害，费氏鹰雕面临严重威胁。全球成熟个体数量估计为100至240只。"},{"name":"鹰雕","english_name":"Mountain Hawk-Eagle","scientific_name":"Nisaetus nipalensis","overview":"鹰雕（英文名：Mountain Hawk-Eagle，学名：Nisaetus nipalensis），是鹰形目鹰科鹰雕属的鸟类。又名熊鹰（台湾）、赫氏角鹰，属于大型猛禽，身长70至84厘米。上半身暗褐色，腹部有粗横斑，喉部具黑色纵纹。幼鸟颜色较淡，翅膀上有不规则褐色块，头部及腹面为白色调。分布于喜马拉雅山脉至台湾和日本的山地森林地带。","appearance":"成年鹰雕体型硕大，背部暗褐色，腹部具粗横斑，喉部有黑色纵纹。头部有竖立的薄羽冠。幼鸟整体较淡色，翅膀带不规则褐色斑块，头部和腹部为干净的白色调。翼展134至175厘米，雄鸟体重2300至2700克，雌鸟体重2500至3900克。眼睛金黄色至橙色，蜡膜黑色至灰黑色，脚黄色至黄白色。","call":"一般沉默，但在繁殖季节会发出高音、尖锐的管笛声，后接一或两个柔和的音符，如“kleee-kik”或“kleee-kikik”。","habits":"栖息于海拔600至4000米的密集山地和蒙坦常绿及混合落叶林。在日本偏好成熟的山地森林，有开阔的下层植被和大型树木用于筑巢。主要以小型至中型哺乳动物、鸟类、蜥蜴、蛇和偶尔鱼类为食，也会捕食家禽。通常从隐蔽的栖木上狩猎，快速俯冲捕获地面猎物。","breeding":"繁殖季节在斯里兰卡为12月至3月，在喜马拉雅山区为2月至6月，在日本为2月至8月。巢由成对鹰雕建造，直径可达1.8米，深度90至120厘米，位于12至30米高的大树上。每次产卵1至2枚，孵化由雌鸟承担，持续约43至50天。幼鸟期70至80天，日本地区幼鸟于6月至8月离巢。","identification":"与凤头鹰雕相比，本种下腹部更多为条纹而非斑点，具有较短的羽冠和较窄的尾部暗色条纹。与N. nipalensis nipalensis相比，N. nipalensis orientalis体型较大，尾巴和翅膀较长，颜色较浅，条纹较少。","protection":"IUCN：LC（无危）。列入CITES II。数量稀少至罕见，可能因广泛森林砍伐而减少。全球数量估计不足10,000只，日本约有1800只，列为Endangered。在东南亚部分地区遭受宠物贸易威胁。","distribution":"繁殖区域包括喜马拉雅山脉、印度、尼泊尔、孟加拉国、泰国、台湾、越南和日本。非繁殖区域包括印度河流域、缅甸、泰国、马来西亚半岛的低地。在中国大陆分布于东北部巴基斯坦至中国东南部，包括台湾和日本。","other":"在1990年至2008年间，日本研究区域的繁殖成功率与日本水青冈种子产量正相关，可能因为种子产量增加导致猎物数量增加。"},{"name":"力氏鹰雕","english_name":"Legge's Hawk-Eagle","scientific_name":"Nisaetus kelaarti","overview":"力氏鹰雕（英文名：Legge's Hawk-Eagle，学名：Nisaetus kelaarti），是鹰形目鹰科鹰雕属的鸟类。其分布区域主要集中在印度次大陆南部至斯里兰卡一带。该鹰以其独特的白色尖端冠羽、灰色条纹脸颊和长腿而著称，相对较大的猛禽。","appearance":"力氏鹰雕体长介于66至84厘米之间，翼展可达134至175厘米，体重因性别而异，雄鸟通常在2300至2700克之间，雌鸟则重2500至3900克。上体呈棕色，下体有条纹，翅膀宽大且具条纹，尾巴长且有深浅相间的条带。头部具有长度可变的冠羽，脚爪强壮且覆有羽毛。虹膜颜色从金黄色到橙色不等，蜡膜呈灰黑色，脚趾色偏淡黄至灰白色。幼鸟比成鸟更显苍白，下体几乎全白。","call":"在繁殖季节较为活跃，最常发出的叫声是一种高音调、尖锐的笛声，后跟一两个较柔和的音符，例如'kleee-kik'或'kleee-kikik'。","habits":"栖息于海拔600至4000米的茂密山地常绿森林和混合落叶林，偶尔降至200米。在日本，偏好成熟的山地森林，以开阔的林下层和大树作为筑巢地点。主要以小型至中型哺乳动物、鸟类、蜥蜴、蛇类甚至鱼类为食，也捕食家禽。狩猎时，从森林内部隐蔽处出击，迅速俯冲捕获地面猎物。","breeding":"繁殖期在斯里兰卡为12月至3月，在喜马拉雅山脉为2月至6月，在日本则从2月至8月。巢由一对鹰雕建造，直径可达1.8米，深度90至120厘米，位于大型树木12至30米高处。繁殖期间，雌雄双方会共同防御巢穴。每窝产蛋一枚，偶尔两枚，平均大小为70毫米×57毫米，孵化期约43至50天，主要由雌鸟负责。幼鸟在巢中停留70至80天，之后于6月至8月离巢。亲鸟的照顾期可能延长至次年2月，幼鸟在此期间不会远离巢穴超过1公里。","identification":"与山鹰雕相比，力氏鹰雕体型较小，下体羽色无条纹，胸腹部分条纹更为明显，尾羽的暗色条纹较窄。亚种kelaarti与指名亚种相似，但下体颜色略浅。","protection":"IUCN：LC（无危）。CITES II（濒危野生动植物种国际贸易公约二级）。全球数量估计少于10,000只，其中约1800只在日本，已被列为濒危物种。东南亚部分地区存在非法宠物贸易威胁。","distribution":"主要分布于印度西南部和斯里兰卡，繁殖区域集中在这些地区的山地森林。","other":"自1990年至2008年间，日本研究区域内力氏鹰雕的繁殖成功率与日本水青冈种子产量正相关，这可能是因为种子产量增加导致猎物数量增多。"},{"name":"马来鹰雕","english_name":"Blyth's Hawk-Eagle","scientific_name":"Nisaetus alboniger","overview":"马来鹰雕（英文名：Blyth's Hawk-Eagle，学名：Nisaetus alboniger），是鹰形目鹰科鹰雕属的鸟类。以英国动物学家爱德华·布莱斯（Edward Blyth）命名，他在1810年至1873年间担任孟加拉亚洲学会博物馆馆长。马来鹰雕分布于马来半岛、新加坡、苏门答腊及其周边岛屿，以及婆罗洲，栖息于海拔500至1500米的山地常绿森林。","appearance":"成年马来鹰雕上体呈深褐色至黑色，下体具显著的黑斑纹，白色底色。飞行时可见宽阔的圆形翅膀和尾部一条宽阔的白色横带。头部有小而不太显眼的冠羽。幼鸟上体较暗，头和下体颜色偏棕黄色，眼虹膜灰色至淡黄色，喙灰黑色，脚黄色至黄白色。与成年相比，幼鸟尾部条纹较细。","call":"在繁殖季节较为活跃，常见鸣声为连续的尖锐哨音“kleee kleee kleee”，有时前缀一两个较轻的音符，如“kee-kee-kleeee”。","habits":"马来鹰雕偏好在山地森林中活动，偶尔会降至低至200米的地带，最高可达2200米。成鸟通常定居，而幼鸟在扩散期间可能通过低地开阔地带。它们以树栖哺乳动物、蝙蝠、鸟类和蜥蜴为食，甚至报道过捕食家鸡。捕猎时，它们从隐蔽的高树冠处敏捷飞行，捕捉猎物。","breeding":"关于繁殖信息甚少，已知在马来半岛有筑巢记录，孵化期在11月，单个雏鸟从12月末持续至次年4月末。在苏门答腊，观察到10月中旬有求偶和收集筑巢材料的行为，7月18日发现活跃的巢穴。巢由树枝构成，位于森林中大型突出树木的树冠处，巢中从未发现超过一只雏鸟，暗示每次繁殖仅产一枚卵。","identification":"与华莱士鹰雕相比，马来鹰雕体型更大，上体颜色更黑，尾部横带更宽。幼鸟与华氏鹰雕幼鸟相似，但尾部条纹更细，可通过海拔高度（马来鹰雕偏好更高海拔）和体型大小区分。","protection":"IUCN：LC（无危）。列入CITES II附录。总体上数量不多，全球种群数量和趋势信息缺乏，但由于长期的栖息地丧失和大面积森林砍伐，其数量疑似在减少。","distribution":"分布于泰国南部至马来半岛、苏门答腊及其卫星岛屿（Simeulue、Nias、Mentawai Islands、Belitung）、北婆罗洲和中婆罗洲。","other":"马来鹰雕在开放林地和岛上更密集的树丛中筑巢，每巢仅产一枚卵。"},{"name":"爪哇鹰雕","english_name":"Javan Hawk-Eagle","scientific_name":"Nisaetus bartelsi","overview":"爪哇鹰雕（英文名：Javan Hawk-Eagle，学名：Nisaetus bartelsi），是鹰形目鹰科鹰雕属的鸟类。中等大小的猛禽，分布于爪哇的热带森林中。作为印尼的特有种，被誉为印度尼西亚的国鸟，通常被称为Garuda，源于印度教和佛教神话中的神鸟形象。其显著特征为红褐色的头颈和密集的黑色斑纹。","appearance":"爪哇鹰雕体长约60厘米，具有鲜明的黑色垂直条纹和白色喉部，以及深色上体和白底带重横纹的下体。成鸟头部和颈部红褐色，腹部、两胁和大腿有厚重的横纹。尾部相对较长，带有3-4条暗色带。幼鸟头部和下体呈红褐色至淡黄色，下体无斑纹，头颈颜色较暗。成鸟虹膜黄色，幼鸟虹膜蓝灰色；蜡膜灰黑至灰色；脚黄色。","call":"一般沉默，但在繁殖季节会发出双音节的尖锐拉长哨声“kee-heee”，以及一系列管笛式的哨声，最后一音节加重“kwip-kwip-kwip-kweee”。","habits":"主要栖息于爪哇的湿润热带森林，偏好原始森林，但也可见于次生林和茶种植园等受扰动的环境。活动范围广泛，从海拔200米至1200米，偶尔降至海平面，最高可达3000米。成鸟多定居，而幼鸟和未成熟个体在扩散期间会穿越次生生长的栖息地。以多种脊椎动物为食，包括鼠类、松鼠、树鼩、猴子、苏门答腊臭鼬、小型鹿类、家鸡、雉鸡、鹌鹑、鸽子、蟆口鸱、啄木鸟、鹎、蛇和蜥蜴。","breeding":"繁殖期从12月至7月。由一对鹰雕使用树枝建造并以绿叶装饰的巢位于高树上，离地面高度在15至50米之间。巢的直径约70至150厘米，深度20至56厘米。每次仅产一枚白色带有小褐色斑点的卵，孵化期约为47至48天，主要由雌鸟负责。雏鸟孵化后约70天离巢，幼鸟可能与父母共处一年以上。","identification":"与体型明显更大或更小的同属鹰雕相比，爪哇鹰雕头部和颈部的深红褐色更为突出。幼鸟头部和下体的红褐色至淡黄色以及下体无斑纹也是辨识要点。","protection":"IUCN：EN（濒危）, CITES: 附录二","distribution":"爪哇鹰雕为爪哇岛的特有种，分布于从乌戎库龙远西至阿拉斯普尔沃远东的多个森林地带。主要栖息于山区，包括东爪哇的森普岛、婆罗腾格塞梅鲁国家公园、默鲁贝蒂里国家公园和阿拉斯普尔沃国家公园。","other":"爪哇鹰雕面临着非法贸易和栖息地丧失的双重威胁，尤其是幼鸟和未成熟个体在扩散期间容易落入人口密集区，增加了被捕获的风险。"},{"name":"苏拉鹰雕","english_name":"Sulawesi Hawk-Eagle","scientific_name":"Nisaetus lanceolatus","appearance":"成年苏拉威西鹰雕头部暗棕色，有冠羽，喉咙白色带中央条纹，胸部红褐色伴大胆斑纹，腹部密集横纹，腿有羽毛覆盖。飞行时，身体和前翅密集条纹，外翅稀疏条纹，尾巴均匀条纹。翅膀宽大，内侧膨大。幼鸟头部和下体白色，上体深棕色，尾部条纹较窄。","call":"发出响亮的‘ke-ke-ke-ke…’叫声。","habits":"生活在从低地到山区的高大森林中，偏好开放地带。比南洋蜂鹰体型更大，头部更重，喙更大，腿有羽毛，尾纹间隔更均匀。幼鸟可能与年轻的棕腹隼雕混淆，但后者有深色面颊和面罩，翅膀更长更窄，尾巴更短。","breeding":"繁殖季节可能为5月至8月，基于已见出巢幼鸟的时间。巢建于巨大树木的水平枝干上，位于离地面约20米的寄生植物中。据推测每窝产一枚蛋，但未得到证实。","identification":"与南洋蜂鹰相比，苏拉威西鹰雕体型更大，头部更重，喙更大，腿有羽毛，尾纹间隔更均匀。幼鸟可能与棕腹隼雕混淆，但后者有深色面颊和面罩，翅膀更长更窄，尾巴更短。","protection":"IUCN：LC（无危）","distribution":"分布于苏拉威西岛及附近的Muna和Butung岛，Banggai群岛（Peleng和Labobo）和Sula群岛。"},{"name":"菲律宾鹰雕","english_name":"Philippine Hawk-Eagle","scientific_name":"Nisaetus philippensis","overview":"菲律宾鹰雕（英文名：Philippine Hawk-Eagle，学名：Nisaetus philippensis），是鹰形目鹰科鹰雕属的鸟类。以热带湿润低地森林为其自然栖息地，特有于菲律宾。体长56至69厘米，翼展105至125厘米，雌鸟体重介于1168至1280克之间，明显大于雄鸟。上体暗棕色，下体浅棕色，头部和胸部有条纹，下腹部细条纹。其独特之处在于8厘米长的后向羽冠。鸣声为尖锐的‘week wik！’。","appearance":"菲律宾鹰雕是一种大型猛禽，体长64至80厘米，体重约2190克。虹膜呈亮黄色，喙黑色，蜡膜黑灰色，腿和脚黄色，爪黑色。背部为棕色，腰部和尾上覆羽有淡白色横斑，尾羽具宽幅黑色和灰白色相间的横带。头侧和颈侧有黑色和黄褐色条纹，喉部和胸部白色，喉部有一条显著的黑色纵纹，胸部有黑褐色纵纹，腹部密布淡褐色和白色相间的横斑。飞翔时，宽阔的翅膀和尾羽下的黑白相间横斑非常醒目。","call":"发出尖锐的‘yiep-yiep’叫声，不同于凤头鹰雕的上升四音节尖叫，通常在上午晚些时候最为频繁。","habits":"栖息于低地和山脚森林，最高可达海拔1050米，偏好原生森林，偶尔出现在选择性砍伐的区域。似乎定居，但幼鸟可能有岛屿间移动的可能性。以隐蔽的栖木为偏爱，饮食习惯未知，但可能以大型鸟类和一些哺乳动物为主食。","breeding":"繁殖信息未知，但在一月曾观察到生殖器官增大的个体，三月底有空中求偶展示的报告。","identification":"与凤头鹰雕和较小的Pernis属物种相似，但后者具有裸露的小腿、更小的头部和喙、较长的颈部、较瘦的身体和更长、边缘更平行的翅膀。与Nisaetus cirrhatus limnaeetus相比，本种更大、更强壮，休息时翅膀更接近尾端。","protection":"IUCN：EN（濒危）。CITES II级。估计现存400至600只成熟个体。自1980年以来，吕宋岛（主要在Sierra Madre山脉）和民都洛岛共有21个记录点。森林覆盖率下降、农业开垦、放牧和伐木是主要威胁。","distribution":"分布于菲律宾北部的吕宋岛和民都洛岛。","other":"平氏鹰雕曾被认为是其亚种，现已提升为独立物种。"},{"name":"平氏鹰雕","english_name":"Pinsker's Hawk-Eagle","scientific_name":"Nisaetus pinskeri","overview":"平氏鹰雕（英文名：Pinsker's Hawk-Eagle，学名：Nisaetus pinskeri），是鹰形目鹰科鹰雕属的鸟类。菲律宾特有种。分布于莱特岛、萨马岛、内格罗斯岛、巴西兰省、保和岛及棉兰老岛。其最显著的特征是头部棕色至深橄榄色，有黑色条纹，背部暗褐色，下腹部细密条纹，幼鸟颜色较淡。面临栖息地丧失和狩猎威胁。","appearance":"体长54-61厘米，重约1200克。典型的鹰雕特征，具4-5根长达8厘米的黑色冠羽。头部棕色至深橄榄色，杂以黑色条纹；背部及翅膀上部暗褐色，尾巴具4-5条较窄的深色横纹；喉部纯白色，但有一条可变的中央黑线；上胸部有黑色条纹，其余下部羽毛变色范围从赭色到锈褐色或橄榄褐色，伴以显著的黑色条纹；最下部区域和大腿羽毛密集条纹。虹膜明亮铬黄色，喙和蜡膜黑色，腿黄色。雌雄相似，雄鸟体型较小。幼鸟比成鸟颜色浅得多，头部和颈部白色，仅眼圈和长黑冠羽为黑色，逐渐融入鼠灰色至上部棕色。","call":"发出双音节的叫声“wheee-whit”，与菲律宾鹰雕的叫声相似。","habits":"栖息于低地和低山成熟森林，最高可达海拔1900米的高山苔藓森林。叫声为双音节的“wheee-whit”。","breeding":"繁殖信息不详，但有记录显示每繁殖季产生一枚蛋，孵化期约47天，最长记录为49天。幼鸟成长至五个月后进入离巢阶段，父母鹰会停止在巢中喂食，转而在附近树枝喂食，鼓励幼鸟学习飞翔。","identification":"与菲律宾鹰雕相比，体型略小，下部羽毛更密集地条纹。幼鸟颜色明显较淡，头部和颈部白色，而的头部更为前伸。","protection":"IUCN：EN（濒危）","distribution":"分布于菲律宾中部和南部的大部分维萨亚群岛（Visayas）、棉兰老岛（Mindanao）和巴西兰省（Basilan）。具体包括萨马岛（Samar）、比里兰岛（Biliran）、莱特岛（Leyte）、内格罗斯岛（Negros）、锡基霍尔岛（Siquijor）、保和岛（Bohol）、棉兰老岛（Mindanao）和巴西兰省（Basilan）。","other":"遗传分析支持其独立物种地位。"},{"name":"华氏鹰雕","english_name":"Wallace's Hawk-Eagle","scientific_name":"Nisaetus nanus","overview":"华氏鹰雕（英文名：Wallace's Hawk-Eagle，学名：Nisaetus nanus），是鹰形目鹰科鹰雕属的鸟类。属于鹰雕属，活跃于马来半岛、苏门答腊及婆罗洲的热带低地森林。以英国自然学家阿尔弗雷德·拉塞尔·华莱士命名，其体长约46厘米，体重介于500至610克，为世界上最小的鹰之一。","appearance":"华氏鹰雕具有典型的小型鹰雕特征，站立时可见竖立的黑色小冠羽，顶端白色。成鸟翼部呈深褐色，脸部较淡。飞行中可见其下体密布黑色横纹，尾部有两道白色条带，翅膀内侧部分呈浅棕色。与布莱斯鹰雕相比，其翅膀下侧并非全黑白色。幼鸟头部和下体呈淡黄褐色，与布莱斯鹰雕尾部横纹相似，但华氏鹰雕下体无斑点，腿上羽毛丰满，尾端黑色更宽。","call":"发出尖锐、高音调的“yik-yee”或“kliit-kleeik”声，第二音节上升。","habits":"栖息于低地常绿和半常绿森林，包括龙脑香林、泥炭沼泽森林和河岸森林，偶尔出现在次生林和合欢树丛中，海拔高度可达1000米，但在500米以下最为常见。狩猎时可能在森林内部或边缘静候，捕食鸟类、蝙蝠、松鼠、鼠类、蜥蜴和蛇等。","breeding":"繁殖季节可能主要在12月至3月，巢穴通常建在大树的低叉处，高达35米。一对华氏鹰雕在巢附近会进行空中展示，但具体细节未知。已知的巢穴观察显示，每次繁殖仅有一只雏鸟。","identification":"与布莱斯鹰雕和山鹰雕相比，华氏鹰雕体型较小，颜色较淡。幼鸟与布莱斯鹰雕相似，但后者尾部有横纹，而华氏鹰雕下体无斑点，腿上有羽毛覆盖，尾端黑色更宽。","protection":"IUCN：VU（易危）","distribution":"繁殖区域：马来半岛、苏门答腊和婆罗洲。","other":"面临低地雨林丧失的威胁，由于采伐、转为种植园和农业，以及重大森林火灾，导致数量稀少。"},{"name":"黑鹰雕","english_name":"Black Hawk-Eagle","scientific_name":"Spizaetus tyrannus","overview":"黑鹰雕（英文名：Black Hawk-Eagle，学名：Spizaetus tyrannus），是鹰形目鹰科黑白鹰雕属的鸟类。分布于中美洲至南美洲的鹰科鸟类。其分布范围从中墨西哥至巴西南部，哥伦比亚至秘鲁东部，远至阿根廷北部。拥有独特的黑色羽毛，翅膀下方带有明显的白色条纹，尾羽宽大且具灰色横纹。黑鹰雕是热带森林中的显著成员，以它的壮观飞行和嘹亮哨声著称。","appearance":"成年黑鹰雕全身黑色，翅膀宽大，尾部长而圆，尾羽上可见3条宽广的灰色横纹。翅膀下方的主翼和次级飞羽上带有宽阔的白色条纹，下翼覆羽亦有大量白色标记。头部顶冠由黑色羽毛组成，基部白色。幼鸟的羽毛颜色较淡，头部为白色和黄褐色混合，胸部有黑色和棕色条纹，腹部则为黑色斑点和白色相间。雄鸟和雌鸟外观相似，但雌鸟体型略大。","call":"黑鹰雕在飞行中会发出响亮、远传的哨声，这些声音常揭示其存在。","habits":"黑鹰雕栖息于低地热带森林，既出现在开放森林也见于密林地带。它们经常在空中高飞，吸引注意的尖锐哨声让人印象深刻。它们主要捕食哺乳动物、鸟类和爬行动物，通常从树上捕获猎物。","breeding":"繁殖行为知之甚少，但已知黑鹰雕在树冠中筑巢，巢位于侧枝上，远离树干中心，平均高度约25.5米。每对黑鹰雕一般只产一枚卵，估计孵化期为44天。研究表明，它们在雨季产卵的频率更高。","identification":"与同属的丽鹰雕相比，黑鹰雕的羽毛更暗，翅膀下方有明显的白色条纹，尾羽的灰色横纹更为突出。幼鸟的羽毛颜色较淡，头颈部分白黄相间，有助于与成鸟区分。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，从中墨西哥到阿根廷东北部，覆盖亚马逊盆地和巴西东部沿海森林。","other":"黑鹰雕的发展缓慢，可能每两年或三年才繁殖一次。"},{"name":"黑白鹰雕","english_name":"Black-and-white Hawk-Eagle","scientific_name":"Spizaetus melanoleucus","overview":"黑白鹰雕（英文名：Black-and-white Hawk-Eagle，学名：Spizaetus melanoleucus），是鹰形目鹰科黑白鹰雕属的鸟类。大型猛禽，拥有鲜明的黑白羽色，黑色眼斑，橙黄色喙基和短小的黑色冠羽，是热带美洲森林中的壮观物种。分布范围广泛，从墨西哥南部到阿根廷东北部，栖息于低地热带森林。","appearance":"黑白鹰雕体型大，全身以白色为主，背部和翅膀上覆黑色，头部有黑色眼斑和短小的黑色冠羽，尾巴呈黑灰相间的条纹状。翼下明亮的白色与黑色的翼上形成鲜明对比，翼内侧有独特的白色前缘。喙黑色，基部橙黄，脚趾亮黄色。成年个体两性相似，雌鸟略大。幼鸟上体混有棕灰色，翼上覆羽尖端有白色边缘。","call":"飞行时不常鸣叫，与黑鹰雕和丽鹰雕不同。","habits":"栖息于各种低地森林环境，偏好混合林和部分开阔地带。以哺乳动物、鸟类、爬行类和两栖类为食，通过高空翱翔发现猎物，然后俯冲捕猎。飞行技术高超，能在远距离识别猎物。","breeding":"巢筑于高树的森林冠层，由树枝构成，位于视野良好的位置，如山脊。筑巢季节可能在雨季开始前，但在不同地区有所不同，如在巴拿马，筑巢始于雨季的干旱期。","identification":"与幼年丽鹰雕相似，但后者具淡色眼区、黄色蜡膜，腹部和胫羽有大量黑色条纹。与灰头美洲鸢浅色型幼鸟相似，但灰头鸢胫部无羽、眼区淡色、蜡膜黄色，上体褐色而非黑色，翼下主羽有更明显的条纹。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲和南美洲，从墨西哥南部至阿根廷东北部，包括伯利兹、玻利维亚、巴西、哥伦比亚、哥斯达黎加、厄瓜多尔、法属圭亚那、危地马拉、圭亚那、洪都拉斯、墨西哥、尼加拉瓜、巴拿马、巴拉圭、秘鲁、苏里南和委内瑞拉。","other":"关于其生态习性和种群状况的信息有限，每只鸟需要至少约1,400公顷的狩猎领地。"},{"name":"丽鹰雕","english_name":"Ornate Hawk-Eagle","scientific_name":"Spizaetus ornatus","overview":"丽鹰雕（英文名：Ornate Hawk-Eagle，学名：Spizaetus ornatus），是鹰形目鹰科黑白鹰雕属的鸟类。热带美洲的壮观而罕见的鹰类，以其羽毛华丽的头部侧面和大胆的腹部条纹著称。广泛分布于中美洲和南美洲低地及山麓地带的热带森林中，自墨西哥东南部直至阿根廷北部。通常在清晨时分出现在树梢或森林边缘，而到了上午晚些时候，人们更可能看到它们在树冠上空盘旋，发出持久的叫声。","appearance":"成年丽鹰雕具有橙色的头部侧面，头部顶部和长而尖锐的羽冠呈黑色。其腹部有明显的黑色条纹，尾部带有宽幅的黑白条带，翼下白色，带有斑点。羽冠在飞行时平伏，但在停歇时可以竖起。幼鸟头部和腹部白色，腹部有细小的条纹，与成鸟明显不同。","call":"飞行时发出远距离传播的、类似打嗝的哨声，揭示了它的存在。","habits":"丽鹰雕栖息于热带森林中，一般在海拔1800米以下活动。它们在清晨时分出现在树梢或森林边缘，而到了上午晚些时候，人们更可能看到它们在树冠上空盘旋，发出持久的叫声。它们的饮食广泛，从大型鸟类如鵙鸟和巨嘴鸟到猴子和负鼠，甚至更小的猎物都是它们的食物。它们的飞行特征深沉有力，翅膀扁平向前伸展，尾巴有时闭合有时展开。","breeding":"繁殖季节通常在中美洲为12月至9月，而在巴西则为8月至1月。筑巢于高大树木的暴露枝条上，高度通常在20至30米之间，巢由树枝构成，直径约1至1.25米，深度约50厘米。每次产一枚蛋，孵化期约为43至48天。","identification":"与黑鹰雕相比，丽鹰雕的羽毛颜色更为鲜艳，腹部条纹更为显眼。幼鸟与灰腹鹰的幼鸟在羽毛模式上相似，但后者体型较小，腿无羽毛，且无羽冠。","protection":"IUCN：NT（近危）","distribution":"分布于中美洲和南美洲，从墨西哥东南部至阿根廷北部，包括哥伦比亚东部、委内瑞拉、特立尼达和多巴哥、厄瓜多尔东部、圭亚那、巴西、秘鲁东部、玻利维亚中部和东部、巴拉圭南部和阿根廷东北部。","other":"丽鹰雕面临的主要威胁是森林砍伐，特别是在亚马逊雨林区域，导致其栖息地丧失，进而影响其生存状况。"},{"name":"黑栗雕","english_name":"Black-and-chestnut Eagle","scientific_name":"Spizaetus isidori","overview":"黑栗雕（英文名：Black-and-chestnut Eagle，学名：Spizaetus isidori），是鹰形目鹰科黑白鹰雕属的鸟类。大型南美猛禽，属于鹰科。其分布区自委内瑞拉至阿根廷西北部，栖息于安第斯山脉的云雾森林中，以猎捕小型哺乳动物和鸟类为主。黑栗雕因其壮观的外观和重要的生态角色而受到关注，但因栖息地破坏和人类迫害，其数量急剧下降，被列为濒危物种。","appearance":"成年黑栗雕身长60至80厘米，翼展可达147至180厘米，是Spizaetus属中体型最大的成员。雌鸟比雄鸟大4%至14%，尾部更长。头部、背部黑色，胸腹部呈丰富的栗色，带有黑色条纹。翅膀上白色斑块与栗色下翼形成鲜明对比，尾巴灰色，有厚实的黑色次端带。橙黄色的眼睛和黄色的喙脚。幼鸟外观差异极大，头和身体白色，背部和肩部灰褐色，翅膀和尾部有黑白相间的条纹。","call":"通常沉默，繁殖季节时会发出一系列尖锐单调的哨声“KEEEuw...KEEEuw..”。离巢的幼鸟会发出一系列尖叫的哨声“yeEEW..yeEEW..yeEEW”。","habits":"主要栖息于海拔1500至2800米的重林山地，偏好在大型山谷中的亚热带和下温带区域。狩猎活动主要在树冠层进行，经常翱翔，很少被观察到栖息。以大型鸟类如鵽类和树栖哺乳动物如松鼠、猴子为主要猎物，偶尔捕食树懒、树豪猪和浣熊。","breeding":"巢建于2月至3月，孵化期在4月至5月，幼鸟大约在8月至9月离巢。巢由巨大树枝构成，直径可达2米，深约1米。每窝产1至2枚卵。雌鸟负责孵卵和夜间守护，雄鸟提供食物。幼鸟在4个月左右离巢，但在一年内仍依赖父母。","identification":"成年黑栗雕在黑色和栗色的组合上独一无二，与其它Spizaetus鹰有明显区别。幼鸟与苍白型冠鹰相似，但翼和尾的条纹更细，胸部和腹部无条纹。","protection":"IUCN：EN（濒危）","distribution":"分布于委内瑞拉至阿根廷西北部的安第斯山脉，包括哥伦比亚、厄瓜多尔、秘鲁和玻利维亚的云雾森林。","other":"由于栖息地丧失和被视为家禽捕杀者的迫害，黑栗雕的数量急剧减少，目前全球仅存不到1000只成熟个体。"},{"name":"非洲冠雕","english_name":"Crowned Eagle","scientific_name":"Stephanoaetus coronatus","appearance":"非洲冠雕是一种大胆、具有显著标记的大型猛禽，拥有长尾巴和宽大的翅膀，外观上与巨型雀鹰相似。成鸟的下腹部有黑白色斑点和条纹；有时胸部会出现变化不定的红褐色斑纹。幼鸟的下翼呈奶油色。头部较小，有庞大的羽冠（通常平伏）。背部呈石板黑色，逐渐变为头部和翅膀上的棕色，尾巴上有两条灰色带纹和狭窄的白色尖端。腹部有黑色斑点，逐渐变成腹侧的条纹，大腿部分呈白色，稀疏地散布着黑色斑点。雌鸟比雄鸟平均大10%，标记更重，下方颜色更红（少奶油色），每只翅膀上少一条黑色条纹，通常头部较短，尾巴相对较长。虹膜绿色到黄色，喙暗灰色，腿和脚黄色。","call":"全年都有叫声，特别是在赤道地区的午后，雄鸟发出尖锐的“kewee-kewee-kewee...”，而雌鸟的声音更低沉、更柔和，为“kooee-kooee-kooee...”。在求偶展示中，这种叫声尤其明显，雄鸟在高空进行一系列陡峭的俯冲和攀升，雌鸟有时会加入。","habits":"非洲冠雕居住在密集的森林和低地森林中，从广阔的热带雨林到小片山地和河岸森林，甚至成熟的外来桉树种植园。在东非，它们倾向于在北方雾带森林植被类型中筑巢，研究发现82%的巢位于本土树木中。当觅食时，它们会进入周边的次生森林或干燥的灌木草原。记录显示它们从海平面到至少3300米的高度。","breeding":"非洲冠雕在西非从10月到12月产卵，在刚果民主共和国、加蓬和东非（高峰为6月至1月）全年产卵，在赞比亚和津巴布韦从8月到2月产卵，在南非从7月到3月（主要为9月至3月）。每对可能有自己的产卵周期。在繁殖季节，雄鸟会进行壮观的空中展示，伴随着响亮的叫声，雌鸟有时会加入。巢由大量树枝构成，直径约150至250厘米，深度50至300厘米，位于大型森林树的主叉处，有时暴露在树冠中。每对鹰可以在长达50年内使用同一个巢。","identification":"非洲冠雕与猛雕幼鸟相似，但非洲冠雕的下部羽毛更呈黄色调，有斑点的两侧和尾巴上更宽的条纹。雌鸟和雄鸟之间存在差异，雌鸟更大，标记更重，下方颜色更红，尾巴相对更长。","protection":"IUCN：NT（近危）","distribution":"从塞内加尔东部间断分布到肯尼亚南部，以及南苏丹东部和埃塞俄比亚中部，向南延伸至安哥拉西北部、刚果民主共和国、赞比亚、津巴布韦，以及东非和南非东部。","other":"非洲冠雕在一些地区被猎人视为害鸟，因为它们捕食小型家畜，但在某些地区，也被认为是有益的，因为它们捕食损害幼树的哺乳动物。"},{"name":"棕腹隼雕","english_name":"Rufous-bellied Eagle","scientific_name":"Lophotriorchis kienerii","appearance":"棕腹隼雕体型紧凑，体长46-61厘米，翼展105-140厘米，雄鸟体重约733克，雌鸟约800克。特征为黑色头罩与白色喉部形成鲜明对比，腹部亮棕红色，上体漆黑，短而蓬松的顶冠，腿被羽毛覆盖。幼鸟缺乏头罩，眼周有深色斑，下体全白。虹膜呈深棕色至红棕色，喙基及脚黄色。","call":"通常沉默，但在繁殖季节会发出重复的尖锐“keeee”声，展示飞行或伴侣间接触时，有时延长为吹笛般的“kee-kee-kee-kipkip-trree”。","habits":"栖息于低山和山脚地带的阔叶林和混交林中，常单独活动，善于空中飞翔，速度极快且灵活。以鸡类、翠鸟、鸠鸽类、鼠类等为食，通过埋伏捕猎，有时在地上奔跑追捕猎物。在林中空旷处观察和寻找猎物，发现后突然俯冲捕捉。","breeding":"繁殖期从12月中旬至翌年3月中旬，营巢于密林高大乔木顶部，巢由枯枝构成，内垫绿叶。每对通常有2个巢，每窝产1枚卵，卵产在绿叶上。亲鸟轮流孵卵，领域性强。","identification":"与同属物种相比，棕腹隼雕的黑色头罩和亮棕红色腹部是显著区别，幼鸟的全白下体也易于识别。","protection":"IUCN：NT（近危）, CITES II（华盛顿公约二级）","distribution":"分布于亚洲南部、东南亚及印尼苏拉威西岛，印度尼西亚、菲律宾、苏门答腊等地常见，中国仅在南亚热带森林有记录。","other":"历史上曾被分类在不同属内，现认为属于独特属Lophotriorchis。"},{"name":"猛雕","english_name":"Martial Eagle","scientific_name":"Polemaetus bellicosus","overview":"猛雕（英文名：Martial Eagle，学名：Polemaetus bellicosus），是鹰形目鹰科猛雕属的鸟类。是非洲最大的鹰之一，本属唯一物种。分布广泛，主要见于非洲南部，拥有庞大的体型和显著的外部特征。","appearance":"成年猛雕体长78至96厘米，翼展188至227厘米，体重3.03至6.2千克。头部、背部和上胸部呈深褐色，腹部白色带深色斑点。飞行时，下翅为棕色。幼鸟外观与成鸟明显不同，具有灰白色上部，下部纯白，尾部和翼上有更淡的条纹。雄鸟和雌鸟的外观相似，但雌鸟通常更大。","call":"繁殖季节发出低沉而柔和的哀怨哨声“koweeoh”，在空中展示时则发出一系列较长的哨声“klee-klee-klee-klee”。幼鸟向父母呼唤时会发出类似的一系列哨声。","habits":"栖息于稀疏林地边缘、草原、灌木丛、沙漠和半荒漠地带，偏好开阔环境，避免人类密集居住区。以脊椎动物为食，能从六公里外发现猎物，主要猎食大鸟、蜥蜴和小型哺乳动物。狩猎时从高处俯冲袭击。","breeding":"繁殖季节高度可变，筑大型巢于树叉或电线杆上，距地面5至70米。单产一枚卵，偶尔两枚，孵化期47至53天，幼鸟孵化96至104天后离巢，可能依赖父母8至12个月。每年或每两年繁殖一次。","identification":"与非洲冠雕相似，但猛雕有更白的下部、无斑点的侧腹和较窄的尾纹。幼鸟与非洲冠雕幼鸟相似，但前者尾巴较短，翅膀较长，下部纯白。","protection":"IUCN：EN（濒危）","distribution":"广泛分布于撒哈拉以南非洲，从塞内加尔东部至埃塞俄比亚和索马里，南至南非。常见于东非和南非，但在西非较为罕见。","other":"因猎食家畜和当地珍贵猎物，遭到人类大量捕杀，导致数量急剧下降。"},{"name":"长冠鹰雕","english_name":"Long-crested Eagle","scientific_name":"Lophaetus occipitalis","overview":"长冠鹰雕（英文名：Long-crested Eagle，学名：Lophaetus occipitalis），是鹰形目鹰科长冠鹰雕属的鸟类。非洲的猛禽，以其独特的耸立羽毛冠而著称。属于单型属 Lophaetus。分布于中部至南部非洲，主要栖息于森林边缘和湿润地区，以小型哺乳动物为主要食物。","appearance":"长冠鹰雕是一种体型较大、体态粗壮的鹰，全身黑色，最显著的特点是其高耸的、松散的羽冠。成年个体的体色呈黑褐色，头部后方有长长的细羽毛形成羽冠，二级飞羽有黑色横纹并带有浅灰色条纹，翼下的初级飞羽和中翼覆羽为白色，形成飞行时可见的白色斑块。尾巴黑色，带有淡灰色条纹。眼睛颜色随性别不同，雄鸟为亮黄色，雌鸟可能较暗，蜡膜和脚为黄色。雄鸟体重在912-1300克之间，雌鸟稍大，体重介于1300-1500克，体长53-58厘米，翼展可达112-129厘米。雌鸟的羽冠略短，跗跖部分呈现混杂的棕白相间。","call":"长冠鹰雕在繁殖季节尤其活跃，发出响亮、尖锐、拖长音的‘keeeyah’叫声，音调在结尾处下降。在栖息时也会发出一系列急促的‘kik-kik-kik...’声。","habits":"长冠鹰雕偏好开放的树林、森林边缘和靠近沼泽及长草区的林地。它们会利用异域的松树和桉树种植园以及小规模农田。活动高度从海平面到2000米，偶尔可达3000米。它们倾向于在固定位置长时间停留，偶尔才翱翔天际。在雨季良好的地区，它们会追踪鼠类数量的增加，出现在临时湿润地带，甚至在那里繁殖。","breeding":"繁殖通常发生在雨季，但时间并不固定，一年内可能多次成功繁殖。筑巢期在西非为1月至6月，在苏丹为3月至7月，在埃塞俄比亚为6月至11月，在东非几乎全年均可繁殖，在南非和中部非洲为4月至次年1月。巢由树枝构成，直径50-80厘米，深15-30厘米，位于森林边缘高树的上部枝杈。每窝产1-2枚卵，孵化期约42天。雏鸟的第一层绒羽为浅灰色，第二层绒羽背部灰色，腹部白色。离巢时间为53-58天，一对父母有时能成功抚养两只雏鸟，甚至在同一年内抚养第二窝。","identification":"长冠鹰雕与维瑞奥克斯鹰相比，体型更为紧凑，尾部较短，翅膀更宽且末端呈方形。所有年龄阶段都有明显的羽冠。雌鸟平均比雄鸟大7%，重27%，羽冠略短，跗跖部分有混杂的棕白相间的色彩。","protection":"IUCN：LC（无危）。列入CITES附录II。在东非较为常见，但在适宜的湿润生境出现的地方和时间，分布往往具有局部性。全球种群估计数以万计，但具体数字不明；南非特兰斯瓦尔地区估计有200对。尽管显眼，但因主要以鼠类为食而不受人类迫害。面临的主要威胁是森林和湿地的大规模破坏，但通过利用异域种植园、小型农业空地和其他次生林地，一定程度上缓解了这一问题。随着森林的部分清理，更多适合该物种的生境被开辟，数量可能正在增加。","distribution":"长冠鹰雕广泛分布于非洲，从西部的塞内加尔和冈比亚向东延伸至埃塞俄比亚，南至纳米比亚东北部、博茨瓦纳北部、津巴布韦、莫桑比克，以及南非的东部和南部地区。","other":"虽然目前长冠鹰雕被归入单型属Lophaetus，但近期研究表明它与斑鹰科形成了一个分支，包括乌雕、印度乌雕和小乌雕。若分类调整，这些物种将被归入Lophaetus属。"},{"name":"林雕","english_name":"Black Eagle","scientific_name":"Ictinaetus malaiensis","overview":"林雕（英文名：Black Eagle，学名：Ictinaetus malaiensis），是鹰形目鹰科林雕属的鸟类。中型猛禽，通体黑褐色，具独特的黄色喙基和脚，翼长且呈狭长的V字形，尾长且扇状。广泛分布于热带与亚热带亚洲的山地森林和丘陵，从南亚至东南亚，包括中国东南部。以捕食鼠类、蛇、蜥蜴、蛙、雉类和小型鸟类为主。","appearance":"林雕是一种大型但体形修长的鹰，体长约75厘米，翼展可达148至182厘米。体重介于1000至1600克之间，略小于同域的山鹰。全身羽毛深褐色至黑色，头部、翅膀和尾巴颜色更深，尾羽上有隐约的灰褐色横斑。眼睛和喙基为深褐色，喙和脚呈鲜亮的黄色。翼尖呈手指状，尾长且展开时呈扇形，收起时楔形。幼鸟头部、下体和翼下覆羽为淡褐色，具斑点。","call":"在繁殖季节期间会发出重复的、略带沙哑的尖锐哨声“kheeee kheeee kheeee”，在空中展示飞行时发出。此外，也会从栖木或飞行中发出连续的哀怨叫声“keee-keeeuw”或“hee-lee-leeuw”。","habits":"林雕栖息于海拔1000至2500米的山地森林中，偏好具有良好森林覆盖的地区。它们在炎热的下午侵袭其他鸟类的巢穴，以鼠类、蛇类、雉鸡、蛙、蜥蜴、小鸟和鸟卵以及大的昆虫为主要食物。飞行时翅膀缓慢扇动，显得从容不迫，同时也能在浓密的森林中高速飞行和追捕猎物。","breeding":"繁殖期从11月至翌年3月，营巢于山地浓密的常绿阔叶林或落叶阔叶林中高大乔木的上部，巢宽约3至4英尺。每窝产卵1至2枚，卵色为白色或灰白色，具少许粉红色或红褐色斑点。雌鸟负责孵卵，对巢的保护非常强烈。","identification":"林雕通过其独特的翼形和尾形、深色羽毛与黄色喙和脚的对比，以及缓慢优雅的飞行方式，很容易与其他大型猛禽区分。幼鸟与成鸟在颜色上有明显差异，幼鸟具淡褐色头部、下体和翼下覆羽。","protection":"IUCN：LC（无危）","distribution":"林雕广泛分布于热带和亚热带亚洲，包括印度、尼泊尔、斯里兰卡、缅甸、中国东南部（云南、福建）、台湾、东南亚等地。在中国，分布于陕西南部、安徽南部和海南岛。","other":"林雕在中国属于国家二级保护动物。"},{"name":"小乌雕","english_name":"Lesser Spotted Eagle","scientific_name":"Clanga pomarina","overview":"小乌雕（英文名：Lesser Spotted Eagle，学名：Clanga pomarina），是鹰形目鹰科乌雕属的鸟类。中型猛禽，广泛分布于欧亚大陆东部，尤其在欧洲东部至土耳其和亚美尼亚一带繁殖，冬季迁徙至非洲南部。该物种以其独特的两色对比外观著称，头部和喙较小，成鸟展示出暗色飞羽与较浅体色的鲜明对比。","appearance":"小乌雕长约60厘米，翼展可达150厘米，头部和翼覆羽呈淡褐色，与深色羽毛形成对比。成年鸟的上翅有白色斑块，臀部有明显的白色“V”字标记，这一特征在同类物种中更为模糊。幼鸟的翅膀对比度较低，飞羽上有显眼的白色斑点，颈部有一块奶油色斑片，与成年鸟明显不同。","call":"小乌雕通常沉默，但在繁殖季节会发出重复的吠叫式‘kyeep kyeep kyeep’或‘kyek kyek kyek’叫声。雄鸟在展示时会发出响亮、拉长的哨声‘weeek’，雌鸟在求偶或乞食时发出尖锐的长音‘pseeek’。","habits":"小乌雕栖息于开阔或轻度林木覆盖的地带，偏好森林边缘、河流沿岸的森林和靠近草地与农田的湿润树林。它主要以小型哺乳动物、鸟类、两栖类、爬行类和昆虫为食，善于在开阔地带狩猎，利用三种狩猎技巧：高空盘旋俯冲、从树梢静候出击和地面行走捕食。","breeding":"小乌雕在中欧地区的繁殖季节为4月底至5月初，幼鸟在7月底至8月初离巢。巢建于树上，高度从4米到30米不等，主要由大型树枝构成，内部铺有绿色枝条和草。每次产卵2枚，偶尔1枚或3枚，孵化期约为39天。雏鸟覆盖灰色绒毛，约8周龄时离巢，由于同窝相残现象，一般仅一只幼鸟存活至离巢，但在食物丰富的环境下，如爱沙尼亚的田鼠高峰期，可有两只幼鸟同时成长。","identification":"小乌雕与乌雕的区别在于体型更小、颜色更浅，成年鸟的上翅有明显双白色逗号标记，而乌雕仅有一个。幼鸟与乌雕幼鸟相比，翼覆羽无斑点，颈部有奶油色斑片。","protection":"IUCN：LC（无危）, CITES II（濒危野生动植物种国际贸易公约附录二）。全球数量在1980年代中期估计约10万只，但到2004年已降至14,000至19,000对繁殖对（42,000至57,000只个体）。面临的主要威胁包括栖息地改变和猎杀，特别是在叙利亚和黎巴嫩的迁徙期间。","distribution":"繁殖区主要在中欧和东欧，向东南延伸至土耳其和亚美尼亚，非繁殖区集中在非洲南部，从苏丹南部至安哥拉东部、纳米比亚东北部、博茨瓦纳北部和南非东北部。","other":"小乌雕与乌雕在波兰存在频繁的杂交现象，杂交率自1996年至2012年间增长了超过30%。"},{"name":"印度乌雕","english_name":"Indian Spotted Eagle","scientific_name":"Clanga hastata","overview":"印度乌雕（英文名：Indian Spotted Eagle，学名：Clanga hastata），是鹰形目鹰科乌雕属的鸟类。属于鹰科的乌雕属，原生于南亚地区。体型略大于鸢，具典型大型鹰的结构特征，翼尖六指散开，臀部呈淡色。成年个体通体富丽的棕色，嘴裂线长而明显，延伸至眼后。虹膜深褐色，鼻孔圆形。亚成鸟颜色较浅，胸腹部有浅色斑点。飞行时，从下方观察，翅膀和尾巴在乳白色羽毛上细密地横着棕色条纹。与其它大型鹰不同，其腿部长而轻羽，不像其它鹰那样有蓬松的“裤子”。在草地、灌木丛、轻林和湿地之上翱翔，与乌雕不同，可在远离湿地的地方发现。","appearance":"印度乌雕体长约50-60厘米，翼展约150厘米，头部宽大，嘴裂显著，比其他斑鹰种类更宽。整体颜色较淡，虹膜深色，使得眼睛显得比羽毛更深。成鸟与乌雕的区别在于颜色更浅、虹膜更暗以及栖息环境的偏好。幼鸟经过约3-4个月，变为光泽的棕色，头颈羽毛尖端呈奶油色，形成斑点外观。尾上覆羽呈浅棕色带白色条纹，中覆羽有大的奶油色斑点。18个月后换羽，颜色变深，斑点减少。一些老幼鸟几乎不具斑点，缺乏幼小乌雕颈部的奶油色斑块。","call":"叫声被描述为高音的咯咯笑声，以及一系列尖锐、断续的‘kleep kleep kleep’叫声。","habits":"印度乌雕主要栖息于低地的开阔森林和森林边缘，草地上围绕的树丛，农田区和有树木的都市公园，常靠近水源。成鸟通常是留鸟或极短距离的迁徙者，与高度迁徙的乌雕形成对比。幼鸟可能在印度境内有一定的迁徙性。以哺乳动物、鸟类、爬行动物和两栖动物为食。","breeding":"繁殖期从3月末到8月，在印度。巢由树枝构成，内部铺有绿叶，通常位于树的上三分之一处的分叉中。巢大小约为40-60厘米宽×30-40厘米深。每次产卵几乎总是1枚，偶尔2或3枚，孵化期38-42天，雌鸟承担大部分孵卵任务，雄鸟短暂覆盖卵并提供所有食物给雏鸟。雏鸟期报道为7周至10周。","identification":"与小乌雕相比，印度乌雕翼稍长，跗跖较长，头部和背部颜色更深，虹膜呈棕色而非黄色，尾下覆羽颜色较浅，喙裂更大。幼鸟颜色较成鸟浅，与小乌雕的幼鸟相似，但总体颜色更浅，上翼覆羽斑点较少，颈部无赤褐色斑块。","protection":"IUCN：VU（易危）。CITES II（华盛顿公约附录二）。在整个分布范围内密度低，因栖息地丧失和退化而疑似数量下降。可能已从孟加拉国消失，印度、巴基斯坦和缅甸的数量大幅减少。","distribution":"分布于印度（主要是北部，也有中部，可能南部分散），孟加拉国（可能已经灭绝），西南部和南部缅甸，巴基斯坦；最近在柬埔寨确认繁殖。","other":"与C. clangula在冬季重叠分布，由于外观相似，使评估现状变得困难。"},{"name":"乌雕","english_name":"Greater Spotted Eagle","scientific_name":"Clanga clanga","overview":"乌雕（英文名：Greater Spotted Eagle，学名：Clanga clanga），是鹰形目鹰科乌雕属的鸟类。别名: 花雕、小花皂雕、大斑雕，中大型猛禽，体型略小于草原雕。分布广泛，从东欧至亚洲东部，冬季迁徙至南亚、东南亚等地。在中国东北、华北、华东、中南及新疆有分布，是中国国家一级保护动物。","appearance":"乌雕为大型雕类，成鸟呈深褐色，翼宽，尾短，翼下有逗号形白班。幼鸟羽毛斑驳，背部及翼上有明显污白色斑点。雌雄外观相似，但雌鸟通常比雄鸟大20%，重50%。喙黑色，蜡膜和脚黄色，虹膜深褐色。","call":"叫声为尖锐的\"kyack\"、\"tyuck\"或\"dyip\"，可重复两到三次，类似于小型犬吠声。","habits":"栖息于湿森林边缘，常接近湿地、沼泽、湖泊等水域。在冬季和迁徙期间，会出现在人类改造的环境，如稻田和垃圾堆。以小型哺乳动物、鸟类、两栖类、爬行类和偶尔的小鱼、昆虫为食，具有较强的适应性。","breeding":"繁殖季节从4月至8月，一窝产卵1-3枚，灰色有时带稀疏的棕色和灰色斑点，平均大小67.5毫米×54毫米。孵化期41-44天，仅雌鸟孵化。幼鸟出生时为纯白色或灰褐色绒毛，第二次换羽为淡灰色，头部颜色更深。由于兄妹相残现象，第二只幼鸟很少存活。父母照顾幼鸟，主要由雌鸟负责，雄鸟提供食物。幼鸟约60-67天离巢，体重约1900克。","identification":"与小乌雕相似，但体型更大，颜色更暗，翼下有更大的白色斑点，翼下覆羽和翅膀上的白色斑点更多。在飞行中，乌雕的翅膀显得更宽，尾巴更短。","protection":"IUCN：VU（易危）","distribution":"繁殖于东欧至亚洲东部，冬季迁徙至南亚、东南亚、中东、地中海盆地和东非部分地区。在中国分布于东北、华北、华东、中南及新疆。","other":"面临的主要威胁包括栖息地丧失、农业强化、人类干扰、中毒和电线碰撞。"},{"name":"细嘴雕","english_name":"Wahlberg's Eagle","scientific_name":"Hieraaetus wahlbergi","overview":"细嘴雕（英文名：Wahlberg's Eagle，学名：Hieraaetus wahlbergi），是鹰形目鹰科隼雕属的小型棕色鹰，以其较弱的喙和较为纤细的身体著称。这种鹰主要分布在非洲南部至东部地区，是季节性迁徙的物种，常见于林地和草原地带。","appearance":"细嘴雕体长53-61厘米，翼展可达130-146厘米，体重介于437-1400克之间，雌鸟平均比雄鸟大5%左右。其头部有轻微的冠羽，眼睛呈深棕色，腿和蜡膜为黄色。羽毛颜色多变，以深巧克力棕色最为常见，但也存在较浅色和中间色型个体。幼鸟与成鸟相似，但翅膀覆羽边缘更宽泛，头部和颈部黑色条纹更为密集。","call":"细嘴雕在繁殖季节会发出响亮的'kleeee-ee'声，无论是站立还是飞行中都能听到，叫声类似但比非洲隼雕更为哀婉。此外，还会发出类似鸥的叫声和快速重复的'kyip-kyip-kyip'声，尤其是在巢边的问候仪式中。","habits":"细嘴雕栖息于林地、灌木草原和农田地带，避免沙漠和密林，但在附近有森林的开垦区和荆棘丛中可见。它们猎食范围广泛的脊椎动物和昆虫，从树上或飞行中捕猎。在非洲南部繁殖（8月至3月），并在更北的区域全年可见。","breeding":"繁殖期主要在雨季，于高大的树木分叉处筑巢，巢由干枝构成并铺以绿叶，直径38-80厘米，深度25-60厘米。一窝通常产一枚蛋，孵化期约43-46天，主要由雌鸟负责。雏鸟孵化后70-77天离巢，但有时可达62-80天。在高密度区域，繁殖成功率较低。","identification":"细嘴雕通过其较小的头冠、深棕色的眼睛和相对较小的体型与其他鹰类相区别。与其他同属物种相比，它拥有较长的尾巴和翅膀，后者几乎达到尾尖长度。","protection":"IUCN：LC（无危）","distribution":"分布于西非从毛里塔尼亚南部和塞内加尔至苏丹、埃塞俄比亚，东至南非北部和东部，向西至安哥拉和纳米比亚北部与中部。在非洲南部至东部繁殖，而北部区域主要为非繁殖地。","other":"细嘴雕是非洲南部和中部最普遍的鹰类之一，总体数量估计约为10万只。它对森林砍伐较为敏感，但目前尚未受到杀虫剂影响的报告。"},{"name":"靴隼雕","english_name":"Booted Eagle","scientific_name":"Hieraaetus pennatus","overview":"靴隼雕（英文名：Booted Eagle，学名：Hieraaetus pennatus），是鹰形目鹰科隼雕属的鸟类。中型鹰类，主要分布于欧亚大陆，从西南欧和北非至亚洲中部和印度北部，以及南非。其显著特征为长而突出的初级飞羽、方形长尾和停息时露出的‘靴状’腿羽。在中国，主要见于新疆、东北、河北等地的森林或林地环境。","appearance":"靴隼雕体长42-51厘米，体重雄鸟510-770克，雌鸟840-1250克，翼展113-138厘米。有两种颜色形态：浅色形态具有对比强烈的双色调，深色形态类似黑鸢和鹞类。正面观察时，肩部有明显的白色‘着陆灯’。成年个体虹膜呈暗黄棕色、橙棕色或红棕色，蜡膜和脚黄色。幼鸟多形性，与成鸟相似，尤其是深色形态，浅色形态下部有更多条纹和红棕色调。","call":"靴隼雕通常沉默，但在繁殖季节变得高度鸣叫。主要叫声为尖锐、快速上升的三音哨声‘kli-kli-klee’，有时延长为较低音的第四音或一系列长笛般的哨声，整体音质似滨鹬。","habits":"靴隼雕栖息于森林与开阔地带混合的环境，常见于丘陵地区，飞行时翅膀偶尔扇动。主要以小型哺乳动物、鸟类和爬行动物为食，如蜥蜴、兔子、昆虫等。狩猎时主要从空中俯冲捕捉地面的猎物。","breeding":"繁殖期在4月至5月，筑巢于树上或岩石缝隙中，巢由树枝和嫩叶构成，通常重用旧巢。每窝产2枚蛋，平均孵化期为37-40天，由雌鸟孵卵，雄鸟提供食物。雏鸟在50-54天后离巢，之后可能与成鸟共同生活47天以上。","identification":"靴隼雕与黑鸢和鹞类在深色形态下容易混淆，但肩部的白色‘着陆灯’和特定的叫声是重要的辨识特征。","protection":"IUCN：LC（无危）","distribution":"繁殖区包括欧洲西南部、北非、亚洲中部至印度北部以及南非部分地区。非繁殖期广泛分布在非洲撒哈拉以南地区和南亚。","other":"靴隼雕在中国属于国家二级保护动物。"},{"name":"小隼雕","english_name":"Little Eagle","scientific_name":"Hieraaetus morphnoides","overview":"小隼雕（英文名：Little Eagle，学名：Hieraaetus morphnoides），是鹰形目鹰科隼雕属的鸟类。体型较小的鹰科隼雕属鸟类，仅分布于澳大利亚（除塔斯马尼亚州），具有明显的轻型和暗色形态。其头部和颈部带有黑色条纹，下体呈沙色至淡色，而暗色形态则通常为深棕色或丰富的赤褐色。雄鸟体重在440-810克之间，雌鸟则重达745-1250克，翼展可达101-136厘米。","appearance":"小隼雕体长38-55厘米，体型健壮，拥有完全覆盖羽毛的腿和方形带横纹的尾巴。翅膀展开时，雄鸟比例上翼更长，但体重仅为雌鸟的一半左右。颜色形态多样，随年龄变化，常见的是轻色形态，背部和翅膀呈深棕色，头部和颈部有黑色条纹，下体沙色到淡色。暗色形态相似，但头部和下体通常是更深的棕色或赤褐色。雄鸟和雌鸟外观相似，但雌鸟较大，通常颜色更深。幼鸟类似成年鸟，但色彩更强烈地偏向赤褐色，图案对比度较低。","call":"在繁殖季节时较为活跃，发出一系列快速的两到三个哨音‘pee-pee-peh’，有时会延长成一连串的音符，用于空中展示、交配和巢穴附近伴侣间的联系。","habits":"栖息于多种开阔和森林环境，如稀疏林木的丘陵、灌木丛、靠近水源的林地、草原；海拔从海平面到1500米。偏好崎岖的山地，避开完全无树的区域和密集森林。以狩猎为主，偶尔吃腐肉，食物包括小型哺乳动物、鸟类、爬行动物、大型昆虫、鱼类。在不同地区偏好不同的猎物，如南方偏爱兔仔，北方则以鸟类为主，干旱地带则以爬行动物为主。","breeding":"繁殖季节因纬度而异：热带北部地区较长，占据旱季，从3月至12月；南部较短，通常8月至10月，但有时5月开始，或延续至12月。筑巢于活树叉中，平台由树枝构成，宽约60-75厘米，深约30厘米，铺以绿叶。每窝产卵2枚（1-3枚），孵化期约为36-40天，幼鸟白色绒毛，离巢期约54-66天，离巢后依赖父母约2个月。","identification":"与啸鸢相比，小隼雕尾部较短，翅膀前缘较暗。可以通过头部后方形成的黑色小冠羽来识别。成鸟虹膜红褐色至橙褐色，蜡膜淡灰色至蓝白色，脚部蓝白色至浅灰色。幼鸟与成鸟相似，但下体条纹较少，色彩更偏赤褐色，虹膜棕色，蜡膜和脚部奶油色。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚（除塔斯马尼亚州），包括稀疏林木的丘陵、灌木丛、靠近水源的林地、草原等生境，海拔从海平面到1500米。","other":"近年来在澳大利亚首都地区数量显著下降，部分原因是栖息地丧失（郊区发展）和被楔尾雕驱赶。"},{"name":"侏隼雕","english_name":"Pygmy Eagle","scientific_name":"Hieraaetus weiskei","overview":"侏隼雕（英文名：Pygmy Eagle，学名：Hieraaetus weiskei），是鹰形目鹰科隼雕属的鸟类。主要分布在新几内亚和摩鹿加群岛的低地及山地森林。其体型紧凑，胸部条纹明显，翼展宽而细长，尾羽扇形展开，翼尖黑色。飞翔时姿态独特，常在树冠上空低飞翱翔。与数量众多的雀鹰和苍鹰在外形上有显著区别，尾部更短、更宽。","appearance":"侏隼雕体型小至中等，长度介于38至48厘米之间，翼展可达112至126厘米。雄鸟体重约为483克。其外观与近亲小隼雕相似，但体型更小，喙、尾和趾较短。浅色型个体具有白色下翼覆羽和白色下体，胸部有宽阔的深色条纹；深色型个体下翼覆羽呈棕色，下体红褐色；两种形态的颊部、头部和颈背均有棕色条纹，尾部有7至8条黑色横纹。幼鸟与成鸟相似，但尾部外侧有较窄的淡色带，初级飞羽更加尖锐。","call":"飞行中发出简单的高音‘piwit！’叫声。","habits":"栖息于原始雨林、河岸森林、季风林及林缘地带，飞行高度通常低于树冠层。活动范围广泛，从海平面到海拔1950米的区域都有分布，已知最高峰记录为2420米。据报告，会攻击群居的灰乌鸦。","breeding":"关于繁殖行为的信息较少，但有报道指出，其求偶飞行中会发出类似‘sip sip see’的哨声。","identification":"与小隼雕相比，侏隼雕体型更小，尾部和脚趾较短，下体条纹更明显。与一些鸢类在体型上相似，但翼下图案不同。","protection":"IUCN：LC（无危）；在新几内亚广泛分布但总体数量不多。随着栖息地内的森林砍伐，种群可能正在减少。","distribution":"繁殖区域主要位于新几内亚和摩鹿加群岛（包括哈马黑拉岛、特尔纳特岛、布卢岛、塞拉姆岛）。","other":"直到最近才被确认为独立物种，此前被认为是小隼雕的亚种。"},{"name":"艾氏隼雕","english_name":"Ayres's Hawk-Eagle","scientific_name":"Hieraaetus ayresii","overview":"艾氏隼雕（英文名：Ayres's Hawk-Eagle，学名：Hieraaetus ayresii），是鹰形目鹰科隼雕属的鸟类。中型鹰科鸟类，以非洲木林地带为栖息地。其名称源于南非鸟类学家Thomas Ayres。体型虽小，却展现出鹰的强健体魄，拥有独特的黑白相间羽毛，主要在撒哈拉沙漠以南的非洲各地分布。","appearance":"艾氏隼雕是一种中等大小的猛禽，体长44至57厘米，翼展106至137厘米。雄鸟体重介于615至714克，而雌鸟更重，达879至1150克。其头部略显圆润，具轻微的冠羽，上体黑色带有白色斑点，下体白色并有深色斑块或条纹。飞行时，可以看到其翅膀下方有明显的黑色横纹。雄鸟和雌鸟在外形上有细微差异，雌鸟通常更大，颜色更深，腹部斑点更密。存在全黑或几乎全黑的变异个体，胸部有白色斑点。","call":"艾氏隼雕在繁殖季节会发出重复的高音哨声“hueeep”，有时延长为“hip-hip-hip-hueeep”。当巢附近受到干扰时，也会发出类似猎鹰的“kack kack kack”叫声。","habits":"栖息于密集的落叶林木地带，包括画廊森林、森林边缘、树丛和异国树种植园，甚至城市郊区。活动范围广泛，从海平面到3000米海拔。雨季时，从中央非洲的浓密森林迁移到南部更开阔的树丛草原，可能进入东非沿海地区。在南非城镇中，以鸽子和野鸽为食。","breeding":"繁殖期在不同地区有所差异，筑大型枝巢，直径可达60至129厘米，通常位于大树分叉处，离地面9至32米。每年产一枚蛋，平均尺寸为61.2×49.8毫米，孵化期约为43至45天。雏鸟孵化后约73至75天离巢。","identification":"与非洲靴隼雕相比，艾氏隼雕体型较小，外观更为紧凑，头部突出较少，尾巴较长，下体斑点更密。飞行时，翅膀上的白色‘窗户’与靴鹰相似，但总体标记有所不同。","protection":"IUCN：LC（无危）","distribution":"分布于撒哈拉沙漠以南的非洲，从几内亚和塞拉利昂向东至刚果，然后从刚果民主共和国和安哥拉东北部至埃塞俄比亚和索马里，再向东南延伸至赞比亚、博茨瓦纳、津巴布韦和南非东北部。非繁殖季节可能广泛游荡。","other":"艾氏隼雕在全球范围内数量不多，估计总数在1000至10,000只之间，但由于分布范围广泛，目前数量稳定，故被列为低危物种。面临的主要威胁是林地砍伐，部分地区因捕杀家鸽而遭到迫害。"},{"name":"茶色雕","english_name":"Tawny Eagle","scientific_name":"Aquila rapax","overview":"茶色雕（英文名：Tawny Eagle，学名：Aquila rapax），是鹰形目鹰科雕属的鸟类。又名非洲草原雕或非洲茶色雕，中大型、高度多变的雕，羽毛颜色从奶油色到灰棕色不等，偶尔呈深棕色。其分布广泛，主要栖息于非洲热带稀树草原和半沙漠地带，以及印度次大陆。","appearance":"茶色雕的喙和头部强壮而突出，身体比例匀称，脚爪有力。站立时，翅膀尖端大致与尾尖齐平。成年个体羽毛颜色多样，从暗灰色到红棕色，再到淡黄色，雌鸟通常比雄鸟稍大且更暗，幼鸟色泽较为单一，常随年龄增长而变化。眼色从黄色到淡棕色不等，脚和蜡膜始终为黄色。","call":"发出较空洞的吠声“kau-kau”，雄鸟在求偶时会发出更高音调的“ki-ark”，同时伴有粗糙的“kekeke...”声，雌鸟在巢中会发出喵喵的“shreep-shreep”。尽管并不特别爱鸣叫，但在非洲的鸣叫声被认为比在欧洲过冬的个体更为频繁。","habits":"茶色雕主要栖息于树木繁茂的开阔平原、草地、荒漠和低山丘陵地带的荒原草地，从海平面至海拔3,000米的高度均有踪影，但避开沙漠和茂密的林地。食物主要包括哺乳动物、鸟类、爬行类、昆虫类、两栖类、鱼类和腐肉。它们会守候在旱獭和鼠类的洞口等待猎物出现，有时也会在空中飞翔寻找猎物。","breeding":"实行一夫一妻制，繁殖季节因地区而异。营巢于悬崖、山顶岩石堆或高大的孤立树上，巢由枯枝构成，内部垫有枯草、草叶、羊毛和羽毛。每窝产卵1至2枚，卵为白色，可能有黄褐色斑点。孵化期约39至45天，主要由雌鸟承担。雏鸟晚成性，由双亲共同喂养76至85天后离巢。","identification":"与草原雕相比，茶色雕体型较小，喙线较短，尾部略圆至几乎方形，且尾羽更短，类似秃鹫。颜色变化较大，雌鸟比雄鸟稍大且更暗。","protection":"IUCN：VU（易危）","distribution":"非洲广泛分布，印度次大陆也有分布。具体而言，北非、西非、东非、南非、印度等地均有其踪迹。","other":"适应性强，能在各种环境中成功繁殖，从平均巢间距3.5至59公里，密度1对/64至300平方公里不等。"},{"name":"草原雕","english_name":"Steppe Eagle","scientific_name":"Aquila nipalensis","overview":"草原雕（英文名：Steppe Eagle，学名：Aquila nipalensis），是鹰形目鹰科雕属的鸟类。俗名: 草原鹰、大花雕、角鹰，藏名扎唐无巴，大型猛禽。其特征为深褐色的羽毛，宽阔的翅膀，以及翼尖七个明显的‘手指’。成鸟全身深褐色，幼鸟和亚成鸟在休息时翅膀上有明显的黑色边缘白色宽带。分布于开阔的草原、沙漠、灌木丛、湿地和山区。迁徙时，会在中东、红海和喜马拉雅山脉的大规模迁徙路线上集中出现。","appearance":"大型雕类，羽色呈饱满的褐色，两翼宽阔，翼尖具七枚张开的翼指。成鸟整体深褐色，亚成鸟停栖时，翅膀上明显可见外缘黑色的白色宽带。在飞行中，该特征转化为翼下位于初级与次级飞羽间的白色条纹。幼鸟耗时四年达到成年羽色。雄鸟体重2000-3500克，雌鸟体重2300-4900克，翼展165-214厘米。","call":"发出重复、粗哑、响亮的吠叫声“kwowk”或“kow”。也有尖锐的啸声。在飞行中，这些叫声会结合成一系列低沉的吠叫，每个都由尖锐的啸声引发。","habits":"栖息于开阔的草原，常停息在地面或高崖及枯树。飞翔时较低，遇见猎物会猛扑下去捕捉，有时守候在鼠洞口。以啮齿动物为主食，如各种鼠类、兔类、貂类等。在沙漠地带以大沙地鼠为主食。也捕食雷鸟和雉类等鸟类。","breeding":"繁殖期4-6月，筑巢于悬崖、山顶岩石堆、地面、土堆、干草堆或小山坡上。巢主要由枯枝构成，内部铺有枯草茎、草叶、羊毛和羽毛。每窝产卵2-3枚，灰白色，有红褐色斑点。孵化期约45天，育雏期55-60天，幼鸟于8月底离巢。","identification":"与乌雕的主要区别在于体型更大，翅膀更宽，颜色更深，以及翼尖的特征性白色条纹。草原雕的叫声和行为模式也与乌雕有所不同。","protection":"IUCN：EN（濒危）, CITES: II, 中国国家重点保护野生动物名录: I级（2021.02.05）","distribution":"繁殖区主要在欧亚大陆中部，包括俄罗斯、哈萨克斯坦、蒙古国和中国。非繁殖区遍布东洋界、阿拉伯半岛和非洲。","other":"草原雕是迁徙性鸟类，冬季会迁移到东洋界、阿拉伯半岛和非洲等地。在迁徙途中，它们可能会在中东、红海和喜马拉雅山脉的大规模迁徙路线上聚集。"},{"name":"西班牙雕","english_name":"Spanish Imperial Eagle","scientific_name":"Aquila adalberti","overview":"西班牙雕（英文名：Spanish Imperial Eagle，学名：Aquila adalberti），是鹰形目鹰科雕属的鸟类。属于鹰科雕属的大型猛禽，以独特的‘肩章’而被旧文献称为白肩雕。分布于伊比利亚半岛，为该地区的特有种，数量稀少，一度濒临灭绝。","appearance":"西班牙雕体长72至85厘米，翼展可达177至220厘米，体重在2.5至4.8千克之间。雌鸟体型略大，平均重3.43千克，雄鸟平均3.19千克。成鸟通体呈深黑色，翼肩处有显著的白色带状斑纹，头部后方有淡黄褐色的羽毛。幼鸟羽毛呈均匀的浅沙色，翼上下有明显的黑色条带。","call":"发出深沉的‘owk owk’声，快速重复多达8至10次，声音比金雕更深沉，主要用于空中展示和雄鸟的叫声。","habits":"偏好干燥成熟的林地，尤其是兔类密集的区域。主要栖息于伊比利亚半岛的西班牙和葡萄牙，偶尔在北非发现。为留鸟，不迁徙。以穴兔为主要食物，也会捕食其他小型哺乳动物、鸟类、爬行动物。","breeding":"繁殖季节为2月至4月，通常在高大的树冠上筑巢，如栓皮栎和松树，巢宽约1.5米。每窝产卵2至3枚，孵化期约为43天，雌鸟主要负责孵卵。幼鸟出生后约63至77天离巢，但在巢附近逗留长达160天。","identification":"与白肩雕相似，但整体颜色更深，成鸟翼肩处的白色带状斑纹更明显，幼鸟羽毛颜色更单一。","protection":"IUCN：VU（易危）","distribution":"主要分布于西班牙中部和西南部，以及葡萄牙部分地区，历史上曾在摩洛哥繁殖，现仅见于摩洛哥的冬季访问。","other":"由于栖地丧失、非法投毒和主要食物穴兔数量的减少，数量曾大幅下降。自1980年代起，通过保护措施，种群数量逐渐恢复。"},{"name":"白肩雕","english_name":"Eastern Imperial Eagle","scientific_name":"Aquila heliaca","overview":"白肩雕（英文名：Eastern Imperial Eagle，学名：Aquila heliaca），是鹰形目鹰科雕属的鸟类。又名: 御雕，大型猛禽，别称御雕。其身披暗褐色羽毛，头部和颈部呈淡褐色，缀以黑斑，肩部具有一抹醒目的白色。分布于欧洲东南部至西伯利亚中部，迁徙至东洋界、阿拉伯半岛和非洲东北部过冬。白肩雕偏好山地、草原、丘陵、河流砂岸等地，最高栖息于海拔1,400米的高处。在中国，白肩雕为国家一级保护动物，数量稀少。","appearance":"白肩雕是大型猛禽，体长68至90厘米，翼展1.76至2.2米，雄鸟平均重2.62千克，雌鸟平均重3.9千克。全身黑褐色，背部具光泽，肩部有白色羽毛。头部和颈部为褐色，点缀以黑斑。尾部灰褐色，有不规则的黑色横斑。雌雄差异明显，雌鸟体型较大，重约10%以上。幼鸟的羽毛颜色较浅，带有深褐色条纹。","call":"白肩雕主要在繁殖季节发出叫声，其主要叫声为深沉、刺耳的‘owk owk...’或‘kraw-kraw...’，连续快速重复8至10次，比金雕的叫声更深沉、更粗糙。","habits":"白肩雕栖息于山地、草原、丘陵、河流砂岸等地，最高可达海拔1,400米。偏好混交林和阔叶林，冬季也出现在低山丘陵、森林平原、小块丛林和林缘地带。常单独活动，或在空中翱翔，或长时间停息于空旷地区的孤立树上、岩石和地面上。飞行缓慢，类似鹫。以啮齿类、松鼠、花鼠、黄鼠、跳鼠、仓鼠、田鼠、旱獭以及鸽、鹳、雁、鸭等鸟类为食，偶尔食动物尸体和捕食家禽。","breeding":"白肩雕在4至5月间产卵，每窝产卵2枚，卵白色，有褐色斑点。第一枚卵产出后即开始孵卵，雌雄共同孵卵约一个半月。雏鸟为晚成性，约43天出壳，55天以后离巢。白肩雕属于单配性动物，即雄鸟和雌鸟整个哺育期都会在一起，共同承担养育后代的责任。","identification":"白肩雕与金雕相似，但体型较小，肩部的白色羽毛和尾部的黑色横斑是其显著特征。与西班牙雕相比，肩部的白色羽毛更加有限，下体羽毛颜色更深。","protection":"IUCN：VU（易危）","distribution":"繁殖区位于欧洲东南部至西伯利亚中部，迁徙至东洋界、阿拉伯半岛和非洲东北部过冬。在中国，白肩雕在沿海的旅顺、福建、广东等地，以及甘肃西北部有记录，为少见的旅鸟和冬候鸟。","other":"美国普渡大学科学家的研究发现，中亚地区的白肩雕可能是世界上最忠实的鸟类，成年鹰不会与自己的配偶失散，显示出极高的忠诚度。"},{"name":"格氏雕","english_name":"Gurney's Eagle","scientific_name":"Aquila gurneyi","overview":"格氏雕（英文名：Gurney's Eagle，学名：Aquila gurneyi），是鹰形目鹰科雕属的鸟类。又译: 格尼氏雕，属于鹰科雕属的大型猛禽。分布于新几内亚及其周边小岛，包括西巴布亚群岛、阿鲁群岛和西德安特卡斯特罗群岛（Goodenough岛）。在摩鹿加群岛也有记录，包括莫罗泰、哈马黑拉、特尔纳特、巴坎、卡西鲁塔和安汶，近期还在塞兰岛发现。以低地和山地森林为栖息地。","appearance":"格氏雕是一种中等体型的全黑色至深褐色的Aquila鹰，具有较淡的腿部羽毛，比同类鹰有更短的翅膀、更纤细的腿和更长的尾巴。成年鸟体长66至86厘米，翼展165至185厘米，雌鸟比雄鸟大，翼展可达530至568毫米。幼鸟呈现灰色和棕色的混合，腹部和腿部颜色偏浅。脚部黄色，虹膜暗黄色，喙灰褐色。","call":"其叫声被描述为中到高音调、略带鼻音的下降式哨声，每秒重复一次。","habits":"生活在低地和山地原始雨林及沼泽森林，包括沿海地带，偶尔访问附近的空地和农田。从海平面到海拔2970米都能找到它的踪迹，但在1500米以上很少见。它通常单独或成对出现，偶尔以三只为单位，可能是家庭群。以低飞和缓慢的方式在森林冠层或地面搜寻猎物，利用山脊的上升气流在悬崖或山坡上翱翔。","breeding":"关于繁殖行为知之甚少。已知会在高大的森林树上筑建大型的巢穴，但具体繁殖细节未知。","identification":"与楔尾雕相比，格氏雕的尾巴更长且圆润，而非楔形。在摩鹿加群岛，它与较小的区分开，后者翅膀形状更像桨，臀部、眼周和喙周围有白色斑点，以及初级飞羽基部明显的白色斑块。","protection":"IUCN：NT（近危）, CITES II（濒危野生动植物种国际贸易公约附录二）","distribution":"分布于西巴布亚群岛、新几内亚、阿鲁群岛和西德安特卡斯特罗群岛（Goodenough岛）以及摩鹿加群岛的多个岛屿，包括莫罗泰、哈马黑拉、特尔纳特、巴坎、卡西鲁塔和安汶，最近在塞兰岛也有记录。","other":"格氏雕的种名和英文通用名纪念了英国银行家兼业余鸟类学家John Henry Gurney（1819–1890）。"},{"name":"金雕","english_name":"Golden Eagle","scientific_name":"Aquila chrysaetos","overview":"金雕（英文名：Golden Eagle，学名：Aquila chrysaetos），是鹰形目鹰科雕属的鸟类。俗称: 鹫雕、金鹫、黑翅雕、洁白雕（幼鸟），性情凶猛。广泛分布于北美的干旱平原、岩崖山区以及开阔原野，其分布区域跨越了温带到沙漠地带。金雕在人类文化中占有重要地位，是墨西哥的国鸟，古代巴比伦王国和罗马帝国也曾将其作为王权的象征。在中国，金雕是国家一级保护动物。","appearance":"金雕是一种大型猛禽，体长66至102厘米，翼展可达1.8至2.34米。雌鸟比雄鸟大，差异在大型亚种中更为显著。全身大部分为暗棕色，背部、颈后部和冠部有较淡的金色羽毛，给予其名称“金雕”。幼鸟的羽毛更暗，翼下有白色斑块，尾巴基部白色，末端有黑色横带。随着年龄增长，白色逐渐减少。成年金雕的翅膀宽大，呈轻微的V形，尾部较长，足部羽毛颜色较浅，接近白色。","call":"金雕的叫声相对微弱，通常在繁殖季节或领土争斗时发出。声音高而尖锐，有时被描述为‘相当可怜’和‘小狗般的’，与它们强大的外表形成鲜明对比。","habits":"金雕主要栖息在开阔的山区、草原、沙漠边缘以及靠近悬崖的地带。它们偏爱自然植被环境，避免人类开发区域和浓密的森林。它们主要以大中型鸟类和中小型哺乳动物为食，包括土拨鼠、野兔、藏原羚及狐、鼬等。金雕善于翱翔和滑翔，常在高空中盘旋寻找猎物，发现目标后能以每小时300公里的速度俯冲捕杀。","breeding":"金雕在繁殖季节形成稳定的配对，营巢于高大的树木顶端或悬崖凹处。巢巨大，由枯枝和细软材料构成，可重复使用多年。每窝产卵2枚，偶尔产卵数量可能有所不同。孵化期约为45天，雏鸟晚成性，经过亲鸟共同抚育约80天后可离巢独立。","identification":"金雕与白尾海雕和光头鹰等类似物种在幼鸟阶段容易混淆，主要区别在于金雕缺乏广泛的白色斑块，仅在翼下和尾部有局部白色。成年后，金雕的金色颈部羽毛和较短的颈部轮廓成为明显特征。","protection":"IUCN：LC（无危）","distribution":"金雕广泛分布于北美、中美洲、欧亚大陆，包括广阔的温带欧洲、北亚、北美洲、北非和日本的部分地区。在中国，主要分布于西部地区。","other":"金雕在忽必烈时代的蒙古猎人中曾被用于捕狼，但这一陋习对金雕构成了严重威胁。金雕在全世界的动物园中从未有人工繁殖成功的记录。"},{"name":"楔尾雕","english_name":"Wedge-tailed Eagle","scientific_name":"Aquila audax","overview":"楔尾雕（英文名：Wedge-tailed Eagle，学名：Aquila audax），是鹰形目鹰科雕属的鸟类。澳洲最大的猛禽之一，体型庞大，翼展可达2.84米，身长最大1.06米。全身黑褐色，肩颈部羽色偏浅，具独特的楔形尾羽，长而有力的脚和强大的喙。广泛分布于澳大利亚大陆，南至塔斯马尼亚岛，北至新几内亚南部。偏好开放森林、草地、灌木丛生地带，避免人类密集区。","appearance":"楔尾雕体型庞大，体长81-104厘米，体重雄鸟2.025-4.03千克，雌鸟3.05-5.3千克，翼展182-232厘米。全身大部分黑色，头部相对较小且扁平，颈部较长，翅膀宽阔，腿部羽毛丰满。尾巴呈独特的钻石形状，与属内其他物种显著不同。幼鸟颜色更金黄，随年龄增长逐渐变暗。","call":"发出尖锐而细长的哨声，随后是微弱的下降音调，\"see-tyu\"，以及各种微弱的口哨声、吠叫和尖叫，雌鸟的声音听起来更低沉。","habits":"栖息于海拔2000米以下的草原、林地、沼泽地区，避免沙漠、雨林和海岸环境。日行性，白天大部分时间在2000米高空翱翔寻找猎物。单独或成对生活，偶尔成群狩猎，群体最多可达15只。占据9-100平方公里的领地，领地大小取决于猎物和其他资源的丰富程度。","breeding":"筑巢高度从1.8米至30米，巢宽1.8米，深逾3米，重达400公斤，多年使用。产卵时间因地区而异，一般在4-9月间，多数在7月。每窝产卵1-4枚，多为2枚，孵化期42-48天。幼鸟3个月大时离巢，但仍依赖父母4个月左右。幼鸟7-8个月后能飞行超过850公里。性成熟于3岁，寿命20-25年，圈养条件下最高纪录为60年。","identification":"与格氏雕区别在于棕红色颈背、尾部形状和奶油色至淡黄色的脚。幼鸟与格氏雕幼鸟的区别在于较暗的下体和尾部形状。fleayi亚种具有更重的脚和爪子，成鸟有淡色颈背，缺乏红色羽毛。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚大陆，包括塔斯马尼亚岛，以及新几内亚中南部。在澳大利亚，从北部的Cape York半岛到南部的Wilsons Promontory和Great Otway国家公园，西部的Shark Bay到东部的Great Sandy国家公园和Byron Bay均有分布。在塔斯马尼亚岛全境以及多个岛屿上也有分布。","other":"历史上曾遭受人类强烈迫害，但现在数量稳定，部分得益于兔子的引入和人类活动带来的大量腐肉。"},{"name":"黑雕","english_name":"Verreaux's Eagle","scientific_name":"Aquila verreauxii","overview":"黑雕（英文名：Verreaux's Eagle，学名：Aquila verreauxii），是鹰形目鹰科雕属的鸟类。壮观的大型黑色鹰科猛禽，主要分布在非洲南部和东部的丘陵和山区，延伸至亚洲西部。以18世纪访问非洲南部的法国博物学家Jules Verreaux命名的。黑雕以其独特的飞行姿态而闻名，展现长尾和长翼，翼基部略显狭窄，背部和翼端有白色斑块，使其在黑色羽毛中格外显眼。成年黑雕体长可达75至96厘米，翼展1.81至2.2米，雄鸟体重3至4.2千克，雌鸟更重，可达3.1至5.8千克。","appearance":"黑雕体型庞大，头部明显，颈部较长，尾巴稍圆且长，尤其在雌鸟中更为明显，翅膀呈桨状，尤其是雌鸟更为突出。羽毛大部分为纯黑色，但在背部、臀部和上尾覆羽上有醒目的白色斑点，飞行时尤为显著。亚成鸟颜色较为混杂，背部为棕色，腹部条纹状，但仍然具有白色的翼板和特征性的体形。成鸟在5到6岁时达到成年羽毛。","call":"黑雕相对沉默，但已知会发出响亮的‘whaeee-whaeee’声，用于接触或驱赶入侵者。还发出各种咔哒声、啄声、尖叫声、吠声和鸣叫声，特别是在警戒时。","habits":"黑雕偏爱年降水量小于750毫米的较干燥地区，栖息于山地、河谷和岩石地带，海拔从海平面到5000米以上。它们主要依赖岩兔作为食物来源，占比至少60%-90%，但也吃其他中型哺乳动物、鸟类和爬行动物。黑雕主要在空中狩猎，俯冲捕食，偶尔从栖木出击，甚至会协同猎杀。","breeding":"黑雕的繁殖期因地区而异，南部非洲从4月到8月，阿拉伯半岛从11月到1月。筑巢活动几乎全年可见，巢由枯枝和绿叶构成，通常建在悬崖或洞穴中，偶尔在树上或电塔上。每窝产2枚（1-3枚）蓝白色或带红褐色斑点的蛋，孵化期43-47天，雌鸟主要负责孵化。雏鸟孵化后，雌鸟几乎独自喂养，雄鸟提供食物，兄长雏鸟常在孵化后不久杀死弟弟。雏鸟约90-99天离巢，之后依赖父母约125天。","identification":"黑雕在成年后几乎无法与其他物种混淆，尤其是其独特的黑白羽毛图案和体形。与之相近的是长冠鹰，但后者体形更纤细，尾部更长，翅膀更窄且尖锐。亚成鸟可能与金雕混淆，但金雕没有黑雕那样的白色翼板和头部特征。","protection":"IUCN：LC（无危）","distribution":"黑雕主要分布在东非，从苏丹东部、厄立特里亚、埃塞俄比亚到索马里，然后向南延伸至南非，穿过纳米比亚西部和安哥拉西南部。在埃及和中东（西奈半岛、以色列、约旦和阿拉伯半岛）以及乍得东部和苏丹西部有孤立种群。在尼日尔（阿伊尔山脉）、毛里塔尼亚、马里、阿尔及利亚和喀麦隆也有记录。","other":"黑雕在南非某些农业开发地区似乎能适应环境变化，繁殖成功率高于邻近未受人类影响的自然保护区。然而，它们在小牲畜农场区受到严重迫害，导致部分地区消失。"},{"name":"非洲鹰雕","english_name":"Cassin's Hawk-Eagle","scientific_name":"Aquila africana","overview":"非洲鹰雕（英文名：Cassin's Hawk-Eagle，学名：Aquila africana），是鹰形目鹰科雕属的鸟类。属于鹰科雕属的相对小型鹰类，以其黑色和白色的羽毛著称。生活在西非至中非的热带雨林中，以鸟类和树松鼠为主要猎物。1865年由约翰·卡辛首次描述。","appearance":"非洲鹰雕是一种小型鹰，具有紧凑而有力的体型和略带冠状的头部。上体呈黑色，下体非常白，仅两侧为黑色。飞行时，翅膀下前方呈实黑色。翼展约103至113厘米，体长50至61厘米，雄鸟体重938至1049克，雌鸟可达1153克。幼鸟与成鸟羽毛颜色差异显著，幼鸟上部淡赤褐色，下部白色并带有深色斑点，成鸟则更黑上部更白下部。","call":"发出响亮且重复的“kwe-kwe-yaaa”叫声以及简单的上升哨声。","habits":"栖息于低地热带常绿森林及相邻的次生林和河岸林，甚至进入大型树木的种植园。活动范围从海平面到2300米高。主要通过在森林树冠上守望狩猎，偶尔在森林上方低飞寻找猎物。","breeding":"筑巢于高达22至23米的森林树冠中，使用大型棍子筑巢并铺以绿色树叶，巢宽约100厘米。繁殖季节在10月至12月间，可能每年繁殖一次，每次产卵1-2枚，孵化期和育雏细节尚不明确。","identification":"与其他鹰雕的区别在于缺乏下体的条纹或斑点，飞行时展现出前翅下方的实黑色块。与冀长和尾短的艾氏隼雕相比，下体更单一的白色，后者有更深色的飞羽和尾巴，翼缘和尾端的对比度较小。","protection":"IUCN：LC（无危）；被列入CITES附录II。","distribution":"分布于西非的塞拉利昂和利比里亚东至刚果民主共和国和乌干达西部；也有记录在安哥拉西北部和肯尼亚西部。在坦桑尼亚的乌祖翁瓦山脉有一笔记录。","other":"近年来由于森林砍伐，其种群数量正在稳步下降，但目前尚未达到将其保护等级升级至Vulnerable（易危）的水平。"},{"name":"白腹隼雕","english_name":"Bonelli's Eagle","scientific_name":"Aquila fasciata","overview":"白腹隼雕（英文名：Bonelli's Eagle，学名：Aquila fasciata），是鹰形目鹰科雕属的鸟类。中型、体态健硕的鹰科鸟类，体长约55至67厘米，体重范围为1.4至3.03千克。其显著特征为条纹状白色下体与深色翅膀和尾巴形成鲜明对比。幼鸟呈红棕色，尾部缺少成年鸟宽阔的黑带。广泛分布于欧洲南部至亚洲中部，包括非洲北部。主要栖息于温暖、阳光充足的山区或崎岖地形，偏好岩石嶙峋的环境，偶尔在冬季迁至更为开阔的区域。","appearance":"白腹隼雕的体型中等偏大，体长55至67厘米，翼展可达143至176厘米，体重介于1.4至3.03千克之间，雌鸟平均比雄鸟大10%左右。上体为深棕色，下体有条纹状白色，翅膀内侧有黑色中线。背部中央有明显的白色斑块，尾部末端有一宽黑带。眼睛虹膜呈黄色至橙黄色，蜡膜和脚为黄色。幼鸟上体颜色较暗，下体红棕色，缺乏成年鸟的尾部黑带，随年龄增长逐渐呈现成年鸟的羽毛特征。","call":"在繁殖季节较为活跃，发出尖锐的“iuh”声或更长的哨音“eeeuu”，有时下降音调。也会发出类似吹笛的低沉‘klu-klu-klu...’或‘ki-ki-ki...’的警报声，以及巢附近的吠叫、咕噜和哼哼声。","habits":"白腹隼雕主要栖息于山区，偏好有悬崖和岩石的环境，如茂密的灌木丛和树林边缘。它们适应性强，可在人类活动频繁的区域生存。繁殖季节以外，会迁至海拔较低的开放地带。它们是空中高手，善于利用热气流翱翔。主要以中型鸟类和哺乳动物为食，如兔子、雉鸡和鸽子，也捕食蜥蜴。","breeding":"繁殖期从2月至3月开始，筑巢于悬崖、岩石洞穴或大树上，巢巨大，由树枝构成，内衬绿叶。每窝产卵1至3枚，通常2枚，卵孵化期为37至41天，主要由雌鸟孵化。幼鸟由雌鸟照顾，雄鸟负责捕食。幼鸟在约60至70天后离巢。","identification":"白腹隼雕与非洲隼雕相似，但可通过条纹状白色下体和尾部宽阔的黑带来区分。亚种A. f. renschi体型较小，下体和尾部的条纹更加明显。","protection":"IUCN：LC（无危）","distribution":"分布于欧洲南部至亚洲中部，包括非洲北部。在中国，主要分布在南部地区。","other":"白腹隼雕的种群数量在过去曾因栖息地破坏、电击死亡和人为迫害而大幅下降，尤其是在欧洲部分地区。"},{"name":"非洲隼雕","english_name":"African Hawk-Eagle","scientific_name":"Aquila spilogaster","overview":"非洲隼雕（英文名：African Hawk-Eagle，学名：Aquila spilogaster），是鹰形目鹰科雕属的鸟类。中型猛禽，具有独特的黑白相间的羽毛图案。主要分布于撒哈拉以南非洲的半干旱草原、灌木丛及河岸森林，以鸟类为主要猎物，尤其是珍珠鸡和珠颈斑鸠。叫声独特，类似‘klooeee’。","appearance":"非洲隼雕体长55至68厘米，翼展130至160厘米，体重雄鸟1150至1400克，雌鸟1400至1750克。背部黑色带白色斑点，腹部白色带泪滴状暗色条纹，尾巴灰色带狭窄的暗色横纹及宽阔的黑褐色亚端带。飞行时，翅膀下方呈现棕色和白色，尾部主要为淡灰色，末端有一条粗厚的暗色条纹。虹膜黄色，喙和脚绿色至黄色。幼鸟的下体部分完全红褐色。","call":"叫声为重复的旋律哨声‘klooee’，有时延长为‘klu-klu-klu-klooee’。","habits":"居住在半干旱草原、灌木丛和河岸森林，主要以鸟类为食，也会捕食小型哺乳动物、蛇和蜥蜴。狩猎时通常从滑翔飞行或栖木上俯冲，偶尔在树间快速搜索飞行。成年鸟通常定居，而幼鸟的活动限于出生地周围的分散。","breeding":"繁殖季节在旱季，筑建大型的棍子巢，位于显眼的树叉上，如金合欢、猴面包树、桉树等。每次产卵1至3枚，孵化期42至44天，雏鸟的第一次绒羽为深灰色，腹部和腿部为白色。较大的雏鸟通常在孵化几天后杀死较小的兄弟。","identification":"与白腹隼雕相比，非洲隼雕体型更大，头部较长，翅膀较短，尾巴较短。幼鸟与艾氏隼雕相似，但可通过比例和缺乏清晰的翅膀‘窗户’来区分。","protection":"IUCN：LC（无危）","distribution":"从塞内加尔东部至厄立特里亚、埃塞俄比亚和索马里，南至纳米比亚、博茨瓦纳和南非东北部。在繁殖区域内，主要分布在东非和南部非洲的广阔地带。","other":"非洲隼雕与白腹隼雕曾被认为是同一物种，但现在被普遍认为是独立的物种。"},{"name":"双齿鸢","english_name":"Double-toothed Kite","scientific_name":"Harpagus bidentatus","overview":"双齿鸢（英文名：Double-toothed Kite，学名：Harpagus bidentatus），是鹰形目鹰科齿鹰属的鸟类。主要分布在中美洲至南美洲东部，包括墨西哥东部到巴西东南部。因上颌具有的独特‘双齿’而得名，这在野外难以直接观察。成年双齿鸢体长29至35厘米，重约160至230克，雌雄羽色相似，但雌鸟色彩更为丰富，体型略大。","appearance":"双齿鸢拥有灰色的头部，上体和双翅覆羽呈蓝灰色，胸腹部为棕红色，喉部可见白色与深灰色相间条纹。尾巴红褐色，带有三道白色和黄色带纹。眼睛红润，鸟喙黑色具绿蜡质感，腿爪黄色，爪尖黑色。雌雄个体在羽色上相似，但雌鸟颜色更深，体型更大。幼鸟上体深棕色，下体白色至淡黄，有明显的垂直棕色条纹。","call":"发出尖锐的叫声，如“tsip-tsip-tsip-tsip-wheeeeeoooip”、“wheeeeoooo”或“cheeeeee-it”，在防御巢穴或争斗时尤为明显。接触叫声为吹哨般的“see-weeeeep”或“chee-weet”。幼鸟乞食时会发出类似成鸟接触叫声的“chee-weet”，但音调更高，更加粗糙。","habits":"双齿鸢主要栖息于成熟热带和亚热带森林内部，偶尔出现在森林边缘、开阔地带、次生林和受干扰的森林。它们偏好在高树冠上捕食，主要以昆虫和小型脊椎动物为食，如蜥蜴、青蛙、鸟类、蝙蝠和小型哺乳动物。双齿鸢会跟随猴子群落，利用猴子活动驱赶的猎物。","breeding":"繁殖季节在各地有所不同，从雨季结束的干燥季节开始至雨季初期。雌鸟负责筑巢，雄鸟提供食物。巢呈浅杯状，位于大树分叉处，高度从7至33米。每巢产卵1至2枚，孵化期为42至45天，幼鸟在27至37天后离巢，由父母继续喂养至少两个月。","identification":"双齿鸢与其它鸢类相比，头部较暗，上体蓝灰，下体红棕，尾巴有明显的三道灰白横带。幼鸟上体深棕色，下体白色至淡黄色，有垂直的深色条纹。与纹腹鹰相比，外形更接近Accipiter类。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲亚马逊河流域，从墨西哥东部至巴西东南部，包括哥伦比亚、委内瑞拉、圭亚那、厄瓜多尔、秘鲁、玻利维亚和巴西的亚马逊地区。","other":"双齿鸢在全球范围内并不面临直接威胁，但在大面积森林砍伐的区域可能无法生存。"},{"name":"棕腿齿鸢","english_name":"Rufous-thighed Kite","scientific_name":"Harpagus diodon","overview":"棕腿齿鸢（英文名：Rufous-thighed Kite，学名：Harpagus diodon），是鹰形目鹰科齿鹰属的鸟类。以其独特的棕红色大腿羽毛命名。广泛分布在南美洲的亚马逊雨林东部和东南部，包括巴西南部、阿根廷北部、巴拉圭以及亚马逊地区的非繁殖季访问国如圭亚那和委内瑞拉。成鸟具有灰色的身体，较暗的上部和较浅的下部，以及醒目的红棕色大腿和橙红色的眼睛。","appearance":"棕腿齿鸢体长29至35厘米，翼展可达60至70厘米。成鸟的头部和上体呈板岩灰色，尾巴有三条淡色条纹和白色的羽毛尖端。喉咙呈白色，有一条中央的深色条纹，下体灰色逐渐变为白色的下尾覆羽。幼鸟上体为深棕色，头部侧面有条纹，下体白色，胸部和腹部有暗色条纹，侧腹有条纹，与成鸟相似的红棕色大腿。雌鸟比雄鸟略大。","call":"已知的叫声包括高音的'chee'声和双音节的'chee-weet'乞食声，成鸟也会发出三音节的鸣叫声。","habits":"棕腿齿鸢栖息于低地雨林的树冠层，偏好原始森林，但也适应次生森林，只要树冠封闭。它是一种南迁的候鸟，繁殖季节结束后从南向北迁徙到亚马逊地区。主要以昆虫、蜥蜴和小型鸟类为食，有时跟随军队蚁群或猴子群体以捕捉被惊扰的猎物。","breeding":"繁殖季节为10月至翌年2月，主要在南半球的夏季。巢为小树枝搭建的平台，位于树叉或水平树枝上，离地面12米左右。一窝产卵1至2枚，孵化期未知，雏鸟约4周后离巢。","identification":"与双齿鸢相似，但可通过其红棕色大腿和黄色的眼睛来区分。","protection":"IUCN：LC（无危）。虽然全球不被视为受威胁，但在其繁殖地——大西洋森林，由于栖息地丧失和森林碎片化，可能面临保护问题。","distribution":"繁殖于巴西南部、阿根廷北部、巴拉圭，非繁殖季扩展至亚马逊地区的巴西、玻利维亚、圭亚那和苏里南，偶尔见于法属圭亚那、委内瑞拉和哥伦比亚。","other":"其饮食中包含大量蚱蜢和蝗虫，这可能使其在接近农业区时易受到农药中毒的风险。"},{"name":"食蜥鵟","english_name":"Lizard Buzzard","scientific_name":"Kaupifalco monogrammicus","overview":"食蜥鵟（英文名：Lizard Buzzard，学名：Kaupifalco monogrammicus），是鹰形目鹰科食蜥鹰属的鸟类。广泛分布于非洲次撒哈拉区域。尽管其名称中包含‘buzzard’一词，但分子系统发育研究表明它与鵟属（Buteo）关系较远，更接近于Accipiter鹰。该物种以其独特的垂直黑色喉纹和灰白色相间的下体著称。","appearance":"食蜥鵟是一种厚实的中等体型猛禽，体长30至37厘米，翼展可达63至79厘米。雄鸟平均重246克，雌鸟平均重304克。头部较大，喙小，腿长且大部分被羽毛覆盖。上体、头部和胸部呈灰色，喉咙有明显的黑色垂直条纹，腹部为白色，带有细暗色条纹。翅膀下方白色，尾部黑色，末端白色并有一道白色横纹。眼睛颜色从深红棕色到黑色不等，蜡膜和腿为红色至橙红色。幼鸟与成鸟相似，但翅膀边缘略带棕色，裸露部分颜色较浅，眼睛为棕色，面部皮肤和腿为橙黄色至粉色。","call":"食蜥鵟的鸣唱是一串清晰悦耳的‘kleeeo klu-klu-klu-kli-kli-klee’声，重复且逐渐加速，然后逐渐消失，通常在繁殖季节从显眼的栖木上发出，有时也会在飞行中鸣叫。","habits":"食蜥鵟主要栖息于湿润的落叶阔叶林区，雨季时会扩展至河流森林和邻近的密集草原。它们主要以大型昆虫、蜥蜴、小蛇为食，偶尔也捕食蛙类、啮齿动物、蛛形纲动物、小型鸟类及可能的腐肉。白天活动，尤其是清晨和傍晚，它们长时间停留在约8米高的显眼栖木上，一旦发现地面猎物，便快速出击，攻击半径可达45米。","breeding":"繁殖期在西非和东北非为2月至4月，在加蓬为9月，在扎伊尔全年皆有可能，在乌干达为1月至3月和8月至10月，在苏丹为3月至6月，在南部和中部非洲为5月至3月（马拉维为8月至12月）。筑巢前会在开阔处频繁鸣叫甚至唱歌，但没有报道中的空中求偶展示。巢由两性共同建造，形状为碟状，直径可达40厘米，深度15厘米，位于树的外侧枝叉或侧枝上，高度从3至25米不等。巢通常由树枝构成，内衬苔藓、干草、树叶等。每窝产卵1至3枚，卵白或带有红褐色斑点，孵化期为33至34天，主要或完全由雌鸟孵化。雏鸟出生时覆有白色绒羽，第二次换羽时变为淡灰色，由双亲共同喂养，32至40天后离巢，之后还需依赖父母30至40天。","identification":"食蜥鵟最显著的辨识特征是其垂直黑色喉纹和清晰的白色尾端横纹，这使其与其他非洲热带猛禽区分开来。与Gabar鵟最为相似，但可通过喉纹、尾部条纹和尾端颜色加以区分。","protection":"IUCN：LC（无危）。食蜥鵟在西非较为常见和显眼，但在东、中、南非数量较少，尽管如此，某些地区仍可见其局部丰富。易受森林砍伐和草地燃烧的影响，但已适应部分被清理的原始森林区域。","distribution":"食蜥鵟广泛分布于非洲次撒哈拉地区，从厄立特里亚至南非东北部，常见于西非、津巴布韦、莫桑比克，以及纳米比亚、博茨瓦纳和南非东北部的部分地区。偏好湿润、密集的草原林区，尤其是在雨季。","other":"尽管食蜥鵟在非洲的分布广泛，但对其适应人类土地使用的程度尚不清楚。"},{"name":"小歌鹰","english_name":"Gabar Goshawk","scientific_name":"Micronisus gabar","overview":"小歌鹰（英文名：Gabar Goshawk，学名：Micronisus gabar），是鹰形目鹰科小歌鹰属的鸟类。体型纤细、羽色偏灰的小型鹰类，具明显的头罩和白色尾基，外形似缩小的暗色歌鹰。存在罕见的黑色型。广泛分布于非洲及阿拉伯半岛的干旱和湿润稀树草原，以突袭水洼边的小鸟和小型脊椎动物为食。鸣声为独特的连续“peeii-peeii-peeii”和“teeui-teeui-teeui”，类似小石鸻。","appearance":"体长28–36厘米，雄鸟体重90–173克，雌鸟167–240克，翼展56–66厘米，雌鸟明显大于雄鸟。正常色型成鸟头罩深灰色，上体灰色，尾基白色，飞行时可见翼下和尾下具密集横纹；黑色型通体黑褐，仅初级飞羽和尾羽有淡灰色横斑，无白色尾基。虹膜红褐至暗红色，蜡膜橙色，足红色，黑色型足具黑斑。幼鸟虹膜先灰后黄再橙，蜡膜及足橙黄。上体褐色具纵纹，胸腹具纵纹和横斑，尾基白色。黑色型幼鸟全身黑褐。","call":"平时安静，繁殖期发出尖锐似笛的“kew-he, kew-he, kew-heee”或连续吟诵般的“sweee-pee-pee-pee-pee”“twee-twit-twee-twee-twit”，近似白眉金鹃或小石鸻的叫声；巢旁两性快速重复“twi-twi-twi-twi-twi”，乞食幼鸟发出微弱笛音。","habits":"栖息于开阔的荆棘稀树草原、河谷灌丛、农田高树区及落叶阔叶林，海拔可达2000米，偶至2700米。多为留鸟，但西非旱季有局部南迁，11月至次年5月见于冈比亚和科特迪瓦，肯尼亚塔鲁沙漠1–3月可见北迁个体。成对或松散集群活动，常从隐蔽处突袭，亦低空巡飞，在地面持续追击。捕食对象以10–80克的雀形目为主，偶取352克的盔珠鸡雏、小型爬行类、哺乳类、昆虫及蝙蝠；可突袭织布鸟巢。","breeding":"繁殖期随地区而异：西非及东北非3–6月，东非2–11月分双峰，南非8–3月高峰9–11月。空中盘旋展示并伴有鸣叫。巢由雌鸟主筑，为35厘米宽、10–15厘米深的细小枝桠杯状巢，置于5–15米高的刺树或阔叶树顶端，内衬土块、蛛丝、细枝、草根、纸屑等，外覆群体蜘蛛Stegodyphus的网伪装。每窝2枚（1–4枚）青白或白色卵，间隔3–4天产出，雌鸟孵卵33–35天，雄鸟供食；雏鸟先后间隔2–4天出壳，30–35天离巢。同一巢中可同时出现灰色和黑色型雏鸟。","identification":"与同属鹰类区分：赞比亚雀鹰喉部具横斑；褐耳鹰喉白且虹膜红色；暗色歌鹰体型大得多。与Accipiter melanoleucus黑色型相比，后者喉白、尾无横纹、蜡膜及足黄色且体型更大。灰色型与食蜥鵟相比，后者更粗壮，喉具中纹，尾黑具单条白带。","protection":"IUCN: LC（无危）。列入CITES附录Ⅱ。广泛分布于各种稀树草原及林地，数量普遍但局部稀少。","distribution":"指名亚种分布于安哥拉、赞比亚、莫桑比克至南非；aequatorius亚种分布于埃塞俄比亚高地至刚果民主共和国北部、赞比亚北部及莫桑比克北部；niger亚种分布于塞内冈比亚至厄立特里亚、西南阿拉伯半岛及乍得南部、南苏丹。","other":"无"},{"name":"暗色歌鹰","english_name":"Dark Chanting Goshawk","scientific_name":"Melierax metabates","overview":"暗色歌鹰（英文名：Dark Chanting Goshawk，学名：Melierax metabates），是鹰形目鹰科歌鹰属的鸟类。中型鹰科鸟类，广泛分布于非洲次撒哈拉地区及南部阿拉伯半岛。体型健壮，以灰褐色为主色调，具有橙红色腿脚与喙基，两翼黑色初级飞羽，尾部黑白相间。叫声独特，常发出似歌吟的加速笛音和颤音，尤其在繁殖季节更为频繁。","appearance":"暗色歌鹰为中型猛禽，体长42-50厘米，雄鸟体重646-695克，雌鸟体重841-852克，翼展86-104厘米。上体暗灰色，下体白色，具细黑纹。翼尖和飞行羽深色，形成均匀的暗翼图案。头部、胸部和背部为基本暗灰色，除胸部外的下体为白色，带有精细的黑色条纹。初级飞羽黑色，尾巴具有宽大的黑白条纹。橙红色的蜡膜和长腿为其显著特征。雌鸟通常比雄鸟体型更大，羽色更深。幼鸟呈棕色，类似鹰属的色彩和图案，但翼宽且尾长。","call":"叫声包括一系列加速的管乐般哨音和颤音，被描述为歌吟或吟唱，每串有约12个音符。此外，还会发出高音的'peee-u'声。在繁殖季节叫声更频繁。","habits":"栖息于开阔的林地和稀树草原，偏好混合灌木丛和阔叶林，避免密集森林和沙漠。猎食多样，包括哺乳动物、鸟类和爬行动物，常从树梢俯冲捕捉地面或空中猎物。已知会跟随蜜獾、南方地面犀鸟、狗或人类，捕食因它们而惊扰的小动物。","breeding":"繁殖季节为3月至5月在西北非洲，2月至4月在西南阿拉伯，6月至7月在东非，8月至11月（主要9月至10月）在南非。筑巢于树上，由双方共同建造，巢呈扁平平台状，由树枝构成，内衬蜘蛛网和其他材料，有时用水泥加固。产卵数为1至2枚，偶尔3枚，蛋呈蓝白色，由雌鸟单独孵化约36至38天。雏鸟孵化后约50天离巢，约3至8个月后完全独立。","identification":"与其他Melierax属成员相比，暗色歌鹰具有灰色条纹臀部，而其他种类臀部较淡，偏爱干燥环境，且臀部无条纹。东部歌鹰具有黄色喙基皮肤，而淡色歌鹰则有浅色内侧飞羽和深色翼尖，形成鲜明对比的翼图。雄鸟通常比雌鸟翼覆羽颜色更淡。","protection":"IUCN：LC（无危）；但摩洛哥和阿拉伯半岛的两个孤立亚种高度脆弱，尤其是 theresae，仅限于摩洛哥西南部一小片区域，被认为几乎灭绝，主要原因是森林砍伐和狩猎。","distribution":"广泛分布于非洲次撒哈拉地区，避开刚果盆地的雨林和非洲最南端，以及南部阿拉伯半岛。在非洲南部，常见于茂密的林地，特别是在miombo（Brachystegia spp）、mopane（Colosphermum mopane）、Zambezi teak（Baikiaea plurijuga）、Knob thorn（Senegalia nigrescens）和Marula（Sclerocarya birrea）组成的树冠。","other":"与淡色歌鹰和东部歌鹰有物种分类争议，有时被视为单一物种或与另两者合并为淡色歌鹰。"},{"name":"灰歌鹰","english_name":"Eastern Chanting Goshawk","scientific_name":"Melierax poliopterus","overview":"灰歌鹰（英文名：Eastern Chanting Goshawk，学名：Melierax poliopterus），是鹰形目鹰科歌鹰属的鸟类。又名: 东部歌鹰，中等体型的猛禽，主要特征为灰色头部、颈部、胸部和背部，黑色上尾和翼尖，白色或轻微条纹的上尾覆羽，橙红色的腿，以及黄色的蜡膜。常见于东非的半沙漠、干燥林地和稀树草原，自埃塞俄比亚南部至坦桑尼亚东北部。","appearance":"灰歌鹰平均体长49至55厘米，翼展96至110厘米，尾长20至25厘米，雄鸟平均为雌鸟的85%大小。其外观类似于鵟，但尾部较短，呈阶梯状，翅膀更宽。成鸟头、颈、胸及上身灰色，上尾覆羽白色或轻微条纹，腹部有窄细的灰白条纹，下尾覆羽白色，腹部和翼内侧白色，次级飞羽浅灰色，初级飞羽深色，尾部上方黑色下方白色带灰色条纹。幼鸟上部暗褐色，下部白色带棕色条纹，腹部覆羽有棕色横斑，尾部棕色，有宽大的深棕色横斑，臀部白色，可能部分条纹或无条纹。","call":"其叫声包括悦耳的笛声'rhee-opee-opee-opee'和低沉的'kleee-yeu'，在繁殖季节会发出'pereu-pereu-pereu-repee-repee-repee-repee...'的叫声，声音比暗色歌鹰略高。","habits":"灰歌鹰通常在干燥的荆棘灌木丛和稀树草原生活，海拔高度可达2000米，但在1600米以下更为常见。它们主要以蜥蜴、蛇、小型鸟类、啮齿类和大型甲虫为食，偶尔也会食用腐肉。狩猎时主要从显眼的树梢俯冲捕捉地面猎物，很少在地面行走或追逐空中小鸟。","breeding":"繁殖期在旱季结束时，非洲东北部为2月至9月，肯尼亚西北部为2月至6月和8月至次年1月。繁殖时会在月光下的夜晚进行集体空中展示，叫声中盘旋于地面20至60米高的小范围内。巢建在浓密树叶覆盖的树冠中，通常是金合欢或大戟属植物，用枯草、粪便和其他杂物铺垫，有时会用红嘴奎利亚雀旧巢。每年似乎会建造新巢。每窝产1至2枚绿色白色无斑点的蛋，孵化期36至38天，主要由雌鸟承担，幼鸟49至56天离巢。","identification":"与暗色歌鹰相比，成年灰歌鹰具有黄色面部皮肤，幼鸟和成鸟的臀部纯白而非条纹灰色，这在飞行中尤为明显。幼鸟比暗色歌鹰更淡，臀部和下尾覆羽条纹较少。","protection":"IUCN：LC（无危）。CITES II（华盛顿公约二级保护）。在适宜生境中广泛分布，显眼且常常见到。在肯尼亚Tsavo的理想生境中，家庭领地范围为1.2至2.1平方公里，密度为每100平方公里50至60对。主要受到树木砍伐、大象破坏栖息地和半干旱生境过度放牧的威胁。","distribution":"分布于东非，从埃塞俄比亚和索马里南部到乌干达东北部和坦桑尼亚东北部。"},{"name":"淡色歌鹰","english_name":"Pale Chanting Goshawk","scientific_name":"Melierax canorus","overview":"淡色歌鹰（英文名：Pale Chanting Goshawk，学名：Melierax canorus），是鹰形目鹰科歌鹰属的鸟类。中型鹰科鸟类，以灰白色的外表、粉橙色的腿和喙基部著称。栖息于非洲南部的干燥灌木丛、草原及沙漠地带，海拔低于2000米。淡色歌鹰因其类似鸥类的‘kleeeu’叫声而得名。","appearance":"体长46-60厘米，体重雄鸟493-750克，雌鸟700-1300克，翼展102-123厘米。成鸟具铅灰色上身，白色斑点点缀在大翼覆羽，翅膀内部浅色，尾端深色，对比鲜明。雌鸟比雄鸟大8%，重约30%。与暗色歌鹰相比，淡色歌鹰更浅色，翅膀上有浅色区域，臀部无条纹，呈白色。虹膜暗红棕色，嘴基和蜡膜红色，腿红色，幼鸟则颜色较浅。","call":"在繁殖季节发出响亮悦耳的‘kleeu-kleeu-kleeu-klu-klu-klu…’鸣唱，加速并变得颤音，每系列可达12个音符，无论是在栖息还是飞行中都能听到。","habits":"栖息于干旱的灌木草原、草原甚至真正的沙漠，通常选择有树木或木质多肉植物的地方。以小型脊椎动物为主食，如蜥蜴、啮齿类，偶尔捕食小型鸟类、昆虫、甲虫、蚱蜢、白蚁和腐肉。狩猎方式多样，从低矮的栖息地或地面搜索，追逐飞行中的猎物，甚至跟随小型食肉动物如蜜獾、豺狼和獴。","breeding":"筑巢期为6月至12月，在南非，整体繁殖季可能延长至3月。巢建于树叉中，常选刺树如Boscia、金合欢或大戟，有时隐蔽于藤蔓中或电力杆上。巢由树枝构成，内铺干粪、毛发、碎布、羊毛等，直径40-76厘米，深达25-40厘米。每年产卵1-3枚，平均两枚，间隔两天产一枚，孵化期约35-38天，由雌鸟承担大部分孵化任务。雏鸟出生时覆盖白色绒羽，44-56天后离巢。","identification":"与暗色歌鹰区别明显，后者偏好湿润林地，翅膀羽毛颜色更深，形成统一色调，臀部有灰色条纹；而淡色歌鹰更浅色，翅膀上有浅色板块，臀部无条纹，腿更长。","protection":"IUCN：LC（无危）","distribution":"广泛分布于非洲南部的干旱地区，从安哥拉南部至津巴布韦和南非，常见于干燥的半沙漠地带。","other":"在某些干旱年份，淡色歌鹰可能完全放弃繁殖。已知最老的个体至少21岁。"},{"name":"非洲长尾鹰","english_name":"Long-tailed Hawk","scientific_name":"Urotriorchis macrourus","overview":"非洲长尾鹰（英文名：Long-tailed Hawk，学名：Urotriorchis macrourus），是鹰形目鹰科非洲长尾鹰属的鸟类。独特的猛禽，以其显著的长条纹尾巴著称，分布于西非至中非的热带雨林地带，从利比里亚至乌干达和刚果民主共和国中部。","appearance":"非洲长尾鹰拥有非常醒目的长而条纹的尾巴，上体和胸部为深灰色，下体为赤褐色，喉部和尾下覆羽为白色，形成鲜明对比。飞行时，可见其下翼的白色飞羽带有深灰色的重条纹。存在一种罕见的灰胸型，胸部为灰色，喉部更淡，但仍有白色的尾下覆羽。喙为黑色，眼睛、蜡膜、腿和脚为黄色。幼鸟呈棕色，有白胸‘平淡型’和‘斑驳型’两种形态，后者胸部带有棕色条纹。翼展81-90厘米（32-35英寸），总长56-65厘米（22-26英寸），其中尾长占30-37厘米（12-15英寸）。雌鸟比雄鸟大15%左右。由于尾部约占整个体型的56%，这使得它与灰褐鹞一样，拥有相对于体长最长的尾巴。","call":"这是一种颇为鸣叫活跃的鸟，通常首先通过其在树冠中发出的长而拉长的尖叫声被发现。","habits":"栖息于西非至中非的热带雨林中，偶尔进入相邻的廊道森林和次生森林，包括退化的拉菲亚沼泽森林。分布海拔从海平面到约900米。居民性，通常不迁徙，但在某些情况下可能会有流浪个体。以猎食松鼠、蝙蝠和啮齿类为主，强健的腿和脚表明偏好哺乳动物作为猎物，但也捕食一些鸟类。长尾巴使其能在树枝间灵活追捕。","breeding":"繁殖习性直到最近才有所描述。在塞拉利昂，9月观察到成年鹰喂养刚刚离巢的幼鸟；在喀麦隆可能于7-8月繁殖，即雨季高峰期，基于收集标本的生殖腺状态。在象牙海岸，成年鹰与幼鸟一起出现在10月。叫声可能揭示其在森林中的存在。在象牙海岸发现的巢穴位于地面以上20-35米，由两性共同建造，直径约40-70厘米，其中一个巢位于Ceiba pentandra树上；3月的巢仍在建造中，而4月的巢至少有一只大型幼鸟，身上覆盖着白色绒毛。","identification":"与较小的红胸鹰相比，非洲长尾鹰具有不成比例的长尾，这是主要的辨识特征。存在暗色型个体，背部更黑，下体为石板色。","protection":"IUCN：LC（无危）。列入CITES附录II。虽然隐蔽，但广泛记录于原始森林中，依赖大片茂密森林生存。受森林砍伐影响严重，因无法忍受次生栖息地，可能在西非大部分地区数量大幅下降。在塞拉利昂并不罕见，在象牙海岸广泛分布且常见。","distribution":"分布于西非至中非的热带雨林，从几内亚西部沿几内亚湾海岸南至安哥拉北部，东至中非共和国南部、刚果民主共和国北部、南苏丹和乌干达西部。","other":"学名Urotriorchis由Richard Bowdler Sharpe于1874年创造，结合了希腊语“Uro-”（意为‘尾’）和‘triorchis’（被认为有三个睾丸的一种鹰），‘macro-’来自希腊语‘长’，所以macrourus意味着‘长尾’，正如其英文名所示。"},{"name":"栗肩鹰","english_name":"Chestnut-shouldered Goshawk","scientific_name":"Erythrotriorchis buergersi","overview":"栗肩鹰（英文名：Chestnut-shouldered Goshawk，学名：Erythrotriorchis buergersi），是鹰形目鹰科褐肩鹰属的鸟类。稀有的猛禽，拥有黑色的冠羽，深色翅膀边缘衬以栗色，胸部重纹，腹部条纹明显。黄色的眼、腿和喙基部为其显著特征。这种鹰主要分布于新几内亚的山麓和较低海拔的森林地带。","appearance":"体型较大，长度约43至53厘米，翼展可达85至109厘米。通体大部分为黑色和赤褐色，上部更为显著，下部白色带有暗色条纹；肩羽宽缘赤褐色；大腿有条纹；尾部长而有条纹。与褐肩鹰相比，翅膀较短，成年个体的黑白相间更明显，缺乏下体的赤褐色。罕见的黑化型存在于一些成年个体中，与黑化的白颊鹰相似，但尾部条纹更多更窄，眼色为黄色。幼鸟为丰富的赤褐色，带有黑色标记，飞羽和尾巴呈烟灰色。","call":"发出强烈的高音鼻音上升音符，大约每秒一次，类似于白颊鹰的叫声，但节奏更慢，具有独特的强迫感。","habits":"栖息于新几内亚的山地和低海拔雨林，从海平面到1600米高度。通常出现在森林内部，很少在森林上方翱翔。以鸟类为主要猎物，可能也会捕食小型哺乳动物和爬行动物。","breeding":"关于繁殖的信息非常有限，仅观察到一只完全成长但仍在依赖父母的幼鸟在十月期间发出乞食叫声。","identification":"与白颊鹰的区别在于通常在更低的海拔发现，眼色为黄色而非深色。黑化型和幼鸟形态与白颊鹰类似，但通过尾部条纹和眼色可以区分。","protection":"IUCN：NT（近危）。CITES: II级。非常稀少，记录极少，可能总数仅在数百只，或若分布广泛，则可能达到四位数。","distribution":"分布于新几内亚的北部、东北部、中东部和东南部山区。"},{"name":"褐肩鹰","english_name":"Red Goshawk","scientific_name":"Erythrotriorchis radiatus","overview":"褐肩鹰（英文名：Red Goshawk，学名：Erythrotriorchis radiatus），是鹰形目鹰科褐肩鹰属的鸟类。以锈红色的羽毛和大型黄色的腿脚著称。分布于澳大利亚北部和东部热带地区，尤其沿河流系统附近。成年雄鹰体重630-640克，雌鹰则重1110-1370克，翼展可达111-136厘米。","appearance":"褐肩鹰体型健壮，羽毛呈锈红色，具有醒目的黄色腿脚。在栖息时，尾巴比折叠的翅膀更长。飞行时，翼缘凸起明显，常以翅膀向后、头部突出的姿态翱翔。雌鸟比雄鸟大得多，有时甚至达到雄鸟的75%体重。头部颜色较浅，带有黑色条纹，两色翅膀底面和红棕色的小翼羽和中翼羽，白色飞羽上有黑色条纹。幼鸟更为红棕色，尤其是头部和胸部。成年雄鹰虹膜为棕到黄色，雌鹰为黄色到金黄色；幼鸟虹膜暗棕色。","call":"发出‘keep-keep-keep-keep’的声音，有时穿插着刺耳的尖叫声，在争斗或领地维护时；展示时，雄鹰会发出‘ik-ik ik-ik ik-ik’的叫声，雌鹰偶尔会以响亮的‘ahk ahk ahk’回应；还有各种尖叫和咯咯声，与澳大利亚鹰科鸟类的叫声截然不同。","habits":"栖息于沿海及近海岸的开阔森林和林地，尤其是热带和亚热带的桉树森林，海拔从海平面到约1000米。主要捕食成年鸟类，如鹦鹉和鸽子，偶尔也会捕食哺乳动物、爬行动物和大型昆虫。狩猎方式多样，包括从树上的隐蔽位置进行短暂守候，或是在树冠上空长时间滑翔或拍打飞行，有时会在空中追逐猎物。","breeding":"繁殖季节通常在5月至10月之间，筑巢于高大的树木的暴露叉枝上，巢由树枝搭建，内铺绿叶，离地面高度9-29米。每次产卵1-2枚，由雌鸟孵卵，孵化期39-43天。幼鸟出生时覆有白色绒毛，离巢时间为51-53天，雄鸟可能略短，雌鸟稍长。幼鸟离巢后依赖父母至少10-11周。","identification":"与同类猛禽的区别在于其大胆的红褐色鳞状上体和大腿，松散且条纹明显的羽毛，枕部有小冠，更长的翅膀，非常强壮的腿脚。雄鸟和雌鸟在外形上有显著差异，雌鸟更大，腹部更白，黑色条纹更重。","protection":"IUCN：EN（濒危）","distribution":"分布于澳大利亚北部和东部，从西澳大利亚的金伯利地区向东延伸至北领地、昆士兰州，最远至新南威尔士州北部。在北澳大利亚连续分布，但在新南威尔士州几乎绝迹。","other":"过去曾被列为易危物种，现在估计数量比以前认为的要多，但仍然稀少且疑似在减少。"},{"name":"多氏鹰","english_name":"Doria's Goshawk","scientific_name":"Megatriorchis doriae","overview":"多氏鹰（英文名：Doria's Hawk，学名：Megatriorchis doriae），是鹰形目鹰科多氏鹰属的鸟类。体型较大的猛禽，主要分布在新几内亚低地和Batanta岛。该鹰以灰褐色为主色调，背部和长尾具有明显的条纹，下体呈淡色并带有稀疏的褐色条纹。眼眉淡色，眼纹深暗，与同属的长尾鹰相比，不翱翔，体型略大，眼睛颜色较暗，腿色为黄色而非白色。","appearance":"多氏鹰体长可达51至69厘米，雌鸟比雄鸟大12%-19%，体重可达1000克，翼展范围在88至106厘米之间。拥有强壮的喙，头部较小，有轻微的冠羽，翅膀圆形，尾巴长而圆或楔形。背部、上翼和尾巴有明显的条纹，下体淡色并带有稀疏的棕色条纹。脚部强健，趾长。幼鸟颜色略浅，更偏赤褐色，缺乏黑色面罩，可能有淡色头部。虹膜暗金色，蜡膜绿色到蓝灰色，腿部灰色至黄灰色。","call":"多氏鹰常发出拉长的嘶嘶声，无论是栖息还是飞行中，甚至在被其他鸟类围攻时也会发出这种叫声。","habits":"多氏鹰栖息于新几内亚的低地雨林、季风森林和红树林地带，通常保持在树冠下方，不会翱翔。活动范围从海平面至海拔1650米，但主要在1100米以下。以鸟类为食，包括小极乐鸟，偶尔捕捉小型无脊椎动物。在森林树冠内长时间等待，选择在吸引猎物的地方设伏，如开花树木或小极乐鸟的聚集地。","breeding":"关于繁殖知之甚少。会在树冠中建造大型棍状巢穴，但具体的繁殖周期、孵化期和育雏期未知。","identification":"与长尾鹰相似，但多氏鹰不翱翔，体型稍大，眼睛颜色更深，腿部颜色为黄色。幼鸟颜色较淡，更偏向赤褐色。","protection":"IUCN：LC（无危）。由于栖息地破坏，多氏鹰面临威胁，其数量估计在数千只，总分布面积超过40万平方公里。","distribution":"主要分布于新几内亚低地和Batanta岛，包括海岸盐沼或半咸水生长的灌木或树木，季节性热带森林。","other":"该物种的命名是为了纪念意大利自然学家Giacomo Doria。"},{"name":"侏鹰","english_name":"Tiny Hawk","scientific_name":"Microspizias superciliosus","overview":"侏鹰（英文名：Tiny Hawk，学名：Microspizias superciliosus），是鹰形目鹰科 Microspizias 属的鸟类。体型小巧，雄鸟约20厘米，与星椋鸟相仿，而雌鸟略大，可达26.5厘米。广泛分布于中美洲至南美洲北部，自尼加拉瓜延伸至阿根廷北部。其显著特征为细密的腹部条纹，深色头冠，以及相对较短的尾巴。","appearance":"侏鹰的成年雄鸟呈暗灰色，脸部带有斑驳的灰色，眼眉淡灰，黑色的冠羽和颈背。白色腹部覆盖着细致的灰色条纹，除无标记的喉咙外。尾巴较长，带有三个较浅的灰色带。成年雌鸟相似，但背部偏棕色，腹部偏黄，下方的条纹为棕色。黄色的蜡膜和腿脚，尖喙呈灰色，成年个体的眼睛为红色或红棕色。幼鸟有两种形态：棕色和赤褐色。棕色形态的鸟背部深色，腹部白色，重叠着肉桂色条纹；赤褐色形态的鸟背部更偏栗色，腹部条纹为赤褐色，头部较暗，尾巴更鲜艳。","call":"发出尖锐、高音且略带颤音的连续20至30个音符，音调不一。初始音符加速后，转为稳定的节奏，可描述为一系列的'caucau-ca-ca-ca'或'keer-keer-keer'。","habits":"栖息于低地雨林，高度可达1800米，但主要在800米以下。偏好边缘开阔地带，如大块空地旁的森林碎片和次生林。清晨或傍晚会在高处的开放枝干上晒太阳，一般单独出现。猎食鸟类，尤其是蜂鸟和小型雀形目，有时也会捕食啮齿类和蝙蝠。","breeding":"繁殖季节可能因地理位置而异，从巴拿马到哥伦比亚，大约在2月至6月之间；在南部地区，可能在10月至1月。它们建造棍状巢，有时位于高树的树冠中。已知的一次记录显示，一对侏鹰在委内瑞拉利用了旧的黑领鹰巢。雌鸟产下1至3枚蓝白色带轻微棕色斑点的蛋。","identification":"与半颈鹰的区别在于腹部条纹更细，且颈部缺乏明显的浅色环。幼鸟有两色型：棕色和赤褐色，后者在背部和翅膀上有暗色条纹，腹部为红褐色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲北部，具体包括尼加拉瓜至阿根廷北部，以及中间的国家和地区。在低海拔的热带雨林和次生林中较为常见。","other":"尽管记录稀少，但其分布范围广阔且适应次生林环境，暗示物种短期内并无生存威胁。"},{"name":"半领鹰","english_name":"Semicollared Hawk","scientific_name":"Microspizias collaris","overview":"半领鹰（英文名：Semicollared Hawk，学名：Microspizias collaris），是鹰形目鹰科 Microspizias 属的鸟类。稀有的小型猛禽，以独特的黑色上部羽毛和颈部白色带状标记著称，分布于南美洲的委内瑞拉至秘鲁一带的中海拔云雾森林。","appearance":"体型小巧，成鸟长度约25-30厘米，翼展43-53厘米。头部及颈背黑色，有一条断续的白色颈环，背部其余部分为黑褐色。喉部白色，下体白色带有棕色至黑色条纹。尾巴灰色，带有五道黑色横纹。眼睛橙黄色，脚和蜡膜黄色。雌鸟比雄鸟大4-22%，翅膀长度168-180毫米。幼鸟呈棕色或锈色，带有淡色颈环。","call":"已知的唯一叫声是一连串四个略升高的高音调穿透音，持续约0.5秒，听起来像'quee-kee-kee-kee'。","habits":"栖息于亚热带湿润或潮湿的山地森林，通常在森林内部活动，偶尔翱翔。以小鸟为食，包括蜂鸟，曾在厄瓜多尔西北部观察到攻击一群暗腹丛唐纳雀。可能成对狩猎。","breeding":"关于繁殖行为的信息稀缺。","identification":"与侏鹰相似，但下体条纹更宽且模糊，颈部标记更明显。成年个体比白眉燕鵙体型稍大。","protection":"IUCN：LC（无危）。全球数量估计在2500-9999之间，成熟个体约1500-7000。虽然分布稀疏且数量稀少，但目前没有证据显示其种群正在减少。","distribution":"分布于委内瑞拉西南部至秘鲁南部，包括哥伦比亚、厄瓜多尔等地的安第斯山脉两侧。最近在秘鲁南部（库斯科）、亚马逊州和圣马丁被发现。在玻利维亚西部拉巴斯也有记录。","other":"曾被认为与侏鹰形成超种，但后者可能不属于Accipiter属，这导致了对Accipiter属定义特征的质疑，使得半领鹰和其他物种的位置变得不确定。"},{"name":"凤头鹰","english_name":"Crested Goshawk","scientific_name":"Accipiter trivirgatus","overview":"凤头鹰（英文名：Crested Goshawk，学名：Lophospiza trivirgata），是鹰形目鹰科鹰属的鸟类。又名: 凤头苍鹰（台湾）、粉鸟鹰、凤头雀鹰，中等体型的鹰科猛禽。体长30-46厘米，体重224-450克，雌鸟体型大于雄鸟。头部暗褐色，具有短而通常低伏的凤头状冠羽。上体暗褐色，下体白色带橙褐色条纹，胸有深色条纹，腹部和胁部有棕色至栗色横斑。飞行时展现‘慢拍翅、直滑翔’的特征，尾部可见白色羽簇。","appearance":"成年凤头鹰头部呈灰色，翅膀褐色，下体白色具橙褐色横纹，喉部有黑色纵纹。雌鸟体型比雄鸟大8-22%，头部和颈背颜色更深，背部颜色更淡，胸部色彩较少。亚成鸟头部黑褐带淡色边缘，下体底色为淡黄色，具斑点而非条纹。飞行中尾基部两侧可见蓬松的白色羽簇。","call":"鸣叫较为沉寂，发出‘he-he-he-he-he-he’的尖厉叫声及拖长的吠声。","habits":"凤头鹰是留鸟，栖息于2000米以下的山地森林、山脚林缘地带，也出现在竹林和小面积丛林地带，偶尔至山脚平原和村庄附近。飞行缓慢，盘旋时双翼常向下压或抖动。主要捕食蛙、蜥蜴、鼠类、昆虫、鸟类和小型哺乳动物。","breeding":"繁殖期4-7月，常在森林上空翱翔并发出响亮叫声。营巢于针叶林或阔叶林中高大的树上，距地面6-30米，巢由枯枝堆砌，内衬绿叶。每窝产卵2-3枚，卵椭圆形，大小43-54mm×37-41mm。孵卵期间领域性强，会攻击靠近巢区的人。","identification":"与近似种相比，凤头鹰体型较大，有明显的短凤头状冠羽，下体具橙褐色横纹。亚成鸟头部黑褐带淡色边缘，下体底色为淡黄色，具斑点而非条纹。","protection":"IUCN：LC（无危）。CITES: 附录II。在中国为国家二级保护动物。","distribution":"分布于东洋界，从印度、斯里兰卡至中国南部、印尼、台湾和菲律宾。在台湾，常见于城市环境中。","other":"在马来西亚和新加坡，有证据表明凤头鹰适应了城市生活。"},{"name":"苏拉凤头鹰","english_name":"Sulawesi Goshawk","scientific_name":"Accipiter griseiceps","appearance":"成年苏拉威西凤头鹰具有灰头、棕背，喉部有中央条纹，胸前有明显的白色底纹和粗大的条纹，大腿部分有横斑。翅膀下方为灰白，散布着暗色标记，尾巴有横纹。幼鸟头部呈棕色，腹部有红褐色标记。雌鸟平均比雄鸟大12%，体重可达雄鸟的140%。喙、腿和虹膜的颜色随年龄而变化。","call":"发出较为微弱的高音调‘tseee-tseee-tseee…’声，相较于其他鹰属物种的类似叫声，节奏较慢，但在多数情况下保持沉默。","habits":"栖息于原始森林和次生林内部，尤其偏好带有一些开阔地带的环境，同时也能在红树林和木草原中找到它们的身影。活动范围从海平面至海拔2000米。以突袭的方式猎食，主要捕食蜥蜴、小型鸟类、大型昆虫、小型哺乳动物及偶尔的家禽。","breeding":"关于繁殖的信息极少。已知繁殖季节包括5月至7月，筑巢可能在5月，雏鸟在6月底被观察到。巢建于山地森林中不高树木的主枝分叉处。","identification":"成鸟因灰色头部和喉部中央条纹而独特。幼鸟与日本和中国雀鹰幼鸟的区别在于，前者仅在大腿部有横斑，且翅膀下方标记较少。","protection":"IUCN：LC（无危）。CITES II（濒危野生动植物种国际贸易公约二级附录）。尽管普遍认为数量不多，但可能实际上比预想的更常见，只是由于其隐蔽的行为而鲜少被观察到。","distribution":"分布局限于印尼的苏拉威西岛、托吉安群岛、穆纳岛和布通岛。"},{"name":"灰腹鹰","english_name":"Grey-bellied Hawk","scientific_name":"Accipiter poliogaster","overview":"灰腹鹰（英文名：Grey-bellied Hawk，学名：Accipiter poliogaster），是鹰形目鹰科鹰属的南美森林猛禽，体型较大而稀有。广泛分布于亚马逊雨林至阿根廷北部，但在其范围内分布零散且数量稀少。","appearance":"体长38-51厘米，雄鸟翼展宽约69-84厘米，头大，翅膀尖端较短且圆，尾巴较短。成年鸟上体黑色，头部侧面黑色或灰色，尾部有三条宽阔的灰色横纹和白色尖端。下体非常淡的灰白色，翅膀下无斑纹；喉咙和尾下覆羽白色，虹膜、蜡膜、腿脚均为黄色。雌鸟比雄鸟大4-21%，脸部颜色不同，雄鸟灰脸，雌鸟黑脸。幼鸟外观类似成年丽鹰雕，但体型更小，有裸露的大腿，黑色冠羽延伸至尖端，胸部有栗色颊斑和颈环，下胸和腹部白色，有断续的黑色横斑。","call":"在森林上空翱翔时发出尖锐的‘kek-kek-kek-kek-kek-kek’叫声，尾音渐弱，类似双色鹰的叫声。报警声较为延长，是一连串快速的7-8个旋律音符，对入侵者或潜在捕食者作出反应；在向巢穴运送食物时，会发出单一的高音调声音，雌鸟的单个音符比雄鸟的更长。","habits":"常栖息于热带低地雨林，从低地至海拔800米，偶尔出现在河流边森林边缘和密集林地。在亚马逊地区，记录于高地和季节性泛滥的瓦尔泽亚森林。通常在半开放的树冠高处静猎，然后攻击混合物种的鸟群。","breeding":"已知唯一巢穴位于巴西南部，直径约80厘米，深约50厘米，由小枝搭建，离地面18米。巢中含两枚卵，仅雌鸟孵化，孵化期间占巢时间96%，孵化期未知。仅一雏鸟存活，由雌鸟喂养，雄鸟提供食物，49天左右离巢，至少到90天仍由成鸟喂食。","identification":"与灰背林隼相似，但体型更大，尾巴更短更方。幼鸟与丽鹰雕极为相似，但体型更小，有裸露大腿，且黑色冠羽延伸至尖端。","protection":"IUCN：NT（近危）","distribution":"分布于安第斯山脉以东，从哥伦比亚东北部和厄瓜多尔东北部（可能只有迁徙鸟），委内瑞拉南部和圭亚那地区，通过巴西，秘鲁东部，玻利维亚，巴拉圭东部至阿根廷东北部（米西奥内斯）。在亚马逊盆地内广泛但零散分布。","other":"全球估计数量在1000-10000只之间。主要威胁是亚马逊盆地加速的森林砍伐。尽管该物种能够忍受一定程度的生境退化，但其分散的分布使其容易受到森林片段化和干扰的影响。"},{"name":"红胸鹰","english_name":"Red-chested Goshawk","scientific_name":"Accipiter toussenelii","overview":"红胸鹰（英文名：Red-chested Goshawk，学名：Accipiter toussenelii），是鹰形目鹰科鹰属的鸟类。是西非特有的中型猛禽。通常被误认为与非洲鹰同种，但实际存在显著差异。雌性红胸鹰明显大于雄鸟，拥有独特的红褐色腹部和黑色带白斑的尾巴。分布于西非的低海拔森林，包括雨林和密生的次生林。","appearance":"红胸鹰的翼展在雄鸟中为18.4至20.3厘米，雌鸟为20.4至24.3厘米，体长约为翼展的3/5。雄鸟体重150至235克，雌鸟170至265克。成年红胸鹰的眼睛、蜡膜和腿均为橙黄色。东部亚种的成鸟背部深灰，头部较浅，腹部红褐与白色相间，尾部黑色带2至3块大白斑。西部亚种的成鸟背部深色，喉部灰色，腹部混有红褐色，尾部有3块白斑。幼鸟背部黑色或黑褐色，腹部白色带深褐色斑点。","call":"红胸鹰的典型叫声为‘磨擦般刺耳的krit或尖锐的whit’，每隔2到3秒发出一次，用于伴侣间的联系、求偶和领地标记。","habits":"红胸鹰栖息于低海拔的森林环境，偏好雨林和密集的次生林，靠近河流和沼泽地带，包括红树林。它们不会迁徙，仅在幼鸟扩散时离开巢区。以青蛙、淡水蟹为主食，偶尔猎食大型昆虫、蜥蜴、蚯蚓、小型哺乳动物和鸟类。","breeding":"繁殖季始于7月或8月，延续至次年2月。巢筑于高6至20米的大树主枝或侧枝，由树枝构成，内部铺有新鲜叶子。雌鸟产2至3枚蛋，孵化期4至5周，雏鸟32至36天后离巢。","identification":"红胸鹰与非洲鹰相比，具有更明显的红褐色腹部和不同的鸣叫声。两个亚种群之间也存在外观差异。","protection":"IUCN：LC（无危）","distribution":"分布于西非，包括从刚果盆地向西至加蓬和喀麦隆南部，以及从喀麦隆西部至塞内加尔的区域。在繁殖季节，分布于西非的低海拔森林。","other":"红胸鹰的两个亚种群可能被视为独立物种，西方群体被称为西非鵟（Accipiter macroscelides）。"},{"name":"非洲鹰","english_name":"African Goshawk","scientific_name":"Accipiter tachiro","overview":"非洲鹰（英文名：African Goshawk，学名：Accipiter tachiro），是鹰形目鹰科鹰属的鸟类。中到大型的猛禽。其特征为灰色与赤褐色相间的羽毛，拥有典型宽阔的翅膀和长长的尾巴。分布于非洲东部、中南部和南部，包括南至南非西部开普省，北至刚果民主共和国南部，东至索马里和埃塞俄比亚南部。","appearance":"成年非洲鹰上体呈灰色，雄鸟比雌鸟颜色更深，下体为白色并带有赤褐色条纹，雄鸟的条纹更为明显。翼下为浅赤褐色，逐渐变白，飞羽和尾羽从烟熏般的棕色到灰色不等，上有淡灰色条纹。喙为黑色，蜡膜绿灰色，眼黄色，腿和脚亦为黄色。雌鸟体重270-510克，雄鸟150-340克。雄鸟的翼展为440-570毫米，雌鸟为540-700毫米，约为身长的1.7倍。幼鸟背部为棕色，下体和侧腹为白色，带有明显的棕色斑点。","call":"在展示时非常喧闹，发出特有的咔哒声，每隔2-3秒一次，听起来像是两块石头相撞。","habits":"栖息于森林和密集的灌木林，包括低地和山区，也能在河流沿岸森林、异国树木种植园、公园和大花园中发现。早晨常在树冠上方翱翔，以慢速拍打翅膀和滑翔的方式展示飞行。主要猎食如犀鸟或鹧鸪大小的鸟类，但也吃小型哺乳动物、蜥蜴和偶尔的无脊椎动物。采用伏击狩猎策略，等待在栖木上，观察到猎物后迅速扑击。","breeding":"非洲鹰为领域性鸟类，配偶双方会一起进行波浪式飞行的求偶展示，同时大声鸣叫，有时以陡峭的俯冲结束。雌鸟筑巢，用树枝搭建平台，内衬新鲜树叶、松针、苔藓和槲寄生。巢通常建在树干旁的枝条上，偏好茂密的树冠中。有时会占用非洲小雀鹰的旧巢。每年7-12月产卵，高峰在9-11月，每次产1-3枚蛋，由雌鸟孵化约35-37天，期间雄鸟定期提供食物。雏鸟在30-35天左右离巢，但在巢附近停留约六周才完全独立，离开巢后1-3个月完全自立。","identification":"与红胸鹰的中央非洲亚种有时被视作同一物种。","protection":"IUCN：LC（无危）","distribution":"非洲：东部，中南部，南部，具体包括从南非的西部开普省向北至刚果民主共和国南部，通过东非，直至索马里和埃塞俄比亚南部，包括马菲亚岛、乌恩古贾岛（即桑给巴尔岛）和奔巴岛。"},{"name":"栗胁雀鹰","english_name":"Chestnut-flanked Sparrowhawk","scientific_name":"Accipiter castanilius","overview":"栗胁雀鹰（英文名：Chestnut-flanked Sparrowhawk，学名：Accipiter castanilius），是鹰形目鹰科鹰属的鸟类。是非洲中西部热带雨林中的小型猛禽，以其深色石板灰背、猫头鹰般的面容、浓密的红棕色和灰色条纹胸腹以及更红的侧翼而著称。体型小巧，鲜少在密林深处出现，偶尔可见其跟随行军蚁群活动。","appearance":"成年栗胁雀鹰体长28-37厘米，翼展43-58厘米，雄鸟体重115-150克，雌鸟147-200克。上体呈黑灰色，喉部细白纹，侧翼和大腿为栗色，虹膜红色，蜡膜和脚黄色。雄鸟尾巴较长，下方颜色较暗，雌鸟下方颜色更深，侧翼斑纹更重。幼鸟上体棕色，喉部中央有条纹，胸部斑点密集，侧翼条纹或斑点，虹膜灰绿至黄绿色，蜡膜绿黄色，脚黄色。","call":"鸣叫特征尚未被描述。","habits":"栖息于低地热带常绿森林，有时延伸至邻近的密集次生林。倾向于在低处（1-3米）的灌木丛中活动。在刚果民主共和国，观察到其在村庄附近和种植园中猎食，甚至进入民宅追逐鸡只。主要在低海拔地区活动，从海平面至约750米高度。","breeding":"繁殖信息有限。刚果民主共和国的主要繁殖期为1月至4月，幼鸟出现在1月至6月。加蓬地区的繁殖可能也在1月至4月间。未报道空中求偶飞行展示。","identification":"与较大的非洲鹰和红胸鹰相似，但可通过其较小的体型、较长的尾巴和更暗的颜色加以区分。雄鸟具有相对于其他趾较长的内爪。","protection":"IUCN：LC（无危）。CITES II级。尽管隐秘，但在原始森林的大片区域内仍被认为相对常见。然而，对森林砍伐脆弱，部分地区的数量可能因森林严重破坏而大幅减少。","distribution":"分布于中西非，从尼日利亚南部向东和向南穿过喀麦隆和加蓬至刚果民主共和国（刚果盆地）。其在尼日利亚以西的上几内亚森林的存在需进一步确认。","other":"通常被视为单一物种，尽管一些权威认为刚果盆地的小型个体为亚种 beniensis。"},{"name":"褐耳鹰","english_name":"Shikra","scientific_name":"Accipiter badius","overview":"褐耳鹰（英文名：Shikra，学名：Accipiter badius），是鹰形目鹰科鹰属的鸟类。又称: 褐耳苍鹰，常见于亚洲和非洲的干树林与灌木丛地带。也被称作小带斑苍鹰，拥有锐利的双色瞳孔——雄鸟的虹膜呈红色，雌鸟则为黄橙色或深黄色。其上体颜色为蓝灰色，带有细密的棕橙色横纹，尾部有狭窄的暗色条纹。幼鸟则呈现更褐色的外观，具有明显的髭纹和斑驳的下体。广泛分布在亚洲和非洲的多个地区。","appearance":"褐耳鹰体型较小，长度在25至44.5厘米之间，体重介于100至266克，展翼宽度雄鸟个体为48至56厘米，雌鸟则为56至68厘米。这种鹰拥有相对厚实的体态，喙部突出的钩状齿状结构明显，翅膀较短，尾巴较长，腿和脚趾较短。头部具淡绿黄色的蜡状膜，眼睛颜色因性别和区域而异，从深红到几乎黑色。尾羽中央部分无条纹，呈现单一的灰色。雄鸟通常有赤褐色的颈圈，而雌鸟比雄鸟大10%，重约40%，上体颜色更深，下体的条纹更宽泛且较少赤褐色。幼鸟的胸部有棕色斑点，侧腹有条纹，眼睛最初为暗灰色，喉部有一条黑色线纹。","call":"褐耳鹰的叫声在繁殖季节尤其响亮，包括尖锐的“piu-piu-piu”声，雌鸟在飞行和栖息时都会发出，还有尖厉的“kwit-kwit”声，响亮的“kee-kee-kee-kee-kee”展示叫声，以及雌雄间的互鸣“kewick”（雄鸟）和“kiew”（雌鸟）。","habits":"褐耳鹰栖息在干燥的林地和灌木丛，包括落叶林、稀树草原，从干旱的草原到湿润的密林，偏好阔叶林，很少在针叶林中被发现。它们也能在小型的异国树木种植园和城市花园中找到栖身之所。海拔高度从海平面到2000米，偶尔可达3000米。它们在秋季迁徙，从帕拉尔地区南迁，经过阿拉伯半岛，到达伊朗南部、巴基斯坦、印度和东南亚，部分个体在里海南部过冬。","breeding":"繁殖期通常在旱季结束时，从3月到6月在东南亚，3月至8月在斯里兰卡，1月至6月在印度，1月至5月在苏门答腊，1月至5月在非洲西部和东北部，全年可能在东非（主要是4月至5月在索马里），8月至1月在南非（高峰在9月至12月）。筑巢由双方共同完成，巢为浅碟状，由树枝制成，内衬树皮碎片，有时会有叶子。巢通常建在离地5至16米的树叉或水平枝上，产卵数通常为2至3枚，在非洲，3至4枚在印度，3至4枚在阿塞拜疆，卵为淡蓝白色，孵化期为30天。","identification":"与东雀鹰相似，但下体颜色更浅，尾下的条纹更少，更不明显，后者罕见地具有如此突出的中线。不同亚种在体型和羽毛颜色上有所差异，如poliopsis体型最大，cenchroides次之，badius在亚洲最小；在非洲，sphenurus比polyzonoides更大。","protection":"IUCN：LC（无危）","distribution":"广泛分布于非洲、亚洲和欧亚南部。在中国大陆，主要分布于山地和平原森林、有稀疏树木的农田、草地、草原和荒漠地带，偶尔在公园、果园、村庄和城市上空可见。","other":"褐耳鹰是非洲和印度最常见的小型猛禽之一，常在人类居住地附近频繁出现。在阿拉伯地区，尽管数量不多，但已确认在迪拜和科威特等地出现。"},{"name":"尼岛雀鹰","english_name":"Nicobar Sparrowhawk","scientific_name":"Accipiter butleri","appearance":"体型小，翼短尖，尾中长而略重。雄鸟上体灰色，下体淡色具细薄的棕色横斑，尾端黑色。雌鸟总体偏褐色。幼鸟上体红褐色，下体红棕条纹，尾有两道暗色带。眼橙黄，嘴绿黄色，腿黄色，随年龄颜色渐淡。雌鸟比雄鸟大，上体更褐，下体红褐斑纹更明显。","call":"发出尖锐的双音节“kee-wick”，类似栗翅牛鹂的叫声。","habits":"栖息于原始森林的上层，偏好低海拔环境，低于100米。似乎定居，主要以蜥蜴为食，也捕食部分昆虫。狩猎行为未详。","breeding":"繁殖活动记录于2月和9月，有报道称每年繁殖两次，但存疑。已知一巢位于12米高榕树水平枝梢，具体繁殖细节未知。","identification":"与栗翅牛鹂相比，体型较小，色泽较淡，尾部无条纹。雌雄差异在于颜色深浅和斑纹明显程度。","protection":"IUCN：VU（易危）","distribution":"仅限于印度尼科巴群岛的特里莎、邦波卡、提兰乔、卡莫尔塔、卡恰尔、南考瑞、皮洛米洛、小尼科巴和大尼科巴等岛屿。","other":"因人类移民导致的栖息地破坏和退化为主要威胁，自20世纪60年代以来加剧，影响其生存状态。"},{"name":"东雀鹰","english_name":"Levant Sparrowhawk","scientific_name":"Accipiter brevipes","overview":"东雀鹰（英文名：Levant Sparrowhawk，学名：Accipiter brevipes），是鹰形目鹰科鹰属的鸟类。具有蓝灰色上体和橙色横纹下体的特征，雌鸟体型比雄鸟大，喉部有深色条纹。繁殖于东南欧至哈萨克斯坦西部，冬季迁徙至非洲中部。","appearance":"成年雄鸟呈暗蓝色至灰色，上体淡蓝灰，下体淡色带粉红或红色细纹。雌鸟平均比雄鸟大9%，上体呈棕灰色，下体和翼下更重地条纹，喉部有暗色条纹，缺乏雌性雀鹰的白色眉纹。飞行中，从下方看，几乎白色的翼下和黑色翼尖形成鲜明对比。幼鸟上体深棕色，下体密布暗纹，颈后有浅色斑点；喉部有暗色条纹，比雌鸟更明显。成鸟虹膜深红褐色，蜡膜灰绿至黄绿色，脚黄色；幼鸟虹膜暗黄灰色，蜡膜绿黄色。","call":"典型的叫声是一系列尖锐的'keeveek'或'kewick'短语。","habits":"栖息于林地、灌木丛、河岸走廊和平原森林，偏好在草甸、平原和耕作区的树木簇中筑巢。迁徙性强，常以大群形式迁飞。食物包括蜥蜴、大型昆虫和各种小型鸟类，如麻雀、雀科和燕子，有时也会抢夺其他猛禽的食物。","breeding":"繁殖期在5月至6月初。巢由树枝构成的小平台，内部铺有小枝和叶子，建在树上，靠近树干，离地面4至20米高。每窝产3至5枚卵，平均3.6枚；雌鸟独自孵化30至35天，雄鸟提供食物，雌鸟喂养雏鸟。雏鸟约45天后离巢，之后数周仍依赖成鸟。性成熟于1岁。","identification":"与稍大的雀鹰相比，东雀鹰外观更整洁，翅膀更尖，更像猎隼。与非常相似的褐耳鹰和其他非洲雀鹰在越冬地进行区分。雌雄体型和颜色差异是辨识关键。","protection":"IUCN：LC（无危）。被列入CITES附录II。全球估计超过30,000对繁殖个体，总数量可能高达100,000只。","distribution":"繁殖于东南欧、乌克兰东部、俄罗斯西南至哈萨克斯坦西部，局部分布在土耳其、高加索、伊拉克和伊朗。冬季迁徙至撒哈拉以南非洲的东萨赫勒地带。","other":"在乔治亚州，这种鹰被猎鹰爱好者视为不受欢迎的物种，许多被捕获的东雀鹰因猎人试图捕捉其他更受欢迎的物种而遭到杀害。"},{"name":"赤腹鹰","english_name":"Chinese Sparrowhawk","scientific_name":"Accipiter soloensis","overview":"赤腹鹰（英文名：Chinese Sparrowhawk，学名：Accipiter soloensis），是鹰形目鹰科鹰属的鸟类。俗名: 鸽子鹰、鹅鹰、红鼻士排鲁鹞、鹰芒子（北京地区），小型猛禽，成鸟上体呈灰色，下体白色略带浅橙色，鼻孔上方有亮橙黄色斑点。广泛分布于东亚地区，包括西伯利亚东部、朝鲜半岛、中国东南部、台湾等地，冬季南迁至东南亚，最远可达印尼群岛。","appearance":"成年赤腹鹰体长25至35厘米，翼展52至62厘米，雄鸟体重约106至140克，雌鸟稍大，重125至204克。上体灰暗，下体泛淡橙色，翼尖黑色鲜明。幼鸟上体深褐色，下体具条纹，翼下横纹较淡。雌鸟比雄鸟体型更大，颜色更深，腹部橙色更明显，眼睛颜色更浅。","call":"仅在繁殖季节发声，求偶时发出尖锐的‘kee-kee-kee...’声，焦虑时则发出类似但较短促的叫声。雌鸟携带食物时发出低沉的呻吟，雄鸟接近巢穴时的叫声类似于雀鹰。","habits":"赤腹鹰栖息于山地森林、林缘地带及低山丘陵的小块丛林，偏好靠近稻田或湿地的环境，主要捕食青蛙、大型昆虫、蜥蜴和小型鸟类。狩猎时通常从栖木上俯视，也会低飞或盘旋，偶尔甚至悬停。活动范围广泛，从海平面至海拔1500米，主要在1000米以下。","breeding":"繁殖期在早到中6月，求偶时雄鹰发出炫耀性的鸣叫。巢建于树上，由枯枝和绿叶构成，平均产卵3至4枚，孵化期约为28天，幼鸟出生后22天左右离巢，不久便开始学习捕食。","identification":"与日本松雀鹰相似，但赤腹鹰的翼下横纹较淡，成鸟的翼尖黑色更加突出。幼鸟虹膜颜色可能为柠檬黄，而日本松雀鹰幼鸟虹膜为黄色。","protection":"IUCN：LC（无危）。赤腹鹰被列为国家Ⅱ级重点保护动物，同时被列入CITES附录II。","distribution":"繁殖于西伯利亚东部、朝鲜半岛、中国东南部、台湾；越冬分布自中国东南部至菲律宾和印尼群岛，北至印尼摩鹿加群岛。","other":"赤腹鹰在迁徙期间数量可观，如在日本秋迁季节，观察到过万只个体。在北苏拉威西和菲律宾东部，冬季时常见到大量赤腹鹰。"},{"name":"马岛鹰","english_name":"Frances's Sparrowhawk","scientific_name":"Accipiter francesiae","overview":"马岛鹰（英文名：Frances's Sparrowhawk，学名：Accipiter francesiae），是鹰形目鹰科鹰属的鸟类。她是开普殖民地总督洛瑞·科尔的夫人。","appearance":"马岛鹰体型小，长度介于28至35厘米之间，体重因性别而异，雄鸟约为104至140克，雌鸟则更重，可达112至185克，翼展大约40至54厘米。雄鸟胸部较淡，而雌鸟体型更大，颜色偏棕，下部有更宽和密集的条纹。幼鸟与成年雌鸟相似，但通常更苍白，有更多肉桂棕色的条纹，喉咙中间的条纹更为突出，翅膀下的淡色部分带有肉桂色。不同亚种在大小、色彩强度和腹部条纹的范围上差异明显。","call":"非常活跃的鸣叫声，特别是在繁殖季节。发出响亮、尖锐的中到高音调的‘kee kee kee’和‘kwit kwit kwit’声，音符有时单独发出，有时间隔2至3秒重复。叫声比马岛雀鹰的声音更低沉且不那么尖锐。","habits":"生活在各种原始和次生森林以及商业种植园，如桉树和咖啡园，甚至城市郊区的花园中。主要以大型昆虫为食，如蝉、蜻蜓、螳螂、甲虫等，也吃蜘蛛和小型脊椎动物，包括蛙类、变色龙、蜥蜴、啮齿类和小鸟，甚至能捕食到如家八哥大小的鸟类。通常从隐蔽处迅速出击猎物，有时在河岸边停留，飞扑向潜在的猎物。","breeding":"繁殖期主要在9月至12月，尤其是在马达加斯加和梅约特岛。筑巢于密林中的大树叉间，巢由树枝构成，内衬绿叶，高度在4.5至7米之间。一窝产蛋1至5枚，通常为2至3枚，蛋呈蓝白色，有紫色和棕色斑点。孵化期大约为30至32天，幼鸟出巢时间为25至29天。","identification":"与马岛雀鹰区分困难，尤其是幼鸟和雌鸟。通过尾下覆羽的条纹（马岛鹰有细条纹，马岛雀鹰则没有）、喉咙的图案（后者更狭窄）、背部颜色（马岛雀鹰通常更深）、腹部的图案和颜色（马岛雀鹰最白，有清晰的深色条纹，马岛鹰通常偏白，有相对较宽的棕色条纹）以及脚趾长度（马岛鹰较短）来区分。","protection":"IUCN：LC（无危）","distribution":"马岛鹰分布在马达加斯加和科摩罗群岛（除莫埃利岛外），在马达加斯加东北部的马索阿拉半岛数量最多，估计有180对。在科摩罗群岛，格里沃迪亚种在大科摩罗较为常见，但在梅约特岛数量最多，达到每2至2.6公顷一对的密度，估计总数为7225至10960对。","other":"全球种群估计至少有4万对，种群似乎稳定。尽管偶尔在马达加斯加被猎杀食用，但因其适应力强，能够在种植园和人类居住区的大花园中生存，使其对本土森林退化和损失的抵抗力较强。"},{"name":"斑尾鹰","english_name":"Spot-tailed Sparrowhawk","scientific_name":"Accipiter trinotatus","overview":"斑尾鹰（英文名：Spot-tailed Sparrowhawk，学名：Accipiter trinotatus），是鹰形目鹰科鹰属的鸟类。仅见于印度尼西亚的苏拉威西岛及其附近岛屿。其最显著的外部特征是头部淡灰色，喙与眼之间有鲜黄色标记，尾羽上有明显的白色斑点。胸部呈鲑鱼粉色，腹部为白色。该物种主要栖息于低地和丘陵地带的高大森林中。","appearance":"成年斑尾鹰体长介于26至31厘米，翼展可达45至51厘米。体型较小，翼短而尾长，上体呈铅灰色，下体白色带有葡萄酒红色调于胸及上腹部。幼鸟有两种不同的形态：一种背部具斑点，另一种上体栗色无斑。成鸟与近缘种红胸雀鹰和苏拉威西雀鹰相似，但可通过尾羽上的三（有时二）个白色斑点加以区分。雌鸟个体平均比雄鸟大17%左右。","call":"斑尾鹰发出独特尖锐的叫声，如“ki-ki-ki-ke-ke-ko”。也会发出柔和的“mow”声。","habits":"斑尾鹰通常单独活动，主要栖息于低地和丘陵地带的原始森林，高达1600米，尤其在250至1300米间最为常见。它也会出现在红树林和高大的次生林中，从树冠到林地地面均有其踪迹。这种鹰似乎全年定居。","breeding":"关于繁殖行为的信息目前尚未可知。","identification":"斑尾鹰与红胸雀鹰和苏拉威西雀鹰的区别在于尾羽上的白色斑点，以及面部的显著特征，即黄铬色的眼眶区与深色喙和眼睛形成鲜明对比。幼鸟与上述两种的幼鸟差异明显，表现为背部有斑点或上体栗色无斑。","protection":"IUCN：LC（无危）。CITES II（濒危野生动植物种国际贸易公约附录二）。在北苏拉威西较为常见，能在次生林中生存，显示出对有限的人类活动压力有一定的适应能力。","distribution":"斑尾鹰的分布局限于苏拉威西岛、Talisei（位于东北半岛）、Muna和Butung（位于东南部）。"},{"name":"灰鹰","english_name":"Grey Goshawk","scientific_name":"Accipiter novaehollandiae","overview":"灰鹰（英文名：Grey Goshawk，学名：Accipiter novaehollandiae），是鹰形目鹰科鹰属的鸟类。体型健壮的中型猛禽，以两种颜色形态存在：灰色形态和白色形态，后者被称为白鹰。灰鹰是澳大利亚东部和北部地区的特有种，其分布区覆盖了西澳大利亚东北部至昆士兰东部，维多利亚州西南部和塔斯马尼亚岛。澳大利亚大陆上最大的鹰属猛禽。","appearance":"灰鹰的成年个体长度约在44至55厘米之间，翼展可达72至101厘米。性别差异明显，雄鸟体重在238至470克之间，而雌鸟体重则在530至990克之间。灰色形态的灰鹰背部和头部呈淡灰色，翼尖深色，胸部和腹部有灰色条纹，尾部也有类似条纹。白色形态则全身纯白，两种形态的眼睛均为红色，腿为黄色。幼鸟外观类似于成鸟，但灰色幼鸟背部更偏褐色，胸部和腹部条纹较粗，且眼睛为棕色。","call":"灰鹰发出一系列‘yewik, yewik, yewik, yewik’或‘kuwit, kuwit, kuwit kuwit’的叫声，雌鸟的叫声比雄鸟低沉。","habits":"灰鹰主要栖息在雨林、高大树木的开放森林、森林边缘和相邻的开阔地带，以及河流边的画廊森林，海拔高度从海平面到大约1500米。它们偏好在森林中筑巢，尤其在昆士兰州，它们更倾向于选择比共存的褐鹰更为密集的森林。在非繁殖季节，它们可能会进入较为开阔的栖息地，偶尔还会出现在城市区域。灰鹰主要以鸟类和小型哺乳动物为食，偶尔也会捕食蛇、蜥蜴、蛙类、节肢动物甚至腐肉。","breeding":"灰鹰的繁殖期在南澳大利亚为9月至2月，在北澳大利亚则为5月至12月。它们单独繁殖，巢穴由树枝构成，内部铺有绿色叶子，宽度约为50至60厘米，深度约35厘米，通常位于大树冠层中，离地面高达15米。每窝产卵数量通常为2至3枚，孵化期约为31至34天，幼鸟出生时覆盖着白色的绒毛。幼鸟大约在30至42天后离巢，之后依赖父母38至43天。已知的最长寿命为12年，是在圈养条件下记录的。","identification":"灰鹰与褐鹰相比，翅膀更宽，且两种形态在颜色上有显著差异。此外，灰鹰在体型上比褐鹰更大。","protection":"IUCN：LC（无危）。被列入CITES附录II。全球估计少于10,000只个体，但在澳大利亚南部和西北部罕见。塔斯马尼亚的种群因森林砍伐而减少，目前估计有70至110对。东南澳大利亚也面临栖息地丧失问题。人类干扰可能导致巢穴被遗弃，但有时会在城市地区出现。DDT并未显著影响蛋壳厚度。","distribution":"灰鹰主要分布在澳大利亚的东北部至东部，包括西澳大利亚东北部至昆士兰东部，维多利亚州西南部和塔斯马尼亚岛。","other":"灰鹰与褐鹰自由杂交。"},{"name":"杂色鹰","english_name":"Variable Goshawk","scientific_name":"Accipiter hiogaster","appearance":"杂色鹰是一种中等体型的鹰，翼较短且呈圆形（在小巽他群岛的亚种中更为尖锐），尾羽短而有黑色条纹，呈现出明显的区域变异性。成年个体通常上部为灰暗色调，头部颜色稍淡；一些亚种具有红褐色颈环；下部普遍为纯红褐色，颜色深浅因亚种而异。幼鸟上部呈棕色，冠部颜色更深，下部为奶油色到淡黄色，胸腹部有棕色至红褐色的条纹或斑点。","call":"杂色鹰的常见叫声是一连串急促的、类似口哨的尖叫声，声音为“ki-ki-ki-ki-ki-ki-ki-ki-ki！”。","habits":"杂色鹰栖息于低地森林边缘地带，偏好在树上寻找猎物。它们在一定程度退化的栖息地中也能相对丰富，但对其具体的生活习性，包括繁殖、饮食和行为，目前仅有一些零星的报告。","identification":"杂色鹰与领雀鹰、褐鹰相似，但体型更大，且缺乏红褐色项圈。与摩鹿加鹰、红颈雀鹰、白颊鹰等在外观上有细微差别，可通过翼型、尾部形状、颜色模式和上体颜色进行区分。","protection":"IUCN：LC（无危）","distribution":"繁殖区域与非繁殖区域均覆盖了印尼的摩鹿加群岛和小巽他群岛，延伸至新几内亚、俾斯麦群岛和所罗门群岛。","other":"杂色鹰的复杂变异性曾使一些评论员认为这可能涉及至少三个不同物种而非单一物种，22个亚种被确认，其中一些表现出明显的多态性。"},{"name":"褐鹰","english_name":"Brown Goshawk","scientific_name":"Accipiter fasciatus","overview":"褐鹰（英文名：Brown Goshawk，学名：Accipiter fasciatus），是鹰形目鹰科鹰属的鸟类。上体呈灰色，颈背有栗色领圈，下体主要为红褐色，带有细密的白色条纹。分布广泛，主要栖息于澳大利亚及周边岛屿的桉树森林、灌木丛、农田和城市区域。","appearance":"成年褐鹰体长40-55厘米，翼展75-95厘米。雌鸟显著大于雄鸟，成年雄鸟体重约220克，雌鸟可达355克。头部厚重，喙大，腿粗壮有力。幼鸟胸部有深色斑点。热带亚种通常比温带亚种小，且颜色和体型有所差异。","call":"主要叫声为快速连续的尖锐口哨声，‘ki-ki-ki-ki…’，每秒约5个音符，通常音调和音量逐渐升高。还有较慢的‘kee…kee…kee…’，每秒约2个音符，以及上滑的喵喵声。","habits":"栖息于森林、林地和灌木丛，农田和城市区域；海拔高度从海平面至1500米。以静候狩猎为主，常从隐蔽的枝头出击，也会在低空快速飞行捕食。主要捕食小型哺乳动物、鸟类、爬行动物、两栖动物和节肢动物。","breeding":"筑巢于高树上的平台，由树枝构成，内部铺垫绿叶。通常产卵3枚（2-4枚），孵化期29-33天，雏鸟全身覆盖白色绒羽，离巢期28-37天。一岁达到性成熟，平均年生存率65%-79%，最长记录寿命11年。","identification":"与领雀鹰相比，具有更重的眉棱，圆形尾巴和强壮的腿脚，中趾较短。热带亚种可通过颈后栗色领圈与灰鹰区分开。","protection":"IUCN：LC（无危）；CITES II。在澳大利亚南部因生境破坏而局部数量减少，但兔子的引入对其有利。","distribution":"广泛分布于澳大利亚及周边岛屿，包括华莱士群岛、新几内亚、新喀里多尼亚、瓦努阿图和斐济。在太平洋地区主要栖息于雨林。","other":"历史上曾被非法猎杀，尤其是幼鸟，但影响不大。"},{"name":"黑背鹰","english_name":"Black-mantled Goshawk","scientific_name":"Accipiter melanochlamys","overview":"黑背鹰（英文名：Black-mantled Goshawk，学名：Accipiter melanochlamys），是鹰形目鹰科鹰属的鸟类。主要分布在新几内亚的山区，栖息于海拔1090至3500米的热带雨林和云雾森林中。","appearance":"成年黑背鹰具有鲜明的黑色背部、尾巴和头部罩，深棕黄色的下体和领圈，体型丰满，头部较小。翼展可达65至80厘米，长度介于32至43厘米之间，雄鸟体重约172至256克，雌鸟较大，平均体重约为294克。虹膜、蜡膜和脚部在成鸟中呈橙黄色至橙色，在幼鸟中为黄色。","call":"其叫声被描述为一系列尖锐的“kya...kya...kya”声和快速的“di di di”音符，音调先升后降。","habits":"主要以鸟类为食，如裸眶山鸠，也会捕食小型哺乳动物、蛙类和昆虫。它能在森林中飞行捕捉鸽子，追逐森林边缘和空中的鸟群，甚至在花园和次生林中悄悄狩猎，攻击被网捕的小鸟。","breeding":"关于其繁殖生态的信息未知。","identification":"与一些低地鹰种相似，但黑背鹰的上体为黑色而非灰色。幼鸟与栗肩鹰的幼鸟相似，但体型更小，头部条纹状，缺乏黑色顶冠。","protection":"IUCN：LC（无危）。被列入CITES II附录。虽然广泛分布于新几内亚大陆的所有山区，但由于生活在偏远、崎岖且森林茂密的地区，很少被观鸟者遇见。全球估计数量在1000至10,000只之间。","distribution":"分布于新几内亚的山区，包括蒙塔涅地区。","other":"生物学细节未知；物种可能受到局部森林砍伐的影响。"},{"name":"斑鹰","english_name":"Pied Goshawk","scientific_name":"Accipiter albogularis","overview":"斑鹰（英文名：Pied Goshawk，学名：Accipiter albogularis），是鹰形目鹰科鹰属的猛禽。分布于Bougainville岛和所罗门群岛，其自然栖息地为亚热带或热带湿润低地森林和山地森林。","appearance":"斑鹰体型中等，长度33至43厘米，翼展60至80厘米，雄鸟体重170至250克，雌鸟较大，重365至440克。具有灰色翅膀、背部和头部的淡色型，颈后有红褐色领圈，下部白色；黑色型全身黑色，眼色浅；中间型上黑下白。雌鸟有时全为暗色，羽毛呈石板黑色。","call":"在繁殖季节会发出类似\"ku-ku-ku...\"或\"ki-ki-ki...\"的音乐性叫声，与燕隼的叫声相似，其余时间较为沉默。","habits":"栖息于热带雨林、森林边缘、次生林、空地、本土花园和城镇边缘，海拔高度可达至少1800米。偏好森林环境，但在某些岛屿上，当灰鹰物种不存在时，它也会出现在更开阔的地带。主要以小型鸟类、蜥蜴和昆虫为食。","breeding":"繁殖行为包括空中翻滚舞蹈展示、陡峭垂直俯冲和高空盘旋。已知筑巢并育有幼鸟的时间为7月和9月。巢通常位于10至20米高的树上，可能在森林中，有时在较开阔区域。","identification":"与白颊鹰相比，斑鹰较小且更浅色，与拟雀鹰相似但更大。暗色型斑鹰在较高海拔森林内更为常见。","protection":"IUCN：LC（无危）。CITES II级。尽管在部分地区普遍，但其生物学和种群趋势几乎未知。低地的栖息地面临森林砍伐威胁，且在DDT重度使用区可能因蛋壳变薄导致繁殖失败。","distribution":"分布于所罗门群岛，包括Solomon Is.等地区。"},{"name":"白腹鹰","english_name":"White-bellied Goshawk","scientific_name":"Accipiter haplochrous","overview":"白腹鹰（英文名：White-bellied Goshawk，学名：Accipiter haplochrous），是鹰形目鹰科鹰属的中型猛禽，特有于新喀里多尼亚。成鸟头部和背部呈石板灰色，腹部白色，眼睛鲜红，腿黄色，外观独特。幼鸟上部暗褐色，下部斑驳的棕色和白色，胸部有斑点，腹部有条纹。","appearance":"成年白腹鹰的头和背部为深灰色，腹部白色，眼红色，腿黄色。幼鸟的上体为深褐色，下体则为明显的棕色和白色相间，胸部有斑点，腹部有条纹。成年雄鸟体重152至218克，雌鸟227至281克，翼展58至74厘米。","call":"发出快速而尖锐的‘tseee-tseee-tseee’叫声。","habits":"栖息于低地和山地的热带雨林边缘，海拔从海平面到1300米，偏好于比褐鹰更为密集的森林地带。以蜥蜴、壁虎、昆虫（如蚱蜢、甲虫）和小型哺乳动物（如Rattus exulans）为主食，偶尔捕食鸟类，包括鹦鹉、鸽子和家鸡。","breeding":"繁殖季节可能从九月持续到十二月，筑巢和孵化在十月进行。有关繁殖的其他信息未知。","identification":"成鸟与褐鹰相比，头部颜色更淡，有明亮的栗色领环，上体为棕色，下体有栗色条纹。幼鸟与褐鹰幼鸟相似，但体型较小，尾巴较短，头部可能更浅色。","protection":"IUCN：NT（近危）, CITES II. 在新喀里多尼亚普遍但数量正在适度减少，面临的主要威胁是森林生境的丧失和退化。","distribution":"仅分布于新喀里多尼亚的Grande Terre。","other":"法律保护物种，有时因捕食家禽而在人类居住区遭到杀害。"},{"name":"斐济鹰","english_name":"Fiji Goshawk","scientific_name":"Accipiter rufitorques","overview":"斐济鹰（英文名：Fiji Goshawk，学名：Accipiter rufitorques），是鹰形目鹰科鹰属的鸟类。为斐济特有种，分布于Viti Levu、Vanua Levu、Taveuni、Kadavu、Gau和Ovalau等较大岛屿。曾被视为澳大利亚和新喀里多尼亚褐鹰的同种。斐济鹰适应性强，栖息于多种森林环境，直至海拔1200米的高度。","appearance":"斐济鹰体长30-42厘米，雌鸟比雄鸟大11%-25%，体重雄鸟约190-209克，雌鸟约281克，翼展58-73厘米。它拥有烟灰色的背部和主要呈粉色的下部（淡灰色浸染），颈部有领状羽毛，喉部白色带有模糊的暗色中线，尾巴短而无条纹，翅膀相对短且尖（滑翔飞行时稍向上弯曲），喙部较重，腿和脚粗壮。成年人在分布范围内无可混淆，为唯一具有这些特征的Accipiter种类。两性相似，但雌鸟倾向于颈部更红，下部灰粉色更深，有时可见模糊的白色条纹。虹膜、蜡膜和腿橙黄色，幼年颜色较淡。幼鸟上部斑驳棕色，颈部边缘红色，下部奶油色至红色，黑色和红色强烈条纹，大腿和侧腹有条纹。","call":"在巢边或与幼鸟一起时非常嘈杂，尤其是在傍晚，发出尖锐的'ki...ki...ki'声，高而细的'shee-shee-shee'声，或快速重复的'weit-weit-weit'声，之后可能跟着更询问式的'queerk? queerk? queerk?'。","habits":"斐济鹰栖息于各种林木环境，从密集的森林到有树木的农田和城市公园，海拔从海平面至1200米。它们在森林、森林边缘、椰子种植园和空地上的树木中筑巢。以小型鸟类为食，最大可达Peale's Imperial-pigeon的大小，偶尔吃鸡和引进的家八哥。也捕食鼠类、蜥蜴、甲壳类和大型昆虫，罕见地从浅水区抓取小鱼和虾。幼鸟偶尔吃腐肉，年轻个体被观察到多次用脚探入草丛中尝试捕捉Red Avadavats。","breeding":"繁殖季节通常在7月至12月，多数产卵在9月至10月；2月至5月的异常记录可能代表受飓风干扰后的晚繁殖。巢为大型树枝平台，内部铺有树叶，常建在轻度叶冠覆盖的树上，高度6至16米，最高可达25米。每窝通常产2-3枚蛋（1-4枚），常见两个幼鸟成功离巢，但关于孵化和离巢期的具体信息未知。","identification":"与褐鹰相比，斐济鹰体型较小，色彩更鲜艳，无条纹。成鸟在分布范围内无可混淆的类似物种。","protection":"IUCN：LC（无危）。CITES II级。虽然分布范围和总数量有限（估计有数千只），但由于一些岛屿上仍存大量原始森林，密度高，物种普遍但研究较少。经常遭到猎杀；可能对DDT引起的蛋壳变薄和随后的繁殖抑制敏感。","distribution":"斐济鹰分布于斐济群岛（除东南部岛屿和小岛外），包括Viti Levu、Vanua Levu、Taveuni、Kadavu、Gau和Ovalau等岛屿。","other":"尽管今天认为斐济鹰仅限于斐济，但在汤加的'Eua岛上发现了归因于该物种的化石骨头。"},{"name":"摩鹿加鹰","english_name":"Moluccan Goshawk","scientific_name":"Accipiter henicogrammus","overview":"摩鹿加鹰（英文名：Moluccan Goshawk，学名：Accipiter henicogrammus），是鹰形目鹰科鹰属的鸟类。别名:灰头鹰鹰，大型暗灰色鹰科鸟类，具有深赤褐色的下体，包括成鸟的条纹大腿。黄色的眼睛、喙基和腿。幼鸟上方斑驳的棕色，下方有粗厚的条纹。栖息于从低地到山地的森林中，不翱翔，通常被观察到停歇。2010年被列入鸟类红色名录。","appearance":"摩鹿加鹰体长37至48厘米，翼展64至75厘米，属于中等到较大的鹰属物种，拥有厚重的喙。成鸟上体呈深灰色，下体赤褐色，尾部有不明显的深色横带。幼鸟上方强烈条纹，下方亦然，头部有白色条纹，背部和翅膀覆羽上有白色横条，裸露部位更绿且更淡。雌鸟比雄鸟大2至20%。","call":"发出响亮、穿透力强、加速的一系列哨声，‘kwe-ke-ke-ke-ke-ke-ke’。","habits":"居住在从海平面至1300米的森林内部，偶尔出现在森林边缘。似乎定居，但幼鸟可能有一定范围的游荡。以蜥蜴、小型鸟类（包括幼年的暗色林鹑）、小型哺乳动物和昆虫（如蚱蜢）为食，狩猎方式是在隐蔽的栖木上等待，然后快速突袭猎物。","breeding":"关于繁殖的信息目前未知。可能不会使用展示飞行，未曾报道过翱翔。","identification":"与红颈雀鹰和杂色鹰相比，成鸟缺乏赤褐色颈圈，且下体更深的赤褐色。比赤腹鹰大得多，上体、下体和下翼颜色更深。幼鸟与红颈雀鹰和Variable、Meyer’s Goshawks的幼鸟不同，因为它们有条纹而非斑点。","protection":"IUCN：NT（近危）。CITES II。在印尼北马鲁古特有种鸟区，数量看似不多，但可能比想象中普遍。初步估计成熟个体数量可达10,000只。主要威胁是森林砍伐导致的生境丧失。","distribution":"分布于印尼的摩罗泰岛、哈马黑拉岛和Bacan（北摩鹿加群岛）。在繁殖区域和非繁殖区域没有明显差异。","other":"主要威胁是商业伐木、森林清理以建立油棕、咖啡、橡胶和木材树种的种植园，以及小规模的农业迁移、采矿和定居。"},{"name":"蓝灰雀鹰","english_name":"Slaty-mantled Goshawk","scientific_name":"Accipiter luteoschistaceus","overview":"蓝灰雀鹰（英文名：Slaty-mantled Goshawk，学名：Accipiter luteoschistaceus），是鹰形目鹰科鹰属的鸟类。主要分布于巴布亚新几内亚的俾斯麦群岛，包括Umboi和新不列颠岛。具有暗灰色的上部羽毛和白色的下部羽毛，橙色的腿和面部皮肤，是低地雨林中的特有种。","appearance":"蓝灰雀鹰体型中等，翼展可达55至65厘米，雌鸟比雄鸟大，雄鸟的体重在205至222克之间。拥有短而圆的翅膀，短尾巴，大喙和长而窄的腿。下部羽毛颜色从白色到淡肉桂色或淡黄色不等，上部羽毛为板岩灰色（头部最深，肩部较浅）。雌鸟上部羽毛呈棕色，头部和颈背逐渐变黑，下部羽毛为淡黄色，胸部有更明显的棕色条纹。幼鸟上部羽毛为强烈黑色条纹的赤褐色，尾部亦然，下部羽毛除喉咙外有粗大的条纹，喉咙有细窄的中线。","call":"蓝灰雀鹰的叫声描述有限，已知的叫声包括在新不列颠岛上的幼鸟发出的尖锐‘kee...kee...'声，以及在新爱尔兰岛描述的激动时发出的‘keek-keek'声，但后者可能并非来自该物种。","habits":"栖息于低地和山丘的森林、森林边缘和部分清理过的区域，海拔从海平面至至少700米，但可能更高。在所有退化和人工环境中，其数量远少于灰鹰，但在开阔的森林和可可种植园中仍有发现。蓝灰雀鹰以15厘米长的蜥蜴为食，形态暗示它可能捕食爬行动物和昆虫。","breeding":"关于繁殖的信息稀缺，偶然的观察表明可能在新爱尔兰岛四月左右繁殖，但该物种在该岛的存在尚未得到证实。","identification":"与同域的Accipiter brachyurus相比，蓝灰雀鹰的面部皮肤和腿部为橙红色（而非黄色），中趾较短，缺乏赤褐色的领环（在短尾雀鹰中通常不明显）。与白颊鹰相比，蓝灰雀鹰体型较小，而灰头鹰可能不会出现在海拔750米以下的地方，因此与蓝灰雀鹰在海拔上可能部分分离。幼鸟的条纹比Bismarcks地区的其他鹰属幼鸟更重，而黑长尾鵟的体型要大得多。","protection":"IUCN：VU（易危）","distribution":"分布于俾斯麦群岛的Umboi（位于新不列颠岛西边）和新不列颠岛（东南部）。","other":"蓝灰雀鹰的全球种群估计在2500至9999只成熟个体之间，相当于总共3750至14,999（或约3500至15,000）只个体。主要威胁是低地和山丘森林的大规模砍伐，以及低地森林被清除用于油棕榈种植园。采矿业可能很快成为重大威胁，特别是在新不列颠岛。"},{"name":"拟雀鹰","english_name":"Imitator Goshawk","scientific_name":"Accipiter imitator","overview":"拟雀鹰（英文名：Imitator Goshawk，学名：Accipiter imitator），是鹰形目鹰科鹰属的鸟类。分布于所罗门群岛的布干维尔岛、舒瓦瑟尔岛和圣伊莎贝尔岛。栖息于海拔1000米以下的热带雨林深处。","appearance":"体长28-33厘米，翼展53-63厘米，雄鸟体重约208克，雌鸟体重在200-291克之间。成鸟背部、胸部和头部全黑，腹部白色。与斑鹰相比，拟雀鹰偏好较封闭的栖息环境，拥有黑色喉咙。飞行时，其翅膀下方有一条厚实的深色边缘，不同于斑鹰相对白色的翅膀底部。上体呈光泽的黑色，下体为石板黑色，带有清晰的横纹。","call":"叫声相对鲜为人知，但据说类似于其他雀鹰的系列尖锐哨声。","habits":"主要栖息在热带雨林和高大的次生森林中，从低地到海拔1000米。与斑鹰不同，拟雀鹰更喜欢生活在密集的森林内部。","breeding":"有关繁殖的信息极少，已知雄鸟在6月/7月可能具有扩大的生殖腺，雌鸟在10月初处于繁殖状态。","identification":"与斑鹰的区别在于其更小的体型（特别是在圣伊莎贝尔岛上）、更黑而有光泽的上体、石板黑色的下体和清晰的横纹。幼鸟的上体呈棕色，冠部有淡色斑点，下体有细小的红褐色条纹。","protection":"IUCN：NT（近危）。全球估计数量在250至999只成熟个体之间，总数量可能在350至1500只之间。","distribution":"分布于北与中所罗门群岛的布干维尔岛、舒瓦瑟尔岛和圣伊莎贝尔岛。","other":"关于其生态和生物学的研究有限，需要更多调查以确定种群规模和趋势。"},{"name":"苍头鹰","english_name":"Grey-headed Goshawk","scientific_name":"Accipiter poliocephalus","overview":"苍头鹰（英文名：Grey-headed Goshawk，学名：Accipiter poliocephalus），是鹰形目鹰科鹰属的鸟类。最显著的特征为暗灰色背部、淡灰色头部与白色腹部，面部皮肤与腿部橙色，使它在其分布范围内独一无二。分布于新几内亚及其邻近岛屿，包括Saibai岛（澳大利亚领地，托雷斯海峡西北部）。","appearance":"体长30至38厘米，翼展56至65厘米，雄鸟体重180至283克，雌鸟更大，体重225至380克。上半身呈石板灰色，头部与肩部颜色较浅，下半身主要为白色，胸部与尾下覆羽有灰色斑纹或条纹。成年个体具有明显的头部与颈背淡色区域。幼鸟上半身呈深褐色，边缘带有棕色或淡黄色，下体白色，带有粗大的胸部条纹。","call":"发出一系列尖锐、高音的哨声，持续2.5至3秒，比其他新几内亚地区的同属物种叫声更为急促。","habits":"栖息于热带雨林、森林边缘、次生林，海拔高度从海平面到1500米。以蜥蜴、小型蛇类、昆虫和其他节肢动物为主食，偶尔捕食小型鸟类。通过静止狩猎的方式从栖木发起攻击。","breeding":"繁殖季节未知，观察到的孵化时间可能在8月末至9月初。巢由树枝搭建，内部铺有叶子，位于树顶高处，已知巢穴高度可达27米。每窝产一枚蛋，内有发育中的雏鸟。具体繁殖行为细节不明。","identification":"与同属的其他五种鹰相比，灰头鹰的头部和颈背明显更淡，橙色的面部皮肤和腿使其在分布区内容易识别。罕见的黑色变异体全身黑色，尾羽和飞羽下侧有暗色条纹。","protection":"IUCN：LC（无危）。CITES II（濒危野生动植物种国际贸易公约附录二）。在新几内亚低地和山区广泛分布，包括靠近本土耕作区和破碎森林区域。","distribution":"分布于新几内亚及其周边岛屿，包括四王群岛、阿鲁群岛、亚彭岛、D'Entrecasteaux群岛和路易西亚德群岛。在澳大利亚的Saibai岛也有记录。","other":"尽管在新几内亚低地和山区常见，但其生态习性仍了解不多。"},{"name":"灰头鹰","english_name":"New Britain Goshawk","scientific_name":"Accipiter princeps","overview":"灰头鹰（英文名：New Britain Goshawk，学名：Accipiter princeps），是鹰形目鹰科鹰属的鸟类。较为罕见的大型鹰科鹰属鸟类，分布局限于新不列颠岛的森林山地。其全身均匀的板岩灰色，头部略深，下体呈淡灰色，有时带有模糊的条纹。具有橙色的眼睛、腿和喙基。成鸟特征鲜明，雌鸟体型较雄鸟大。","appearance":"灰头鹰体长38至45厘米，翼展75至86厘米，属于中到大型的鹰类。上体为板岩灰色，头部颜色最深，翅膀和尾巴颜色亦深，下体白色轻染或带有细小的灰色波状斑纹。翅膀短而圆，尾巴短，喙粗壮，腿粗且趾短。成年个体特征明显，头部颜色比近缘种苍头鹰更深，下体无横斑。","habits":"栖息于海拔760至1425米的丘陵和高山原始雨林，偶尔在低地森林出现，最低记录至海平面附近。通常观察到单个个体，或是在亚冠层栖息，或是在森林中缓慢而有力地飞行。食物包括昆虫和小型鸟类，如曾记录到捕食梅兰尼西亚地鸫（Zoothera talasea）。","breeding":"关于繁殖的信息尚不清楚。","identification":"与较小的蓝灰雀鹰相比，灰头鹰体型更大，头部颜色更浅，缺乏后者奶油色的下体。与短尾雀鹰相比，没有红褐色的颈圈，下体更灰色。与同域分布的灰鹰亚种dampieri和有明显的区别。","protection":"IUCN：VU（易危）, CITES II。灰头鹰的数量稀少且正在减少，主要受到森林砍伐的威胁。在新不列颠岛的四个样本点和少数近期记录中被发现。","distribution":"分布于新不列颠岛山区，包括诺曼比岛（巴布亚新几内亚当特尔卡斯托群岛）、塔古拉岛（巴布亚新几内亚路易西亚德群岛中部，东部，新几内亚东南部）和新不列颠岛山区（俾斯麦群岛东南部）。"},{"name":"红腿雀鹰","english_name":"Red-thighed Sparrowhawk","scientific_name":"Accipiter erythropus","overview":"红腿雀鹰（英文名：Red-thighed Sparrowhawk，学名：Accipiter erythropus），是鹰形目鹰科鹰属的鸟类。分布于西非至中非低地森林的小型鹰科鸟类。其体型接近大型鸽子，以暗黑头部、背部和尾巴以及独特的白色臀部为显著特征。腹部色彩变化多样，有时带有条纹，但喉咙总是明亮的白色。","appearance":"红腿雀鹰是一种小型的鹰科鸟类，体长22-28厘米，翼展45-57厘米，体重因性别差异而异，雄鸟78-94克，雌鸟132-170克。上身呈深灰色至黑色，有白色的臀部，下体颜色变化大，通常带有红色色调或条纹，但喉咙总是白色。雄鸟比雌鸟小，雌鸟上身颜色更偏棕色，眼环橙色至红色，喙基黄色至橙色，腿黄色至橙色。幼鸟下体有淡色斑点，下腹有条纹，裸露部位全为黄色。","call":"红腿雀鹰在繁殖季节发出快速、尖锐的‘kew-kew-kew...’叫声，与非洲小雀鹰的声音非常相似。","habits":"栖息于低地热带雨林，特别是在开阔地带和次生林附近，包括画廊森林。主要在早晨和黄昏活动，以小型鸟类和大型昆虫为食，如蜡嘴雀、织布鸟、毛虫、蝴蝶、蜻蜓、蚱蜢和有翅白蚁。在隐蔽的树冠下层捕食，也会沿着森林边缘和相邻的次生林狩猎。","breeding":"繁殖行为未知。筑巢时间为11月在象牙海岸，3月在贝宁，12月至3月在加蓬，3月至5月在塞拉利昂，7月在刚果民主共和国。巢由松散的树枝构成，建在高大的森林树木中，高度从15米到40米不等，通常在较为开阔的地方，如沼泽边缘或草地旁。每窝产2枚蛋，其他细节未记录。","identification":"与非洲小雀鹰相似，但红腿雀鹰体型较小，上身颜色更深，下体常带红色调。雌性红腿雀鹰通常比雄鸟大14%，质量可能多65-75%，上身颜色更偏棕色，眼睛颜色较淡。","protection":"IUCN：LC（无危）, CITES II（濒危野生动植物种国际贸易公约二级附录）","distribution":"广泛分布于西非至中非，包括塞拉利昂、贝宁、加蓬、刚果民主共和国等地的低地热带雨林。","other":"红腿雀鹰可能在原始森林中以高密度存在，但在西非由于能利用画廊森林和次生林，其分布范围可能并未大幅减少。"},{"name":"非洲小雀鹰","english_name":"Little Sparrowhawk","scientific_name":"Accipiter minullus","overview":"非洲小雀鹰（英文名：Little Sparrowhawk，学名：Accipiter minullus），是鹰形目鹰科鹰属的鸟类。是最小的鹰科成员之一，体型小巧，善于隐秘飞行，常穿梭于林间捕猎小型鸟类、哺乳动物及昆虫。其显著特征为白色臀部和尾羽上部的两处淡色斑点。","appearance":"体长20至25厘米，翼展39至52厘米，体重74至105克。雄鸟背部深蓝灰色，腹部具细条纹，雌鸟体型稍大，背部棕色，腹部条纹更明显。幼鸟呈褐色，腹部有黑色大斑点。成鸟喙黑，脚黄，幼鸟喙和脚呈绿黄色。","call":"发出独特的高音双音节，下降再上升的“chy-lip”声。","habits":"栖息于开阔的林地、灌木丛、森林边缘及河谷地带。活动范围广泛，从海平面到1800米海拔均有分布。主要以小型鸟类为食，偶尔捕食小型哺乳动物、蜥蜴和大型昆虫。","breeding":"繁殖期为3月至6月在埃塞俄比亚，3月至5月及10月至1月在肯尼亚，8月至12月在赞比亚。巢由细枝和绿叶构成，建于树叉中，离地面5至25米。每年新建巢穴。通常产2枚白色无斑点的蛋，孵化期31至32天，幼鸟25至27天后离巢。","identification":"与红腿雀鹰相似，但体型较小，下部更偏赤褐色，且一般缺少腹面条纹。雄鸟背部颜色较暗，雌鸟体型更大，颜色更深。","protection":"IUCN：LC（无危）","distribution":"分布于苏丹东南部、厄立特里亚、埃塞俄比亚至南非，西至安哥拉和纳米比亚。","other":"能够快速适应新环境，包括外来树种的种植园。"},{"name":"日本松雀鹰","english_name":"Japanese Sparrowhawk","scientific_name":"Accipiter gularis","overview":"日本松雀鹰（英文名：Japanese Sparrowhawk，学名：Accipiter gularis），是鹰形目鹰科鹰属的小型猛禽。体长23至30厘米，翼展46至58厘米，雄鸟重约92至142克，雌鸟略大，重约111至193克。上体深灰，下体白色带灰褐色条纹，雄鸟侧身泛红棕色，雌鸟腹部具重暗棕条纹。喉咙有一细窄纵纹，尤其在雌鸟中更为明显。分布于俄罗斯东部、朝鲜半岛、日本和中国东北部。","appearance":"日本松雀鹰体型小巧，翅膀宽圆，尾巴较短。成年雄鸟背部呈黑色石板状，颈部后方白色，下体白色，带有灰色至红棕色的细条纹。雌鸟背部棕色，下体白色，腹部有较重的棕色条纹。喉咙有中线纵纹，雄鸟较不明显。幼鸟上体暗棕色，下体奶油色，胸部有红棕色条纹，腹部有斑点和侧边条纹，眼上方和颈部后方白色，尾羽有细条纹。眼睛初期棕色，后期黄色，脚黄绿色。","call":"发出尖锐的'kee-bick'声和猫叫般的'kew-kew'声，有时快速连续的'kik-kik-kik'声。","habits":"栖息于多种森林类型，包括常绿、落叶和混合林，海拔可达1800米，偏好靠近河流的南部泰加林和亚高山地带。迁徙和冬季时可见于村落及开阔地带，混杂有灌木丛和农田的树林边缘。主要食物为小型森林鸣禽，偶尔也会捕食中型鸟类、小型哺乳动物、昆虫和爬行动物。","breeding":"繁殖期较晚，通常在6月开始。在树上筑巢，靠近树干，离地面约10米高。巢由树枝构成，内部铺垫树叶和树皮。每窝产2至5枚卵，孵化期25至28天。幼鸟在日本于6月离巢，西伯利亚则为8月。","identification":"与赤腹鹰的区别在于翼尖不黑，翼下横纹明显，下体条纹较细。雌鸟比雄鸟大15%，虹膜颜色不同。","protection":"IUCN：LC（无危）","distribution":"繁殖于俄罗斯东部、朝鲜半岛、日本和中国东北部。迁徙时遍及东南亚、菲律宾、印度尼西亚等地，台湾和琉球群岛南部的亚种为留鸟。","other":"在城市郊区的日本，日本松雀鹰自1981年开始繁殖，数量似乎有所增加。然而，其首选筑巢树种——日本红松的减少可能影响其数量。"},{"name":"松雀鹰","english_name":"Besra","scientific_name":"Accipiter virgatus","overview":"松雀鹰（英文名：Besra，学名：Accipiter virgatus），是鹰形目鹰科鹰属的鸟类。别名: 松儿、松子鹰、摆胸、雀贼、雀鹰、雀鹞，为鹰科鹰属中的中等体型猛禽。其外观与凤头鹰相似但体型较小，无冠羽。广泛分布于南部亚洲的密集森林中，自印度次大陆向东延伸至东南亚及东亚。在中国属于国家二级保护动物。","appearance":"松雀鹰体长24至36厘米，翼展42至70厘米。雄鸟体重介于83至140克，雌鸟则为131至215克，雌鸟比雄鸟大15至25%。成年松雀鹰上身灰褐，头部和颈部颜色更深，下体具橙色条纹和斑点。雄鸟背部黑石板色至黑褐色，脸颊有深蓝色斑块，胸部和两肋红肉桂色，腹部有条纹，尾下覆羽无斑纹。雌鸟背部偏褐色，眼睛颜色较淡。幼鸟整体呈褐色，下体有纵斑。各亚种在体型和色彩强度上有差异。","call":"发出响亮的‘ki-weeer’叫声和快速连续的‘tchew-tchew-tchew’音节，后者可能为幼鸟求食时所发。","habits":"松雀鹰栖息于各种森林环境中，包括湿润的落叶林和常绿山地森林、次生林、种植园、红树林和松林，高度范围从海平面至2200米。主要以鸟类为食，也会捕食昆虫和蜥蜴。狩猎方式敏捷，从隐蔽处快速追逐目标。在台湾北部的繁殖季节（1993-2002年），其饮食以树冠层和森林灌木中的鸟类为主（占总数的58%，生物量的82%），其他食物包括哺乳动物（3%）、爬行动物（7%）、两栖动物（0.2%）和昆虫（32%）。","breeding":"繁殖季节因地区而异，一般在1月至6月间。巢由成对的松雀鹰用树枝搭建，位于地面10至25米的大树上，通常建在悬崖边俯瞰峡谷。每窝产卵3至4枚（范围2至5枚），孵化期约为28天，幼鸟成长期为22至23天，离巢后约四周内分散。","identification":"松雀鹰与凤头鹰相比，体型更小，缺乏冠羽，且腹部橙色调较淡，头部与背部之间羽色差异明显。幼鸟整体偏褐色，胸腹部有褐色纵斑。","protection":"IUCN：LC（无危）。《濒危野生动植物种国际贸易公约》附录二。全球数量接近100,000只，主要威胁为森林砍伐。","distribution":"松雀鹰广泛分布于南部亚洲，从印度次大陆向东跨越东南亚至东亚。在中国，它分布在多个省份，冬季时会迁移到较低海拔的山区。","other":"在某些地区，如印度平原和爪哇低地，松雀鹰不常见，这可能是因为森林的消失。"},{"name":"苏拉雀鹰","english_name":"Dwarf Sparrowhawk","scientific_name":"Accipiter nanus","appearance":"苏拉威西雀鹰具有紧凑的体型，眼黄，喙基部呈淡绿色，腿黄色。成鸟上体为灰色，胸部呈紫红色，腹部和大腿部白色。幼鸟上体红褐色，下体白色，有暗色条纹。其翅膀和尾巴的比例与同属其他物种有细微差别。","call":"发出尖细、高音的‘kiliu’声，有时随后跟连续急促的‘ki-ki-ki-ki-ki’叫声，比红胸雀鹰的声音更高。","habits":"主要栖息于山地和丘陵森林，海拔900至2250米，偶尔降至550米。在Buton岛上，也有在海平面附近的记录。食性包括蚱蜢、蝉和其他大型昆虫，小型鸟类（含幼禽）和蜗牛。","breeding":"繁殖信息极为有限。已知的巢穴位于山地森林中的树干旁的小型结构，六月发现。八月在同一巢下发现一枚蛋。","identification":"与红胸雀鹰和斑尾鹰相比，苏拉威西雀鹰更小，尾巴更短，喙和脚趾更短。从飞行中的白色翼下和无斑点的大腿可以区分于日本雀鹰。眼睛颜色帮助区分斑尾鹰和中国及日本雀鹰。","protection":"IUCN：LC（无危）。CITES II级保护。在苏拉威西岛较为罕见，被认为是当地最少见的鹰科成员。由于栖息地丧失而面临威胁。","distribution":"主要分布在苏拉威西岛的山区，除了西南部和东南部。在Buton岛有记录，最近在苏拉威西岛东南半岛南部也有记录。","other":"尽管记录地点不多，但可能因为与更常见的红胸雀鹰相似而被低估。全球种群数量未知，但记录稀缺暗示其数量适中偏小。"},{"name":"红颈雀鹰","english_name":"Rufous-necked Sparrowhawk","scientific_name":"Accipiter erythrauchen","overview":"红颈雀鹰（英文名：Rufous-necked Sparrowhawk，学名：Accipiter erythrauchen），是鹰形目鹰科鹰属的鸟类。属于鹰科鹰属的鸟类。其最显著的特征是颈部的红褐色带状羽毛，分布于印尼摩鹿加群岛的北部和中部，为华莱士区特有种。","appearance":"体型较小而修长，上体呈暗石板灰色，下体为橙黄色至粉红色，颈项处有一圈红褐色环带。成鸟的眼睛为橙黄色，幼鸟则颜色较淡。嘴基黄色，腿脚绿色。雌鸟比雄鸟大13-28%，颜色略深，腹部灰色更浓。幼鸟上体黑褐色，下体具棕色条纹。","habits":"栖息于低地和山丘的原始森林，海拔高度可达1450米。在树植园和选择性砍伐的低地森林中也能见到。以小型鸟类为食，捕猎方式典型，快速从隐蔽的栖木冲出追击猎物。","identification":"与摩鹿加鹰、摩鹿加鵟、可变鵟和北摩鹿加可变鵟的区别在于红褐色的颈环和腹部颜色。幼鸟的腹部有条纹，不同于其他种类的幼鸟。体型小于摩鹿加鵟、白颊鹰和北摩鹿加可变鵟。","protection":"IUCN：NT（近危）, CITES II。受商业伐木、森林清理和农业扩张的威胁，导致其栖息地减少。","distribution":"分布于印尼的摩鹿加群岛北部和中部，包括塞兰岛等地。","other":"红颈雀鹰是印尼摩鹿加群岛的特有种，其种群数量估计在10,000成熟个体左右。"},{"name":"领雀鹰","english_name":"Collared Sparrowhawk","scientific_name":"Accipiter cirrocephalus","overview":"领雀鹰（英文名：Collared Sparrowhawk，学名：Accipiter cirrocephalus），是鹰形目鹰科鹰属的鸟类。体型较小、构造精细的灰鹰科鸟类，以橙色横斑胸腹为显著特征。分布于澳大利亚、新几内亚及其周边岛屿，偏好森林、林地和灌木丛环境。","appearance":"领雀鹰体长27至38厘米，翼展53至77厘米，雄鸟体重100至156克，雌鸟162至300克。头部灰色，有锈色颈环和锈色条纹腹部。成年鸟具黄色眼睛、绿黄色蜡膜和细长的黄色腿脚。幼鸟上体棕色，下体白色带重褐色条纹。","call":"在繁殖季节发出\"ki-ki-ki-ki\"的嘁嘁喳喳声和柔和的\"wit wit wit\"叫声。","habits":"栖息于森林、林地、灌木丛，包括树木繁茂的农田和城市区域，偏好有零星树木的开阔地带。以小型鸟类为主食，如雀科和椋鸟，偶尔捕食蜥蜴、昆虫和小型哺乳动物。通过隐蔽的树上狩猎或低空快速飞行捕食。","breeding":"筑巢于4至40米高处的活树叉上，由枝条构成，铺以绿色叶子，通常有3至4枚蛋，孵化期35至37天，雏鸟约28至33天离巢，之后依赖父母约6周。","identification":"与同属物种相比，具有方形或凹形而非圆形的尾尖，细长的腿和较长的中间趾。成年鸟的眼睛、蜡膜和脚的颜色可作为识别特征。","protection":"IUCN：LC（无危）；CITES II级；在部分区域可能因栖息地丧失和竞争对手增加而受影响。","distribution":"广泛分布于澳大利亚大陆、塔斯马尼亚岛、新几内亚及邻近岛屿，包括城市和森林地带。","other":"其数量可能因DDT使用导致的蛋壳变薄而减少，现已停止使用DDT。"},{"name":"短尾雀鹰","english_name":"New Britain Sparrowhawk","scientific_name":"Accipiter brachyurus","overview":"短尾雀鹰（英文名：New Britain Sparrowhawk，学名：Accipiter brachyurus），是鹰形目鹰科鹰属的鸟类。主要栖息于新不列颠岛和新爱尔兰（俾斯麦群岛东部）的热带雨林地带。这种鹰拥有深灰色的背部、鲜明的红褐色领圈和淡灰色的腹部，其最显著的特征之一是较短的尾巴和细长的翅膀。雌鸟个体通常比雄鸟大20%左右，这是区分性别的关键点。","appearance":"短尾雀鹰是一种小型猛禽，体长介于27至36厘米之间，翼展可达50至62厘米。其背部呈黑色石板色，冠部颜色最深，具有清晰的红褐色领圈，喉咙和腹部偏白色，胸部淡灰色并逐渐转变为红褐色。翅膀尖锐，尾巴非常短，喙基部相对较宽，腿和脚趾长而窄。虹膜为深红色（幼鸟为棕色），蜡膜绿色至黄绿色（幼鸟更绿），腿色从黄色至橙黄色（幼鸟腿色较浅）。幼鸟的上半身和尾巴有强烈的暗色条纹，头顶黑色带有红褐色边缘的羽毛，下体为淡土黄色，粗略条纹为棕色。","call":"关于短尾雀鹰的鸣叫声，目前尚无具体描述。","habits":"短尾雀鹰主要栖息于热带雨林、森林边缘以及部分清理过的区域，活动范围从海平面至至少900米的高度，但在新爱尔兰的记录显示，它们可以出现在1200至1800米的高海拔。关于迁移行为的信息未知，但推测幼鸟可能在一定程度上会游荡。据其形态学特征推测，它们可能猎食密林中的小型鸟类。","identification":"短尾雀鹰与同域分布的蓝灰雀鹰的区别在于前者具有红褐色领圈且面部和腿部裸露皮肤并非橙红色。与灰头鹰相比，短尾雀鹰体型较小，颜色更深，上下体色均较暗，且无橙红色的裸露皮肤。幼鸟与成鸟的差异主要体现在颜色和条纹上。","protection":"IUCN：VU（易危）, CITES: 附录II。短尾雀鹰数量稀少，仅在两个岛屿上发现，且数量正在下降，特别是在低地森林中。在新不列颠岛和新爱尔兰岛，森林砍伐是主要威胁，尤其是油棕榈种植园的扩张。未来，采矿业也可能成为威胁。","distribution":"短尾雀鹰分布于新不列颠岛和新爱尔兰（俾斯麦群岛东部），主要生活在热带雨林环境中。","other":"短尾雀鹰是新不列颠岛和所罗门群岛中唯一拥有较长中趾的鹰种，这一特征有助于其在密集的森林环境中捕食。"},{"name":"红胸雀鹰","english_name":"Vinous-breasted Sparrowhawk","scientific_name":"Accipiter rhodogaster","overview":"红胸雀鹰（英文名：Vinous-breasted Sparrowhawk，学名：Accipiter rhodogaster），是鹰形目鹰科鹰属的鸟类。小型猛禽，特征为黄色眼睛、浅绿色喙基和黄色腿脚。成年个体上部呈板岩灰色，胸部为酒红色，腹部和大腿颜色较淡。幼鸟背部呈深赤褐色，饰以鲜明的黑褐色斑点和条纹，下部则有厚重的淡色条纹。红胸雀鹰主要分布于印尼的苏拉威西岛、邦盖群岛和苏拉群岛，生活在从海岸至山地的森林环境中，亦可见于红树林和林地。","appearance":"成年红胸雀鹰体长26-33厘米，体重在113克（雄鸟）至264克（雌鸟）之间，翼展可达46-62厘米。拥有黑色的上部，短而圆的翅膀，相对短且方尾。幼鸟上部深赤褐色，饰以黑褐色斑点和条纹，尾巴较淡，具4-5条暗色带，头部和颈后部有白色痕迹，下部为白色或棕黄色，带有厚重的暗色条纹。雌鸟比雄鸟大35%左右，平均大23%，上部更偏棕色，下部酒红色更淡，喉咙、腹部和大腿有更多灰斑。","call":"红胸雀鹰非常善于鸣叫，其叫声被描述为迅速连续的“hihihihihi...”，每1.8秒发出约20个音符，当受到播放声音刺激时会变得更加激动。","habits":"红胸雀鹰栖息于初级和次级森林，海拔高度从海平面至2000米，也出现在红树林和靠近森林村庄的环境以及有部分林地的耕作区。其饮食包括昆虫、蜥蜴、松鼠、小鼠和小型雀鸟，结构特征表明它主要以鸟类为食。","breeding":"关于繁殖的资料极少，但已知在3月底至4月初，在Peleng岛的阔叶树叉上发现过一个活跃的巢穴，由枯枝构成，位于约15米的高度。","identification":"与小型雀鹰相比，红胸雀鹰的叫声更深沉、不那么尖锐，雌鸟个体体型更大，喙、尾和脚趾更长。与斑尾鹰和成年中华及日本松雀鹰的区别在于眼色、尾部斑点和大腿颜色。","protection":"IUCN：LC（无危）。《华盛顿公约》CITES II级。在苏拉威西岛广泛分布但数量似乎不多；可能比想象中更常见，对未受干扰的森林依赖程度可能低于苏拉威西岛上其他鹰属物种。","distribution":"红胸雀鹰主要分布于印尼的苏拉威西岛、邦盖群岛和苏拉群岛（东部）。","other":"系统发育历史显示，红胸雀鹰可能与红颈雀鹰、领雀鹰和短尾雀鹰属于同一物种群。"},{"name":"马岛雀鹰","english_name":"Madagascar Sparrowhawk","scientific_name":"Accipiter madagascariensis","overview":"马岛雀鹰（英文名：Madagascar Sparrowhawk，学名：Accipiter madagascariensis），是鹰形目鹰科鹰属的鸟类。中等体型的雀鹰，背部灰色，腹部有细腻的灰色横条纹。雌鸟体型显著大于雄鸟。仅在马达加斯加发现，属于该岛特有的稀有森林居民。其独特之处在于未被横条纹覆盖的尾下覆羽、喉部的细小纹理，以及异常长的中央脚趾。","appearance":"马岛雀鹰体长29至42厘米，体重在285至348克之间，翼展可达50至69厘米。拥有小型喙、短而圆的翅膀及中等长度带暗色条纹的尾巴。成年个体上身暗灰褐色，下身白色条纹较深，与同域物种相比更为暗淡。幼鸟上身淡棕色，具红褐色边缘的羽毛，颈背有白色条纹。虹膜橙黄色，喙黑色，蜡膜及腿绿色偏黄。","call":"通常发出单个短促、高音调、尖锐或机械感的“whik”、“whisk”或“eeesk”声，以1至4秒间隔重复。另一种叫声“kwee-kwee-kwee”极为少见，但在食物传递时最常听到。","habits":"栖息于马达加斯加各种类型的森林，从低地雨林到海拔1500米的山地森林，主要在1000米以下。偏好在隐蔽的树冠层或中层活动，偶尔在退化森林或异域树木种植园出现。以小型鸟类为主食，辅以昆虫、蛙类和爬行类（主要是壁虎）。狩猎方式为隐蔽等待，然后快速追逐并捕获猎物。","breeding":"繁殖季节在10月和11月。筑巢于森林树中，高度20至28米，巢由细枝构成，宽约50厘米，深约25厘米。每窝产1至4枚卵，孵化期约为35天，幼鸟在36至39天首次离巢，直到60至67天才独立。","identification":"与亨氏鹰相比，体型较小且更纤细；与马岛鹰的区别在于尾下覆羽无条纹、喉部窄条纹、上身颜色更深、下身条纹和颜色更鲜明，以及中央脚趾的长度。","protection":"IUCN：NT（近危）；CITES II级；全球数量估计在10,000至100,000之间，但由于生境丧失导致数量可能正在迅速减少。","distribution":"仅分布于马达加斯加，除了中部地区。在多个保护区有记录，但在退化生境中极少被观察到。","other":"对马岛雀鹰的生态研究和种群数量调查亟需加强，以评估其真实状况和采取相应保护措施。"},{"name":"雀鹰","english_name":"Eurasian Sparrowhawk","scientific_name":"Accipiter nisus","overview":"雀鹰（英文名：Eurasian Sparrowhawk，学名：Accipiter nisus），是鹰形目鹰科鹰属的鸟类。又名: 有黄鹰、鹞鹰、♂ 细胸、♀ 鹞子，中等体型的鹰科鸟类。具有明显的雌雄异型，雌鸟比雄鸟大25%，这是鸟类中最大的性别差异之一。雄鸟有蓝灰色背部和橙色条纹腹部，而雌鸟和幼鸟则为棕褐色。雀鹰广泛分布于欧亚大陆的温带和亚热带地区。","appearance":"雄性雀鹰身长29-34厘米，翼展59-64厘米，重110-196克；雌鸟更大，身长35-41厘米，翼展67-80厘米，重185-342克。雄鸟上体蓝灰色至灰蓝色，下体橙色条纹，眼虹膜橙黄色至橙红色。雌鸟上体暗棕色至灰褐色，下体棕色条纹，眼虹膜鲜黄至橙色。幼鸟上体暖棕色，有锈色边缘，下体粗条纹或斑点，眼虹膜淡黄色。","call":"发出一系列\"kek-kek-kek-kek-kek\"的咯咯叫声，音量和单个音符的传递速度有变化。","habits":"雀鹰栖息于各种森林类型，包括针叶林、阔叶林和混合林，也出现在较开阔的林地，城市公园和郊区。从海平面到4500米的山区都有分布，通常在树线附近筑巢并在树线上方觅食。偏好林地和开阔地带交错的环境。","breeding":"繁殖期为4月至6月，筑巢于树木中，一般每年建新巢。每窝产卵3-6枚，孵化期约32-34天，主要由雌鸟孵化。雏鸟孵化后24-30天离巢，父母继续喂养3-4周。性成熟期为1-3年。","identification":"与苍鹰相比，体型较小，尾巴更长，翅膀更圆，下体有横向条纹而非纵向条纹。雌雄在颜色和大小上有显著差异。","protection":"IUCN：LC（无危）","distribution":"繁殖区遍布欧亚大陆，非繁殖区扩展至东洋界和非洲东北部。在英国和爱尔兰，以及南部繁殖范围内是留鸟。","other":"雀鹰的全球估计种群数量至少为100万对。历史上曾因有机氯农药使用而急剧减少，自1960年代和1970年代禁用后，种群已逐步恢复。"},{"name":"棕胸雀鹰","english_name":"Rufous-breasted Sparrowhawk","scientific_name":"Accipiter rufiventris","overview":"棕胸雀鹰（英文名：Rufous-breasted Sparrowhawk，学名：Accipiter rufiventris），是鹰形目鹰科鹰属的小型猛禽。以独特的橙色腹部和深灰色背部著称，广泛分布于非洲东部、东南部和南部，包括安哥拉、刚果民主共和国、埃塞俄比亚等地。","appearance":"棕胸雀鹰是一种中等体型的雀鹰，背部呈暗灰色，腹部为纯正的橙色，喉部和下腹部为白色。成鸟的头部、背部和翅膀均为灰黑色，黄色的眼睛、蜡膜和脚趾十分显眼。幼鸟背部为棕色，腹部有锈红色条纹和斑点。两性相似，但雌鸟平均比雄鸟大16%，且颜色更深更鲜艳。幼鸟与幼年赞比亚雀鹰的区别在于黄色的眼睛。","call":"成鸟展示时会发出尖锐的连续‘kee-kee-kee-kee-kee’叫声。幼鸟乞食时发出喵喵声。","habits":"栖息于山地森林，但在开阔地带如草原、灌木丛和异域树种植园附近狩猎。主要分布在海拔2000-3000米之间，但在南非可低至海平面。以鸟类为主食，大小从10-90克，甚至能捕食鸽子大小的猎物，同时也会捕食蝙蝠、啮齿动物、蜥蜴和昆虫。狩猎时通常从隐蔽处或低空飞行中迅速出击。","breeding":"繁殖季节在乌干达为7月，在南非为9月至12月。筑巢于树的高叉处，巢由小树枝构成，内部铺有树叶、树皮和苔藓，高度在6-18米之间。每窝产卵2-4枚，孵化期约为34天，雏鸟覆盖白色绒羽，离巢时间为31-36天，离巢后依赖父母的时间为22-41天。","identification":"与赞比亚雀鹰的主要区别在于眼睛的颜色和背部羽毛的均匀深色。雌鸟和雄鸟的辨识在于雌鸟的体型更大，颜色更深。","protection":"IUCN：LC（无危）。CITES II。在南非特兰斯瓦尔地区的密度为每23-33平方公里一对。易受本土森林碎片化和山地木材砍伐的影响，但适应了异域树种植园，因此在开普敦郊区常见。全球数量估计至少有数十万只，南非的数量正在增加，而东非由于栖息地丧失而减少。","distribution":"分布于非洲东部、东南部和南部，包括安哥拉、刚果民主共和国、埃塞俄比亚、肯尼亚、南非、坦桑尼亚、乌干达等地。在南非，从海平面到山区均有分布。","other":"其范围随非本地松树物种的引入而扩展。"},{"name":"纹腹鹰","english_name":"Sharp-shinned Hawk","scientific_name":"Accipiter striatus","overview":"纹腹鹰（英文名：Sharp-shinned Hawk，学名：Accipiter striatus），是鹰形目鹰科鹰属的鸟类。是北美洲体型最小的鹰类。成鸟上体灰蓝，下体橙红横斑；幼鸟褐色，下体纵纹。性凶猛，专以小型鸟类为主食，活跃于各类林地，自阿拉斯加至阿根廷均有分布，北方种群具迁徙习性。","appearance":"体小，翼短而圆，尾长呈方形。雄鸟体长24–27厘米，翼展53–56厘米，体重87–114克；雌鸟体长29–34厘米，翼展58–65厘米，体重150–218克，性别差异极显著。成鸟上体青灰，冠部略深；尾具3–5条暗色横带及白端。下体白色，胸腹及两胁具密集的橙红或茶褐色横斑；眼橙红至红色；蜡膜与足黄色。幼鸟上体暗褐，下体乳白至淡黄，胸腹具粗阔的深褐色纵纹；眼淡黄。各亚种在羽色浓淡、横斑多少及体型大小上差异显著。","call":"通常寂静。繁殖季发出尖锐连续的“kew-kew-kew”或“kek-kek-kek”声，音调高于库氏鹰；受惊时发出细薄快速的告警声。雏鸟乞食时发出高音“ee”。","habits":"繁殖期栖息于针叶林、针阔混交林及山地松林，海拔自海平面至3500米。北方种群秋季南迁，经主要迁徙通道集中；南方种群多为留鸟。冬季进入城市、郊区及灌丛，常潜伏于鸟食器附近伏击小型鸟类。飞行快速灵活，翼拍急促，能在密林中穿梭追捕猎物。","breeding":"一夫一妻，4–5月抵达繁殖区。巢筑于树干水平枝杈上，距地2.5–20米，由枯枝构成，内衬树皮及绿叶。每窝产卵3–5枚，偶达8枚；卵乳白或淡蓝白，具褐、紫或栗色斑块。孵化期约30–32天，仅雌鸟孵卵，雄鸟供食。雏鸟24–32日龄离巢，再依赖亲鸟3–4周。波多黎各种群可育第二窝。","identification":"与库氏鹰极似，但体型更小，头相对较小，尾端更方，足更纤细；翼拍节奏更快。雌纹腹鹰与雄库氏鹰大小接近，但尾形及头身比例仍可区分。幼鸟眼下具明显的浅色眉纹，尾端白尖较小。与其他同属种类相比，体型最小且羽色较淡。","protection":"IUCN: LC（无危）。列入CITES附录Ⅱ。部分州（如田纳西）列为受威胁种。","distribution":"繁殖于阿拉斯加、加拿大全境、美国本土至墨西哥北部及大安的列斯群岛山区；南美的委内瑞拉、哥伦比亚、厄瓜多尔、秘鲁、玻利维亚、巴西、巴拉圭至阿根廷北部。北方种群冬季南迁至美国南部、中美洲至巴拿马及西印度群岛。","other":"历史上因捕食鸣禽被视为害鸟，迁徙通道曾遭大量猎杀。DDT时期种群显著下降，禁用后恢复。因冬季利用喂食器狩猎，出现迁徙“短停”现象，导致东部监测站点数量下降，但北部越冬数量上升。"},{"name":"白胸鹰","english_name":"White-breasted Hawk","scientific_name":"Accipiter chionogaster","overview":"白胸鹰（英文名：White-breasted Hawk，学名：Accipiter chionogaster），是鹰形目鹰科鹰属的鸟类。小型鹰科鹰属鸟类。分布于中美洲，从墨西哥南部至尼加拉瓜，具有独特的白色胸部特征。","appearance":"白胸鹰体型较小，雄鸟长度23到30厘米，翼展42到58厘米，体重82至115克。雌鸟明显较大，平均长度30至37厘米，翼展58至68厘米，体重150至219克。其翅膀宽短，尾部中等长度，具黑灰相间的横带，末端形状因个体而异。上体颜色较暗，近似黑色，下体和脸颊全白，腿长而细，黄色，喙钩状，黑色，蜡膜黄色。","habits":"白胸鹰主要栖息于松林、松栎混交林，常光顾邻近的云雾林、热带干林和农田，海拔300至3000米。它们以隐蔽突袭的方式捕猎，主要以小型鸟类为食，如多种鸣禽，偶尔也会捕食蜥蜴、蝙蝠和大型昆虫。","breeding":"白胸鹰在树枝上筑巢，产卵2至4枚，蛋的尺寸约为38×31毫米，重约19克。孵化期约30天，雌鹰主要负责孵卵和照顾雏鸟，雄鹰则负责领地防御和捕食。幼鸟约一个月后离巢，再依赖父母四周。","identification":"白胸鹰与纹腹鹰相似，但上体颜色更暗，大腿部分呈白色至肉色，下体和脸颊全白。幼鸟上体颜色更深，下体条纹比纹腹鹰幼鸟更细。","protection":"IUCN：NT（近危）","distribution":"分布于中美洲，从墨西哥南部的恰帕斯和瓦哈卡，经洪都拉斯、危地马拉和萨尔瓦多，至尼加拉瓜。","other":"白胸鹰的分类存在争议，部分权威认为它与纹腹鹰和淡胸鹰代表三个独立物种。当前作为 纹腹鹰 的亚种。"},{"name":"淡胸鹰","english_name":"Plain-breasted Hawk","scientific_name":"Accipiter ventralis","overview":"淡胸鹰（英文名：Plain-breasted Hawk，学名：Accipiter ventralis），是鹰形目鹰科鹰属的鸟类。由纹腹鹰的南方种群拆分而来。分布于南美洲，自委内瑞拉至玻利维亚西部，其分类地位仍在讨论中，某些权威将其视为独立物种。","appearance":"体型小，雄鸟长23至30厘米，翼展42至58厘米，体重82至115克。雌鸟明显较大，长约29至37厘米，翼展58至68厘米，重150至219克。羽色多样，常见型上体灰暗，下体白至红褐色条纹或斑点，少有全白色下体或深色变种。幼鸟上体棕色，下体白色带棕色条纹，大腿部红褐色。","habits":"栖息于热带至温带高地，海拔300至3000米，偶尔低至海平面或高达4000米。主要以小型鸟类为食，如雀鸟、莺鸟、雀鹀、鹪鹩、山雀、黄鹂和鸫鸟。善于在密林中迅速飞行捕猎，也会利用鸟食器吸引猎物。偶尔捕食鼠类、蜥蜴、蛙类、蛇类和大型昆虫。","breeding":"筑巢于树枝间，每窝产卵3至8枚，平均4至5枚。卵长37.6毫米×宽30毫米，重约19克。孵化期约30天。雏鸟孵化后，雌鸟负责孵化和照顾，雄鸟保护领地和捕食。幼鸟约一个月离巢，再依赖父母喂养四周。","identification":"与纹腹鹰、白胸鹰和红腿鹰在形态上有显著差异，尤其是在羽色、体型和分布上。具体辨识需结合外观、行为和分布区。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲，从委内瑞拉沿海山脉到哥伦比亚，南至安第斯山脉，经委内瑞拉、哥伦比亚、厄瓜多尔、秘鲁至玻利维亚中部，以及委内瑞拉南部特普伊山区。","other":"当前作为 纹腹鹰 的亚种。"},{"name":"红腿鹰","english_name":"Rufous-thighed Hawk","scientific_name":"Accipiter erythronemius","overview":"红腿鹰（英文名：Rufous-thighed Hawk，学名：Accipiter erythronemius），是鹰形目鹰科鹰属的鸟类。小型鹰科鹰属鸟类，由纹腹鹰的南方种群拆分而来。分布于南美洲的玻利维亚东南部和巴西南部至巴拉圭、乌拉圭及阿根廷北部。红腿鹰以其独特的黄色长而细的腿著称。","appearance":"红腿鹰体型小，雄鸟长度23至30厘米，翼展42至58厘米，体重82至115克。雌鸟显著更大，平均比雄鸟长约30%，体重优势超过50%，体长29至37厘米，翼展58至68厘米，体重150至219克。成鸟具短宽的翅膀和中等长度的尾巴，尾巴带有黑色和灰色条带，尖端形状各异。上体颜色较深，下体有赤褐色或暗色条纹，脸颊通常有一块清晰的赤褐色斑块。虹膜黄色，钩状喙黑色，蜡膜淡黄色。","habits":"红腿鹰栖息于热带和亚热带地区的低地和高地，它们擅长在密集的植被中快速飞行以捕猎。主要以小型鸟类为食，包括雀科、莺科、雀鵙科、啄木鸟科等。偶尔也会捕食啮齿动物、蜥蜴、蛙类、蛇和大型昆虫。","breeding":"红腿鹰在树枝上筑巢，每窝产卵3至8枚，常见的是4至5枚。卵的尺寸约为37.6毫米×30毫米，重约19克。孵化期大约30天。幼鸟孵化后，由雌鸟抚育16至23天，雄鸟则负责守卫领地和捕食。幼鸟大约一个月后离巢，再依赖父母喂养和保护四周。","identification":"红腿鹰与纹腹鹰相似，但上体颜色更深，下体条纹呈赤褐色或暗色，脸颊常有明显的赤褐色斑块。虹膜黄色，与一些书籍中的插图描述相反。","protection":"IUCN：LC（无危）","distribution":"红腿鹰分布于南美洲，包括玻利维亚东南部和巴西南部，延伸至巴拉圭、乌拉圭和阿根廷北部。","other":"当前作为 纹腹鹰 的亚种。"},{"name":"库氏鹰","english_name":"Cooper's Hawk","scientific_name":"Accipiter cooperii","overview":"库氏鹰（英文名：Cooper's Hawk，学名：Accipiter cooperii），是鹰形目鹰科鹰属的鸟类。以森林环境中的树木为栖息地，广泛分布于北美洲，从加拿大南部到墨西哥北部。具有显著雌雄异型性的物种，雌鸟比雄鸟大三分之一左右。库氏鹰主要捕食中型鸟类和小型哺乳动物，其独特的猎食技巧和敏捷的飞行能力使其成为高效的掠食者。","appearance":"库氏鹰拥有相对短而圆的翅膀和圆尾，成年个体上部灰色，下部橙色条纹；幼鸟则呈棕色，有斑驳的羽毛。雌雄外观相似，但雄鸟通常比雌鸟颜色更鲜艳。背部和上翼覆羽蓝灰至棕色，腹部有红褐色条纹，尾部有明显的横带。雄鸟平均体长39厘米，雌鸟平均体长45厘米。","call":"库氏鹰的鸣叫声包括尖锐的哨声和一系列快速的高音节叫声。","habits":"库氏鹰栖息于森林和郊区环境中，常见于城市和乡村的树木中。它们主要分布在北美的森林地带，从加拿大南部到墨西哥北部。库氏鹰以鸟类为主要食物，也会捕食小型哺乳动物。它们的飞行特点是深而慢的拍翅，头部在滑翔时明显超出腕部。","breeding":"库氏鹰的繁殖期主要集中在春季，筑巢于树冠层，巢由树枝构成，内部铺有细枝和植物材料。每窝产卵数量为2到4枚，孵化期约为一个月。雌鸟负责孵卵，雄鸟则负责觅食。","identification":"库氏鹰与体型较小的尖胸鹰和较大的北方鵟鹰相似，但可以通过圆尾、宽尾端白带和头部超出腕部的特征加以区分。幼鸟的条纹高度在腹部比尖胸鹰幼鸟低。","protection":"IUCN：LC（无危）","distribution":"库氏鹰分布于北美洲，从加拿大南部至美国大部分地区，南至墨西哥北部。在繁殖季节，它们主要分布在森林地带，而非繁殖季节则可能出现在郊区和城市环境中。","other":"库氏鹰在19世纪中期由于狩猎、陷阱和农药污染导致东部种群数量下降，但自20世纪后期开始恢复。"},{"name":"古巴鹰","english_name":"Gundlach's Hawk","scientific_name":"Accipiter gundlachi","overview":"古巴鹰（英文名：Gundlach's Hawk，学名：Accipiter gundlachi），是鹰形目鹰科鹰属的鸟类。为古巴的特有种。体型中等，分布于古巴的特定森林地带。","appearance":"古巴鹰体长40至46厘米，体重雌鸟可达675克，翼展74至84厘米。成年鹰上体呈深灰蓝色，头部黑色，下体颜色较淡，有条纹状尾巴。未成年鹰上部暗褐色，下部颜色较浅，有明显的暗色条纹。成年雌鹰平均比雄鹰大7至11%，尾部更长。幼鹰虹膜绿色偏黄，脚色较成年个体淡。","call":"古巴鹰最常见的叫声是一连串响亮的“kek-kek-kek-kek-kek...”，类似于其近亲库氏鹰的叫声。","habits":"古巴鹰不具特化的生活环境，栖息于低海拔的常绿林、半落叶沼泽林、森林边缘、海岸森林及红树林。其饮食几乎完全依赖鸟类，包括鹦鹉、鸽子、乌鸦、夜鹰、北方山鹑、西方红腿鸫和家禽。狩猎方式可能与库氏鹰相似。","breeding":"繁殖习性了解不多，但已知巢筑于树上，高度7至20米，通常靠近树干。巢由树枝构成，大小约为70x80厘米宽，50厘米深。每窝通常产3至4枚蛋，偶尔产两枚。幼鸟离巢时间未知。","identification":"古巴鹰介于库氏鹰和双色鹰之间，前者胸部和脸颊为灰色，后者腹部和大腿有灰红相间的条纹。与纹腹鹰相比，古巴鹰体型更大，头部更显眼，尾巴更长且呈圆形。","protection":"IUCN：EN（濒危）；CITES II级附录物种。全球估计仅存约400只，相当于约270只成熟个体。面临的主要威胁是栖息地丧失和人类迫害。","distribution":"古巴鹰仅分布于古巴，主要栖息在东部两个较大的聚居区，西部有三个较小的群落。它们能在多种森林环境中生存，海拔最高可达800米。","other":"自21世纪初以来，古巴鹰的数量似乎趋于稳定或略有回升。环保教育取得进展，但仍需提高公众意识，以减少对这种猛禽的迫害。"},{"name":"双色鹰","english_name":"Bicolored Hawk","scientific_name":"Accipiter bicolor","overview":"双色鹰（英文名：Bicolored Hawk，学名：Accipiter bicolor），是鹰形目鹰科鹰属的猛禽。广泛分布于中美洲至南美洲北部，从墨西哥南部到阿根廷北部。此物种在热带森林、林地、次生林、种植园和木本灌丛地带最为常见，但在海拔超过2,700米的安第斯山脉高处较为罕见。","appearance":"双色鹰体长34-45厘米，体重200-450克，体型介于北美的灰腹鹰和库珀鹰之间，是中南美洲最大的鹰科之一。雌鸟显著大于雄鸟。成鸟上身呈灰色，翅膀和头部颜色更深，尾部带有条纹。下身颜色从深灰至浅灰不等，南方亚种有时会呈现红褐色。大腿部分总是纯红褐色，但并非总是显眼。成年个体的下翼覆羽在北方亚种中为白色，在南方亚种中为红褐色。幼鸟变异较大，下身颜色从白色、淡黄色到红褐色不等，有时带有暗色条纹，上身比成鸟更偏棕色，大腿部分有时颜色较淡。","call":"双色鹰的叫声通常为一系列鼻音的“keh”声，由10-20个音节组成。此外，还有一种间隔重复的短促‘kek’声，可能是一种接触叫声，雄鸟的叫声更为柔和，在巢穴防御时会变得更大声。雌鸟在索食时发出嘶哑的吼叫声‘keer’。幼鸟在乞食时会发出尖锐的叫声‘keeyaaa’。","habits":"双色鹰主要栖息在热带森林及其边缘，但也可见于次生林、种植园和木本灌丛。它们在海拔从海平面到2,000米的地方都有分布，在委内瑞拉可达2,500米，在秘鲁可达2,700米。它们主要以鸟类为食，包括鸫鸟、嘲鸫和小型鸽子，偶尔也会捕食小型哺乳动物如蝙蝠和啮齿类动物，以及蜥蜴和大型昆虫。在南美洲南部，它们还会捕食智利鸽。双色鹰通过在密林中静候或追逐的方式捕捉猎物，有时会成对狩猎。","breeding":"双色鹰在繁殖季节（通常是旱季的4月至5月）筑巢，巢位于高树上，通常距离地面17.2至25米。巢由枯枝和树叶构成，直径约30至97厘米，深度12至30厘米。每对双色鹰每年都会建新巢，一般不会重复使用旧巢，但会在离前一年巢址25至200米的范围内筑巢。一窝产卵1-3枚，平均2.5枚，蛋壳颜色为偏白。孵化期约为33-35天，主要由雌鸟负责，幼鸟在孵化后1-3天内相继出壳，体重约25-28克，孵化后30-36天左右离巢。幼鸟离巢后仍依赖父母喂养，直到59-64天后才能独立。","identification":"双色鹰与棕腿齿鸢在外表上有相似之处，尤其是与棕腿齿鸢的pileatus亚种相似，但结构上有明显差异。双色鹰体型更大，喉部没有垂直条纹，通常栖息在森林内部，几乎不翱翔。与同属的智利鹰、古巴鹰和Accipiter cooperii关系密切，但可以通过大小、颜色和行为特征加以区分。","protection":"IUCN：LC（无危）","distribution":"双色鹰广泛分布在中美洲至南美洲北部，从墨西哥南部至阿根廷北部，包括西厄瓜多尔、圭亚那、哥伦比亚、秘鲁东部、亚马逊巴西、巴拉圭、玻利维亚和智利北部。","other":"双色鹰的栖息地受到森林破坏和破碎化的威胁，尽管一些早期的研究者认为该物种不受这种栖息地丧失的影响。"},{"name":"智利鹰","english_name":"Chilean Hawk","scientific_name":"Accipiter chilensis","overview":"智利鹰（英文名：Chilean Hawk，学名：Accipiter chilensis），是鹰形目鹰科鹰属的猛禽。在南美洲的森林中较为罕见且难以捉摸，主要栖息于智利中部至南部以及邻近阿根廷的Patagonian森林地带。成年鹰体色以灰色为主，头冠及背部颜色较深，腹部则带有白色和栗色斑纹或条纹。幼鸟羽色偏褐色，下体有明显的暗色条纹。","appearance":"智利鹰的雄鸟体长约为37至38厘米，而雌鸟略大，体长可达41至42厘米。成鸟上体呈黑色，胸腹部为灰烬色并带有深色横纹。喉咙处有纵向的暗色条纹，下尾覆羽为白色。尾上覆羽棕色，有5到6条深色带纹。腿绿色，眼睛黄色。两性羽毛相似。幼鸟上体颜色偏褐，边缘奶油色，胸部和腹部有纵向条纹，尾部的斑纹更为明显。","call":"智利鹰仅在繁殖季节发出叫声，其叫声似乎与双色鹰类似。已知有两种较高音的责骂式叫声：一种类似犬吠的'keh'或'kow'声，另一种则类似于啄木鸟的快速加速的'staccato'式的'kek'叫声。伴侣间会用尖叫声'waaah'互相交流，父母与幼鸟沟通时则会发出柔和清脆的哨声。","habits":"智利鹰主要栖息于温带森林，偶尔也会出现在硬叶林、公园、混合森林和开阔地带。它们在白天喜欢在领地内的树枝上栖息，低飞穿梭于森林之间。它们偏好在开放地带狩猎，如灌木丛、草地或农田。它们避免人类高度干扰的环境，要求至少200公顷的原生森林作为繁殖地。","breeding":"繁殖期在南半球夏季，通常自10月中下旬开始。筑巢于高树叉枝上，巢由干枝交织而成，直径约50至80厘米，高25厘米左右。每窝产卵2至3枚，蛋壳呈淡蓝色或灰白色，形状似鸡卵。孵化期大约3周。亲鸟会保护巢穴免受其他猛禽如红背鹰和金雕的侵扰。","identification":"智利鹰与双色鹰在外观上有明显差异，智利鹰的羽色更偏向灰色调，而双色鹰则色彩更为鲜明。此外，智利鹰的叫声和栖息地偏好也有所不同。","protection":"IUCN：NR（未评估）","distribution":"智利鹰在阿根廷北部至Neuquén省的36°纬度有分布，在智利的分布范围北至O'Higgins区，南至Tierra del Fuego的55°纬度。在智利中部和阿根廷中西部至火地群岛都有其踪迹。","other":"智利鹰的栖息地偏好和季节性移动模式尚待进一步研究。"},{"name":"黑鹰","english_name":"Black Sparrowhawk","scientific_name":"Accipiter melanoleucus","overview":"黑鹰（英文名：Black Sparrowhawk，学名：Accipiter melanoleucus），是鹰形目鹰科鹰属的鸟类。非洲最大的真鹰之一。其分布于撒哈拉以南的森林和非沙漠区域，偏好大型树木密集的地区作为筑巢之所，包括城市边缘和人类改造的环境。","appearance":"成年黑鹰两性皆呈现黑色羽毛搭配白色喉部、胸部和腹部，白胸个体为主流，黑胸变异在南非沿海地区较为常见。幼鸟羽毛呈棕色，带有深色条纹，翼下和尾部具黑白相间的条纹。成鸟的尾部和翅膀下侧带有浅色横纹，腿黄色，脚和爪巨大。","call":"仅在繁殖季节发声，雄鸟发出尖锐的'keeyp'声，雌鸟回应较低沉的'kek'音，求食时雌鸟会发出高音拉长的'kweeeeee-uw'叫声。","habits":"栖息于各种森林、密林、异域种植园，海拔可达3700米，甚至城市环境。猎食中型鸟类，如鸽子、斑鸠和法郎鸡，偶尔捕食小型哺乳动物和蛇类。捕猎方式为快速从隐蔽处冲出袭击目标。","breeding":"繁殖期在西非为8月至11月，肯尼亚和扎伊尔为3月至6月及10月至12月，南部非洲为5月至翌年3月。营巢于高大的森林树冠分叉处，巢由数千根树枝构成，通常重复使用，产卵数为2至4枚，孵化期34至38天。","identification":"与暗色形态的加巴尔鹰和奥瓦姆波鹰相似，但体型更大，腿和喙基部黄色。与鹰鹰属物种区别明显，因有裸露的黄色腿和深色眼睛。","protection":"IUCN：LC（无危）。在非洲广泛分布，适应多种次生林和种植园，但在某些地区受森林砍伐和农药影响。","distribution":"广泛分布于撒哈拉以南非洲，包括热带低地到高海拔山地森林，以及城市环境，如喀麦隆的雅温得和埃塞俄比亚的亚的斯亚贝巴。","other":"黑鹰有两个亚种，适应多种栖息地，包括城市化环境，能有效控制鸽子和斑鸠等鸟类数量。"},{"name":"亨氏鹰","english_name":"Henst's Goshawk","scientific_name":"Accipiter henstii","overview":"亨氏鹰（英文名：Henst's Goshawk，学名：Accipiter henstii），是鹰形目鹰科鹰属的鸟类。大型猛禽，身长52至62厘米，翼展86至100厘米，主要分布在马达加斯加岛的东部雨林和西部干燥森林，一般海拔低于1000米，偶尔出现在次生林和桉树种植园。以森林中的大型鸟类和小型哺乳动物为食，是马达加斯加独特的物种。","appearance":"亨氏鹰具有暗褐色至灰褐色的上体，下体呈细条纹状的灰棕色和白色相间。眼上方有一条明显的浅色条纹，喙黑色，基部呈蓝色，鼻孔处转为黄色，眼睛和腿均为黄色或黄绿色。雌鸟比雄鸟大，翅膀长度可达320毫米，而雄鸟则为279至283毫米。幼鸟上体深棕色，头颈有肉桂色条纹，下体有大胆的斑点。","call":"发出响亮、快速、高音的‘peer...’声，持续约1秒，每2至10秒重复一次，有时会变成连续的‘peer-peer-peer-peer-peer...’声，持续3至20秒，通常在领地防卫时由飞行中的两只鸟一起发出。","habits":"亨氏鹰主要栖息在马达加斯加的原始雨林和干燥森林，海拔一般低于1000米。它们的猎物包括较大的森林鸟类、家禽和小型哺乳动物，如鼠类和小印度麝香猫。它们也会捕食一些狐猴种类。它们长时间在隐蔽处栖息，可能主要在树上捕猎，但也能迅速穿越森林。","breeding":"繁殖季节开始于7月，筑巢发生在9月至10月。巢由树枝构成，内衬绿叶，直径约100厘米，通常建在大树的主枝叉处，离地面12至22米高。每次产卵2至3枚，孵化期约为39至40天，主要由雌鸟孵卵。雏鸟在43至47天后离巢，但在70天内仍靠近巢址。","identification":"与马达加斯加雀鹰和马达加斯加蛇鹰相似，但可通过尾羽上的细条纹、完全条纹的喉咙和正常长度的中趾来区分。幼鸟可能仅基于趾长来区分。","protection":"IUCN：VU（易危）","distribution":"亨氏鹰主要分布在马达加斯加的东部雨林和西部干燥森林，一般不在中部和最南部出现。","other":"由于持续的森林砍伐，亨氏鹰的数量可能正在下降。偶尔因攻击家禽而遭到迫害。"},{"name":"苍鹰","english_name":"Eurasian Goshawk","scientific_name":"Accipiter gentilis","appearance":"成年苍鹰体色上部灰至深灰，下部白至淡灰色，有密集的条纹，头部特征鲜明，有黑色头顶和上耳羽，白色眉纹，橙色眼。幼鸟与成鸟相似，但颜色较暗，条纹更粗，下部有更多褐色斑点。雌鸟比雄鸟大11-15%，体重重50-90%，成年雌鸟体重范围在820-1850克，雄鸟体重范围在517-1170克。体长46-63厘米，翼展89-122厘米。飞行时胸深，头大，翅膀宽，尾巴中等长度。","call":"苍鹰的叫声多种多样，包括尖锐的哨声、高音的啸叫和低沉的咕噜声，但在大多数情况下，它们在飞行和狩猎时保持沉默。","habits":"苍鹰主要栖息于成熟森林边缘，偏好在森林或森林边缘进行狩猎，通过一系列贴近地形的短距离飞行，偶尔从高处的栖木发起攻击。它们是日行性猎手，但有时也会在黄昏和城市的人工照明下狩猎。苍鹰的饮食以鸟类为主，约占总食物量的50%以上，特别喜欢雉鸡类和鸽子，同时也捕食哺乳动物如野兔、树松鼠等。","breeding":"繁殖期通常在春季，求偶行为包括空中追逐和俯冲。营巢于树木上，巢由树枝构成，内衬细枝和草。每窝产卵数量为2-5枚，孵化期约30天，雏鸟孵化后由双亲共同喂养，直到它们能够在空中独立飞行。","identification":"与雀鹰相比，苍鹰体型更大，头部和翅膀更宽，尾巴更短，眉纹更白。与矛隼相比，苍鹰的尾巴更圆，翅膀更宽，飞行时头部不突出于翅膀前方。在亚洲部分地区，与凤头鹰有重叠，但凤头鹰的胸部有锈色条纹，腹部有棕色到锈色的条纹，且缺乏白色眉纹。","protection":"IUCN：LC（无危）","distribution":"苍鹰广泛分布在欧洲和亚洲的温带至亚北极区域，包括北欧、俄罗斯、中国北部、日本等地。在中国，它们分布于东北、华北、华中、西南等地区。","other":"在一些历史时期，苍鹰因人类的迫害而数量锐减，但在法律保护下，其种群已有所恢复。在欧洲和亚洲的一些城市，如德国的柏林、荷兰的阿姆斯特丹和日本的东京，苍鹰已经适应了城市环境，甚至在公园和墓地中筑巢。"},{"name":"白颊鹰","english_name":"Meyer's Goshawk","scientific_name":"Accipiter meyerianus","overview":"白颊鹰（英文名：Meyer's Goshawk，学名：Accipiter meyerianus），是鹰形目鹰科鹰属的猛禽，以Adolf Bernard Meyer命名，其活动范围涵盖摩鹿加群岛、新几内亚、俾斯麦群岛及所罗门群岛，偏好山地森林边缘和开阔地带，具有黑白分明的外观特征。","appearance":"白颊鹰体型大至特大，翼展可达86-105厘米，雄鸟体重约530克，雌鸟重达1100克。上体呈黑色，下体白色，侧翼有细密的黑色条纹。黄色腿部、眼睛和喙基。成鸟与同域物种区别明显，但黑色变异型类似栗肩鹰的黑色变异型，而幼鸟特征相似，但白颊鹰有暗色眼睛而非黄色。","call":"叫声被描述为一系列响亮的上扬啸叫，频率约为每秒1-1.5次，声音略带沙哑，不同于栗肩鹰的叫声，还有一种高音的“ka-ah ka-ah ka-ah”。","habits":"栖息于山地和亚高山雨林，包括部分砍伐区域，森林边缘，河流沿岸的森林内部以及邻近的本土花园。海拔分布从海平面到至少2700米，主要在1200米以上，但在小岛上低海拔也有记录。狩猎活动通常在半开放区域进行，常在清晨飞越森林山脊和台地，追逐正在觅食的鸽子。","breeding":"繁殖季节从南半球冬季持续至初夏，已知一对白颊鹰在9月处于繁殖状态，12月初发现一窝孵化中的幼鸟，8月中旬观察到一窝独立飞行的幼鸟。巢筑于非常高大的树木中，如新几内亚的山毛榉树，一窝通常有三个蛋，由双亲共同孵化，已知一窝中有两只幼鸟成功离巢。","identification":"白颊鹰与苍鹰相比，黑白对比更强烈，颈背常有白色羽缘。黑色变异型与栗肩鹰的黑色变异型相似，但尾部条纹更少且模糊，主要通过眼色区分。","protection":"IUCN：LC（无危）；CITES II。全球数量估计在1000-10,000之间，可能受局部森林砍伐影响，以及DDT导致的蛋壳变薄影响繁殖成功率，但具体数据缺乏。","distribution":"分布于印尼苏拉群岛东部、哈马黑拉岛、Obi、Boano、Seram、Seram Laut、新几内亚的鸟头半岛、Yapen岛、Karkar和Bagabag、Umboi、新不列颠岛、Watom、新乔治亚群岛和Guadalcanal岛。","other":"最近在Taliabu的发现扩展了其已知分布范围，此前未知的记录表明它可能是一种干季访客，特别是在新不列颠岛东北部，以及新几内亚大陆低地的游荡记录。"},{"name":"白头鹞","english_name":"Western Marsh Harrier","scientific_name":"Circus aeruginosus","overview":"白头鹞（英文名：Western Marsh Harrier，学名：Circus aeruginosus），是鹰形目鹰科鹞属的大型猛禽，广泛分布于温带和亚热带的西欧、亚洲和邻近非洲地区。体长介于48至56厘米，翼展可达115至130厘米，体重雄鸟约400至650克，雌鸟约550至800克。雄鸟头部和肩部呈淡灰黄色，背部具黄褐色条纹，雌鸟全身巧克力棕色，头部顶部、喉部和肩部有鲜明的黄褐色。分布范围从欧洲、北非到中亚和中东北部。","appearance":"白头鹞体型庞大，翼展宽广，雄鸟主要呈暗褐色，头部和肩部颜色较浅，雌鸟全身巧克力色，头部、喉咙和肩膀带有显著的黄褐色斑块。幼鸟类似雌鸟，但肩部黄褐色较少。成年雄鸟有三色翼，灰色尾，头部和胸部颜色对比明显，腹部锈褐色。雌鸟颜色较暖，胸有条纹，头部有暗线穿过眼睛，缺乏欧亚种的白色帽状斑块。成年鸟体长43至54厘米，体重雄鸟405至730克，雌鸟540至960克，翼展115至145厘米。","call":"繁殖季节外通常寂静无声，雄鸟展示叫声为远距离传播的尖锐‘whee-ah’或‘kweeoo’声，常在飞行中发出。受惊吓或烦躁时，会发出‘che-ke-ke-ke-ke-kek’的咯咯声。","habits":"偏好广阔密集的湿地植被，如芦苇和香蒲，栖息于淡水和咸水的湿地环境，如沼泽、湿地、湖泊边缘等。低地平原为主，亚洲可达海拔2000米。在迁徙和越冬期间，适应森林、高山、农田等多样环境。以小型至中型鸟类、哺乳动物（尤其是啮齿类）、鱼类、爬行动物、两栖动物和部分昆虫为食，具有很强的机会主义倾向。","breeding":"繁殖期主要在4月至5月，北欧可延至6月。通常一夫一妻制，但雄鸟有时多配偶。巢筑于密集的湿地植被中，如芦苇床，直径约60至80厘米，深度不定。雌鸟负责筑巢，双方共同添加材料。平均产卵数3至6枚，孵化期31至38天，仅雌鸟孵卵。雏鸟35至40天离巢，之后再与父母共处25至37天。性成熟年龄为2至3岁。","identification":"与近缘种白腹鹞相比，雄性白头鹞头部更暗，胸部更红棕色，雌鸟颜色更暖，胸部条纹更明显，无欧亚种特有的白色帽状斑块和眼线。成鸟中存在永久雌鸟相似的雄鸟个体，可通过喙长和体重区分。","protection":"IUCN：LC（无危）。《濒危野生动植物种国际贸易公约》附录II。历史上曾因栖息地破坏、过度使用农药、非法猎杀而数量锐减，现已受到法律保护，数量有所恢复，但全球变暖导致的海平面上升威胁其繁殖地。","distribution":"繁殖于欧洲、北非、中亚至中东北部，越冬于非洲撒哈拉以南、尼罗河谷、印度次大陆、斯里兰卡和中国东南部。在中国，繁殖于新疆西北部天山及周边地区，冬季南迁至印度阿萨姆等地。","other":"历史上，白头鹞曾因人类活动如狩猎、栖息地破坏而数量急剧下降，20世纪70年代后，随着全年保护措施的实施和DDT等化学药剂的禁用，其数量开始回升。"},{"name":"白腹鹞","english_name":"Eastern Marsh Harrier","scientific_name":"Circus spilonotus","overview":"白腹鹞（英文名：Eastern Marsh Harrier，学名：Circus spilonotus），是鹰形目鹰科鹞属的鸟类。中大型猛禽，雄鸟成鸟主要呈现白至浅灰色，翼尖黑色，翼上有浅V字型姿态，雌鸟成鸟则为褐色，分布于西伯利亚中部至中国东北部和日本等地。","appearance":"白腹鹞体长47-55厘米，体重370-780克，翼展119-145厘米。雄鸟成鸟头部、胸部有黑色或深棕色条纹，腹部白色，背部暗色，边缘羽毛白色，尾羽灰色无横斑。雌鸟成鸟整体褐色，胸部有褐色条纹，臀部常呈白色，尾部有4-5条暗色横斑。亚成鸟深褐色，头部和胸部颜色较淡。","call":"发出领地‘myuaa myuu kyuii’和‘ke ke’叫声，雄鸟还发出‘pishee pishee’尖叫。冬季通常沉默，偶尔发出柔和的‘kyu-kyu’或‘keeau’声。","habits":"栖息于开阔地带，尤其偏好大面积的沼泽或芦苇丛，飞行时保持低空，优雅滑翔，有时悬停。主要分布在欧亚大陆，繁殖于西伯利亚中部至中国东北部和日本，越冬于亚洲东南部至菲律宾、婆罗洲和苏门答腊岛。","breeding":"繁殖季节始于4月，巢由枯枝构成，建于地面，通常位于芦苇丛中，产卵数3-7枚，孵化期33-48天，幼鸟35-40天后离巢。","identification":"与白头鹞相似，但雌鸟成鸟腰部无大片白色，亚成鸟整体深褐色，头胸沾米白色，与白头鹞区别明显。与白头鹞相比，差异在于头顶和颈背的深色条纹。","protection":"IUCN：LC（无危）。被列入《濒危野生动植物种国际贸易公约》附录II。","distribution":"繁殖区：欧亚大陆，从西伯利亚中部至中国东北部和日本。非繁殖区：远东东部，覆盖亚洲东南部，南至中国南部，延伸至菲律宾、婆罗洲和印尼苏门答腊岛。","other":"曾被认为是白头鹞的亚种，但在E西伯利亚存在杂交现象。与spilothorax（可能为独立物种）在体型、羽毛形态、栖息行为上存在显著差异。"},{"name":"巴布亚鹞","english_name":"Papuan Harrier","scientific_name":"Circus spilothorax","overview":"巴布亚鹞（英文名：Papuan Harrier，学名：Circus spilothorax），是鹰形目鹰科鹞属的鸟类。分布于新几内亚中部及东部地区，常见于广阔的草甸和湿地之上，以独特的黑、白、灰色调或暗褐色外观著称。","appearance":"巴布亚鹞体型介于47至61厘米之间，雌鸟体重可达890克。成年雄鸟通常呈现银灰色，头部、喉咙、背部有黑色斑点，翼尖黑色，而雌鸟和幼鸟则呈棕色，带有明显的条纹。雌鸟比雄鸟大，且具有独特的白色臀部斑块，这与雌性沼泽鹞不同。幼鸟为暗褐色，头部和胸部颜色较浅。存在黑色变种，雄鸟表现为深黑色，尾部灰色，雌鸟则主要为深棕色。","habits":"巴布亚鹞栖息于新几内亚的广阔草地和开放湿地，尤其是洪水平原和其他湿地环境。它们常在开阔地带低飞或翱翔，尤其在高地地区更为常见。这种鸟会利用燃烧过的草地和农业区觅食，甚至出现在城镇附近的草地和乡村。它们筑巢于高草丛和芦苇中，有时会在海拔404至510米处筑巢，甚至在1500米以上的高地草甸筑巢。","breeding":"繁殖季节在新几内亚的旱季开始时，大约为4月的第一周。已知的巢穴位于低洼、茂密的草地中，完全被植被遮盖。巢中通常有2至3只绒羽幼鸟和1枚蛋，蛋壳呈脏白色，尺寸约为49.2毫米×43.2毫米。然而，由于草地和农田的年度焚烧，巢穴和幼鸟面临威胁。","identification":"巴布亚鹞与白腹鹞极为相似，但二者分布区域不重叠。雄鸟的头部和颈部有更重的条纹，且在新几内亚中部高地的个体拥有全黑色喉咙。雌鸟与白腹鹞雌鸟类似，但缺少明显的白色臀部斑块。","protection":"IUCN：LC（无危）。尽管全球估计数量约3600只（2550至4050之间），巴布亚鹞目前不被视为全球受威胁物种。然而，草地和农田的定期焚烧导致繁殖失败，是对其最大的威胁。","distribution":"巴布亚鹞广泛分布于新几内亚中部和东部，包括中西部至东南部地区，但未在Vogelkop半岛西部出现。有未经证实的澳大利亚目击报告，但可能与沼泽鹞混淆。","other":"曾被归类为白腹鹞的亚种，巴布亚鹞在新几内亚的中央高地和Sepik河谷存在暗色型个体。"},{"name":"沼泽鹞","english_name":"Swamp Harrier","scientific_name":"Circus approximans","overview":"沼泽鹞（英文名：Swamp Harrier，学名：Circus approximans），是鹰形目鹰科鹞属的大型、修长的猛禽，在澳洲和南太平洋岛屿广泛分布。在新西兰，它还有个毛利名‘kāhu’。近700年内，它才到达新西兰，取代了已灭绝的本土物种Eyles's harrier。","appearance":"沼泽鹞全身大部分呈暗棕色，随着年龄增长色泽渐浅，其显著特征是白色的臀部。它通过缓慢低飞的方式狩猎，双翼微张。体型介于48至61厘米之间，翼展可达118至145厘米。成年个体体重范围在580至1100克，雌鸟明显大于雄鸟。在新西兰，雄鸟的平均体重约为640克，雌鸟平均870克。","call":"雄鸟在展示飞行中的叫声是一种远传的下降音调‘wheeoo’，而雌鸟的叫声更低沉、拖长；雄鸟在向巢穴运送食物时会发出低沉的‘kok-ok’声；面对人类入侵者，则会发出‘kekekek’的声音。非繁殖季节中，它们大多保持沉默。","habits":"栖息于陆地、河口和沿海湿地，草地、农田和牧场，海拔从海平面至1700米。筑巢于高高的芦苇、草丛、作物和其他密集地面覆盖物中，但在开阔乡村的各种生境上空猎食。冬季迁徙至澳大利亚北部和新几内亚，最长记录移动距离为1520公里，从塔斯马尼亚到新南威尔士东北部。主要以哺乳动物（尤其是塔斯马尼亚的兔子）、鸟类和鸟蛋、爬行动物、两栖动物、鱼类、大型昆虫和腐肉为食。","breeding":"繁殖期为9月至2月，主要在10月至12月在澳大利亚产卵。通常是单配制，偶尔多配偶制。筑巢于地面或水面之上，由枯枝、芦苇、干草和其他植物构成，有时位于作物中或离地4.5至7米的低树上。每窝通常产3至4枚蛋（1至7枚），孵化期31至34天，雏鸟初生时覆有白色绒羽，约43至46天离巢，离巢后依赖父母4至6周。最长寿的环志个体活到了18岁。","identification":"与白头鹞相比，沼泽鹞显得更暗淡，雌鸟颜色更深，腹部更红棕色。幼鸟整体深褐色，臀部有淡淡的痕迹（主要是红棕色）。","protection":"IUCN：LC（无危）。列入《濒危野生动植物种国际贸易公约》（CITES）附录II。在适宜生境中常见，但在湿地被排水的地方局部数量减少。巢穴容易受到人为干扰的影响。曾经因DDT使用导致蛋壳厚度显著降低，现在DDT使用已停止。有时被射杀，也有沿路死亡的情况。","distribution":"繁殖于澳大利亚（除中部和南部）, 斯图尔特岛北部和南部, 新西兰查塔姆群岛东部和南部, 瓦努阿图, 新喀里多尼亚（包括新喀里多尼亚忠诚群岛）, 斐济和汤加（波利尼西亚西南部、中南部）。非繁殖期分布至新几内亚中南部Trans-Fly和新西兰北岛东北部的Kermadec Islands。","other":"在新西兰，沼泽鹞仅在最近几百年内建立种群，随着低地森林被早期的波利尼西亚定居者大规模清除。它在新西兰的化石记录中缺失。沼泽鹞受益于欧洲人的定居，如今在开放的农田中非常普遍。"},{"name":"非洲泽鹞","english_name":"African Marsh Harrier","scientific_name":"Circus ranivorus","overview":"非洲泽鹞（英文名：African Marsh Harrier，学名：Circus ranivorus），是鹰形目鹰科鹞属的鸟类。属于鹰科鹞属，常见于南部、中部和东部非洲的湿地区域，自南非北至南苏丹。","appearance":"体型中等偏大，长度约44-49厘米，翼展可达105-125厘米，体重382-590克。雌鸟比雄鸟大7%，颜色更深，腹部更红棕色。成年雄鸟背部有灰色调，雌鸟呈褐色。幼鸟比成鸟颜色更深，带有赤褐色臀部，下体单一色，仅在两肋和腹部有栗色斑点，胸部有淡色带，头部、颈背和脸部有白色斑点。3岁时达到成鸟羽毛。眼睛黄色，幼鸟为棕色；喙基黄色，幼鸟较暗或绿色；脚也是黄色。","call":"通常在巢附近才发出声音，雄鸟的叫声为哀婉的哨音'jeeee-uk'和柔和的'to-woot'，雌鸟在食物传递时回应雄鸟的'pew'声，展示飞行时发出尖叫'oweep'，受惊时发出嘈杂的'kyak-kyak-kyak...'。","habits":"栖息于湿地，包括沼泽、季节性湿地、草甸和农田。活动范围广泛，从海平面到3000米，东非大部分记录海拔在1500米以上。以小型哺乳动物、鸟类为主食，偶尔捕食蜥蜴、青蛙、昆虫、腐肉和鱼类。狩猎时低空飞行，贴近地面5-20米，快速转弯捕捉猎物，或顺风快速扫过，捕获飞行中的猎物。","breeding":"主要在旱季繁殖，筑巢于芦苇丛中，离水面0.45-2.5米高，巢由杂草和芦苇构成，内衬干草，直径45-62厘米，深10-30厘米。每窝产卵2-6枚，平均3-4枚，卵呈蓝白色，孵化期31-34天，主要由雌鸟孵卵，雄鸟提供食物。雏鸟出生重21克，21天后能自我喂食，36-41天离巢。","identification":"与小欧亚泽鹞相似，但更苗条、颜色更浅，可通过翅膀和尾巴的横纹以及较暗的头部识别。幼鸟的暗棕色与成鸟有明显差异，尤其是胸带和头部的白色斑点。","protection":"IUCN：LC（无危）。CITES II。在东非和南非的主要湿地中常见，尤其在博茨瓦纳、赞比亚和乌干达。南非洲有500-1000对。面临湿地排水、过度放牧和人类干扰的威胁，部分地区数量下降。","distribution":"主要分布在南部和东部非洲，从南非北部至南苏丹，包括博茨瓦纳的奥卡万戈三角洲和纳米比亚东北部等地。","other":"适应性较强，能在人造水库生存。轻微污染但未受农药显著影响。"},{"name":"留尼汪鹞","english_name":"Reunion Harrier","scientific_name":"Circus maillardi","overview":"留尼汪鹞（英文名：Reunion Harrier，学名：Circus maillardi），是鹰形目鹰科鹞属的鸟类。现被普遍认为是独立物种。留尼汪鹞的数量呈现下降趋势，已被列为濒危物种。","appearance":"留尼汪鹞体长约42至55厘米，雌鸟比雄鸟大3%至15%。雄鸟头部和背部呈黑色，带有白色条纹；腹部、下翼和臀部为白色，尾巴灰色，翅膀灰黑相间，翼前缘白色。雌鸟和幼鸟为深棕色，臀部白色，尾巴有条纹。雄鸟的虹膜偏黄，雌鸟及幼鸟虹膜暗褐色；喙基和腿黄色。","call":"通常保持沉默，但在繁殖季节会发出叽叽喳喳的威胁声、哀鸣的求偶声和咯咯的与食物相关的叫声。","habits":"留尼汪鹞栖息于海拔300至700米的森林地带，也出现在甘蔗田和草地。饮食包括引入的哺乳动物（如鼠类）、小型蜥蜴、青蛙及腐肉，原始食物主要是鸟类和昆虫。它具有适应树间狩猎的圆形宽翅，以及捕食其他鸟类常见的短跗跖和长爪。","breeding":"繁殖期从一月至五月，通常产两到三枚白色蛋，筑巢于地面。","identification":"与马岛鹞相比，体型较小，颜色更深，翅膀和腿部较长。","protection":"IUCN：EN（濒危）；CITES: 二级。留尼汪鹞自1966年起受法律保护，1974年保护力度加强，1989年获得进一步保护。尽管如此，它仍面临栖息地破坏、人为迫害和鼠药中毒的威胁。","distribution":"仅分布于非洲的留尼汪岛（马斯克林群岛西部）。","other":"曾于毛里求斯有化石记录，但现已在当地绝迹。"},{"name":"马岛鹞","english_name":"Malagasy Harrier","scientific_name":"Circus macrosceles","overview":"马岛鹞（英文名：Malagasy Harrier，学名：Circus macrosceles），是鹰形目鹰科鹞属的猛禽。栖息于马达加斯加和印度洋的科摩罗群岛，体型介于42至55厘米之间，雌鸟比雄鸟大13%左右。雄鸟背部呈黑色，头部灰暗带条纹，腹部和臀部白色，尾巴灰色伴以深色横纹，翅膀尖端黑色，次级飞羽灰色带深色斑点。雌鸟整体色调较雄鸟偏棕色。","appearance":"马岛鹞具有典型的鹞类特征，翼展宽广，尾部长而优雅，飞行时展现优美滑翔姿态。雄性马岛鹞的头部和胸部有黑色条纹，腹部纯白，背部黑色，翅膀前端黑色，次级飞羽灰色带深色条纹，尾巴灰色伴以狭窄的深色横纹，臀部白色。雌鸟颜色更深，上体棕色，头颈条纹，下体浅色带重棕色条纹，尾巴棕色伴以狭窄的深色横纹，臀部同样白色。两性均有黄色眼睛和蜡膜，喙黑色，腿和脚黄色。幼鸟外观类似成年雌鸟，但上体更暗，下体可能条纹更重；眼睛棕色，蜡膜和腿的颜色与成鸟相同。","call":"在繁殖季节之外，马岛鹞大多保持沉默。雄鸟在空中求偶时会发出'koue'叫声；两性在保卫领地时发出'ouek'叫声，并在受到惊吓时发出'kekekeke'警报声；雌鸟在向雄鸟索食时会发出'kiou...kiou...kiou'叫声。","habits":"马岛鹞广泛分布于各种开阔地带，包括沼泽、草原、灌木丛、稻田和森林边缘。它们在马达加斯加的高海拔（1100-1700米）湿地和草原上最为常见，也可见于低海拔环境。在科摩罗群岛，它们的栖息地更为多样，包括干燥地带和森林上空。它们在永久性湿地中定居，但在季节性湿地中游荡。季节性的气候变化、猎物减少和人类干扰可能导致其离开繁殖地。","breeding":"马岛鹞在马达加斯加的旱季（8月至10月）开始筑巢，而在科摩罗群岛则在10月。雄鸟负责巢的大部分构建工作，耗时约25至30天。巢由草和草本材料制成，建在沼泽地面上，距离水面24至81厘米。巢的尺寸为50至77厘米长×34至51厘米宽。通常产卵数为2或3枚，偶尔4枚，卵大小约为48.7毫米×37.5毫米，新鲜重量34.8至39克。孵化仅由雌鸟承担，持续32至34天。雏鸟出生时体重25至32克，约42至45天后离巢，大约70天后离开出生地。在八次完整监测的繁殖中，61%的卵成功孵化，50%的雏鸟成功离巢，75%的巢穴繁殖成功。","identification":"马岛鹞最易与黑鸢混淆，但其翅膀更长，尾巴更长、更窄且不分叉，臀部白色，下体淡色。与马达加斯加雀鹰等其他猛禽相比，其瘦长的鹞形体态十分独特。雄鸟和雌鸟的颜色有所不同，雌鸟更大，色调更深。","protection":"IUCN：EN（濒危）；CITES II。马岛鹞在马达加斯加广泛分布但并不普遍，且并非所有湿地都有其踪迹。2005年至2006年的调查覆盖了潜在栖息地的71%，仅发现80只个体。在科摩罗群岛，格兰德科摩罗、莫埃利和安乔安岛上的栖息地几乎被完全破坏，估计三个独立的亚群落中仅有不超过50只成熟个体存在。全球种群数量估计少于250只成熟鸟。由于种群数量极小且在下降，2016年被提升为濒危状态。主要威胁来自人为因素，包括原生湿地转化为稻田、不受控制的火灾摧毁巢穴以及人类的迫害。","distribution":"马岛鹞在马达加斯加西部和中部地区以及科摩罗群岛的格兰德科摩罗（Njazidja）、莫埃利（Mwali）和安乔安（Nzwani）岛屿有分布。在马达加斯加，它遍布全岛除南部外的沼泽和草地，尤其在西北部数量较多，海拔高度从海平面到1800米。在科摩罗群岛，它们更常见于干燥地带和森林区域，已知出现在四大主岛上，但最近没有在马约特岛（Maore）的记录。","other":"曾被认为是留尼汪鹞的亚种，但现在普遍认为是独立物种。"},{"name":"长翅鹞","english_name":"Long-winged Harrier","scientific_name":"Circus buffoni","overview":"长翅鹞（英文名：Long-winged Harrier，学名：Circus buffoni），是鹰形目鹰科鹞属的鸟类。广泛分布于南美东部，从哥伦比亚到圭亚那，南至巴西东北部，智利中部和阿根廷中部。以草场和湿地为栖息地，具有独特的面部盘状结构，用于狩猎时定位猎物。","appearance":"长翅鹞是一种中型猛禽，体长46至60厘米，翼展119至155厘米，雌鸟较雄鸟大，体重范围从390至645克。其最显著特征为长而窄的尾巴和长翅膀，翅膀呈灰色，主翼羽深色，下体白色，胸带黑色，上体灰色，头部黑色，喉部有白色点斑。雌雄颜色相似，但雌鸟体型更大，背部棕色，喉部有赤褐色斑点，腹部有棕色条纹。幼鸟似雌鸟，但胸部条纹更宽。存在黑色变型，全身黑色，仅臀部白色。","call":"长翅鹞通常在飞行中发出快速连续的\"klee-klee-klee\"声，或一种音调迅速下降的颤音，但在巢穴防卫时会发出快速的类似涉禽的叽叽喳喳叫声。","habits":"长翅鹞栖息于南美的低地热带区，偏好开阔地带，如麦田、稻田、草地、草原和湿地，偶尔出现在较干燥环境或林缘。它们通常在离地面不到5米的高度上空掠过，以各种小型动物为食，包括鸟类、爬行动物、两栖动物和小型哺乳动物。迁徙模式复杂，南部种群至少部分迁徙，北部种群可能全年留驻。","breeding":"繁殖季节在南美各地有所不同，从6月的特立尼达到哥伦比亚的8月，再到阿根廷中部的9月至1月。筑巢于地面或近水面处，巢由芦苇和草构成，直径40至65厘米，深度10至30厘米。每窝产卵3至4枚，有时遭受黑头鸭的寄生。","identification":"长翅鹞与同属的斑腹鹞形态相似，但两者分布范围很少重叠。长翅鹞的特征在于其较长的翅膀和尾巴，以及独特的黑白相间的下体。","protection":"IUCN：LC（无危）；被列入CITES附录II。","distribution":"长翅鹞全年分布于南美东部，包括哥伦比亚、圭亚那、巴西东北部、智利中部和阿根廷中部，偶尔访问玻利维亚、秘鲁、智利、特立尼达和多巴哥，远至阿根廷南部的火地岛。在巴拿马和福克兰群岛偶有记录。","other":"尽管长翅鹞的种群数量有所下降，但由于广泛的分布范围，目前仍被列为无危物种。其面临的最大威胁是栖息地的退化，尤其是湿地的排水、污染等人造成因。"},{"name":"斑鹞","english_name":"Spotted Harrier","scientific_name":"Circus assimilis","overview":"斑鹞（英文名：Spotted Harrier，学名：Circus assimilis），是鹰形目鹰科鹞属的鸟类。也被称为烟鹰。体型介于鹞鹰和雕之间，飞行迅速，视力敏锐，能在远距离精准锁定猎物。在澳大利亚和印尼的苏拉威西岛及松巴岛可见其踪迹。","appearance":"斑鹞是一种中等体型的猛禽，腿长，翅膀窄长。成年个体胸腹部呈栗色并带有醒目的白色斑点，幼鸟则有条纹。雄性斑鹞体长50-55厘米，雌鸟更大，可达58-61厘米，翼展121-147厘米。成年个体的头部看起来较短且宽，由类似猫头鹰的面部羽毛造成。雄鸟上部蓝灰至灰色，雌鸟胸腹有显著的白色斑点。幼鸟上部深棕色和淡黄色，下部淡黄色并带有棕色条纹。","call":"发出尖锐、高音的“wik wik wik”声和更嘈杂的“kikikikik”声，用于各种情境，包括巢穴防御和喂食，但通常较为沉默。","habits":"栖息于树少或稀疏的草地、半沙漠和灌木丛，以及开阔的草原、平原和农田（尤其是小麦地）。从海平面到至少1500米的高度均可发现其踪迹。部分迁徙，冬季有些个体移至热带地区。主要食物包括陆生鸟类、小型哺乳动物、大型昆虫和爬行动物，偶尔也会食用腐肉。通过低空、缓慢的系统性搜索来捕食，俯冲至地面捕获猎物。","breeding":"通常在南澳大利亚的9月至10月繁殖，有时在3月至6月；在北方则是6月至9月。一次繁殖季可能养育两窝幼鸟。独居并实行单配偶制，占据大片不重叠的领地。巢建于活树上，高度2-15米，由树枝搭建，内衬绿色叶子，宽40-70厘米，深16-39厘米。每窝产卵2-4枚，孵化期32-34天，幼鸟36-43天离巢，离巢后至少依赖父母6周。","identification":"与沼泽鹞相比，斑鹞更为纤瘦，尾巴更长，翅膀基部宽阔且指状，尾巴略呈楔形。雌鸟比雄鸟大25%，体重平均多40%。幼鸟颜色较浅，翅膀和尾巴暗色，肩部锈色明显，尾巴横纹明显，与沼泽鹞的灰暗或更深的颜色形成对比。","protection":"IUCN：LC（无危）。在《濒危野生动植物种国际贸易公约》中列为CITES II级。一般数量不多但分布广泛；在南方可能因栖息地创造和本土及引入猎物的增加而受益局部。蛋壳厚度未因DDT而显著减少。","distribution":"主要分布在澳大利亚（除塔斯马尼亚）和印尼的苏拉威西岛及松巴岛。偶尔出现在东帝汶。在澳大利亚大陆广泛分布，但在密林、海岸、悬崖和山脉地区较少见。在新南威尔士州分散分布，构成单一人口。","other":"对兔子的依赖曾使其受到兔病毒疾病爆发的影响，导致其转向更多依赖本土猎物。"},{"name":"黑鹞","english_name":"Black Harrier","scientific_name":"Circus maurus","overview":"黑鹞（英文名：Black Harrier，学名：Circus maurus），是鹰形目鹰科鹞属的鸟类。中型非洲鹞鹰，分布于南非至博茨瓦纳和纳米比亚。以其独特的全黑色外观而著称，仅在飞行时可见白色臀部和翼下白色斑块。黑鹞在南非西部和南部沿海平原分布明显，倾向于沿海地带或内陆山区筑巢。","appearance":"黑鹞体长44-50厘米，翼展105-115厘米。其显著特征为全身大部分暗色，但在飞行中可见白色臀部和翼下的白色斑块。幼鸟呈棕色，胸部有明显的条纹，腹部淡色并带有暗色斑点。雌鸟体型较雄鸟大至少7%，达到成年羽毛的时间可能在第一年末。","call":"黑鹞发出柔和的\"pi-pi-pi-pi...\"声作为联系信号和求偶时的叫声，雌鸟在索食时也会发出这种声音。此外，它们还发出尖锐的哨声\"seeeeeu\"，以及在警戒或攻击时的\"chek-ek-ek-ek-ek\"声。","habits":"黑鹞栖息于南非特有的fynbos生境、半沙漠Karoo地区和沙丘灌木丛，偶尔在高草和农田上空狩猎。它们在冬季会向北迁徙至更干燥的草原和草原地带。以小型鸟类、哺乳动物、昆虫、蜥蜴和青蛙为主要食物，偶尔吃腐肉。","breeding":"黑鹞主要在雨季繁殖，集中在南非的冬季降雨区，产卵期为7月至11月。筑巢于地面，常选在枯枝、茎、芦苇或杂草上，巢宽35-45厘米，深5-15厘米。一窝产2-5枚蛋，孵化期约为34-35天，由雌鸟单独孵化。雏鸟由雌鸟主要喂养，雄鸟提供食物。","identification":"黑鹞与同属的其他物种相比，其独特之处在于飞行中的白色臀部和翼下白色斑块，这有助于在野外识别。成鸟与其他大型黑色鹞鹰区分明显，而幼鸟与某些种类的幼鸟相似，需通过细节辨认。","protection":"IUCN：EN（濒危）","distribution":"黑鹞主要分布在南非（尤其是西开普省，北部和东部开普省较少见），纳米比亚西北部有极小的繁殖群体。非繁殖季节，它们出现在纳米比亚大部分地区和莱索托。","other":"黑鹞面临的威胁包括农业扩张、fynbos和草原的无控制燃烧、外来植被入侵和城市化，导致其栖息地丧失。"},{"name":"白尾鹞","english_name":"Hen Harrier","scientific_name":"Circus cyaneus","overview":"白尾鹞（英文名：Hen Harrier，学名：Circus cyaneus），是鹰形目鹰科鹞属的鸟类。中等体型的猛禽。其特征为飞行时翅膀呈V字形，能在开阔地带低空飞行以听觉寻找鼠类。雄鸟呈灰蓝色，雌鸟和幼鸟则为暖褐色，所有个体具有明显的白色腰部。分布广泛，遍布欧洲、亚洲中部至俄罗斯远东，南至北非和亚洲南部。","appearance":"白尾鹞体长42-50厘米，翼展100-121厘米，雄鸟体重300-400克，雌鸟370-708克。雄鸟整体呈灰色，具白色臀部，翼尖黑色，腹部浅色。雌鸟和幼鸟为深棕色，胸部有条纹，翼下覆羽无赤褐色横斑。幼鸟与成鸟相似，但颜色稍暗。","call":"雄鸟在求偶飞行中会发出‘che-kuk-kuk-kuk...’的叫声，雌鸟则以柔和高音的‘che-ke-ke-kek’回应。受到惊吓或生气时也会发出类似叫声。此外，还有一种‘kweeee’或‘kweeee-eh’的尖叫用于多种情境，如求食。","habits":"白尾鹞栖息于开阔地带，包括草甸、沼泽、牧场、农田、年轻松树林，冬季分布更为广泛。它们偏好平坦或缓坡地形，能适应较高海拔，最高可达2500米。主要以小型哺乳动物和鸟类为食，如田鼠、小鸟，偶尔捕食成年雉鸡和鸭子。","breeding":"繁殖期从4月至7月初，雄鸟可同时与2-3只雌鸟配对。巢筑于地面的浓密植被中，由雌鸟建造，主要材料为小枝和草。每窝产卵3-6枚，孵化期约29-31天，由雌鸟承担。雏鸟孵化后，最初由雄鸟觅食，后期雌鸟也会参与，雏鸟在32-42天后离巢。","identification":"雄鸟与乌灰鹞雄鸟区别在于体型较大，缺乏黑色横斑。雌鸟与乌灰鹞雌鸟相比，领环色浅，头部色彩平淡，翼下覆羽无赤褐色横斑。幼鸟翼短而宽，翼尖圆钝。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧洲至亚洲中部和北部，冬季迁徙至南欧、北非、中东至中国东南部、韩国和日本。","other":"历史上曾与草原鹞和乌灰鹞被视为同一物种，现已确认为独立种类。"},{"name":"北鹞","english_name":"Northern Harrier","scientific_name":"Circus hudsonius","overview":"北鹞（英文名：Northern Harrier，学名：Circus hudsonius），是鹰形目鹰科鹞属的鸟类。中型猛禽，以其独特的白臀斑和低飞狩猎行为著称。广泛分布于北美大陆北部，包括加拿大和美国北部，栖息于开阔地带，如草原、湿地和农田。","appearance":"北鹞体长41-52厘米，翼展97-122厘米，雄鸟体重约350克，雌鸟平均530克，雌雄体型差异显著。雄鸟上体灰色，下体白色，翼尖黑色，雌鸟及幼鸟棕色，翼尾带黑纹，所有个体具特征性的白色臀部斑块。","call":"雌鸟在接收食物时发出哨音“piiheh”，遇警时发“chit-it-it-it-it-et-it”声；雄鸟鸣叫“chek-chek-chek”，展示飞行时为更弹跳的“chuk-uk-uk-uk”。","habits":"北鹞栖息于开阔环境，如沼泽、草原和农田。繁殖季节雄鸟维持2.6平方公里领地，雌鸟筑巢于地面，通常在高密植被中。雄鸟实行一雄多雌制，最多与五位雌鸟配对。冬季向南迁徙至美国南部、墨西哥和中美洲。","breeding":"每窝产4-8枚蛋，孵化期31-32天，主要由雌鸟负责，雄鸟提供食物。雏鸟36天左右离巢，雌鸟需两年成熟，雄鸟三年。","identification":"与同属的其他鹞类相比，北鹞具有更明显的性二色性，雄鸟灰白相间，雌鸟及幼鸟呈暖棕色，所有个体皆有白色臀部斑点以作区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美至中美广泛区域，冬季迁徙至南美。","other":"历史上因控制鼠害而受到农民欢迎，被称为‘好鹰’，但曾因农药使用导致数量下降。"},{"name":"斑腹鹞","english_name":"Cinereous Harrier","scientific_name":"Circus cinereus","overview":"斑腹鹞（英文名：Cinereous Harrier，学名：Circus cinereus），是鹰形目鹰科鹞属的鸟类。常见于南美洲的开阔地带，尤其是巴塔哥尼亚的湖泊和沼泽附近。斑腹鹞在北部分布较少，为稀有种类。雄鸟呈银灰色，腹部有细锈色横纹；雌鸟和幼鸟背部呈灰褐色，腹部有横纹或纵纹。所有斑腹鹞都具有显著的白色臀部带。该物种在南美洲中南部广泛分布，从哥伦比亚到火地岛，包括巴拉圭和巴西东南部。","appearance":"斑腹鹞体长39至48厘米，雄鸟体重315至407克，雌鸟体重427至510克。翼展90至115厘米。雄鸟上部羽毛呈珍珠灰色，胸部灰色，下部白色，有鲜明的红褐色条纹。雌鸟背部深棕色，颈背有白色斑点，尾巴灰白色，有四条狭窄的黑色带和宽黑色末端带。下部白色，胸部有不规则灰色条纹，腹部和尾下覆羽有栗色条纹。雌鸟体型较大。幼鸟与雌鸟相似，但背部更棕色，下部主要白色，胸部和侧部有深色垂直条纹。","call":"斑腹鹞通常在繁殖季节外保持沉默。雄鸟的求偶鸣叫是一种快速的‘kekekekekekek’声，通常在求偶飞行中发出，雌鸟则发出较柔和的‘chekekekek’声。当受惊或烦躁时，会发出类似快速‘kikikikikiki...’的鸣叫声。还有一种高音尖叫‘kyeeee’或‘keeeee-eh’，用于多种情境。","habits":"斑腹鹞主要栖息在南美洲的草原、牧场和湿地，常出现在沼泽、河流、溪流和大湖附近，海拔从海平面到安第斯高原的4500米。其食谱以小型鸟类和其他小型脊椎动物为主，也会偶尔捕食青蛙，昆虫虽占一定比例，但总体消耗量相对较小。狩猎技巧典型，以活跃搜索的方式低空飞行于开阔田野、沼泽或灌木丛上空，高度低于10米。大部分鸟类猎物可能是巢中的雏鸟。","breeding":"斑腹鹞在南半球的筑巢期为10月至次年1月，晚于当地其他猛禽。巢由芦苇和芦茎构成，内衬干草，建于草地或沼泽地面上。每窝通常产3至5枚蛋，尺寸为41至46毫米×32至35毫米。雏鸟有脏白色的绒毛。斑腹鹞可能在一定程度上与同类保持较近的距离，但会防御领地不受其他鹞属鸟类侵扰。在阿根廷，已知在黄颈鹮的群落中筑巢。","identification":"斑腹鹞与其他鹞属鸟类的区别在于其明显的白色臀部带和腹部的红褐色条纹。雌雄之间主要通过体型大小和色彩差异辨识，雌鸟较大且颜色更深。","protection":"IUCN：LC（无危）。根据《濒危野生动植物种国际贸易公约》（CITES）列为附录II。尽管斑腹鹞的种群数量正在下降，但由于其分布范围广泛，目前并不被视为脆弱。然而，在智利和阿根廷部分地区，由于农药使用和湿地排水，该物种似乎有所减少；在森林被清除的地方，其数量反而有所增加。在福克兰群岛几乎绝迹，可能是因为自然草原的破坏和人为猎杀；现在很少见到，可能不再繁殖。在哥伦比亚被认为是局部分布。估计种群数量为12,000至38,000对。","distribution":"斑腹鹞的繁殖区域从哥伦比亚中部延伸至火地岛，包括巴拉圭和巴西东南部，以及整个安第斯山脉至火地岛。在南美洲中南部广泛分布，包括阿根廷、智利、秘鲁、玻利维亚、巴拉圭、巴西南部，以及安第斯山脉北部至哥伦比亚。","other":"斑腹鹞在南美部分地区，如火地岛，相当常见，在某些区域是仅次于叫隼的第二丰富的猛禽。"},{"name":"草原鹞","english_name":"Pallid Harrier","scientific_name":"Circus macrourus","overview":"草原鹞（英文名：Pallid Harrier，学名：Circus macrourus），是鹰形目鹰科鹞属的鸟类。典型的草原鸟类，得名源自古希腊语，意为‘长尾的圆圈飞鸟’，暗示了它独特的飞行模式。雄鸟呈灰白相间，翼尖黑色，而雌鸟和幼鸟通常被称为‘环尾’，因腹部呈浅黄色，背部棕色，具白色上尾覆羽。在中国，分布于新疆、河北、长江下游的江西与江苏、西藏南部、广西及海南等地。","appearance":"成年草原鹞体型中等，长度约40-48厘米，翼展可达95-120厘米。雄鸟体重约315克，雌鸟略重，平均445克。雄鸟上部呈灰白色，下部白色，翼尖有明显的黑色。雌鸟和幼鸟的上部棕色，腹部为带有棕色条纹的浅黄色，头部有清晰的面部图案，这有助于与其他鹞类的鉴别。","call":"草原鹞的叫声较为罕见，繁殖季节时会发出快速高亢的‘kiki-kiki-kik’声，类似于其他鹞类，但更独特。","habits":"草原鹞主要栖息于开阔的草原、沼泽和荒地，冬季则迁徙至非洲、印度和东南亚。它们以小型哺乳动物和鸟类为主食，如田鼠、百灵鸟和鹨类，同时也捕食大型昆虫、蜥蜴和蛙类。狩猎时，它们低空飞行，接近地面，一旦发现猎物便迅速俯冲捕捉。","breeding":"繁殖期通常在春季，一般在4月至5月。巢建于地面，多选择草原凹陷干燥处。每窝产卵3-6枚，平均4-5枚，卵色白色，带淡红或褐色斑点，大小约为44.6×34.7毫米。雌鸟负责孵卵，期间进行换羽，雄鸟则在幼鸟开始飞行时换羽。育雏期大约持续35-45天。","identification":"雄性草原鹞以其灰白色的上体和黑色的翼尖为显著特征，易于识别。雌鸟和幼鸟与乌灰鹞相似，但其腹部颜色较浅，面部图案更为明显，有助于区分。","protection":"IUCN：NT（近危）","distribution":"繁殖区域主要在欧亚大陆的东部至中部亚洲，包括俄罗斯、哈萨克斯坦和中国西北部。非繁殖区域覆盖非洲南部、印度、东南亚直至缅甸。在中国，分布于新疆、河北、长江下游的江西与江苏、西藏南部、广西及海南。","other":"近年来，由于草原的农业开发和荒漠化加剧，草原鹞的生存环境受到严重威胁，对其研究仍显不足，数量逐渐减少。"},{"name":"鹊鹞","english_name":"Pied Harrier","scientific_name":"Circus melanoleucos","overview":"鹊鹞（英文名：Pied Harrier，学名：Circus melanoleucos），是鹰形目鹰科鹞属的鸟类。鹰科鹞属的猛禽，又称喜鹊鹞、喜鹊鹰等。以其独特的黑白羽色而著称，站立时外观类似喜鹊，飞翔时黑色的翼尖、头部至背部极为显眼。繁殖于西伯利亚东南部、朝鲜半岛及中国东北部，越冬分布广泛，从巴基斯坦至菲律宾和婆罗洲。","appearance":"雄鸟具有引人注目的黑白羽色，头部、颈部、胸部、背部和初级飞羽为深黑色，前翼、臀部及下体其余部分为明亮的银白色。雌鸟灰褐色，上体带灰色，下体较浅，翼下具细窄的暗色横纹。成年雄鸟虹膜鲜黄色，雌鸟虹膜呈褐色，随着年龄增长转为黄色；喙黑，脚和腿橙黄色。体型：雄鸟43-50厘米长，体重254-325克；雌鸟略大，体重390-455克；翼展110-125厘米。亚成鸟巧克力棕色，翼下及腰部色浅。","call":"繁殖季节外通常寂静无声。展示时，雄鸟反复发出类似北方鹬的‘kiiy-veee’叫声，雌鸟则发出快速的‘kee-kee-kee’声。遇警或烦扰时，发出急促的‘chak-chak-chak-chak’声。","habits":"栖息于开阔的低山丘陵、山脚平原、草地、河谷、沼泽、林缘灌丛等地，繁殖期后亦可见于农田和村庄附近的草地和丛林。独居，常在林边草地和灌丛上空低飞，呈‘V’字形翼展，缓缓飘浮，时高时低。晨昏活跃，夜宿草丛。主要捕食小鸟、鼠类、蛙类、蜥蜴、蛇和昆虫等小型动物，通过低空飞翔或长时间飘浮搜寻猎物。","breeding":"繁殖期为5月至7月，成对在林缘和林间路旁求偶，雄鸟作圆周盘旋并俯冲接近雌鸟，交配在地面进行。巢建于疏林中灌丛草甸上，呈浅盘状，由干苔草构建。每窝产卵4-5枚，卵乳白色或淡绿色，孵化期约30天，雌鸟为主孵化，雏鸟晚成性，亲鸟共同抚育。","identification":"雄鸟黑白分明的羽色极富特色，不易混淆。雌鸟与蒙氏鹞、草原鹞的雌鸟相似，但下体更白，翼上和尾上有较多的灰色，翼下具窄的暗色横纹。与幼鸟相似的有草原鹞和白腹鹞的幼鸟。","protection":"IUCN：LC（无危）。列入《濒危野生动植物种国际贸易公约》附录II。数量有限，全球估计有10,000个体，数量可能中等下降。","distribution":"繁殖于西伯利亚东南部、蒙古东部至阿穆尔地区和中国东北；越冬分布自印度、斯里兰卡至中国南部、婆罗洲和菲律宾。在中国大陆，主要见于东北地区。","other":"在某些年份，当啮齿动物丰富时，一些个体可能在中国南部和东北部度过冬季。"},{"name":"乌灰鹞","english_name":"Montagu's Harrier","scientific_name":"Circus pygargus","overview":"乌灰鹞（英文名：Montagu's Harrier，学名：Circus pygargus），是鹰形目鹰科鹞属的鸟类。得名于英国自然学家乔治·蒙塔古。体羽呈灰色，翼尖黑色，具独特的黑色翼带，腹部有锈色条纹。分布于欧洲西部、非洲西北部至亚洲中部，冬季迁徙至非洲撒哈拉以南和印度。依赖开阔地带，如草地、沼泽和农田。全球估计有35,000-50,000对，是受农业实践影响的物种。","appearance":"乌灰鹞体长39–49厘米，体重雄鸟227–305克，雌鸟254–445克，翼展102–123厘米。正常雄鸟有黑色主翼和黑色翼带，帮助其与草原鹞区别。雌鸟比雄鸟大11%，背部略浅于草原鹞和白尾鹞。雌鸟深色形态巧克力色，雄鸟暗色形态几乎全黑，仅翼下表面灰色。幼鸟较雌鸟暗，具红褐色下体和翼下覆羽，无斑纹。成鸟虹膜、蜡膜和足黄色，喙灰黑色。","call":"雄鸟展示叫声为尖锐的'kek..kek..kek...'，通常在求偶飞行时发出，雌鸟以柔和、较快的'kekekekek'回应。当受惊或烦躁时会发出类似叫声。此外，还有一种高音尖叫'keeee'或'keeee-eh'，用于各种情境，如求食和求偶。","habits":"栖息于低山丘陵和平原地带，偏好开阔地带如草地、沼泽和农田。迁徙性物种，夏季繁殖于欧亚大陆，冬季迁至非洲和印度。以鼠类、蛙、蜥蜴和大型昆虫为食，也捕食小鸟和鸟蛋。日间活动，以滑翔或轻拍翅膀的方式飞行。休息时多在地面或土堆上。","breeding":"繁殖期为5月至8月，巢建于水边草地或干芦苇丛中，由细灌木枝条、芦苇和草构成，内垫干草。每窝产卵3至6枚，白色，偶尔带褐色斑点。孵化期27至30天，由雌鸟承担，雏鸟需35至42天喂养后才离巢。","identification":"与白尾鹞和草原鹞的区别在于更细长的翅膀、更轻盈的飞行，雄鸟有黑色翼带和锈色腹部。雌鸟和幼鸟与草原鹞的区别在于脸部更苍白，颈部有淡色项圈。","protection":"IUCN：LC（无危）。列入CITES附录II。中国国家重点二级保护动物。面临栖息地破坏和农业实践的威胁。","distribution":"繁殖于欧洲西部、非洲西北部至亚洲中部，冬季迁徙至非洲撒哈拉以南和印度。","other":"高度依赖农业区域，易受农业实践影响，如作物收割。"},{"name":"赤鸢","english_name":"Red Kite","scientific_name":"Milvus milvus","overview":"赤鸢（英文名：Red Kite，学名：Milvus milvus），是鹰形目鹰科鸢属的鸟类。优雅的大型猛禽，拥有锈橙色的长叉尾，飞行时展现轻松悠扬的翼拍与滑翔，常见于田野和路边上空盘旋。其体色较黑鸢更为红润，脸部更淡，翅膀下部有更大的白色斑块，尾部叉形更深。栖息于多种半开放生境，从森林到农田、荒野地带，偶尔在城市区域出现，以腐肉为食，与乌鸦共同觅食。","appearance":"赤鸢身长60至72厘米，体重雄鸟介于757至1221克，雌鸟介于960至1600克，翼展可达143至171厘米。体型大于黑鸢，羽色呈红褐色；尾巴明显叉开且顶部呈锈红色；头部更白；翅膀下方展示较大的白色斑块于初级飞羽。幼鸟体色较淡，头部颜色较深，尾巴颜色不如成鸟红润。小型亚种fasciicauda体型较小且颜色更深。","call":"赤鸢的叫声通常是伴侣间的鸣叫，类似‘weee-oo’的叫声，与欧亚鵟的叫声相似但音调更高，有时更尖锐；这种叫声常在短时间内快速重复。","habits":"栖息于开阔的林地，包括混合了农田、牧场或荒野的多变地形。在低至中海拔地区常见，但在摩洛哥的树林中可达2500米高。冬季倾向于占据更开阔的区域，如无树木的农田、废弃地、灌木丛和湿地。在历史上，曾在城市中充当清道夫角色，例如16世纪英格兰伦敦的城市清道夫。目前仍与人类关系密切，访问城镇边缘的丰富觅食区，如垃圾场。","breeding":"筑巢通常位于阔叶或针叶树的树杈中，高度约为12至15米。巢由枯枝构成，内部铺垫草或羊绒。每窝产卵1至4枚，通常为2枚，间隔3天产一枚。孵化主要由雌鸟承担，自首枚卵开始，孵化期为31至32天。雌鸟负责孵化和喂养雏鸟，而雄鸟提供大部分食物。雏鸟首次换羽为浅黄色，第二次换羽带有红晕。离巢时间在50至60天之间，成年后至少2至3周继续由父母喂养。成功繁殖的幼鸽数量一般为1至2只，偶尔3只。首次繁殖可能在2岁，通常更晚，直至7岁。野外寿命最长记录为26年。","identification":"赤鸢与黑鸢的区别在于整体更红润的体色，脸部颜色更淡，翅膀下部有更大、更白的斑块，尾部叉形更明显。幼鸟与成鸟在体色、头部颜色和尾部颜色上有显著差异。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要分布在西欧，包括葡萄牙、西班牙、中央欧洲至东欧俄罗斯、南至意大利南部，北至南斯堪的纳维亚半岛、拉脱维亚和英国，南至巴尔干半岛少数地区。在德国、法国和西班牙，种群在1990年至2000年间有所下降，但随后趋于稳定。由于其他地区的增长，总体种群数量正在增加。在瑞典、丹麦、波兰和英国等北欧地区，种群数量正在增长。","other":"在英国，赤鸢曾因人类活动而濒临灭绝，但通过再引入计划，尤其是在英格兰和苏格兰，种群得到了恢复。"},{"name":"黑鸢","english_name":"Black Kite","scientific_name":"Milvus migrans","overview":"黑鸢（英文名：Black Kite，学名：Milvus migrans），是鹰形目鹰科鸢属的鸟类。俗称: 老鹰，广泛分布于欧洲、亚洲、非洲和澳洲的中型猛禽，以全身暗色羽毛和飞行中明显的尾叉为典型特征。它是世界上最常见的昼行性猛禽之一，既能独居，也能在迁徙或食物丰富处形成大群；特别适应人类环境，常见于城市、垃圾场及水域周边。","appearance":"体长44–66厘米，翼展120–153厘米；雄鸟体重630–928克，雌鸟750–1,080克。成鸟通体以棕褐色为主，尾羽色淡，仅微具叉形；头颈短，飞行时尾叉可因尾羽展开而不明显。幼鸟色淡，斑纹更为对比。全球各亚种在体型、羽色、嘴色及尾叉深度上差异显著：欧洲与西亚的指名亚种 migrans 嘴黑色，尾叉20–35毫米；东亚的 lineatus 体型最大，羽色更棕，耳羽黑形成“面罩”；南亚的 govinda 体型较小，羽色较均匀；澳洲的 affinis 最小，通体暗褐；非洲的 aegyptius 与 parasitus 成鸟嘴多黄色，腹面更红棕，尾叉更深。","call":"常年嘈杂，最常见叫声为拖长下滑的尖厉“kleeeeerrrrrr”，偶在尾音加入“pee-pee-pee”音节。","habits":"栖境极为多样，从半荒漠、草原、稀树草原到湿地、河岸、湖泊、海岸及城市，均可见，唯避浓密森林。海拔分布由低地至4 000米皆有记录。具迁徙、游荡或局部定居性，指名亚种迁徙最显著，秋季数十万只经直布罗陀海峡往返欧非；东亚 lineatus 部分迁徙，部分留居；非洲及南亚各亚种随雨季移动。觅食半径可达30公里，飞行轻捷，常滑翔盘旋；食性极广，以小型兽类、鸟类、爬行类、两栖类、鱼类、昆虫及腐肉为主，亦大量取食人类垃圾与市场废弃物，并惯于空中抢夺其他鸟类或游人食物。","breeding":"繁殖期因纬度与气候差异极大：温带欧亚3–6月，热带非洲干季，南非8–12月，澳洲7–11月，印度德里12–4月。单对或松散群居营巢，每平方公里可多达15巢。巢筑于乔木、棕榈、悬崖、建筑物或电线杆，年年沿用，由雄鸟主要搬运枝条、破布、塑料等，雌鸟负责搭建，巢高4–15米，筑巢期18–83天。每窝通常2–3枚卵，大小46–56×36–42毫米，间隔1–2天产下；雌鸟专司孵化26–38天；雏鸟42–63天离巢，再经15–47天独立。首年即可繁殖，最长寿记录23年。","identification":"与同属的赤鸢相比，黑鸢体型较小，羽色更深，尾叉较浅；飞行中红鸢翼更长且尾叉显著。亚种间区别：指名亚种 migrans 嘴黑，尾叉浅；lineatus 体型最大，耳羽黑，翼下具大白斑；govinda 体型小，羽色均匀；affinis 最小且通体暗；aegyptius 与 parasitus 具黄嘴、腹面红棕、尾叉深。","protection":"IUCN: LC（无危）。列入CITES附录Ⅱ。因适应力强且耐受人类，全球总体无立即危机，但欧洲、前苏联及北非局部因毒饵、农药、电击及污染而下降；佛得角种群形态与基因独特，值得特别关注。","distribution":"繁殖区：佛得角群岛、西北非、欧洲中南部至西南亚；冬季主要迁至撒哈拉以南非洲。lineatus 繁殖于乌拉尔至日本、印度北部、中国北部及台湾，冬季南抵东南亚。govinda 分布于巴基斯坦至印度、斯里兰卡、中南半岛及马来半岛。affinis 见于苏拉威西、摩鹿加、帝汶、新几内亚及澳洲北部至维多利亚州。aegyptius 繁殖于埃及、西南阿拉伯及东非海岸至肯尼亚；parasitus 遍及撒哈拉以南非洲、科摩罗及马达加斯加。","other":"分子研究显示黄嘴鸢（aegyptius 与 parasitus）及黑耳鸢（lineatus）可能应拆分为独立种，但形态差异不足，需进一步研究。Cape Verde 种群或被定为独立亚种 tenebrosus。"},{"name":"黄嘴鸢","english_name":"Yellow-billed Kite","scientific_name":"Milvus aegyptius","overview":"黄嘴鸢（英文名：Yellow-billed Kite，学名：Milvus aegyptius），是鹰形目鹰科鸢属的鸟类。其最显著的外部特征是拥有全黄色的喙，与访客黑鸢形成鲜明对比。分布广泛，遍及非洲大陆。","appearance":"黄嘴鸢具有独特的黄色喙，成鸟与幼鸟在羽毛上并无显著差异，但幼鸟的外观可能与同龄的黑鸢相似。体型中等，翼展宽广，适应多种栖息环境。","habits":"黄嘴鸢栖息于多样化的生境，包括城市郊区公园，但较少见于干燥的纳米布沙漠和卡拉哈里沙漠。它们以广泛的脊椎动物和昆虫为食，许多食物来源于腐食。","identification":"黄嘴鸢通过其黄色的喙与黑鸢相区别，尤其在成鸟阶段。幼鸟与黑鸢幼鸟相似，辨识需更细致观察。","protection":"IUCN：LC（无危）","distribution":"黄嘴鸢在非洲广泛分布，是非洲南部七月至三月的常见候鸟，有时甚至到五月。在非洲大陆内迁徙。","other":"现为黑鸢的亚种。"},{"name":"啸鸢","english_name":"Whistling Kite","scientific_name":"Haliastur sphenurus","overview":"啸鸢（英文名：Whistling Kite，学名：Haliastur sphenurus），是鹰形目鹰科栗鸢属的鸟类。飞行中常鸣叫。","appearance":"啸鸢体长51至59厘米，翼展120至146厘米，雄鸟体重380至1100克，雌鸟更大，重600至1000克。头小，具轻微冠羽，腿短，翅长，尾长。成鸟头部、胸部和尾部呈淡沙色，翅膀和背部偏褐色，黑飞羽明显。幼鸟下体有重斑纹，上体红褐色，有更暗的斑点。虹膜接近黑色，喙灰暗。","call":"啸鸢叫声独特，主要发出清晰的下降哨声，通常随后是一连串快速上升的短音符，叫声在巢边尤其频繁。","habits":"栖息于轻木林和开阔地带，常见于陆地和海洋湿地附近，海拔从海平面到1400米。部分迁徙，澳大利亚鸟向南移动长达2430公里。以小动物、腐肉为主食，包括哺乳动物、鸟类、爬行动物、鱼类、甲壳类、昆虫、路杀和大型尸体。在新几内亚，冬季更倾向于觅食腐肉。飞行狩猎，有时悬停，掠夺其他猛禽的食物。","breeding":"繁殖季节长，多在旱季（南半球秋季至春季）于热带地区，南区晚冬和春季。巢为平台状，用树枝建造，宽40至150厘米，深30至100厘米，置于3至62米高的树杈，常为桉树或电线杆。每窝产卵2至4枚，孵化期35至38天，雏鸟覆盖奶油色或浅黄色绒毛，离巢前44至54天，之后依赖父母6至8周。","identification":"与幼鸟相比，啸鸢有更长的主翼羽和尾羽，澳大利亚亚种更苗条，翼尖更窄且略呈叉状，羽毛更暗且统一。飞行时有上下摆动的动作。","protection":"IUCN：LC（无危）。CITES II级。海岸和热带地区数量普遍，人类活动对其有利。澳大利亚南部局部下降，因湿地排水和食物减少。","distribution":"分布于澳大利亚、新喀里多尼亚的Grande Terre（大特尔岛）和新几内亚的中南部、东北部、东南部。","other":"在Taunton科学国家公园，斑点园丁鸟模仿啸鸢叫声，功能不明。"},{"name":"栗鸢","english_name":"Brahminy Kite","scientific_name":"Haliastur indus","overview":"栗鸢（英文名：Brahminy Kite，学名：Haliastur indus），是鹰形目鹰科栗鸢属的鸟类。属鹰科雕亚科栗鸢属，中型猛禽。其最显著的特征是拥有砖红色的体羽与鲜明的白头和胸，这使它在众多猛禽中独树一帜。分布于印度次大陆、东南亚及澳大利亚，偏好内陆和沿海湿地环境。","appearance":"栗鸢体长44至52厘米，体重雄鸟409至650克，雌鸟434至700克，翼展110至125厘米。成鸟具有独特的对比色彩，胸背为深棕色，头部、颈部和胸部为白色。幼鸟呈现暗褐色，翼下有明显白色斑块。雌鸟体型略大于雄鸟。亚种间存在羽毛颜色和喙色差异。","call":"栗鸢的叫声是一声哀婉的‘Kyeeerrh’，在繁殖季节之外较为沉默。","habits":"栗鸢主要栖息于海岸、河口、河流、湖泊、湿地、稻田及城市区域，尤其热带地区会远离水源出现在森林、农田和草原。它们的活动范围广泛，从海平面到海拔500米，但在喜马拉雅山脉可达1500至1800米，大巽他群岛高达3000米。栗鸢主要以小型动物、腐肉为食，包括哺乳动物、鸟类、爬行动物、两栖动物、鱼类、甲壳类、节肢动物等。","breeding":"繁殖期在南亚为12月至翌年4月，澳大利亚南部和东部为8月至10月，北部和西部为4月至6月。巢建于树上，常用小枝和树叶搭建，位于树冠层，多见于红树林中。每窝产卵1至2枚，偶尔1至4枚，卵为淡白色或蓝白色，孵化期26至35天，由双亲共同参与。","identification":"栗鸢与黑鸢相比，翅膀更短，尾巴更圆，易于区分。幼鸟与黑鸢的亚洲亚种有明显区别，尤其是翅膀短和尾部圆润。","protection":"IUCN：LC（无危）。CITES附录II。尽管在全球范围内普遍分布且数量可观，但在某些地区，如爪哇和泰国非沿海部分，栗鸢的数量正在减少。","distribution":"分布于远东和澳新界，从巴基斯坦至印度尼西亚、菲律宾、新几内亚、澳大利亚卫星岛屿、俾斯麦群岛和所罗门群岛，沿海区域遍及澳大利亚（除塔斯马尼亚南部）。","other":"栗鸢在印尼被称为elang bondol，是雅加达的官方吉祥物。在印度教中，被认为是毗湿奴神鸟Garuda的当代化身。"},{"name":"白腹海雕","english_name":"White-bellied Sea Eagle","scientific_name":"Icthyophaga leucogaster","overview":"白腹海雕（英文名：White-bellied Sea Eagle，学名：Icthyophaga leucogaster），是鹰形目鹰科 Icthyophaga 属的鸟类。亦称: 白胸海雕，大型猛禽，显著特征为白色头、胸、腹部和尾部，背部和翅膀为灰暗色。广泛分布于印度至中国东部，菲律宾，印度尼西亚，新几内亚，澳大利亚及其周边岛屿，澳大利亚塔斯马尼亚州和俾斯麦群岛。","appearance":"成年白腹海雕具有鲜明的外观，头部、胸部、腹部和尾部为白色，背部和翅膀上部为深灰色，喙基部深色，头部相对较小，颈部长，尾部短且呈楔形，翅膀宽大，腿较短。雌鸟体型普遍比雄鸟大，长度可达90厘米，翼展可达2.2米，体重达到4.5千克。幼鸟羽毛呈褐色，逐渐替换为白色，直至5至6岁时获得成鸟羽毛。","call":"发出响亮的鹅鸣般的叫声，尤其是在繁殖季节，成对鸣叫，叫声持续时间较长。叫声为“啊，啊”，较为简单。","habits":"白腹海雕通常单独或成对沿海岸线低飞，两翼缓慢有力地拍打，偶尔在高空翱翔，双翼形成V字形。它们既在海上觅食，也在陆地上空搜寻食物，常在水面附近活动。食物包括鱼类、海蛇、野鸭，也会捕食陆地上的蛙类、蜥蜴、野兔和蛇，偶尔食用动物尸体或捕食家禽。主要在白天觅食，尤其在晨昏时段活动频繁。","breeding":"繁殖期在北半球为12月至翌年3月，在南半球的澳大利亚等地则通常在5月至10月。巢筑于海岸边高大乔木树上或悬崖岩石上，内陆沼泽地带小树上，没有树木的岛屿地面或岩石上。巢巨大，直径可达250厘米，由枯树枝构成，内部铺有绿叶。一对白腹海雕通常会轮流孵化，雌鸟为主要孵化者，雄鸟仅在白天替换雌鸟。领域性强，双方共同保卫巢区。","identification":"成年白腹海雕独特且不易混淆，但幼鸟可能与楔尾鵰相混淆，不过白腹海雕幼鸟尾巴较短且颜色较浅。与之相关的另一个物种是所罗门海雕，两者被认为是超物种关系。","protection":"IUCN：LC（无危）。在中国国家重点保护野生动物名录中的保护级别由Ⅱ级调整为I级（2021.02.05）。","distribution":"分布于远东地区，包括印度至中国东部，菲律宾，印度尼西亚，新几内亚和澳大利亚周边岛屿，澳大利亚塔斯马尼亚州和俾斯麦群岛。在澳大利亚内陆地区移动范围广泛。","other":"在某些地区，如泰国和其他东南亚部分地区，白腹海雕数量有所下降。"},{"name":"所罗门海雕","english_name":"Sanford's Sea Eagle","scientific_name":"Icthyophaga sanfordi","overview":"所罗门海雕（英文名：Sanford's Sea Eagle，学名：Icthyophaga sanfordi），是鹰形目鹰科 Icthyophaga 属的鸟类。是所罗门群岛特有的一种大型海雕，以独特的暗褐色外观和明显的奶油白色头部著称，拥有强大的喙和黑色的眼线。该物种主要栖息于沿海地带，从海平面到海拔约1500米的高度。其食物链顶端的地位使其成为所罗门群岛上的顶级掠食者。","appearance":"所罗门海雕体长可达70至90厘米，体重在1.1至2.7千克之间，翼展宽达165至185厘米。成年个体的头部和颈部为淡黄色至亮棕色，下体为棕色至红棕色，上体呈深棕色至灰黑色。眼睛颜色为明亮的棕色，尾巴在整个生命阶段保持深色，这是海雕中独一无二的特征。","call":"在繁殖季节，所罗门海雕会发出高音的‘ya-ya-ya…’的鸣叫声，显得较为嘈杂。","habits":"所罗门海雕偏好沿海森林、低地和山地森林、开放的人工改造栖息地及河流区域，甚至能远距离狩猎。它们常在海岸线巡逻或栖息，从水面捕捞鱼类和丢弃的鱼肉，展现出典型的海雕行为。此外，它们还会在海滩上觅食残骸，从白腹海雕那里抢夺鱼类。","breeding":"繁殖季节通常在8月至10月间，所罗门海雕会在死树顶上建造大型巢穴，一次产下两枚蛋，幼鸟在相对未受干扰的环境中较为常见。","identification":"与幼年的白腹海雕相比，所罗门海雕的外观更为统一，具有浅色头部和深色尾巴，这些特征有助于区分两者。","protection":"IUCN：VU（易危）；CITES: 附录II。全球数量估计较小，被认为正在下降，主要受到栖息地破坏和人类迫害的影响。","distribution":"所罗门海雕分布于所罗门群岛，包括布卡岛至马基拉岛，但不包括Rennell和Temotu。在内陆地区较少见，可能与人类活动有关。","other":"传统禁忌的瓦解导致了对这种猛禽的猎杀，用于食物和偶尔的‘运动’，这在较大的岛屿低地是一个潜在的严重问题。"},{"name":"非洲海雕","english_name":"African Fish Eagle","scientific_name":"Icthyophaga vocifer","appearance":"非洲海雕的外观极具特色，全身大多呈棕色，头部、颈部、胸部及尾部雪白，腹部和肩膀呈现漂亮的棕色调。雄鸟较雌鸟小，雌鸟的白色部分更为显著。成年海雕拥有黄色的喙，尖端有一黑斑驳，黄色的腿和利爪。亚成鸟的腿灰色，眼睛淡黄色，喙和脚灰色至肉白色，直到5岁才能完全长成成鸟的羽毛。成年后，头部、背部、肩部、胸部、腹部和大腿为白色，背部黑色，肩部、腹部和大腿为栗色，尾部短，常被翅膀遮挡。在停栖的鸟儿身上，可以看到白色的头部、背部和胸部更广泛，这是与马岛海雕的主要区别之一。","call":"非洲海雕的叫声非常独特，远距离可闻，雄鸟发出的叫声更高亢，是‘WEEE-AH kleeuw kleeuw kleew’，这声音对于许多游客来说，是非洲精神或本质的象征。","habits":"非洲海雕主要栖息于河流、湖泊附近，有时也会出现在河口滨海地区。它通常单独或成对生活，领地面积约25平方公里，是日行性鸟类，白天多数时间栖息于水边树上，等待猎物。其主要食物是鱼类，尤其是200至1000克重的鱼，但也可捕食重达4200克的大鱼。此外，它还会吃水鸟、哺乳动物（如猴子、蹄兔）、爬行动物（如巨蜥、龟、鳄鱼幼崽）、两栖动物、昆虫甚至腐肉。幼鸟在乌干达的高地，会以狮子和豹子的猎杀为食。","breeding":"非洲海雕在一年中的任何时候都可能繁殖，但在某些地区有季节性，如西非的10月至12月/1月，乌干达的7月至10月，南非的6月至8月。它们倾向于在低水位条件下筑巢，通常选择靠近水源的大树高叉处。巢宽约120至150厘米，深度20至60厘米。每窝产卵1至4枚，平均2枚，孵化期为42至45天。幼鸟出生时有白色绒毛，大约在65至75天后离巢。偶尔会有3只幼鸟离巢，但通常只有1至2只幼鸟能存活到独立，大约在离巢后2个月。","identification":"非洲海雕与马岛海雕的主要区别在于颜色模式和大小，雌性非洲海雕比雄鸟更大，且白色部分更为明显。在停栖的鸟儿身上，可以看到更广泛的白色头部、背部和胸部，这是与马岛海雕的主要区别之一。","protection":"IUCN：LC（无危）","distribution":"非洲海雕广泛分布在撒哈拉沙漠以南的非洲大陆，包括Mauritania东部至Eritrea和Ethiopia，向南至South Africa。它常见于大型湖泊、河流、沼泽和水库边缘，有时会在河口附近的海岸出现，海拔高度可达4000米。在大雨后，它会迁移到临时溪流和池塘。","other":"非洲海雕在某些地区，如象牙海岸，面临河流退化和狩猎的威胁，但通过灵活的觅食习惯和快速利用新的蓄水设施或猎物，它也显示出了适应性。"},{"name":"马岛海雕","english_name":"Madagascar Fish Eagle","scientific_name":"Icthyophaga vociferoides","overview":"马岛海雕（英文名：Madagascar Fish Eagle，学名：Icthyophaga vociferoides），是鹰形目鹰科 Icthyophaga 属的鸟类。又称马达加斯加海雕，是鹰科Icthyophaga属的大型海雕。体长约63厘米，具独特的淡色头部和白色尾羽。分布于马达加斯加西北部沿海地带，栖息于干燥落叶森林，主要以鱼类为食。全球数量稀少，受威胁严重，被列为极危物种。","appearance":"马岛海雕体型中等，总长70余厘米，翼展约200厘米。体羽深棕色，头部黄褐色，尾羽白色。喙部黑色，尖端尤为深暗，脚爪浅灰色。雌鸟略大于雄鸟，翼展可达528毫米，而雄鸟则在498毫米左右。幼鸟毛色较暗，上部均匀带有白色斑纹，下部斑驳黄色到白色，喉部红棕色，尾部末端有深色带。","call":"马岛海雕叫声嘹亮，类似鸥鸣的“ko ko koy-koy-koy-koy-koy”，头部后仰发出，与非洲海雕相似，每分钟平均两次，持续5至12分钟。叫声在一天中随时可闻，有时在黎明前。幼鸟饥饿或寒冷时会发出低音量的“peep”声，稍大后发出‘gwa’声。","habits":"栖息于海岸、湖泊和大河岸边，偏好岩石岛屿和树木环绕的环境，包括红树林。活动范围广泛，但多数时间在核心区域189公顷内度过。主要捕食水面鱼，包括引进的罗非鱼和蟹，偶尔吃腐肉。狩猎方式是在水面上方的高枝上守候，然后俯冲捕捉水面的猎物。","breeding":"繁殖季节从5月底至7月中旬开始，筑大型巢于悬崖、红树林或树上，离地面高度7.4至29米。通常产两枚白色卵，孵化期37至43天，主要由雌鸟负责，雄鸟提供食物。雏鸟出生三天体重约80克，54天时可达2500克。幼鸟孵化后75至96天离巢。","identification":"马岛海雕与非洲海雕有明显区别，前者头部黄褐色，后者头部白色。在马达加斯加，其巨大体型、短尾和白色尾羽可轻易与其他猛禽区分开来。","protection":"IUCN：CR（极危）。全球数量极其有限，可能正在下降，估计2010年约有360只个体。主要威胁包括栖息地破坏和人为迫害。","distribution":"分布于马达加斯加西海岸，从莫龙达瓦以北至安齐拉纳纳和贝洛苏梅尔之间，特别是在安萨洛瓦地区西部的贝马拉哈保护区附近，沿希里比纳河，以及从马哈赞巴湾向北至诺西哈拉岛。","other":"尽管面临严重威胁，通过当地社区管理和国际组织合作，一些区域正采取措施防止过度捕捞和砍伐大树，以保护马岛海雕的栖息地。"},{"name":"渔雕","english_name":"Lesser Fish Eagle","scientific_name":"Icthyophaga humilis","overview":"渔雕（英文名：Lesser Fish Eagle，学名：Icthyophaga humilis），是鹰形目鹰科 Icthyophaga 属的鸟类。又名:渔雕雕，广泛分布于印度次大陆至东南亚，主要在喜马拉雅山脚下和南亚的河流与湖泊周边。体长约61至68厘米，具有独特的灰棕色外观，腹部洁白，头部略显灰色。分布于中国南部的广东和海南，以及远东和澳新界的广阔地带。","appearance":"渔雕体长约51至68厘米，体重介于780至785克之间，翼展可达120至165厘米。其体型较小，头小，颜色为灰棕色，头部和颈部有精细的条纹，腹部和大腿部为白色。成年个体的背部和胸部颜色可以从赤褐色到灰色不等，而幼鸟颜色更偏棕色，下部有轻微的条纹。成鸟的尾巴较为均匀，尾尖处有黑色带状斑，而幼鸟的下部更显苍白，尾巴上有棕色斑点。","call":"发出哀怨的啼鸣声，远处听似孩童哭泣，围绕巢穴附近可以听到这种声音，叫声包括‘hak-hak’声或类似大型海鸥的深沉吠叫声。","habits":"渔雕偏好生活在流速较快的山区溪流和河流边缘的森林地带，也会出现在低地湖泊和湿地附近。它们在海拔200至1000米间最为常见，但在某些地区，如苏拉威西岛，也能接近海平面。它们主要依赖于鱼类为食，通过短暂的俯冲从岸边的栖息地或河中的岩石上捕捉猎物。有时，它们也会在水面掠过，抓取鱼儿。","breeding":"繁殖季节在缅甸为11月至次年4月，在印度和尼泊尔为3月至8月。筑巢于河流或大溪流附近的高树上，巢由树枝构成，直径约1米，深度可达30厘米，反复使用后可达到1.5米深，内衬绿叶。一窝通常产2至3枚蛋，也有记录到4枚。在印度南部卡纳塔克邦的考韦里野生动物保护区观察到，雄鸟会将食物直接投入巢中，雌鸟则留在巢内喂养雏鸟长达7周，雏鸟约在9周时能自我进食，12周时能够飞行。","identification":"与更大的灰头渔雕相比较容易区分，灰头渔雕有白色的尾基部和清晰的黑色亚端带，以及颜色均匀的翅膀下方。渔雕的尾巴显得‘脏’一些，黑色带不那么明显，成鸟的翅膀下方有更多斑驳的图案，而幼鸟的下部图案总体更淡。渔雕的腹部白色形状不如灰头渔雕的‘V’字形尖锐。","protection":"IUCN：NT（近危）","distribution":"在喜马拉雅山脉至越南、苏拉威西岛和印尼摩鹿加群岛中西部有广泛分布。在中国，主要见于南部的广东和海南。","other":"全球数量不详，初步估计成熟个体数在1万至5万之间，相当于大约1万5千至7万5千个个体。"},{"name":"灰头渔雕","english_name":"Grey-headed Fish Eagle","scientific_name":"Icthyophaga ichthyaetus","overview":"灰头渔雕（英文名：Grey-headed Fish Eagle，学名：Icthyophaga ichthyaetus），是鹰形目鹰科 Icthyophaga 属的鸟类。广泛分布于东南亚，包括印度、尼泊尔、斯里兰卡，向东至中南半岛、马来半岛、大巽他群岛、菲律宾和苏拉威西岛。其显著特征为深棕色上体、灰色头部和较浅色腹部，白色尾部带宽黑横纹。雌鸟比雄鸟大，重约2.3至2.7千克，而雄鸟约为1.6千克。","appearance":"成年灰头渔雕具有暗褐色上身、淡灰色头部、黄色虹膜、白色腹部和尾部，尾端有宽黑条纹。雌雄差异明显，雌鸟体型更大。幼鸟整体颜色较浅，胸部和翼下有条纹。翅膀长度适中，翼尖不到尾长的一半，尾巴圆，腿短，脚裸露，爪长。成鸟的头部较小，颈部较长，翅膀略短，足部呈灰色到淡黄灰色。","call":"灰头渔雕发出的叫声包括咕噜声、尖锐的尖叫、类似猫头鹰的“ooo-wok”声以及响亮的咯咯声，这些叫声在繁殖季节尤为频繁，夜间亦可听到。","habits":"栖息于低地森林，高度通常低于300米，偶尔可达1500米，偏好靠近大型淡水体如河流、湖泊、沼泽等地。它们是定居型猛禽，以鱼为主食，偶尔捕食小型鸟类、哺乳动物和爬行动物。它们会在水面附近等待，进行短暂飞行捕食水面或水下的猎物。","breeding":"繁殖季节一般在11月至次年5月之间，筑巢于高树上，离地面8至30米，巢由树枝构成，直径可达1.5米，深度2米。每窝产卵1至4枚，孵化期为28至30天，雏鸟大约10周后离巢。","identification":"与较小的渔雕相比，灰头渔雕的尾部对比更强烈，成年鸟的腹部斑块边缘更整齐。与玉带海雕相比，灰头渔雕体型较小，翅膀相对较短，腹部颜色更深。","protection":"IUCN：NT（近危）","distribution":"分布于印度、尼泊尔、斯里兰卡、中南半岛、马来半岛、大巽他群岛、菲律宾和苏拉威西岛。在新加坡、马来西亚、柬埔寨等地较为罕见，而在印度东北部、斯里兰卡北部和东部较为常见。","other":"灰头渔雕在斯里兰卡常被称为“水塘老鹰”，因其喜栖息于灌溉水塘。"},{"name":"玉带海雕","english_name":"Pallas's Fish Eagle","scientific_name":"Haliaeetus leucoryphus","overview":"玉带海雕（英文名：Pallas's Fish Eagle，学名：Haliaeetus leucoryphus），是鹰形目鹰科海雕属的鸟类。亦称玉带海雕或band-tailed fish eagle，大型猛禽，拥有独特的淡沙色头部和白色面部，主要分布于东帕里亚尔地区的哈萨克斯坦、俄罗斯、塔吉克斯坦等国。","appearance":"玉带海雕体长72至84厘米，翼展可达180至215厘米，雄鸟体重在2000至3300克之间，雌鸟略重，为2100至3700克。成鸟背部暗褐色，腹部颜色较淡，头部呈脏灰色。最显著的特征是飞行时下部宽阔的白色尾带。幼鸟全身较暗，尾部全黑，但翅膀下部有明显的白色区域。","call":"繁殖期间叫声频繁，叫声为响亮、浑厚且传播远的‘kha-kha-kha-kha’或‘gao-gao-gao-gao’，连续的嘶哑‘kook-kook-kook’声，有时发出尖锐兴奋的吠叫。","habits":"栖息于河流、湖泊和淡水湿地，常见于干旱地区或草原。迁徙模式主要受北方冰封影响，冬季可能到达内陆海域，如阿拉伯地区水库和沿海地带。在中国，可上至海拔5200米的高原。","breeding":"繁殖期在北印度和缅甸为9月至2月，筑巢于大树中，靠近水源。巢由树枝搭建，内部铺有柔软材料。产卵2至3枚，孵化期约40天，双亲共同抚养幼鸟，直至70至105天后离巢。","identification":"与灰头鱼鹰相比，体型更大，翅膀更长而尾巴相对较短。与白尾鹰相比，体型较小，上体颜色较浅，尾巴无白色。幼鸟与某些鸢类相似，但体型更大。","protection":"IUCN：EN（濒危）。在中国，被列为国家一级重点保护动物，中国濒危动物红皮书等级为渐危。","distribution":"分布于中国、印度北部、哈萨克斯坦、俄罗斯、塔吉克斯坦等国。在中国，主要分布在新疆中西部、青海、内蒙古东北部等地。","other":"玉带海雕尾羽珍贵，曾遭人类捕杀。在中国，数量稀少，栖息地破坏和草原灭鼠灭虫是主要威胁。"},{"name":"白尾海雕","english_name":"White-tailed Eagle","scientific_name":"Haliaeetus albicilla","overview":"白尾海雕（英文名：White-tailed Eagle，学名：Haliaeetus albicilla），是鹰形目鹰科海雕属的鸟类。大型猛禽，体长74-92厘米，体重2800-6900克。体羽多为暗褐色，头部、颈部羽色较淡，呈沙褐色或淡黄褐色，尾羽纯白色，形成鲜明对比。主要分布于温带欧亚大陆，从南部的希腊和土耳其延伸到北部的格陵兰和冰岛，偏好沿海、河流及淡水湖泊的栖息环境，以鱼类为主要食物。","appearance":"白尾海雕拥有长而厚重的喙，两翼宽阔似木板，尾部较短且楔形。成鸟头部和躯干浅褐色，尾部白色，喙黄色。幼鸟起初尾部几乎全呈褐色，具白色条纹，喙黑色；约四年后尾部变为全白。雌鸟平均比雄鸟大15%，重25%。","call":"主要在繁殖季节发出一系列尖锐的叫声，如“kyo-kyo-klee-klee-klee-klee...”，伴侣通常会立即回应类似系列的叫声。也会发出单一的尖叫声“kleee”或类似鸥类的“kyueew”。","habits":"主要栖息于沿海、河流及淡水湖泊的广阔沼泽地区。繁殖期偏好有高大树木的水域或森林地区的开阔湖泊与河流地带。以鱼类为食，也捕食鸟类和中小型哺乳动物，有时吃腐肉和动物尸体。冬季食物缺乏时，偶尔会攻击家禽和家畜。","breeding":"繁殖期为4月至6月。巢筑于湖边、河岸或附近的高大树上，巢由树枝构成，内部放置细小的枝叶和羽毛。每窝产卵通常为2枚，偶尔1至3枚。孵化期35至45天，雏鸟晚成性，由亲鸟共同喂养约70天后可离巢。","identification":"与金雕相比，白尾海雕头部和颈部颜色更接近其体羽，尾部纯白色，喙和脚黄色。在飞行时，翅膀水平或轻微上抬，与金雕不同。","protection":"IUCN：LC（无危）","distribution":"广泛分布于欧亚大陆，包括格陵兰、冰岛、北欧、中欧、东欧、俄罗斯、东亚部分地区。在亚洲，最东可达日本的北海道。","other":"历史上曾因人类活动而大幅减少，但自20世纪中叶以来，随着保护措施的实施，种群数量有所恢复。"},{"name":"白头海雕","english_name":"Bald Eagle","scientific_name":"Haliaeetus leucocephalus","overview":"白头海雕（英文名：Bald Eagle，学名：Haliaeetus leucocephalus），是鹰形目鹰科海雕属的鸟类。又名: 美洲雕、白头雕、白头鹰，以其独特的白色头部、黄色喙和脚，以及深褐色的身体著称。雄鸟平均体重约为4.1公斤，体长约70厘米，翼展可达1.8米，而雌鸟通常比雄鸟大25%，平均体重达到5.6公斤。在繁殖季节广泛分布于北美大陆，包括加拿大、美国大陆和墨西哥北部，尤其偏好靠近大型开阔水域的地方，如湖泊、河流和海岸线，以及拥有成熟树木的环境用于筑巢。白头海雕不仅是美国的国鸟，也是该国的象征之一，但在20世纪中叶曾因人类迫害和DDT农药的影响而濒临灭绝。","appearance":"白头海雕是一种大型猛禽，具有鲜明的外观特征。成年个体拥有黑色的身体，与白色头部和尾巴形成鲜明对比。喙、腿和脚呈鲜艳的黄色。雌鸟比雄鸟大25%，平均体重可达5.6公斤。亚成鸟的羽毛颜色较为暗淡，从深棕色到带有白色斑点的混杂色，直到约五岁达到性成熟时才会展现出成鸟的特征。成鸟的翼展宽广，可达2.3米，雄鸟的翼展略窄，大约1.8米。幼鸟的头部并非白色，而是逐渐随年龄增长而转变。","call":"白头海雕的叫声相对微弱，由一系列尖锐的哨声组成。","habits":"白头海雕主要栖息在靠近大型水域的地方，如湖泊、河流和海岸线，以便获取丰富的鱼类食物。它们是飞行高手，滑翔和鼓翼飞行的速度可达每小时56至70公里，即使携带鱼类也能保持48公里/小时的速度。白头海雕并不总是迁徙，除非其领地的水源在冬季冻结，影响觅食，此时它们会向南方或沿海迁移。它们在日间利用热流进行迁徙飞行。白头海雕以鱼类为主要食物来源，但也吃水鸟、哺乳动物、水禽等，有时还会抢夺其他动物的食物。","breeding":"白头海雕在四至五岁达到性成熟，通常返回出生地繁殖。它们实行终身配偶制，每年繁殖季，雌鸟会产下两枚卵，孵化期大约35天。小海雕在三个月后离开巢穴开始独立生活。白头海雕会反复使用和修缮同一个巢穴，有些巢穴的深度可达4米，宽度超过2.5米，重量达到1吨。","identification":"白头海雕与非洲的白尾海雕在头部均为白色，但分布区域不同，且白尾海雕的白色延伸至胸部和颈背。此外，白头海雕的体型更显雄壮。","protection":"IUCN：LC（无危）","distribution":"白头海雕广泛分布于北美洲，包括加拿大、美国大陆以及墨西哥西北部。在繁殖季节，它们倾向于选择靠近大型水源的地区，如湖泊、河流和海岸线。","other":"白头海雕是美国的国鸟，历史上曾因人类迫害和DDT农药的影响而面临灭绝的威胁。自1972年禁止使用DDT以来，白头海雕的数量显著回升。"},{"name":"虎头海雕","english_name":"Steller's Sea Eagle","scientific_name":"Haliaeetus pelagicus","overview":"虎头海雕（英文名：Steller's Sea Eagle，学名：Haliaeetus pelagicus），是鹰形目鹰科海雕属的鸟类。是鹰科海雕属的大型猛禽，平均体重约6.8公斤，拥有特大的黄色喙。主要繁殖于堪察加半岛、鄂霍次克海沿岸、黑龙江、库页岛北部及俄罗斯尚塔尔群岛一带，冬季迁徙至日本千岛群岛和北海道越冬。在中国，分布于辽宁、河北等地，多栖息于海岸、河口，是中国国家一级保护动物，全球性易危。","appearance":"虎头海雕体型巨大，头部硕大，喙为橙色。成鸟体色饱满的褐色，尾部、腹部和肩部雪白，翼尖狭窄，中间宽阔，靠近体侧时又变窄。亚成鸟羽色更深，但在第二年大部分尾部变为白色。喙深黄色，虹膜黄色，腿橙黄色。亚成鸟与白尾海雕亚成鸟相似，但虎头海雕喙更大，尾部呈楔形，翅膀形状独特。雌鸟体型大于雄鸟，重量可达雄鸟的79%。","call":"发出深沉的吠叫声，如ra-ra-ra-raurau，在冬季栖息地和觅食区域尤其明显，叫声类似但传播更远的白尾海雕。","habits":"栖息于海岸和河谷地带，偏好含鱼水域，集中于河流入海口或沿海岸，或鲑鱼迁徙的河流，或提供筑巢条件的湖泊。冬季主要依赖阿拉斯加鳕鱼和太平洋鳕鱼。夏季，成鸟可能在多种生境中活动，而亚成鸟主要在海岸活动。","breeding":"繁殖期为4月至6月，筑巢于海岸附近的林区河谷地带，巢由枯枝构成，形状为盘状，高达1.5米，直径可达2.5米。每窝产卵1至3枚，孵化期为38至45天，雏鸟为晚成性，70天后离巢。性成熟在4至5岁。","identification":"虎头海雕与白尾海雕的区别在于更大的喙，楔形尾，独特的翅膀形状，以及更暗的体色。雌鸟比雄鸟大19%，重79%。","protection":"IUCN：VU（易危）。CITES II。全球数量估计为4600至5100只，包括1830至1900对繁殖对，相当于3600至3800只成熟个体。数量自1990年代以来有所下降。在日本、俄罗斯、中国和韩国受到法律保护。","distribution":"主要繁殖于堪察加半岛、鄂霍次克海沿岸、黑龙江、库页岛北部及俄罗斯尚塔尔群岛。冬季迁徙至日本千岛群岛、北海道、南库页岛、乌苏里兰、韩国和中国东北。少量记录于中国华北地区。","other":"虎头海雕偶尔出现于北美，如德克萨斯州、马萨诸塞州、缅因州、纽芬兰等，以及亚洲内陆至北京和雅库茨克。"},{"name":"蝗鵟鹰","english_name":"Grasshopper Buzzard","scientific_name":"Butastur rufipennis","overview":"蝗鵟鹰（英文名：Grasshopper Buzzard，学名：Butastur rufipennis），是鹰形目鹰科鵟鹰属的鸟类。具有灰色和棕色的上体与赤褐色的下体。喉咙白色，中央有一条黑色线纹。飞行时，翅膀上方显露出独特的赤褐色斑块，而下翼主要是白色。栖息于非洲萨瓦纳和草原地带，迁徙时经常以群体形式出现，尤其在火场附近。叫声为一系列的“ki”音。","appearance":"成年蝗鵟鹰体长35–44厘米，体重雄鸟310–342克，雌鸟300–408克，翼展92–106厘米。体型中等，喙较弱，头部小，腿相对较长，尾巴中等长度，外形似风筝但行动迟缓。赤褐色的翼覆羽和下体在所有年龄段都是显著特征，尤其是结合黑色的翼缘。雌雄外观相似，但雌鸟平均比雄鸟大7%，重9%。虹膜淡黄色（幼鸟棕色），蜡膜和眼周黄色（幼鸟更偏绿黄色），腿色淡黄。幼鸟头部和颈部颜色较淡，有条纹，中央尾羽较灰，下方条纹较少。","call":"发出响亮的叽喳声'ki-ki-ki-ki-keee'，仅在繁殖季节听到。","habits":"栖息环境从林地边缘到干燥的荆棘草原，甚至半沙漠灌木丛。常见于沼泽边缘和火灾后的地面。分布海拔从海平面至1200米。广泛分布，是撒哈拉以南非洲的常见迁徙物种，跨越22°纬度，南迁至几内亚林地边界和森林区域度过10月至3月的旱季，随后北迁至半干旱草原繁殖。","breeding":"繁殖季节在雨季，撒哈拉区域为3–4月，喀麦隆北部为4–5月。可能分散成对领域繁殖。在树叉中筑大型巢，通常较低（高达10–12米），内部铺垫绿色叶子。产卵数1–3枚；雏鸟有白色或浅灰羽毛。孵化期30天，离巢期36天，离巢后依赖期约3周。","identification":"结构特征和飞行时赤褐色的翼板使其易于与其他鵟鹰区分开来。雄鸟和雌鸟在外表上难以区分，但雌鸟平均更大。","protection":"IUCN：LC（无危）。CITES II级。在西非干季时局部地区数量丰富，数量超过所有其他鵟鹰，但易受过度放牧和干旱影响。","distribution":"分布于塞内加尔和冈比亚向东至埃塞俄比亚；迁徙时南迁至一条横跨从塞拉利昂东至肯尼亚和坦桑尼亚北部的带状区域。","other":"形成超种群，与白眼鵟鹰、棕翅鵟鹰和灰脸鵟鹰关系密切，这些物种均分布在亚洲。"},{"name":"白眼鵟鹰","english_name":"White-eyed Buzzard","scientific_name":"Butastur teesa","overview":"白眼鵟鹰（英文名：White-eyed Buzzard，学名：Butastur teesa），是鹰形目鹰科鵟鹰属的鸟类。是鹰科鵟鹰属的中型猛禽。以其独特的白色虹膜著称，体长约40厘米，翼展可达1米左右。广泛分布于南亚，自伊朗东部至巴基斯坦、印度、尼泊尔，直至缅甸。主要栖息于平原至海拔1200米的干燥开放地带，以小哺乳动物、昆虫、两栖动物为食。","appearance":"体型偏瘦，翼展宽大，翼尖接近尾端。成鸟具显著的白色虹膜，喉部白色带有一条深色中线，上体棕色，尾羽红棕色。幼鸟虹膜呈棕色，头部颜色较浅。飞行时可见翼下白色，翼尖黑色。站立时可见后颈处的白色斑块。","call":"发出哀怨的喵鸣声或下降哨音，尤其在繁殖季节频繁。","habits":"偏好干燥的开放森林或耕作区，常在低地至海拔1200米的环境中活动。飞行习惯贴近地面，偶尔翱翔。主要以昆虫、小哺乳动物为食，也会捕食小型爬行动物。叫声低沉，常反复鸣叫。","breeding":"繁殖期为2月至6月，筑巢于树上，巢松散，由双亲共同建造。每窝产卵2至4枚，仅雌鸟孵化，孵化期约19天，但可能更长。双亲共同喂养幼鸟。","identification":"与灰脸鵟鹰在分布重叠区域容易混淆，灰脸鵟鹰具白色眉纹。白眼鵟鹰无典型的翼下腕斑，整个翼下表面呈暗色。","protection":"IUCN：LC（无危）；CITES II；在中国大陆，白眼鵟鹰的分布记录稀少，可能为迷鸟。","distribution":"分布于东洋界，从巴基斯坦至缅甸，包括印度、尼泊尔、泰国和中国西藏南部。在喜马拉雅山脉可至海拔1000米，夏季可能达到2000米。在中国极为罕见。","other":"白眼鵟鹰可能受益于印度的森林砍伐导致的觅食机会增加。"},{"name":"棕翅鵟鹰","english_name":"Rufous-winged Buzzard","scientific_name":"Butastur liventer","overview":"棕翅鵟鹰（英文名：Rufous-winged Buzzard，学名：Butastur liventer），是鹰形目鹰科鵟鹰属的鸟类。广泛分布于东南亚的森林地带，包括爪哇岛和苏拉威西岛，海拔高度可达800米。具有独特的灰褐色外观，翅膀和尾巴呈现出醒目的红褐色调，尤其是在飞行中更为明显。此鹰体型较小，长约38至43厘米，头部和下体偏灰色，而上体和尾羽呈现红褐色。在开阔的森林边缘和次生林中筑巢繁殖。","appearance":"成年棕翅鵟鹰体长38至43厘米，头部和下体以灰色为主，带有细密的暗色条纹，尤其在头冠、颈部和胸部可见。上体和尾羽呈红灰色，飞行时，从上方看，可以看到红栗色的飞羽和红褐色的上尾，从下方看，其下体呈灰色，下翼覆羽白色，飞行羽和下尾灰色。雌雄外观相似，而幼鸟颜色较为暗淡，头部棕色灰色，具白色眉纹。","call":"棕翅鵟鹰的叫声为尖锐的'pit-piu'，在繁殖季节尤为喧闹，第一音节比第二音节更高。","habits":"栖息于平原和低山的稀疏松林中，常见于山地林缘或开阔的田野。飞行方式类似隼，常在空中翱翔，迁徙时结成大群。主要食物包括小型哺乳动物、小鸟、蛇类、蜥蜴、蛙类和大型昆虫。飞行时双翅连续拍打，有时直线飞行，有时围绕特定地点盘旋。","breeding":"繁殖季节在2月至3月或4月（爪哇），可能在6月至7月（苏拉威西）。在大树冠或森林边缘的大型孤树上，由一对鵟鹰共同建造相对较小的棍状巢，内衬绿叶。每窝产2至3枚蛋，但关于孵化和雏鸟期的详细资料尚未发表。","identification":"棕翅鵟鹰与迁徙的灰脸鵟鹰在体型和形状上相似，但灰脸鵟鹰上体和尾巴颜色更深，喉咙白色，腹部有棕色斑纹。","protection":"IUCN：LC（无危）。全球数量估计少于10,000只所有年龄阶段的个体。在大部分分布区内被认为是常见到罕见，但部分地区有减少的趋势。在云南（中国）和爪哇罕见，近几十年在苏拉威西和泰国东北部似乎有所减少。","distribution":"分布于远东和澳新界的亚洲东南部，包括爪哇岛和印尼苏拉威西岛。在繁殖区主要分布于缅甸南部、中国西南云南省、印度支那半岛、爪哇岛以及苏拉威西岛。","other":"尽管在某些地区面临威胁，棕翅鵟鹰在全球范围内并未受到严重威胁，但其数量在某些区域已明显下降。"},{"name":"灰脸鵟鹰","english_name":"Grey-faced Buzzard","scientific_name":"Butastur indicus","overview":"灰脸鵟鹰（英文名：Grey-faced Buzzard，学名：Butastur indicus），是鹰形目鹰科鵟鹰属的鸟类。别名: 灰脸鹰，在台湾被称为灰面鹫，另有南路鹰、扫墓鸟、清明鸟、国庆鸟以及山后鸟等别称。这中型猛禽，体长39—46厘米，体重375—500克。繁殖于俄罗斯东部、日本和朝鲜等地，越冬于印度、缅甸、中南半岛、马来西亚、菲律宾、印度尼西亚和新几内亚等地。","appearance":"成年灰脸鵟鹰上体暗棕褐色，翅膀覆羽同样为棕褐色，尾羽呈灰褐色。头部、胸部及颈部灰色，喉部白色，有黑色髭纹和中线纹，背部和上翼棕色，腹部具棕色条纹。幼鸟上部颜色较淡，下部较浅，有棕色条纹，脸部棕色，眼色棕色，有宽阔的白色眉纹。","call":"灰脸鵟鹰的主要叫声被描述为刺耳的口哨声“whick-awee”或“pik-wee”。","habits":"灰脸鵟鹰栖息于阔叶林、针阔叶混交林以及针叶林等山林地带，高度可达海拔1500米的开阔林区。飞行缓慢沉重，喜欢从树上栖处捕食。主要食物包括小型蛇类、蛙、蜥蜴、鼠类、松鼠、野兔、狐狸和小鸟等动物性食物。","breeding":"每年4月末到5月初迁往繁殖地，9月末到10月初离开繁殖地。在繁殖地，它们会在3月晚期至4月筑巢，由双方共同建造，孵化期28—33天，主要由雌鸟负责。幼鸟在33—41天后离巢。","identification":"灰脸鵟鹰与凤头蜂鹰相比，头部比例更大，翼下横带更不明显，翅膀也更窄。","protection":"IUCN：LC（无危）","distribution":"繁殖于西伯利亚东部，日本，朝鲜半岛和中国东北部；越冬于亚洲东南部，菲律宾，印尼群岛和四王群岛（西北部，新几内亚）。在中国大陆，常见于山地林边或空旷田野。","other":"历史上，台湾地区的灰脸鵟鹰面临的主要威胁是无限制的狩猎。"},{"name":"密西西比灰鸢","english_name":"Mississippi Kite","scientific_name":"Ictinia mississippiensis","overview":"密西西比灰鸢（英文名：Mississippi Kite，学名：Ictinia mississippiensis），是鹰形目鹰科灰鸢属的鸟类。一种中型猛禽，分布于北美中南部和东南部，以狭长的翅膀和长尾著称，体色深灰，尾部黑色，头部和翅膀上有独特的白色斑点。红眼周围有黑色眼圈，喙黑色，口角有黄色边缘。雄鸟体长34-36厘米，重214-304克；雌鸟稍大，体长34.5-37厘米，重270-388克。繁殖期从5月至7月，冬季迁徙至南美中南部。","appearance":"密西西比灰鸢体长34至37厘米，翼展约75至83厘米，雌鸟较雄鸟大，体重范围从214至388克不等。全身呈深灰色调，背部及翅膀上覆羽暗至近黑色，翅膀次级飞羽上方有淡灰色至银白色，尾部均匀黑色，末端略方或微凹。头部、喉部、腹部、两胁及翼下羽毛颜色从浅灰至中灰不等，雄鸟头部和颈背较雌鸟更淡。幼鸟外观与成鸟显著不同，头部、颈部及腹面白色或淡黄，带有大量黑色、褐色条纹，上体及翅膀暗淡，边缘白色至棕色，尾部有大的白色斑点，形成2至3条白色带。","call":"发出尖锐的哨声，类似挤压玩具发出的声音。","habits":"密西西比灰鸢为群居鸟类，无论休息、觅食还是迁徙都以群体形式行动，飞行姿态优美，滑翔能力强。主要以昆虫为食，包括蟋蟀、蝗虫、甲虫等，也会捕食小型脊椎动物如鼠类、蜥蜴、青蛙和蛇。繁殖季节外，它们在树冠层筑巢，冬季迁徙至南美中南部。","breeding":"实行一夫一妻制，繁殖期为5月至7月。巢置于大树树叉上，距地面3至30米。雌鸟产卵数量为1至3枚，双亲轮流孵化29至32天。雏鸟孵化后由双亲喂养约25天，大约6周后雏鸟离巢，但需再经历10天左右的飞行练习才能独立生活。","identification":"成鸟易与巨翅鵟混淆，但可通过其独特的灰黑白色相间的翅膀模式和红色的眼睛加以区分。幼鸟有时会被误认为游隼，但其褐色条纹和尾部的白色带可作为辨识依据。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美中南部和东南部，冬季迁徙至南美中南部，包括阿根廷和巴西。","other":"自20世纪70年代以来，由于人类活动改变了栖息地，导致种群数量在西部美国增加。"},{"name":"南美灰鸢","english_name":"Plumbeous Kite","scientific_name":"Ictinia plumbea","overview":"南美灰鸢（英文名：Plumbeous Kite，学名：Ictinia plumbea），是鹰形目鹰科灰鸢属的鸟类。又名: 铅灰鸢，中型猛禽，以其石板灰色的羽毛、狭长的翅膀和长尾巴著称。分布于中美洲至南美洲北部，从墨西哥东北部至阿根廷北部，活动于低地森林和热带草原。","appearance":"成鸟主要为石板灰色，头部和腹部颜色较浅，下体腹部白色，背部有灰色与白色的暗条纹。尾巴短，呈黑色，带有2-3条白色条纹。眼睛为红色，腿为金黄色或橙色。飞行时可见主飞羽上的红色翼羽。雌雄相似，但雌鸟略大。体长34至37厘米，翼展84至94厘米，体重190至280克。","call":"发出类似哨声的si-see-oo叫声。","habits":"活动于低地森林和热带草原，飞行速度缓慢，频繁滑行，几乎完全捕食昆虫，偶尔也吃蝙蝠、鸟、蛇和蜥蜴。用利爪在地面拨弄猎物，或在空中捕捉昆虫，在飞行中吞噬。","breeding":"南美灰鸢是一夫一妻制。繁殖期从5月到7月，雌雄开始共同建立一个巢，有时修复旧巢。巢放置于离地面3-30米的大树树叉上。雌鸟每巢产1至2枚蓝色或白色的卵，孵化期为31至32天，雏鸟离巢需36天。","identification":"与高度迁徙的密西西比灰鸢相比，南美灰鸢全身颜色更深，缺乏后者翅膀二级飞羽上的白色斑块，而有独特的主飞羽上的红色翼羽。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲北部，从墨西哥东北部至阿根廷北部，包括东墨西哥至秘鲁、玻利维亚、阿根廷以及特立尼达岛。","other":"南美灰鸢在迁移过程中，尤其是在死树枝上栖息时，会形成较大的群体。"},{"name":"黑领鹰","english_name":"Black-collared Hawk","scientific_name":"Busarellus nigricollis","overview":"黑领鹰（英文名：Black-collared Hawk，学名：Busarellus nigricollis），是鹰形目鹰科黑领鵟属的鸟类。从墨西哥中部到阿根廷北部，常栖息于湿地和沼泽地带。","appearance":"成年黑领鹰拥有橙色的体羽和较淡的下体，头部白色至浅黄色，带有黑色的项圈，背部有黑色的条纹。翅膀宽大，尾巴相对较短，眼睛呈亮红棕色，喙和蜡膜为黑色，腿和脚为蓝白色。幼鸟则整体呈褐色，比成鸟暗淡，但具有相似的斑纹。雌鸟体型较大，通常比雄鸟大15%，但实际差异往往较小。","call":"通常很安静，但在繁殖季节会发出类似猪的尖叫声，有时被认为是芦苇般的‘wheeeeeah’声，声音起伏，还有尖锐的尖叫、鼻音哨声、喉音的双音咳嗽声和昆虫般的嗡嗡声。","habits":"偏好热带水域附近的栖息地，包括红树林、稻田、堤岸、沼泽和池塘，甚至小的静水池塘。主要以鱼为主食，也会捕食大型水生昆虫、青蛙、水鸟雏鸟、甲壳类动物、蜗牛、偶尔的蜥蜴、蛇和啮齿类动物。狩猎时通常从栖木上俯冲，偶尔在空中翱翔，但大多数时候在浅水中捕食，因为其羽毛并不防水。","breeding":"繁殖季节在6月至12月间，筑巢于高树或红树林中，巢由细枝和树叶衬里，巢高可达12至35米。每窝产卵1至2枚，孵化期未知，雏鸟的喂养主要由雌鸟承担，孵化至离巢期大约为55天。","identification":"与草原鸡鵟相比，黑领鹰更紧凑，有明显的暗色前额项圈，头部颜色与身体一致，翅膀外侧黑色较少，尾巴较长且有白色带纹。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲北部，从墨西哥中部至阿根廷北部，常见于沿海地带和湿地。","other":"在法属圭亚那，估计有约200对黑领鹰。在巴拿马，由于湿地排水，其数量似乎正在下降，这种情况可能在其他地方也同样存在。"},{"name":"食螺鸢","english_name":"Snail Kite","scientific_name":"Rostrhamus sociabilis","overview":"食螺鸢（英文名：Snail Kite，学名：Rostrhamus sociabilis），是鹰形目鹰科食螺鸢属的鸟类。是美洲中部至南部特有的中型猛禽，主要分布在从南部墨西哥到北部阿根廷，仅在美国佛罗里达半岛发现。以特化的饮食著称，主要食物为淡水苹果螺，拥有镰刀状的喙适于取食螺肉。繁殖于淡水沼泽、浅湖周边，分布区域受季节影响有所变化。","appearance":"食螺鸢体型中等，总长36至48厘米，翼展可达99至120厘米，体重300至570克。雌雄差异较小，雌鸟平均比雄鸟大3%。具有长而宽的翅膀，长度约29至33厘米，尾长16至21厘米，带白色臀部和尾下覆羽。喙呈深钩状，适应取食螺类，长度2.9至4厘米。雄鸟呈深蓝灰色，雌鸟及幼鸟为深棕色，具明显纵纹，雌鸟脸部有白色纹饰。成年个体虹膜红褐色，幼鸟虹膜深棕色。","habits":"栖息于淡水湿地，如沼泽、湖泊边缘，偏好有丰富植被的环境。以群居形式活动，冬季形成大型栖息群体。主要食物为苹果螺，偶尔捕食小型甲壳类、鱼类、小型哺乳动物。飞行时翼拍缓慢，头部向下搜寻猎物。","breeding":"繁殖期在热带地区全年均可，但在温带地区可能受季节影响。巢筑于灌木或地面，一次产卵3至4枚。","identification":"与黑臀食螺鸢相似，但后者尾部更短，颜色更暗。与Black Hawk种类相比，翼展更大，尾部更短。与北鹞相比，翼形不同，前者翼展时呈杯状，后者呈V字形。","protection":"IUCN：LC（无危）。在佛罗里达，由于栖息地退化，曾被列为濒危物种。","distribution":"繁殖于南佛罗里达、加勒比海岛屿至阿根廷东北部，全年栖息于热带地区，温带地区冬季迁徙。","other":"自1967年起列为美国濒危物种，因Everglades湿地恢复计划而逐渐恢复。入侵物种Pomacea maculata的出现，导致食螺鸢快速进化，身体和喙变大。"},{"name":"黑臀食螺鸢","english_name":"Slender-billed Kite","scientific_name":"Helicolestes hamatus","overview":"黑臀食螺鸢（英文名：Slender-billed Kite，学名：Helicolestes hamatus），是鹰形目鹰科黑臀食螺鸢属的鸟类。中型猛禽，分布于中美洲东部至南美洲亚马逊雨林。体长35-41厘米，蓝灰色羽毛覆盖全身，黑色的尾巴和翅膀边缘，橙色的眼睛，裸露的脸部皮肤呈橙红色。黑臀食螺鸢与食螺鸢外形相似，但其尾巴更短且无白色痕迹，眼色为黄色而非红色。","appearance":"黑臀食螺鸢拥有宽大圆顶的翅膀和短方形的尾巴，在飞行中几乎不突出于翅膀之后。整体羽毛呈板岩灰色，翅膀和尾巴为黑色，眼睛颜色从白色到橙黄色，腿、蜡膜和面部皮肤为黄橙至橙红色。幼鸟与成鸟相似，但尾巴有2-3条白色横纹和白色尖端，翼覆羽、次级飞羽和臀部有淡色或白色的边缘。","call":"发出类似猫头鹰的哀怨叫声，'weeeuuu'声，以及鼻音上升再下降的'wheeeaaaaah'声。","habits":"栖息于泛洪森林边缘，如浅水湖周围和干燥的泛洪区域，雨林，沼泽森林边缘，尤其偏爱várzea地区，以及静止的湖泊和种植园，海拔可达750米。经常成群低空翱翔，但飞行高度不高。","breeding":"繁殖季节在委内瑞拉和圭亚那为6月至10月，正值雨季。巢距离地面平均14米高，位于倾斜的树枝或树干分叉处，巢材由树枝构成，外部装饰新鲜枝条，由双亲共同维护。每次产2枚卵，孵化期约30天，雏鸟35天离巢，40天能飞行，双亲轮流孵化、照顾和喂食。","identification":"与雄性食螺鸢相比，黑臀食螺鸢具有黄色眼睛，较短的尾巴，更宽的翅膀和更加纤细的喙。巢中雏鸟的羽毛与成鸟更为接近。","protection":"IUCN：LC（无危）；CITES II（华盛顿公约二级保护）。","distribution":"分布于极端东巴拿马至亚马逊雨林区域，包括北与东哥伦比亚、委内瑞拉西部和东北部、苏里南、法属圭亚那，巴西亚马逊地区至秘鲁东部和玻利维亚（潘多和贝尼）。","other":"曾被重新分类入Rostrhamus属，后再次独立出来。"},{"name":"鹤鹰","english_name":"Crane Hawk","scientific_name":"Geranospiza caerulescens","overview":"鹤鹰（英文名：Crane Hawk，学名：Geranospiza caerulescens），是鹰形目鹰科鹤鵟属的鸟类。以其独特的长腿和小头著称。广泛分布于中美洲和南美洲热带低地，包括墨西哥至乌拉圭的地区。偏好靠近水源的森林边缘和湿地环境。","appearance":"鹤鹰体长介于38-54厘米，体重因性别和亚种而异，雄鸟约225-358克，雌鸟略重，可达273-430克，某些亚种体重范围更宽。翅膀展开宽度为76-111厘米。最显著的特征是其异常长的腿，尤其是胫跗骨部分。羽毛颜色通常为蓝灰色、石板色或黑色，部分亚种下体有不同程度的细白条纹。尾部长而细，黑色，带有两道明显白色或淡黄色横带及窄白色尖端。成鸟的腿长且呈红褐色，眼睛颜色在北美洲和南美洲北部为红色，而在南部则为黄色。幼鸟头部有白色斑纹，下体颜色变化大，从棕色到灰白色不等，有时腹部和腿部有斑点或条纹。","call":"鹤鹰的叫声多样，最常听到的是短促、含糊的爆破声“keeuw！”或“WHEEe-oo”，有时连续重复，音质类似的叫声，也被比作警笛声。饥饿时会发出单音节的‘p-weeOO’叫声，类似于猫的喵喵声。防御或攻击时会发出鼻音、尖锐、拖长的尖叫“MEEeahh”，同样与阔嘴鵟相似。偶尔会发出一系列柔和的哨声，由短促渐变为拖长。","habits":"鹤鹰适应性强，栖息地从干燥的半落叶林到雨林，再到红树林、灌木丛、草地和画廊森林，常见于池塘和沼泽附近。活动范围广泛，从海平面至海拔至少750米，但多数时间位于500米以下。以各种小型脊椎动物为食，包括啮齿类、蝙蝠、蜥蜴、蛇、蛙类和小鸟，也会捕食大型节肢动物、软体动物和果实。捕猎技巧独特，会攀树如啄木鸟般搜寻树洞中的猎物。","breeding":"繁殖季节从四月至十月不等，视地理位置而定。筑巢期在三月底至四月中旬，幼鸟于六月中至六月末离巢。巢较小且浅，由树枝和藤蔓构成，内部铺有草、杂草和细枝，装饰以新鲜树叶，通常建在高10-15米的活树上，但在特定地区高达24米以上。每窝产卵1-2枚，孵化期约39天，由双亲共同孵化，雌鸟承担更多责任。雏鸟孵化时身披淡黄色绒毛，黑裸部分除粉红色的腿外。从孵化到离巢的时间为32-44天。","identification":"鹤鹰与非洲Polyboroides属的鸟类在外形和行为上相似，但并非近亲，是趋同演化的例子。不同亚种间在整体体色和翼下斑纹的多少上有差异，livens、nigra和balzarensis亚种体色均匀，从石板灰到石板黑不等，腹部、大腿和臀部有模糊的条纹（nigra亚种颜色最深；livens比balzarensis体型稍大）；指名亚种为最小的亚种，下方无条纹或仅在大腿和腹部有轻微条纹；gracilis和flexipes亚种上方相对较浅，下方有明显的条纹，后者也是体型最大的亚种。","protection":"IUCN：LC（无危）；CITES II。鹤鹰在全球范围内并不面临严重威胁，但由于森林砍伐，其在墨西哥的数量正在下降，甚至在萨尔瓦多濒临灭绝。","distribution":"鹤鹰分布于中美洲和南美洲的热带低地，从墨西哥向南至乌拉圭。具体而言，它们可以在阿根廷、伯利兹、玻利维亚、巴西、哥伦比亚、哥斯达黎加、厄瓜多尔、萨尔瓦多、法属圭亚那、危地马拉、圭亚那、洪都拉斯、墨西哥、尼加拉瓜、巴拿马、巴拉圭、秘鲁、苏里南、特立尼达、乌拉圭和委内瑞拉找到。","other":"尽管鹤鹰在全球分布广泛，但其数量并不普遍丰富，特别是在墨西哥和萨尔瓦多等地受到威胁。"},{"name":"铅色南美鵟","english_name":"Plumbeous Hawk","scientific_name":"Cryptoleucopteryx plumbea","overview":"铅色南美鵟（英文名：Plumbeous Hawk，学名：Cryptoleucopteryx plumbea），是鹰形目鹰科铅色南美鵟属的鸟类。其分布范围局限于巴拿马东部至厄瓜多尔西北部一带。体长介于33至37厘米之间，翼展可达71至79厘米，具有灰色的外观，翅膀呈黑色并有一条显眼的白色中带，尾巴短而黑，仅有一道白色环带。腿部和喙基部呈现红橙色，使它在森林环境中独具特色。","appearance":"成年铅色南美鵟全身呈现铅灰色，翅膀黑色，尾部具有一条明显的白色中带，下体覆羽白色，大腿处细密地带有白色条纹。虹膜颜色为红橙至红色，裸露部位如蜡膜、额部和腿均为橙色。与近缘物种青灰南美鵟相比，体型更小，翼长在219至248毫米之间，缺乏尾部白色的终端带。雌雄外观相似，雌鸟平均略大于雄鸟。幼鸟大腿处的条纹更加明显，腹部有淡灰色斑点，眼睛呈棕色。","call":"铅色南美鵟最常发出的叫声是一种响亮、拉长的口哨声‘wheeeeuuu’，带有忧郁的音调。当兴奋时，也会发出颤音‘weedidididi’。","habits":"主要栖息于热带雨林中，通常生活在低地和山脚森林的闭合树冠内部，偶尔在退化森林中被记录到。活动范围从海平面至1400米，但主要分布在200至800米的高度。以青蛙、螃蟹、鱼和水蛇为食，沿河岸和湖泊狩猎，主要采取守株待兔的方式捕食，不常翱翔。","identification":"与青灰南美鵟相比，铅色南美鵟体型较小，翼长较短，缺乏尾端白色带，且裸露部分的颜色不同。","protection":"IUCN：NT（近危）","distribution":"分布于巴拿马东部至秘鲁西北部，包括哥伦比亚西部、厄瓜多尔北部以及秘鲁的极西北部（Tumbes）。在大部分分布范围内，由于农业扩张和木材采伐导致的森林砍伐现象普遍且加速，这对其生存构成威胁。","other":"铅色南美鵟曾被归入Leucopternis属，后遗传数据分析显示其与青灰南美鵟不属于同一属，现认为是独立的物种。"},{"name":"青灰南美鵟","english_name":"Slate-colored Hawk","scientific_name":"Buteogallus schistaceus","overview":"青灰南美鵟（英文名：Slate-colored Hawk，学名：Buteogallus schistaceus），是鹰形目鹰科鸡鵟属的猛禽。俗称: “土豹”，体型中等到大，以深灰色为主色调，尾羽具独特的明亮白色横纹，拥有橙色喙基和黄色眼睛。广泛分布于亚马逊雨林，包括巴西、玻利维亚、秘鲁、厄瓜多尔、哥伦比亚、委内瑞拉和法属圭亚那。","appearance":"青灰南美鵟身长约40-46厘米，翼展可达85-96厘米。羽毛呈深铅灰色，头部和翅膀颜色更深，尾羽黑色，末端略带白色，且有一条明显的白色横纹。成年个体的虹膜颜色从黄色到红黄色不等，喙基、眼周皮肤和脚为红橙色。雌雄相似，但雌鸟平均略大。幼鸟腹部、大腿和翅膀下方有细白条纹，虹膜黄色，喙基和腿橙黄色。","call":"其最常见的叫声是一种下降的刺耳哨音'keeyuuu'，带有些许忧郁的音质，重复间隔较长。还有快速连续约20-30个金属般的音符'kikikiki...'。幼鸟的乞食叫声为更高音的芦笛般哨音。","habits":"栖息于热带低地森林和湿地，从海平面至至少500米海拔。常见于缓慢流动的河流、沼泽和湖泊旁，也出现在红树林和河岸森林。主要以蛇、蜥蜴、蛙、鱼、蟹和昆虫为食，观察到跟随松鼠猴群捕食被它们惊飞的昆虫。偶尔猎食小型哺乳动物如鞍背狨猴。","identification":"比近缘种体型更大，裸露部位和下翼覆羽颜色也不同。在亚马逊地区，是唯一具有深灰色羽毛和红色裸露部位的鵟。","protection":"IUCN：LC（无危）。CITES II。总体较为常见，但由于森林砍伐可能构成长期威胁，需进行调查评估确切状况。","distribution":"分布于南美洲亚马逊雨林区域，包括哥伦比亚东南部、委内瑞拉西南部，通过厄瓜多尔东部和秘鲁东部到达玻利维亚北部和东部，东至法属圭亚那东北部和巴西中部。"},{"name":"黑鸡鵟","english_name":"Common Black Hawk","scientific_name":"Buteogallus anthracinus","overview":"黑鸡鵟（英文名：Common Black Hawk，学名：Buteogallus anthracinus），是鹰形目鹰科鸡鵟属的鸟类。其分布范围从美国西南部延伸至南美西北部，包括中美洲、委内瑞拉、秘鲁、特立尼达、小安的列斯群岛等地。这种猛禽以黑色或深灰色为主色调，拥有宽阔的翅膀和较短的尾巴，尾部有一条显著的白色宽带和白色尖端。黑鸡鵟通常栖息于沿海的红树林沼泽、河口和相邻的干燥开阔林地，但在内陆也有发现，包括墨西哥西北部和亚利桑那州的迁徙群体。","appearance":"成年黑鸡鵟体长43-56厘米，平均体重930克左右。两性颜色相似，主要呈黑色或暗灰色，翅膀宽大，尾部短，有明显的白色中间带，尾尖白色。喙黑色，腿和蜡膜黄色。与斑尾鵟相似，但尾部白纹更少，体型更大。幼鸟上半身暗棕色，有斑点和条纹，下半身淡黄色至白色，带有深色斑点，尾巴有多条黑白相间的条纹。","call":"发出独特的管道状叫声，'spink-speenk-speenk-spink-spink-spink'。","habits":"黑鸡鵟主要栖息于沿海红树林、河口和邻近的干燥林地，偶尔出现在内陆。它们会进行懒散的滑翔，偶尔拍打翅膀，有着触爪的空中求偶展示。以螃蟹（尤其是陆地蟹）、小龙虾为主食，也会捕食小型脊椎动物、腐肉（如死鱼）、蛋和昆虫。","breeding":"在树上，通常是红树林中，建造由树枝构成的平台巢，高度从十五到一百英尺不等。每窝产卵一至三枚，通常一枚，卵呈白色，有褐色斑点。已知与赤肩鵟自然杂交。","identification":"与斑尾鵟相比，黑鸡鵟尾部的白色条纹较少，体型更大。","protection":"IUCN：LC（无危）。在美国北部受到《1918年候鸟条约法》的保护。","distribution":"分布于北美、中美和南美，具体从美国西南部至南美西北部，包括墨西哥、中美洲、委内瑞拉、秘鲁、特立尼达和小安的列斯群岛。","other":"曾将古巴黑鹰视为其亚种，但现在被认为是独立物种。"},{"name":"古巴鸡鵟","english_name":"Cuban Black Hawk","scientific_name":"Buteogallus gundlachii","overview":"古巴鸡鵟（英文名：Cuban Black Hawk，学名：Buteogallus gundlachii），是鹰形目鹰科鸡鵟属的鸟类。原生于古巴及其周边若干小岛。其体色深褐至黑色，与停歇的秃鹫不同，具有羽毛覆盖的头部、黄色喙及腿。飞行时，其巨大的体型和翼端显著的白色斑块是最容易辨认的特征。幼鸟上部呈棕色，下部条纹状，与幼年宽翅鹰和红尾鹰相似。","appearance":"成年古巴鸡鵟全长43至52厘米，雄鸟体重可达650克。翼展信息未知。与黑鸡鵟相比，体型较小，背部更偏棕色，具白色颊纹和翼下较大的白色斑块。成鸟眼睛深褐色（幼鸟较淡），蜡膜、眼周及脚橙黄至黄色。幼鸟下部白色，重叠大量棕色斑点。","call":"发出响亮、尖锐的‘weet-WEET-whew’或‘weet-WEET-whew-puh’声，亦会发出刺耳尖叫。","habits":"主要栖息于海岸附近的红树林中，偶尔出现在沙滩和棕榈草原。据观察，其生活方式以定居为主。以蟹类为主食，也捕食鱼类、腐肉、啮齿类和蜥蜴。","breeding":"繁殖期通常从一月持续到六月。巢建于红树林的亚冠层，由红树林枝条构成，内部铺垫树叶。巢直径70至107厘米，深度45至95厘米，离地面高度3.5至8米。每窝产卵1至2枚，卵平均尺寸为55.9毫米×42.7毫米，底色为灰白，有时带有绿色或蓝色调，表面散布红棕色斑点。","identification":"与黑鸡鵟相比，古巴鸡鵟体型更小，背色更偏棕色，翼下白色斑块更大，头部有不明显的颊纹，翼部无红褐色斑块。叫声由三至四个音符组成，而黑鸡鵟的叫声由九至二十四个音符组成。","protection":"IUCN：NT（近危）, CITES II级。古巴国家级：Endangered（濒危）。原生栖息地遭受破坏，导致栖息地碎片化和范围缩减。","distribution":"分布于古巴本土及松树岛（Isle of Pines），主要在沿海红树林区域，偶尔见于内陆森林和山地，但多数记录海拔低于800米。","other":"曾被认为是Mangrove Black Hawk的一个亚种，后因叫声和羽毛模式的不同被分类为独立物种。"},{"name":"棕鸡鵟","english_name":"Rufous Crab Hawk","scientific_name":"Buteogallus aequinoctialis","overview":"棕鸡鵟（英文名：Rufous Crab Hawk，学名：Buteogallus aequinoctialis），是鹰形目鹰科鸡鵟属的鸟类。近危物种。分布于南美洲，自委内瑞拉沿海至巴西东北部沿海地带。以其独特的黑色头部、喉咙和颈背，以及暗红褐色的背部和翼羽著称。","appearance":"体长42.5至46厘米，翼展90至106厘米。雄鸟体重介于506至665克之间，而雌鸟更重，约725至945克。成鸟的头部、喉咙和颈背呈烟灰黑色，背部深红褐色带淡红边缘。下体红褐色，细密的暗色横斑。尾巴黑色，尖端白色，中央有一条薄白带。眼睛棕色，蜡膜和脚黄色至橙红色。幼鸟上体从黑褐至褐黑色，灰色尾巴，下体白色，带有暗色条纹。","call":"发出响亮且略尖锐的哨声或笑声，由5至7个音符组成，起始快速上升并逐渐增强，随后变慢，下降并渐弱，总长度约1秒。","habits":"常居留于沿海低地沼泽、红树林、湿地草原和河流边缘，尤其偏好红树林环境，几乎总是在海平面附近活动。以蟹类为主食，如在苏里南的Ulcides cordatus和Callinectes bocourti。捕食时从低处俯冲，将猎物带到树桩、低枝或干燥地面食用。","breeding":"在苏里南，繁殖季节在雨季（2月至8月）；在巴西东南部可能从9月开始。筑巢于红树林或水边树上的树枝，巢材为枝条，内衬树叶。通常产一枚蛋，有时两枚，但孵化期和雏鸟成长时间未知。","identification":"与和有区别，后者有更广泛红褐色的羽毛，前者尾部有宽白色带，后者头部白色，颈部黑色。","protection":"IUCN：NT（近危）, CITES II。在南美洲红树林中最常见的猛禽之一。由于其栖息地限制，对任何形式的恶化或丧失高度敏感，尤其是在委内瑞拉和法属圭亚那。","distribution":"分布于特立尼达岛，从委内瑞拉卡诺阿吉斯和奥里诺科三角洲向东沿海岸线至巴西东南部（帕拉纳州）。在巴西，从阿马帕到马拉尼昂最为丰富，从塞阿拉到帕拉纳似乎较为罕见。","other":"在牙买加一个1750年历史的洞穴沉积中发现该物种的两块骨头，表明它以前在加勒比海地区存在过。"},{"name":"草原鸡鵟","english_name":"Savanna Hawk","scientific_name":"Buteogallus meridionalis","overview":"草原鸡鵟（英文名：Savanna Hawk，学名：Buteogallus meridionalis），是鹰形目鹰科鸡鵟属的鸟类。分布广泛，从中美洲的巴拿马到南美洲的阿根廷北部都有其踪迹。其下体具有细密的横纹，是其显著的外部特征之一。草原鸡鵟在开放的热带草原、沼泽边缘等地域活跃。","appearance":"草原鸡鵟体长46至64厘米，体重740至1134克，翼展可达121至140厘米。外观瘦长，头部小，颈部和腿较长，翅膀相当长。头部、颈部和下体呈赤褐色至肉桂色；后颈有条纹，背部深棕色边缘呈赤褐色；下方有细密的黑色条纹，除了喉咙处；初级飞羽和次级飞羽宽边黑色；尾巴黑色，中央有一窄带，末端白色。虹膜颜色从红黄色到淡棕色不等，后者可能仅在幼鸟中出现；蜡膜黄色（幼鸟中的颜色更浅），腿部淡橙黄色。雌鸟与雄鸟相似，但体型略大（仅大2-5%）。幼鸟上部呈烟灰色，有明显的白色眼纹；肩部有斑驳的赤褐色；下体呈黄褐色，胸部有黑色斑点，腹部和大腿有条纹；尾巴黑色，有不规则的条纹。","call":"主要鸣叫声音为‘kree-ee-ee-er’，以哀号结尾，既可在栖息地发出，也可在飞行中发出；此外，面对入侵者在巢穴附近时会发出短促的‘krreh’声。","habits":"栖息于热带至亚热带地带，主要海拔高度在1000米以下，但在哥伦比亚曾记录到高达2075米。一般在开阔地带、牧场、树木和棕榈树草原、沼泽地、森林边缘、河岸和红树林中活动，常出现在水边，包括红树林。在南美洲，草原鸡鵟似乎部分迁徙，大量个体在南半球冬季出现在哥伦比亚，可能在季节性完全或部分撤出最南端的繁殖区域。在雨季，淡水螃蟹和鳗鱼成为其重要的猎物。以低矮的栖木为猎捕起点，笨拙地俯冲向猎物，但其饮食中鸟的比例较高，表明它是一个敏捷的捕食者。会从其他鸟类，如鹳、鹮和鹭那里抢夺食物。在草火中觅食，甚至会在火后几米的地方步行搜寻烤熟的猎物，有时会跟随犁耕。","breeding":"繁殖季节长，从2月到9月（雨季）在委内瑞拉，但在南美洲的繁殖季节主要集中在6月至8月；在哥伦比亚和特立尼达岛为2月至6月，在苏里南为12月至5月。筑巢直径约60厘米，内衬树叶或草，通常位于孤立的树上，但有时隐藏在棕榈叶或凤梨科植物中。巢可能因重复使用而变得相当大。每窝产一枚白色蛋（偶尔两枚），尺寸为59-59.5毫米×46-47.5毫米，重量50克。孵化期为39天；幼鸟离巢时间为45至50天；离巢后依赖父母的时间为4至7个月。在棕榈草原的密度为每0.41平方公里一对。巢失败率高（52.9%），但会重新筑巢，尽管成功率不高。长时间的离巢依赖性和相对较高的成年存活率（71%）补偿了低筑巢成功率。","identification":"最易与混淆，但后者通过白色头部和黑色前颈环以及全黑的初级飞羽容易区分。是沿海物种，头部黑色。","protection":"IUCN：LC（无危）。被列入CITES II附录。最近（自2008年以来）由于持续的森林砍伐，该物种已扩散至哥斯达黎加西南部；在哥伦比亚似乎不常见，除草原外，一些地方已经灭绝，例如卡乌卡山谷。在更南的草原环境中普遍常见。物种似乎安全，随着持续的森林砍伐，数量可能会增加。","distribution":"分布于中美洲的巴拿马（从奇里基省西部开始）、南美洲安第斯山脉以西的热带地区（厄瓜多尔西南部和秘鲁西北部）、北哥伦比亚东至委内瑞拉、特立尼达岛和圭亚那群岛，以及巴西大部分地区、玻利维亚东部、巴拉圭到阿根廷北部（图库曼、科尔多瓦和圣菲）和乌拉圭北部；可能已殖民哥斯达黎加（最近在西南部有记录）。"},{"name":"白颈南美鵟","english_name":"White-necked Hawk","scientific_name":"Buteogallus lacernulatus","overview":"白颈南美鵟（英文名：White-necked Hawk，学名：Buteogallus lacernulatus），是鹰形目鹰科鸡鵟属的鸟类。俗称: “土豹”，中等体型的黑白相间猛禽，以黄色喙基、白色头部和腹部、黑色背部为显著特征，尾部白色带黑色次端环纹。常见于巴西大西洋森林密集区，与黑背鵟容易混淆，但后者体型更大且尾部无暗色端环。幼鸟头颈部有暗色条纹。","appearance":"体长约43至48厘米，翼展91至101厘米。头部和下体白色，上体深色；尾部黑色，中间有宽阔的白色亚端环带；虹膜棕色或浅黄色，腿和脚黄色。雌雄羽毛相似，但雌鸟平均比雄鸟略大4%左右。幼鸟与成鸟相似，但头颈有暗色条纹，部分上体羽毛尖端红棕色，尾巴基部黑色部分有不规则白色横斑。","call":"其鸣叫特征未详述。","habits":"主要栖息于稠密的大西洋森林，从海平面到至少900米高度，局部可达1300米，甚至在米纳斯吉拉斯州的塞罗多马尔山脉高达2890米处也有记录。倾向于低地森林环境，而非披风南美鵟。通常被认为是定居物种，但在贝洛奥里藏特城市范围内记录的零星数据暗示可能有分散迁移的行为。以地面猎物为主，如蛇、蜥蜴、两栖动物、哺乳动物、鸟类、蜗牛、昆虫和大型蜘蛛。会跟随行军蚁群和猴群寻找被驱赶出的猎物。","breeding":"关于繁殖生态的信息目前未知。","identification":"与披风南美鵟区别明显，后者尾部全白，有黑色基部，面罩深色，次级飞羽下方更带状，且体型更大，翅膀更长但尾巴较短。在东北巴西，可能与极为罕见的白领美洲鸢混淆，但白领美洲鸢飞行时翅膀呈轻微的双角形，尾部边缘有明显的黑色带，而白颈南美鵟则无此特征。","protection":"IUCN：VU（易危）。被列入CITES II附录。种群数量估计在2500至10000只成熟个体之间，面临因栖息地丧失和人为迫害导致的数量持续下降。","distribution":"分布于巴西东部，从帕拉伊巴州、伯南布哥州、阿拉戈阿斯州和巴伊亚州南部，断断续续至里约热内卢州、圣保罗州和极东的巴拉那州和圣卡塔琳娜州（圣卡塔琳娜州的记录可能仅为历史性的）。","other":"尽管在一些保护区有记录，如帕拉伊巴州的瓜里巴斯生物保护区、巴伊亚州的乌纳生物保护区和三峰国家公园等，但由于种群密度低、保护区之间距离远以及栖息地外的大量森林破坏，白颈南美鵟仍处于风险之中。"},{"name":"大黑鸡鵟","english_name":"Great Black Hawk","scientific_name":"Buteogallus urubitinga","overview":"大黑鸡鵟（英文名：Great Black Hawk，学名：Buteogallus urubitinga），是鹰形目鹰科鸡鵟属的鸟类。别称Urubutinga。主要分布于中美洲和南美洲，从墨西哥至阿根廷北部的热带地区。以黑色为主，有黄色的喙基和腿脚，尾部具有独特的白色条带。成鸟与幼鸟在外形上有所差异，幼鸟呈棕色，有暗色斑纹。","appearance":"成年大黑鸡鵟身长56到64厘米，体重约1.1千克。全身主要为黑色，翼展宽广。尾部较短，有白色基部和黑色尖端。喙全黑，腿脚和蜡膜黄色。雌雄相似，但幼鸟上体暗褐色，下体淡色带暗斑，尾部有多条暗色横纹。","call":"鸣声独特，发出类似'ooo-wheeeeee'的哨音。","habits":"大黑鸡鵟主要栖息于沿海地带，也出现在森林和靠近水源的开阔林地。以狩猎方式获取食物，主要捕食小型脊椎动物，如两栖动物、鱼类、鸟类、小哺乳动物（包括蝙蝠）、螃蟹、大型昆虫、腐肉、蛋和果实。常在地面、植被中或浅水区捕食，也会在空中翱翔。","breeding":"繁殖期间，大黑鸡鵟会在树上筑造大型的棍状巢，通常产一枚带有深色斑点的白色蛋。","identification":"与黑鸡鵟相比，大黑鸡鵟体型略大，腿脚更长，尾巴更长，且叫声不同。成鸟尾部有两条白色条带（北方亚种）或尾部基部宽阔白色而末端黑色（南方亚种）。幼鸟头部比黑鸡鵟显得更白，尾部有较多且较窄的浅色横纹。","protection":"IUCN：LC（无危）","distribution":"大黑鸡鵟广泛分布于中美洲和南美洲，从墨西哥至北阿根廷，包括亚马逊河流域。","other":"大黑鸡鵟曾有一次异常迁徙记录，一只个体在美国得克萨斯州和缅因州出现，最终因严重冻伤被安乐死。"},{"name":"孤冕雕","english_name":"Solitary Eagle","scientific_name":"Buteogallus solitarius","overview":"孤冕雕（英文名：Solitary Eagle，学名：Buteogallus solitarius），是鹰形目鹰科鸡鵟属的鸟类。大型新热带区鹰，体型庞大，羽毛深灰色，尾部带有白色标记。主要分布于墨西哥至南美洲西部和北部的山地森林地带，高度介于600米至2200米之间。","appearance":"成年孤冕雕通体呈暗灰近黑色，翼展宽广，长度可达152至188厘米，身长63至79厘米，体重约3公斤。其翅膀宽大，几乎延伸到尾端，赋予其独特的厚实外观。幼鸟则呈现斑驳的棕黄色，眼部周围有特殊标记，整体上与成鸟相似。","call":"飞行时发出快速连续的尖锐哨声，如'pipipipipi...'或较慢的'weet weet weet...'，持续时间可达20秒。当停栖时，则发出长而有力的'keeeeeerloooooo'叫声。","habits":"主要栖息于山地森林环境，包括热带和亚热带森林、云雾林及松栎林，偏好海拔600至2200米的高度。以蛇类为主食，偶尔捕食其他小型哺乳动物。狩猎技巧高超，能有效捕获树栖物种。","breeding":"繁殖习性知之甚少，巢穴通常由枯枝和绿叶构成，宽度70至120厘米，深度约30厘米，置于高树的分叉处。已知的一次观察显示，幼鸟至少在离巢后2.5个月仍依赖父母供给食物。","identification":"与常见的黑鹰相比，孤冕雕体积更大，翅膀更宽，脚部更粗壮，飞行时尾部的白色带纹更为明显。幼鸟的斑驳羽毛和眼部标记有助于识别。","protection":"IUCN：NT（近危）；全球种群估计在1000至2499只成熟个体间，受栖息地丧失和猎杀威胁。","distribution":"分布于中美洲至南美洲西部和北部，包括墨西哥南部、危地马拉、洪都拉斯、尼加拉瓜、哥斯达黎加、巴拿马、哥伦比亚、委内瑞拉、圭亚那、法属圭亚那、玻利维亚和阿根廷西北部。","other":"面临的主要威胁包括森林砍伐、射杀和一般性干扰。"},{"name":"冕雕","english_name":"Chaco Eagle","scientific_name":"Buteogallus coronatus","overview":"冕雕（英文名：Chaco Eagle，学名：Buteogallus coronatus），是鹰形目鹰科鸡鵟属的鸟类。以灰银色的羽毛、黑色带白边的尾巴和黄色的喙与腿著称。其独特的‘冠’由深灰色羽毛组成。冕雕分布于南美东部和中部，包括巴西、玻利维亚、巴拉圭和阿根廷的中部地区，偏爱开阔的草地、灌木丛和稀树草原。","appearance":"冕雕是一种大型猛禽，成鸟体长可达73至79厘米，翼展约170至183厘米。全身以灰银色为主，背部和头部颜色较暗。短而黑的尾巴上有宽大的白色中间条纹和窄白色尖端。头部有细小的暗灰色羽冠。幼鸟上半身呈棕色，下半身奶油色或淡黄色，有深色条纹。黄色的喙和腿是其显著特征。","call":"冕雕的叫声是一连串高音的哨声，响亮且穿透力强，能在两公里外听到。","habits":"冕雕通常单独或成对出现，偏好在清晨和黄昏时段活动。它们栖息于半开放的生境，如混合草甸、灌木地、稀树草原、沼泽和开阔林地。冕雕以小型到中型哺乳动物为食，如犰狳、臭鼬、啮齿类、负鼠、欧洲野兔和小浣熊等。也会捕食蛇、龟和蜥蜴等爬行动物。","breeding":"冕雕为一夫一妻制。每年8月至10月期间，会在树顶或高处搭建平台状的巢穴，产下一枚带有灰色斑点的白色蛋。孵化期大约45天，雌鸟主要负责孵化，雄鸟则提供食物。幼鸟出生后需亲鸟照顾约9至10个月，直至3至4岁达到性成熟，平均寿命12至15年。","identification":"与近缘物种孤冕雕相比，冕雕体型更大，色泽更浅，且有羽冠。冕雕与大黑鸡鵟和鵟雕的区别在于颜色更深，羽冠存在与否，以及下体的条纹差异。","protection":"IUCN：EN（濒危）","distribution":"冕雕分布于南美洲的东部和中部，具体包括玻利维亚东部、巴拉圭、巴西南部至阿根廷中部。在乌拉圭可能已灭绝，而在其历史分布区的部分地区已被彻底清除。","other":"冕雕面临的主要威胁包括栖息地破坏、与人类建筑的碰撞以及人为迫害。在阿根廷，因误认为冕雕会攻击家畜而遭到猎杀。"},{"name":"横斑南美鵟","english_name":"Barred Hawk","scientific_name":"Morphnarchus princeps","overview":"横斑南美鵟（英文名：Barred Hawk，学名：Morphnarchus princeps），是鹰形目鹰科横斑南美鵟属的鸟类。俗称: “土豹”，分布于中美洲的哥斯达黎加至南美洲的厄瓜多尔北部。其显著特征为黑色头部和上身，带有白色细横纹的腹部，以及宽阔的翅膀和短尾巴。","appearance":"横斑南美鵟体长51至57厘米，翼展可达112至124厘米，体重约1千克。雄鸟和雌鸟在外形上相似，但雌鸟平均比雄鸟大4%左右。成鸟上身和喉咙为黑色，冠羽、颈背和肩羽边缘呈蓝灰色，腹部和翼下覆羽为白色，带有黑色细条纹，尾巴基部灰白，尖端黑色，有明显的白色亚端带。喙和腿黄色，成年个体虹膜深蓝色。","call":"横斑南美鵟通常发出响亮柔和的哨声‘wheeeuuuu’，间隔重复。也会发出快速连续的30至40个哨音‘weeweeweewee…’。","habits":"生活在潮湿的山地森林中，从山脚到亚热带地带，海拔偏好主要在500至2500米之间，偶尔上升至3000米或下降至300米。常见于自然或人为的林间空地边缘，而非大片连续的森林内部。经常成群3至4只在森林上空翱翔。","breeding":"繁殖巢穴位于植被覆盖的悬崖上，由小枝和树叶构成，已知巢穴位于770米和1950米的海拔高度。每次产一枚未标记的白色蛋，孵化期约为80天。幼鸟出生时覆盖着白色绒毛。","identification":"与Geranospiza melanoleucus相比，体型更小且形状明显不同，后者出现在完全不同的生境中。成鸟和幼鸟的区别在于幼鸟颈部、肩羽和上翼覆羽边缘有薄白边。","protection":"IUCN：LC（无危）; CITES II。全球估计数量少于10,000只，由于热带森林的持续破坏，某些地区的数量可能正在下降。","distribution":"分布于哥斯达黎加、巴拿马、哥伦比亚西部、厄瓜多尔东西两侧的安第斯山脉，以及秘鲁西北部安第斯山脉东坡的局部地区。","other":"曾被归入Leucopternis属，但分子研究表明它应独立于单独的单型属。"},{"name":"阔嘴鵟","english_name":"Roadside Hawk","scientific_name":"Rupornis magnirostris","overview":"阔嘴鵟（英文名：Roadside Hawk，学名：Rupornis magnirostris），是鹰形目鹰科阔嘴鵟属的鸟类。体型相对较小的鹰科鸟类，广泛分布于中美洲至南美洲东至阿根廷东北部。其最显著的特征是拥有较大的喙，以及在不同亚种中表现出的色彩差异，从棕色到灰色不等。在飞行中，可以看到翅膀上特有的红褐色调。","appearance":"阔嘴鵟体长31-41厘米，体重范围250-300克，雌鸟比雄鸟大20%左右。成鸟的下胸部和腹部带有棕色和白色的条纹，尾巴上有四到五条灰色的横纹。头部、背部和上胸部颜色从灰到灰棕色，或深巧克力棕色至接近黑色，腹部条纹多样，尾巴颜色从灰色到红褐色，带有多条宽黑带和白色尖端。虹膜黄色至橙红色，蜡膜淡橙色至黄色，腿呈淡橙色至鲜黄色。幼鸟的下部有白色或红褐色的斑点，上背有条纹，下部白色至浅黄色，胸部和腹部有各种深浅的棕色条纹。","call":"阔嘴鵟的叫声包括一种高音的刺耳哨声“kyeeeer”，听起来略显愤怒和不满，以及类似啄木鸟的快速鼻音序列“kyeekeekikikiki”，起初音调上升，第三种叫声是短而低强度的‘wheet’，通常以两音符序列给出，音节间略有停顿，有时仅发出一次。","habits":"阔嘴鵟生活在热带至亚热带的多种生境中，除原始森林、沙漠和开阔平原外，常见于森林边缘、开放森林、次生林中的干扰区域、草原上的画廊森林以及散落的森林碎片。在巴西的一些大城市中也能见到它们的身影，只要有足够的树木存在。它们主要以昆虫、蜘蛛、爬行动物、小型哺乳动物和一些鸟类为食，包括鸟蛋和雏鸟。觅食时，它们通常从突出的枝头、围栏柱等处猎捕，有时也会沿着草火线捕食，甚至因此烧焦自己的飞羽。","breeding":"阔嘴鵟的繁殖期从三月底至五月（干季中晚期），在危地马拉的Petén地区，幼鸟在六月至七月离巢（极少数在五月下旬）。在墨西哥，产卵的平均日期是四月中旬。它们会在树顶建造大型的枝条巢，用绿色叶子铺垫，巢宽20-46厘米，深6-36厘米，由双亲共同建造。通常每窝产一到两个蛋，蛋的颜色为白色，带有紫罗兰色、巧克力色和栗色的斑点。孵化期大约33-37天，由雌鸟主要负责，期间雄鸟提供食物。幼鸟在孵化后的38天左右离巢。","identification":"阔嘴鵟与同属的其他物种相比，最明显的区别在于其较大的喙和特定的羽毛颜色。不同亚种之间在羽毛颜色和大小上也有明显差异。例如，conspectus亚种比griseocauda亚种稍小，背部更纯灰，下部颜色略浅；gracilis亚种主要区别在于体型较小。","protection":"IUCN：LC（无危）。CITES II级（濒危野生动植物种国际贸易公约附录二）。阔嘴鵟分布广泛且普遍常见，是许多生境中最常见的猛禽之一。尽管如此，在某些地区，如萨尔瓦多南部，由于栖息地丧失和农药的大量使用，已观察到数量下降。","distribution":"阔嘴鵟分布于中美洲至南美洲东部，从墨西哥至阿根廷东北部，包括亚马逊盆地大部分地区，可能除了密集的雨林以外，适应了其范围内的大多数生态系统。偶尔在德克萨斯州发现迷鸟。","other":"阔嘴鵟在筑巢时会变得非常有攻击性，有记录显示它会攻击靠近巢穴的人类。"},{"name":"栗翅鹰","english_name":"Harris's Hawk","scientific_name":"Parabuteo unicinctus","overview":"栗翅鹰（英文名：Harris's Hawk，学名：Parabuteo unicinctus），是鹰形目鹰科栗翅鵟属的鸟类。中大型鵟鸟，身长介于46至76厘米之间，翼展约107厘米，体重可达900克。其羽毛呈棕色，翅膀上下两侧为栗色，大腿部分带有黑棕色。该物种是美洲特有，分布自美国西南部至阿根廷南部和智利。栗翅鹰以独特的社会性行为著称，是唯一已知集群生活的猛禽。","appearance":"栗翅鹰是一种体型中等偏大的鵟鸟，全长46至76厘米，翼展可达107厘米，体重约为900克。羽毛颜色主要为深棕色，翅膀上的覆羽和腿部呈现鲜明的栗色，大腿部分带有黑棕色。尾巴黑色，基部和末端有白色斑纹。幼鸟与成鸟相比，下体有较多的淡色条纹。喙为角蓝色，尖端黑色，蜡膜和眼眶为亮黄色。虹膜颜色为中到深褐色。","call":"栗翅鹰的叫声粗犷而刺耳。","habits":"栗翅鹰偏好居住在稀疏的林地和半荒漠地带，也出现在沼泽环境，如南美部分地区的红树林。它们是永久居民，不会迁徙。它们利用散布的大树、电线杆、树林边缘等作为重要的栖息和筑巢场所。栗翅鹰的食物种类广泛，包括小型哺乳动物、鸟类、爬行动物和大型昆虫。它们展现出社会性行为，常以两到七只的小群体活动，协作狩猎。","breeding":"栗翅鹰在小树、灌木或仙人掌上筑巢，巢由树枝、植物根和茎构成，内部铺垫叶子、苔藓、树皮和植物根。每窝产卵2至4枚，颜色从白色到蓝白色不等，可能带有淡棕色或灰色斑点。孵化期为28天左右。幼鸟出生时呈淡黄色，五至六天后转为深棕色。幼鸟可能与父母共同生活长达三年，协助养育后续的幼鸟。","identification":"栗翅鹰与其他鵟鸟的主要区别在于其翅膀上的栗色斑块、大腿上的黑棕色以及尾部的白色基部和末端。它们也是唯一已知以群居形式生活的鵟鸟。","protection":"IUCN：LC（无危）","distribution":"栗翅鹰分布于北美、中美和南美，从美国西南部延伸至阿根廷南部和智利。在北美，主要见于新墨西哥州和亚利桑那州的部分地区。在南美，遍及巴西、阿根廷和智利等地。","other":"栗翅鹰因其容易训练和高度的社会性，成为西方最受欢迎的猎鹰之一，被广泛用于猎鹰术。"},{"name":"白腰鵟","english_name":"White-rumped Hawk","scientific_name":"Parabuteo leucorrhous","overview":"白腰鵟（英文名：White-rumped Hawk，学名：Parabuteo leucorrhous），是鹰形目鹰科栗翅鵟属的鸟类。俗称: “土豹”，属于鹰科短尾鵟属的猛禽，形似小型的老鹰。其尾部不分叉，全身呈深褐色，尾部颜色略浅，双翼下方有明显的白色横纹。常见于南美洲安第斯山脉从委内瑞拉到阿根廷的高山森林地带，偶尔出现在较低海拔的森林边缘或查科地区。在南美洲东南部也有零散分布。该物种通常单独或成对活动，以鼠类为食，是农田中的益鸟。","appearance":"成年白腰鵟体长约33至40厘米，翼展可达67至79厘米。体重方面，雄鸟约290克，雌鸟稍重，约389克。整体黑色，具有醒目的黄色眼睛。飞行时，可以看到其桨状的翅膀和对比鲜明的白色下翼覆羽。尾巴上有对比强烈的黑白相间的条带。幼鸟的上体为棕色，杂有红褐色斑点；下体红褐色斑驳严重。头部有白色眉纹，整体形状紧凑。","call":"鸣声通常为尖锐的哨音，音调较高，有时会表现出音阶下降的特征，如\"KEEEEiu\"，或是一连串单调的高音哨音，结尾时声音颤抖。","habits":"栖息于密林内部和边缘，偏好热带至亚热带区域的高海拔森林。在哥伦比亚，主要分布在1500至2900米的海拔区间，在秘鲁为1650至2500米，在玻利维亚则高达3500米。在阿根廷和巴拉圭的低海拔地区也有发现。主要为留鸟，但有证据表明其存在一定的游荡行为，显示出某种程度的游牧习性。","breeding":"繁殖季节在不同地区有所差异，哥伦比亚记录为2月至3月，厄瓜多尔可能从6月持续到次年1月，巴西则有10月的记录。已知巢穴位于松树顶端，距地面22米，由小松枝和其他植物的细枝构成，内衬绿叶，巢长54厘米，宽38厘米，深18厘米。每窝产卵2至3枚，蛋壳呈奶油色，带有锈褐色的划痕和斑点。","identification":"与同类物种相比，白腰鵟最显著的特征是其白色的腰部和下尾覆羽，以及尾部的灰褐色条带。成鸟和幼鸟的体型和羽色存在明显差异，成鸟黑色为主，幼鸟则为棕色并带有红褐色斑点。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲安第斯山脉，从委内瑞拉至玻利维亚西北部，以及南美洲东南部的巴西南部、巴拉圭和阿根廷东北部。","other":"尽管分布广泛，但白腰鵟的数量并不算多，且对森林扰动有一定的容忍度。"},{"name":"白尾鵟","english_name":"White-tailed Hawk","scientific_name":"Geranoaetus albicaudatus","overview":"白尾鵟（英文名：White-tailed Hawk，学名：Geranoaetus albicaudatus），是鹰形目鹰科鵟雕属的鸟类。主要分布在北美洲南部至南美洲中部。其最显著的特征是白色尾部带黑色末端带纹。成鸟体长可达44-60厘米，翼展118-143厘米，体重在880-1240克之间，略大于斯氏鵟，小于白头海雕。","appearance":"成年白尾鵟上身呈灰色，下身及臀部为白色，带有淡灰色或锈色条纹。尾巴较短，白色并有狭窄的黑色末端带纹，飞行时明显可见。肩部有独特的锈红色斑块。翅膀上表面深色，近黑色主羽基部混有灰色。下翼白色，翼下覆羽有模糊的褐色条纹，延伸至腹侧和大腿。虹膜榛色，喙黑色基部角质色，脚黄色爪黑。幼鸟颜色较暗，接近黑色，尤其在光线微弱时，翼下明显黑白斑点，尾部由棕色多条暗带逐渐变为灰白模糊暗带。","call":"发出尖锐的咯咯声，带有金属质感，类似山羊的叫声或笑鸥的声音。","habits":"白尾鵟偏好开阔或半开阔地带，海拔不超过600米，喜欢在灌木丛、树木、电线杆甚至地面停歇，也常在空中翱翔。它主要生活在干燥环境中，很少出现在雨量充沛的地方。在食物稀缺时，某些种群会进行区域性迁移。","breeding":"白尾鵟在树顶或丝兰等高处筑巢，巢由新鲜折断的树枝（通常是带刺植物）构成，高度在1.5-5米之间。巢内部铺垫干草和其他细软材料，有时放置香料植物枝条以驱虫。每次产卵1-3枚，通常为2枚，蛋壳白色，可能带有浅褐色或薰衣草色斑点。","identification":"成年白尾鵟与斯氏鵟和红尾鵟在大小上有细微差别，可通过尾部特征、肩部锈红色斑块和下体颜色进行区分。幼鸟颜色更深，翼下有明显的黑白斑点，尾部条纹随成熟而变化。","protection":"IUCN：LC（无危）","distribution":"分布于北美、中美和南美，从美国西南部至阿根廷中部，包括加勒比海部分岛屿。","other":"白尾鵟的猎食技巧包括悬停观察周围环境寻找猎物，食物种类多样，从兔子到蜥蜴，再到小型鸟类，甚至在食物匮乏时会捕食鸡只。"},{"name":"红背鵟","english_name":"Variable Hawk","scientific_name":"Geranoaetus polyosoma","overview":"红背鵟（英文名：Variable Hawk，学名：Geranoaetus polyosoma），是鹰形目鹰科鵟雕属的鸟类。而来自胡安·费尔南德斯群岛的亚种则较为独特，可能值得视为独立物种。红背鵟体型较大，适应多种生境。","appearance":"成年红背鵟体长45至62厘米，翼展113至151厘米，体重660至1300克。其羽毛颜色多变，从洁净白色到深灰色和赤褐色，背部可能呈灰色或赤褐色。最显著的特点是白色的尾巴带有黑色的端部横纹。幼鸟更为复杂，上部通常为深棕色，下部为淡色，带有不同程度的暗色条纹。幼鸟也可能全身为深棕色，但这种形态罕见。红背鵟的头部、大腿和尾下覆羽为暗灰棕色，背部为深灰色，上背部和大部分下体为赤褐色。成鸟中，雌雄羽毛颜色有差异，红背的个体通常为雌鸟，灰色的个体通常为雄鸟。","call":"在翱翔时发出响亮的“keeow-kyow-kyow”叫声，特别是在巢区受到干扰时。Puna鵟在飞行中会发出尖锐的‘hee hee hee’声。","habits":"红背鵟栖息于开阔地带，从沿海低地到安第斯山脉的阿尔蒂普拉诺高原，海拔高度从海平面至4600米。它们在智利和阿根廷的西部地区频繁出现在诺托法古斯森林中，而在厄瓜多尔则可见于干旱的沿海低地。它们以小型哺乳动物为主要猎物，例如啮齿类动物、兔子、蜥蜴、昆虫等。红背鵟在白天活跃，偏好在北向山坡上空飞翔，这里风力上升气流丰富，植被稀疏。","breeding":"红背鵟在不同地区有不同的繁殖季节，如厄瓜多尔为12月至7月，智利、阿根廷和福克兰群岛为9月至1月，胡安·费尔南德斯群岛上的亚种为11月至2月。它们建造大型的棍状巢，直径75至100厘米，巢内铺有苔藓、地衣、树叶和杂物，筑于离地面2至7米高的悬崖、仙人掌、树木、灌木或电力杆上。一窝产卵数量为1至3枚，孵化期为26至27天，幼鸟在约40至50天大时离巢。","identification":"红背鵟与鵟雕的区别在于体型较小，翅膀较窄，年轻个体的颜色通常比大多数红背鵟更暗。胡安·费尔南德斯群岛的亚种（exsul）与大陆亚种在颜色模式上有显著差异，可能接近物种地位。","protection":"IUCN：LC（无危）; CITES: II级附录","distribution":"红背鵟广泛分布在南美洲西部和南部，包括智利、阿根廷、厄瓜多尔、秘鲁、南部至福克兰群岛。在智利和阿根廷，它们常见于西部地区的诺托法古斯森林；在厄瓜多尔，可见于干旱的沿海低地；在胡安·费尔南德斯群岛，它们栖息于火山斜坡和开阔的草地。","other":"红背鵟的分类和命名历史上曾有过多次讨论，涉及多个亚种和潜在的物种分割问题。"},{"name":"鵟雕","english_name":"Black-chested Buzzard-Eagle","scientific_name":"Geranoaetus melanoleucus","overview":"鵟雕（英文名：Black-chested Buzzard-Eagle，学名：Geranoaetus melanoleucus），是鹰形目鹰科鵟雕属的鸟类。大型猛禽，广泛分布于南美洲的高山草原、山脉、开阔林地。其活动范围自哥伦比亚北部安第斯山脉延伸至火地岛最南端，亦见于阿根廷潘帕斯草原直至巴西东南部草原生态系统。鵟雕以哺乳动物为主要猎物，其中欧洲兔占据其食物链的重要地位。飞行特征显著，拥有长而尖的翅膀和短小楔形尾巴。","appearance":"鵟雕体型庞大，翼展宽广，尾部短小。成鸟头部和胸部深灰色，腹部白色形成鲜明对比。上翼银灰色，下翼覆羽白色，与暗色飞羽形成对比。未成年个体呈棕色，条纹明显，与红背鵟幼鸟相似，但体型更庞大，尾部更短，更渐变。","call":"鵟雕通常不善鸣叫，但在飞行或接近巢穴时会发出声音，叫声包括类似野人狂笑的声音和类似鹬的哨声。偶尔，飞翔中的鵟雕会发出高音的'kukukukuku'叫声。","habits":"鵟雕栖息于南美山区或丘陵地带，偏好植被稀疏的环境、灌木丛或南部Nothofagus森林。它们常在热气流和垂直气流中翱翔，寻找猎物。鵟雕主要以中型哺乳动物为食，如欧洲兔、Octodon degus等。偶尔捕食小型鸟类、蜥蜴、节肢动物及腐肉。","breeding":"鵟雕在高树、岩石峭壁或高大仙人掌上筑巢，若条件允许，也会选择地面或灌木。繁殖季节全年均可观察到，尤其是在厄瓜多尔。巢由大量树枝构成，直径约85厘米。每窝通常产2枚卵，有时1或3枚，孵化期约为一个月。鵟雕对威胁表现出强烈的防御行为。","identification":"鵟雕与红背鵟幼鸟在羽毛颜色上有相似之处，但鵟雕体型更大，尾部更短，更渐变。成年鵟雕的特征性短尾和宽阔的翅膀使其易于识别。","protection":"IUCN：LC（无危）","distribution":"鵟雕分布于南美洲，从委内瑞拉至智利南部，巴西东南部，覆盖了从哥伦比亚北部安第斯山脉至火地岛的广大区域。","other":"鵟雕对农业有益，因其控制兔子数量，减少农业害虫。"},{"name":"披风南美鵟","english_name":"Mantled Hawk","scientific_name":"Pseudastur polionotus","overview":"披风南美鵟（英文名：Mantled Hawk，学名：Pseudastur polionotus），是鹰形目鹰科白南美鵟属的鸟类。别名: 斗蓬南美鵟，中等体型的南美猛禽，最显著的特征是拥有白色的头部、颈部、上背部及全身下部，背部和尾基部呈蓝灰色，尾端白色，翼尖黑色。主要分布在巴西东部至乌拉圭和巴拉圭东南部。","appearance":"披风南美鵟体长约470-510毫米，具宽肩和圆头，头部、颈部、上背部和全身下部除黑色翼尖和尾基半部外均为白色。成年个体翅膀宽阔，尾羽呈深色，有3-4条窄带，尾端形成浅U形白色斑纹。幼鸟羽毛斑点较多，头部和颈背有暗色条纹。雌鸟比雄鸟略大。","call":"其最常见的叫声是一连串刺耳的滑音‘weeeuw’，间隔发出。有时也会发出一系列高音哨声‘bibibi...bee-eh’，无论是停栖还是飞行中都能听到。","habits":"主要栖息于热带森林地带，海拔从海平面至至少1500米。常见于山地地区，尤其偏好森林边缘、自然空地和松树环绕的干旱树林。以小鸟、蜥蜴、蛇和小型哺乳动物为食，会利用开阔位置的高枝捕猎。","breeding":"关于繁殖的详细信息较少，已知在7月中旬的巴西帕拉纳州发现过一窝仅有一只雏鸟的巢穴。","identification":"与白颈鵟相似，但体形更大，翼展更宽，尾部白色部分明显，而白颈鵟的尾基暗色通常在野外难以观察到。与白领美洲鸢相比，飞行时翼展仅略微高于水平或平飞，尾全白，休息时翼尖与尾尖齐平或超出。","protection":"IUCN：NT（近危）","distribution":"分布于巴西东部，从阿拉戈阿斯和巴伊亚向南至南里奥格兰德州和巴拉圭东南部（阿尔托帕拉纳）。在东北阿根廷的出现仅是假设。","other":"面对持续的栖息地破坏和碎片化，其种群数量显著下降。然而，由于其分布范围更广且位于高地，受森林砍伐的威胁相对较小。"},{"name":"白南美鵟","english_name":"White Hawk","scientific_name":"Pseudastur albicollis","appearance":"成年白南美鵟体长介于46至56厘米之间，拥有非常宽阔的翅膀。其头部、躯干及下翼面均为白色，上翼为黑色，尾部短小，带有黑色与白色条纹。喙呈黑色，腿脚黄色。雌雄外观相似，但雌鸟体型较大，平均重约840克，而雄鸟体重约为650克。幼鸟上半身有明显的黑色斑点，下半身为暗纹白色。","call":"白南美鵟的叫声为哀婉的“kerwee”。","habits":"白南美鵟栖息于低地热带森林，以猎食为主，食物主要包括蜥蜴、蛇（如东部珊瑚蛇）、昆虫（如甲虫和蚱蜢）、螃蟹、两栖动物以及小型哺乳动物（如鼠类、松鼠、小负鼠和蝙蝠）。它也会伺机捕食受惊的鸟类，如大锡纳莫乌。该物种会与觅食的毛猴和南美鼻熊协同捕食。","breeding":"白南美鵟在繁殖季节会于高树上构建大型的棍状平台巢，通常产一枚蓝白色的暗斑蛋。观察到的筑巢行为发生在8月中旬。","identification":"白南美鵟与同域内的其他白色猛禽相比，体型更大，具有灰色的蜡膜和不同的尾羽模式。与灰背南美鵟和黑脸南美鵟、白眉南美鵟等物种的区别在于体型、蜡膜颜色和尾羽图案。","protection":"IUCN：LC（无危）","distribution":"白南美鵟分布于中美洲至南美洲的热带森林地带，具体范围从墨西哥南部至亚马逊雨林，覆盖南美的大部分地区，包括巴西、秘鲁、玻利维亚等国。","other":"白南美鵟的四个亚种在外观上主要呈现白色，但根据地理位置的不同，背部和肩部的黑色程度有所变化。"},{"name":"灰背南美鵟","english_name":"Grey-backed Hawk","scientific_name":"Pseudastur occidentalis","overview":"灰背南美鵟（英文名：Grey-backed Hawk，学名：Pseudastur occidentalis），是鹰形目鹰科白南美鵟属的鸟类。仅分布于厄瓜多尔西部及秘鲁西北部一小部分地区。体长45至52厘米，翼展104至116厘米，雌鸟比雄鸟大10%左右，两性羽毛相似，背部呈暗灰色，头部有灰色条纹，尾部白色并带有一宽黑环。偏好湿润森林环境，常栖息于陡峭峡谷中的半落叶和常绿森林。","appearance":"成年灰背南美鵟拥有灰白相间的头部、颈背和肩部条纹，上体黑色带灰，中等长度的翅膀，尾部白色，末端有一宽黑色亚端带。虹膜深褐色，喙灰色，腿和脚淡黄色。幼鸟与成鸟类似，但上体呈褐色而非铅灰色，颈背有暗色而非白色条纹，胸部有灰色斑点，侧翼有模糊的条纹。","call":"空中展示飞行时，一对灰背南美鵟会发出拉长的尖叫声“keeeaaarr-keeeaaarr...”，声音在中间部分上升，或发出高音调的“kéééoooowww”，前半部分音量大于后半部分。幼鸟发出的声音更柔和、更高且更嘶哑。","habits":"灰背南美鵟是留鸟，栖息于热带和亚热带半落叶及常绿森林，包括干燥和半湿润地区，通常在100至1400米之间，最高可达2900米。其食物包括蜥蜴、蛇、螃蟹、小型啮齿动物、小型鸟类、蚯蚓、青蛙和大型昆虫。","breeding":"繁殖季节似乎全年都有，但活动高峰期集中在12月至翌年4月的雨季。已知的筑巢行为和巢穴信息有限，更多细节待观察。","identification":"与其他同类物种的区别在于尾部图案，与P. albicollis williaminae无已知重叠分布，Spizastur melanoleucos虽羽毛颜色相似但体型比例不同，有较长较窄的翅膀和细长且全条纹的尾巴，以及橙色的喙和更白的头部。","protection":"IUCN：VU（易危）","distribution":"分布于厄瓜多尔西部，从埃斯梅拉达斯省南部到洛哈省西部，以及秘鲁西北部的图姆贝斯地区。","other":"灰背南美鵟面临严重的栖息地破坏威胁，导致其数量急剧下降。其栖息地的森林覆盖率已减少超过90%，道路网络的扩展加速了人类的殖民和土地开发，增加了砍伐、牧场扩张、油棕种植和狩猎等活动的影响。"},{"name":"淡灰南美鵟","english_name":"Semiplumbeous Hawk","scientific_name":"Leucopternis semiplumbeus","overview":"淡灰南美鵟（英文名：Semiplumbeous Hawk，学名：Leucopternis semiplumbeus），是鹰形目鹰科南美鵟属的鸟类。小型森林猛禽，通常隐匿在热带和亚热带湿润森林的树冠或边缘，以其橙红腿和喙为显著特征。在中美洲洪都拉斯东部、尼加拉瓜东部至南美洲哥伦比亚西部和厄瓜多尔西北部有分布。","appearance":"淡灰南美鵟体型小而健壮，翼短，全长约31-36厘米，体重雄鸟平均250克，雌鸟平均325克，翼展51-64厘米。全身铅灰色，翅膀和尾巴黑色，尾部有一或两条细窄白色条纹；腹部纯白，翼尖灰，有暗色条纹。眼睛明亮黄色，喙橙黄至橙红色，腿和脚橙至橙红色。雌雄相似，但雌鸟平均大10%左右。幼鸟头部有白色条纹，胸部有薄黑条纹，尾部有两条白色条纹，眼睛黄棕色至黄色，喙橙黄至橙色，脚橙色。","call":"繁殖季节时，淡灰南美鵟会发出一系列响亮、尖锐的上升哨音：“kwee...wee...wee...wee...wee”。非繁殖季节较为安静，偶尔发出高音调、细薄的上升哨音，间隔重复。","habits":"淡灰南美鵟栖息在热带和亚热带湿润森林中，常见于森林边缘、森林碎片周围和哥伦比亚的高大次生林。海拔高度从海平面至1000米，但主要在500米以下。它们通常静止在高枝上等待猎物，很少飞行。食物包括蜥蜴、蛇、蚂蚁鸟和其他小鸣鸟，也可能捕食蝙蝠、两栖动物和小型哺乳动物。","breeding":"关于淡灰南美鵟的繁殖信息非常有限。在哥斯达黎加曾有一份筑巢记录，发生在一月；二月在哥伦比亚发现一只处于繁殖状态的雄鸟。巢中蛋的描述缺失，孵化期、育雏期、繁殖成功率和生产力信息未知。","identification":"淡灰南美鵟以其独特的铅灰色羽毛、橙红色腿和喙以及明亮黄色的眼睛易于识别。与同属物种相比，其体型较小，颜色更暗。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲洪都拉斯东部至南美洲厄瓜多尔西北部，包括哥伦比亚西部和埃斯梅拉达斯及皮钦查西北部。在秘鲁北部的Allpahuayo-Mishana国家保护区也有观察记录。","other":"尽管在一些原始森林地区被视为局部常见，但由于森林砍伐和栖息地破碎化，淡灰南美鵟的数量可能正在减少。"},{"name":"黑脸南美鵟","english_name":"Black-faced Hawk","scientific_name":"Leucopternis melanops","overview":"黑脸南美鵟（英文名：Black-faced Hawk，学名：Leucopternis melanops），是鹰形目鹰科南美鵟属的鸟类。俗称: “土豹”，中等体型的猛禽。其最显著的特征是黑色的面部与橙色的蜡膜形成鲜明对比。这种物种主要分布在亚马逊雨林北部，包括委内瑞拉东南部、圭亚那、亚马逊河以北至哥伦比亚东部、厄瓜多尔东北部和秘鲁北部。","appearance":"黑脸南美鵟体长35-43厘米，体重雄鸟297-317克，雌鸟329-380克，翼展65-78厘米。头部、上背和颈部呈白色，带有黑色条纹；翅膀和尾巴黑色，翼覆羽和肩羽有明显的白色标记；尾部中央有一条狭窄的白色带；下体全白。眼睛灰或棕，腿和蜡膜黄色或橙黄色。雌雄相似，但雌鸟体型较大。幼鸟头部和颈部仅有微弱的暗色条纹，背部和上翼羽毛边缘呈棕色。","call":"发出尖锐、下降的哨声'KEEuuu'，通常连续几次，间隔发出。","habits":"栖息于低地热带雨林，偏好河流沿岸密集植被和红树林地带。不常见于森林上空翱翔。以蛇和蜥蜴等小型猎物为主食，偶尔捕食鸽子雏鸟。飞行时不长时间滑翔，而是短暂滑翔后快速拍打翅膀。","breeding":"关于繁殖行为的具体信息尚缺，但据推测与同属其他物种相似，会在树冠中筑巢，由双亲共同孵卵约五周。","identification":"与白眉南美鵟区分，黑脸南美鵟尾部仅有一条白色带，而白眉鵟幼鸟尾部有两条。此外，黑脸南美鵟的背部白色较多。","protection":"IUCN：LC（无危）。列入CITES附录II。全球种群数量未知，但因森林砍伐而可能正在减少。","distribution":"分布于南美洲亚马逊雨林北部，包括委内瑞拉东南部、圭亚那、亚马逊河以北至哥伦比亚东部、厄瓜多尔东北部和秘鲁北部。在巴西和秘鲁南部（马德雷德迪奥斯）也有记录。","other":"黑脸南美鵟与白眉鵟存在一定程度的共生现象，两者可能偶尔杂交。"},{"name":"白眉南美鵟","english_name":"White-browed Hawk","scientific_name":"Leucopternis kuhli","overview":"白眉南美鵟（英文名：White-browed Hawk，学名：Leucopternis kuhli），是鹰形目鹰科南美鵟属的鸟类。紧凑型黑白色森林猛禽，拥有独特的白眉特征，分布于亚马逊雨林南部的低地热带雨林，主要在秘鲁东部至马德雷德迪奥斯省，玻利维亚北部和东北部以及巴西亚马逊河以南地区。","appearance":"体长37至40厘米，翼展65至76厘米。头部暗色，有狭窄的白色眼纹。上体黑色，颈部和肩部有白色条纹或斑点，尾部具有一条明显的白色横带。下体全白，仅翼尖呈灰色，带有醒目的黑色横纹。虹膜棕色或红棕色，蜡膜、腿和脚橙色。雌鸟体型比雄鸟大，羽毛相似。","call":"发出高音调、较为细薄的下滑哨声，声音为'keeeeuw'，间隔性地发出。","habits":"生活在海拔500米以下的热带雨林中，通常单独或成对出现。近地面狩猎，已知捕食蛇和蜥蜴，推测也可能捕食蛙类和大型昆虫。","breeding":"关于繁殖行为了解甚少，已知的一个巢穴位于巴西西部，约15米高的次冠层，可能含卵。巢由树枝、小枝和一些枯叶构成。","identification":"与黑脸南美鵟最为相似，但后者上体斑纹更多，头冠和颈背显得更白，无白色眉纹，尾巴底部从下方看更灰。","protection":"IUCN：LC（无危）；CITES II级附录。","distribution":"分布于南美洲，主要在秘鲁东部至马德雷德迪奥斯省，玻利维亚北部和东北部以及巴西亚马逊河以南地区，直至帕拉州的东海岸。","other":"尽管对其生态了解不多，但由于其广阔分布区域内仍有大量原始森林，故目前不认为有立即的生存威胁。"},{"name":"百慕大鵟","english_name":"Bermuda Hawk","scientific_name":"Bermuteo avivorus","overview":"百慕大鵟（英文名：Bermuda Hawk，学名：Bermuteo avivorus），是鹰形目鹰科Bermuteo的鸟类。原生于北美百慕大群岛，现已灭绝。该物种的记录最早见于1603年，由Diego Ramírez提及，当时岛上猎鹰般的猛禽因接近人类而显得异常温顺。","appearance":"由于缺乏详细的描述和现代观察，百慕大鵟的具体外观特征已无法详尽描述，但从其分类来看，它可能具有典型的鹰科猛禽的特征。","habits":"百慕大鵟的生活习性不详，但作为猛禽，它可能以捕食小型动物为主，活动于岛屿特有的生态系统中。","identification":"作为百慕大群岛独有的物种，百慕大鵟与全球其他鹰科成员有明显的差异，但具体辨识特征已难以确定。","protection":"IUCN：EX（已灭绝）","distribution":"百慕大鵟仅分布在北美的百慕大群岛，其生存范围局限于此。","other":"百慕大鵟的灭绝时间不确定，但据推测是在17世纪人类定居岛上后，可能由于狩猎和外来物种的引入导致其消失。"},{"name":"灰鵟","english_name":"Grey Hawk","scientific_name":"Buteo plagiatus","overview":"灰鵟（英文名：Grey Hawk，学名：Buteo plagiatus），是鹰形目鹰科鵟属的鸟类。亦被称为墨西哥苍鹰，中小型猛禽，以其独特的淡灰色外观著称。分布范围从美国西南部至南美洲北部阿根廷和巴拉圭。在北美的繁殖季节，其数量估计不足百对，主要栖息于沿河流和溪流的棉白杨和柳树林中。","appearance":"灰鵟是一种紧凑型猛禽，成鸟体色淡灰，下体有细密的黑白条纹，尾羽黑白相间。雌鸟比雄鸟体型略大，平均体重分别为628克和429克。成年个体总长度约41厘米（雄鸟）至44厘米（雌鸟）。幼鸟上体呈暗黑褐色，下体有深色斑点和条纹，尾部有多条暗色带纹。","call":"发出尖锐的哨音'kleee-ooo'，在繁殖季节尤为显著。","habits":"栖息于开阔的灌木林、热带森林边缘和清空地带。以短促、敏捷的飞行方式捕食地面上的猎物，主要以蜥蜴为食，但也捕食小型哺乳动物、鸟类和蛙类。通常在高处的开放位置等候猎物，然后突然俯冲。","breeding":"繁殖期为12月至5月，实行一夫一妻制。巢建于树顶，由枝条构成，雌雄共同筑巢。每窝产卵1到3枚，通常为2枚，蛋壳颜色为淡蓝或白色。孵化期约为33天，幼鸟大约在6周后离巢。","identification":"与巨翅鵟和赤肩鵟幼鸟相似，但灰鵟幼鸟有更明显的面部图案，下翼较淡，尾基有小白斑。成鸟的尾部条纹和大腿部的条纹是识别要点。","protection":"IUCN：LC（无危）","distribution":"分布于北美至中美洲，从美国西南部至哥斯达黎加西北部，包括墨西哥、瓜地马拉、伯利兹、萨尔瓦多、洪都拉斯、尼加拉瓜。","other":"在美国和墨西哥，主要威胁来自人类开发导致的栖息地丧失和地下水枯竭。"},{"name":"灰纹鵟","english_name":"Grey-lined Hawk","scientific_name":"Buteo nitidus","overview":"灰纹鵟（英文名：Grey-lined Hawk，学名：Buteo nitidus），是鹰形目鹰科鵟属的鸟类。中小型猛禽，广泛分布于中美洲至南美洲北部，包括哥斯达黎加至阿根廷中北部。其最显著的特征是浅灰色的体羽，细密的条纹覆盖全身，尾巴黑色带有三道白色横带。眼睛深褐色，腿部黄色。雌鸟体型较雄鸟大4%-9%，体重可高出29%。","appearance":"成年灰纹鵟体长38-46厘米，平均体重约475克。上体为浅灰色，有细微的暗色条纹；下体为更淡的灰色，有较粗的白色条纹。尾巴黑色，饰有1-2道醒目的白色横带。眼睛深褐色，腿部橙色。幼鸟上体呈暗褐色，尾羽为淡棕色带，腹部白色，有棕色斑点，头部和颈部有棕色条纹。成鸟在飞行时，初级飞羽基部有明显白斑，翼下白色，翼尖、翼角和飞羽边缘黑色，尾散开呈扇形。","call":"灰纹鵟有两种主要叫声：一种是在繁殖季节中发出的一系列3-8个柔和的哨音，听起来像\"wheeuw..wheeuw..wheeuw\"；另一种是间隔性的单音警报声，音调迅速下降。","habits":"灰纹鵟适应性强，栖息于低地热带至亚热带雨林边缘、受扰动的森林和开放的干旱地带。主要以蜥蜴和小型蛇类为食，也捕食鸟类、啮齿类、大型昆虫和甲虫。它们通常从高处的栖木上狩猎，利用敏捷的飞行技巧在森林中捕捉猎物。这种鵟比阔嘴鵟更强大和更快。","breeding":"繁殖期在哥斯达黎加为12月至7月，哥伦比亚、委内瑞拉为1月至5月，巴拿马和苏里南为2月，特立尼达岛为4月。巢由树枝构成，位于树梢，内部铺有小枝。求偶行为包括高空俯冲和模拟追逐。每窝产卵2枚（1-3枚），孵化期32天，幼鸟覆有白色绒毛，背部略呈灰色。幼鸟约在42天左右离巢。","identification":"灰纹鵟与阔嘴鵟幼鸟最为相似，但后者上体颜色更深，下体有更明显的白色眉纹和脸颊。成鸟与灰鵟极为相似，但两者地理分布基本不重叠。成鸟在飞行中，可通过条纹状的初级飞羽尖端、缺乏深色翼缘、深灰色上尾覆羽和更宽的白色亚端尾带进行区分。","protection":"IUCN：LC（无危）。CITES II。尽管没有确切的数量和种群趋势数据，但灰纹鵟被认为是广泛分布的，局部常见至相对较多，适应性强，能利用多种森林和半森林生境，包括受干扰和次生林。然而，亚马逊地区的森林砍伐和其他范围内森林破坏可能对该物种造成威胁。","distribution":"分布于中美洲至南美洲北部，包括哥斯达黎加至阿根廷中北部。特立尼达岛也有记录。","other":"灰纹鵟曾被认为是Asturina属的一部分，但现在被归类于Buteo属。最近的分类学研究将其从灰鵟中分离出来，成为独立物种。"},{"name":"赤肩鵟","english_name":"Red-shouldered Hawk","scientific_name":"Buteo lineatus","overview":"赤肩鵟（英文名：Red-shouldered Hawk，学名：Buteo lineatus），是鹰形目鹰科鵟属的鸟类。以其独特的橙色肩斑和黑白相间的翼羽而闻名。广泛分布于北美洲东部森林地带，偏好成熟混交林，尤其在河岸和湿地附近可见其踪迹。其饮食多样化，主要以小型哺乳动物、两栖动物和蛇类为主。","appearance":"赤肩鵟体长43-61厘米，翼展可达94-111厘米，体重介于486-774克之间。上体为深褐色，肩部显眼的栗红色，翼下为浅淡色，下体胸腹部具红色条纹。尾羽棕褐色，带有多道白色横杠。飞羽下部颜色较浅，翼尖呈黑色。与北美其他鵟类相比，其翅膀更长。","call":"赤肩鵟在繁殖季节早期十分活跃，会发出尖锐的\"kee-rah\"叫声，是森林中的标志性声音。","habits":"赤肩鵟偏爱生活在森林环境中，尤其偏好底土湿润的硬木林和河流附近的沼泽地。它们会从树梢或电线杆上狩猎，主要食物包括小型哺乳动物、两栖类、爬行类和鸟类。在北方的个体会在冬季向南迁徙，最远可达墨西哥。","breeding":"繁殖期一般在春季，赤肩鵟会在大树的主要枝干分叉处建造巢穴。每窝产卵通常3-4枚，由雌鸟负责孵化，雄鸟提供食物。幼鸟约在六周左右离巢，但仍需父母喂养至17-19周。","identification":"赤肩鵟与红尾鵟相比体型较小，尾部更长，翅膀相对窄而前倾。与巨翅鵟的区别在于尾部和翼部的条纹更加明显，且飞行时的翼尖透明区域是其独特标识。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖北美东部，包括加拿大南部至美国东部，向南延伸至墨西哥东北部。非繁殖季节，部分群体迁徙至墨西哥中部。","other":"赤肩鵟能够适应城市环境，近年来随着森林的再生，其栖息地有所增加。"},{"name":"里氏鵟","english_name":"Ridgway's Hawk","scientific_name":"Buteo ridgwayi","overview":"里氏鵟（英文名：Ridgway's Hawk，学名：Buteo ridgwayi），是鹰形目鹰科鵟属的鸟类。体长36至41厘米，以其独特的灰褐色外观著称。仅在加勒比海伊斯帕尼奥拉岛上的海地和多米尼加共和国发现，现被认为在海地已灭绝，仅存于多米尼加东北部的Los Haitises国家公园及其周边地区。全球数量估计不到400只，属于极度濒危物种。","appearance":"成年里氏鵟上半身为灰褐色，下半身有灰色条纹和红棕色斑点，大腿呈淡赤褐色，尾羽黑白相间。翅膀深棕色，带有斑驳图案，脚爪和喙基为金黄色，喙尖黑色。虹膜呈琥珀色，有黄色的眼环。雌雄相似，但雄鸟更灰暗。幼鸟下体羽毛淡黄至白色，有灰棕色斑纹。","call":"里氏鵟的常见叫声为响亮、尖锐且重复的‘wee-uh’。","habits":"里氏鵟为留鸟，栖息于潮湿的森林中，偏好低地森林和成熟与受扰森林的混合地带。它们捕食多种猎物，包括大型昆虫、小型鸟类和蝙蝠，通过在空中盘旋或栖息于高处等待猎物出现，然后迅速俯冲捕捉。","breeding":"繁殖期从12月至翌年6月，筑巢于高树冠中，如Roystonea borinquena。每窝产1至3枚蛋，大多数配偶会养育1至2只幼鸟。","identification":"里氏鵟与红尾鵟的区别在于体型较小、整体灰褐色外观和尾巴上有窄的白色条纹。与其它两种偶尔出现的鵟类相比，体型更大，羽毛颜色更深，腹部颜色更浅。","protection":"IUCN：CR（极危）","distribution":"里氏鵟原生于伊斯帕尼奥拉岛，包括海地和多米尼加共和国，以及一些邻近岛屿。由于森林栖息地的大量破坏，它在多米尼加大部分地区和几乎整个海地已被根除。现在仅存于多米尼加东北部的Los Haitises国家公园及其周边地区。","other":"通过保护和人工繁殖项目，里氏鵟的数量正在缓慢恢复。"},{"name":"巨翅鵟","english_name":"Broad-winged Hawk","scientific_name":"Buteo platypterus","overview":"巨翅鵟（英文名：Broad-winged Hawk，学名：Buteo platypterus），是鹰形目鹰科鵟属的鸟类。广泛分布于北美东部和中部地区，夏季繁殖后向南迁徙至拉丁美洲南部巴西。其羽色有暗色和淡色两种形态，雌鸟较雄鸟略大。以森林中的昆虫、两栖动物、爬行动物、哺乳动物和小型鸟类为食。","appearance":"巨翅鵟体长32至44厘米，体重介于265至560克之间，翼展可达74至100厘米。头部呈深褐色，腹部和胸部有水平条纹，尾巴灰黑并带有白色线条。幼鸟的颜色更为浅淡，具有纵向条纹而非横向条纹。暗色形态的个体上部和下部均为深棕色。","call":"发出高音的哨声，类似于\"kee-ee\"，用于与伴侣和后代沟通，以及展示领地。","habits":"巨翅鵟栖息于大型落叶林和混合落叶林中，冬季迁徙至相似环境的热带地区。它们利用热气流进行长途迁徙，形成壮观的群体，被称为\"kettle\"。狩猎时，它们会从低枝隐蔽处快速俯冲捕捉猎物。","breeding":"繁殖季节为4月至8月，成年后约两年开始繁殖。雄鸟通过空中翻滚、俯冲等动作吸引雌鸟。一窝产卵1至4枚，雌鸟负责孵化，雄鸟偶尔参与喂养。孵化期约为28天，幼鸟出生后需5至6周才能离巢。","identification":"与红肩鵟相比，巨翅鵟的尾巴更短，条纹更密集，翅膀尖端更圆润。暗色形态的个体与短尾鵟相似，但后者尾巴下方为白色，仅有一条亚端带。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美东部和中部，冬季迁徙至加勒比岛屿和拉丁美洲。部分亚种全年居住在加勒比海岛屿上。","other":"巨翅鵟的迁徙行为和繁殖生态已有详细记录，但对其越冬生态和其他生命史细节了解较少。"},{"name":"白喉鵟","english_name":"White-throated Hawk","scientific_name":"Buteo albigula","overview":"白喉鵟（英文名：White-throated Hawk，学名：Buteo albigula），是鹰形目鹰科鵟属的猛禽。这种鸟在南美洲温带雨林中的智利南部和阿根廷相邻地区较为常见，夏季繁殖。其特征为头部深色，喉咙洁白，翅膀展开时略呈扁平状，翼尖微卷。白喉鵟体型较小，迁徙时北上至玻利维亚至委内瑞拉安第斯山脉过冬。","appearance":"白喉鵟体长介于38至48厘米，翼展可达84至102厘米。其特征在于侧胸及大腿部有标记，与短尾鵟区别明显。上半身及头部两侧呈棕色黑色，下部白色，身体两侧为栗色，胸部及腹部有棕色条纹，大腿部有红褐色横纹。尾巴上表面深棕色，下表面灰白色，带有8到10条窄暗带。雌雄外观相似，但雌鸟稍大（约2%至20%）。眼虹膜为棕色，蜡膜、腿和脚为黄色。幼鸟与成鸟相似，但胸部和侧翼有明显的黑色条纹，脸颊和胸部两侧有条纹，大腿部为淡黄色，带有棕色横纹。","call":"通常被认为较沉默，但在繁殖季节会发出尖锐的“kee-ah”声，接近巢穴时叫声会变成下降音调的“kee-ea”。","habits":"白喉鵟主要生活在海拔1700米至3500米的山地湿润森林中，特别是在南美安第斯山脉，包括智利沿海山脉的10至1200米高度。它们在较高海拔处偏好云雾林和高山森林，同时也能适应开阔地带，如普纳草原。在南端的分布区，它们更偏爱Araucaria和Nothofagus树种生长的环境。白喉鵟在非繁殖季节迁徙，向北移动，到达较低海拔，包括海平面附近。","breeding":"白喉鵟似乎仅在其分布区南部繁殖，确切的繁殖季节从九月中旬至少持续到次年四月。已知的繁殖行为包括波动式的展示飞行。巢由活枝和枯枝构成，常覆盖着苔藓，位于距地面13至22米的高度。每窝产1至2枚白色蛋，孵化期约为一个月，主要由雌鸟承担。雄鸟在孵卵期间完全负责雌鸟的喂养，并在幼鸟期间提供至少80%的食物。幼鸟孵化后约40天离巢，期间主要由雌鸟喂养。成鸟可能在幼鸟离巢后继续喂养一段时间。","identification":"与短尾鵟相比，白喉鵟具有清洁的白色喉咙和标志性的‘腋窝’暗色，以及较为平坦的滑翔方式，翼尖轻微上翘。幼鸟与成鸟相似，但胸部和侧翼有更重的黑色条纹。","protection":"IUCN：LC（无危）","distribution":"白喉鵟分布在安第斯山脉从委内瑞拉西北部至玻利维亚，之后在智利中部和阿根廷西部。在智利的阿塔卡马至艾森地区，以及阿根廷圣克鲁斯省均有记录。在南端的分布区，如智利和阿根廷，白喉鵟最为常见。","other":"白喉鵟在一些国家的保护区中被发现，如智利的弗雷·霍尔赫、拉坎帕纳和纳韦尔巴塔国家公园，以及阿根廷的纳胡埃尔瓦皮、佩里托莫雷诺、洛斯冰川和洛斯阿尔塞斯国家公园。"},{"name":"短尾鵟","english_name":"Short-tailed Hawk","scientific_name":"Buteo brachyurus","overview":"短尾鵟（英文名：Short-tailed Hawk，学名：Buteo brachyurus），是鹰形目鹰科鵟属的鸟类。分布于中美洲至南美洲北部，以及美国佛罗里达半岛。其独特之处在于明显的暗色和浅色形态共存并能杂交。尽管在佛罗里达州的种群数量估计不超过150到200对，但该物种在更广泛的范围内相对常见。","appearance":"短尾鵟是一种中等体型的鵟，总身长39-44厘米，翼展83-103厘米。具有两种明显颜色形态：暗色型几乎全身深棕色，而浅色型头颈部深棕色，其余下部白色无斑点，仅上胸有细微的红褐色条纹。两者均具有一条相对较短而宽的尾巴，下部较淡，有宽的暗色亚端带和几条窄带。幼鸟的尾巴比例更长，有更多（7或8条）的条纹，缺乏成鸟的宽暗亚端带。","habits":"栖息于各种森林环境，包括沼泽森林、混合林草原景观、松树林、红树林、沿海沼泽和草原，以及散有树木和灌木的牧场和郊区。在高空以平展的翅膀翱翔，翼尖略向上翘，常被误认为是秃鹫。狩猎时，它会面对风向，长时间悬停在空中，突然垂直俯冲捕捉猎物。","breeding":"在一月到六月间繁殖，筑大巢于树上，高度从2.5到30米不等。巢宽60-70厘米，深30厘米，每窝产1-3枚白色带有深色斑点和斑块的蛋。孵化期约34天，幼鸟成长细节未知。","identification":"最易通过其独特的空中狩猎行为辨认：面向风向，长时间展开翅膀悬停，然后迅速近乎垂直地扑向猎物。与红肩鵟相比，短尾鵟有较长的宽翅和相对较短的宽尾巴；与宽翼鵟相比，短尾鵟的次级飞羽更长，翅膀稍显膨大，且形状略有不同。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲北部，包括墨西哥东部至阿根廷北部，以及美国佛罗里达南部。在热带地区，通常出现在低地山麓。"},{"name":"夏威夷鵟","english_name":"Hawaiian Hawk","scientific_name":"Buteo solitarius","overview":"夏威夷鵟（英文名：Hawaiian Hawk，学名：Buteo solitarius），是鹰形目鹰科鵟属的鸟类。是鹰科鵟属的特有种，仅分布于夏威夷群岛的大岛。夏威夷群岛现存的两种本土猛禽之一，另一种为短耳鸮夏威夷亚种(Pueo)。夏威夷鵟曾广泛分布于多个岛屿，现仅在大岛的原生'ōhi'a lehua森林中繁殖。曾被列为美国联邦濒危物种，2020年被除名。","appearance":"夏威夷鵟体型中等，长约40至46厘米，具有明显的性别二态性，雌鸟平均重605克，雄鸟平均441克。存在深色和浅色两种形态，深色型头部、胸部及翅膀下方为深褐色，浅色型头部较暗，胸部和翅膀下方较浅。成年个体脚和腿呈黄色，幼鸟为蓝绿色。繁殖季节，一对中的可能雌鸟具有独特的黄色前冠区。","call":"夏威夷鵟的叫声尖锐高亢，类似其夏威夷名字发音：\"eeeh-oh\"，在繁殖季节尤其喧闹。","habits":"这种孤独的鵟全年守卫领地，以原生森林中的鸟类、啮齿类、蜥蜴、猎鸟及昆虫为食，偶尔也会攻击已灭绝于野外的夏威夷乌鸦。它们既是机会主义捕食者，又在捕食技巧上多才多艺。","breeding":"夏威夷鵟从3月到9月筑巢，通常产一枚蛋，有时可达三枚。雌鸟承担大部分孵化责任，孵卵期约38天，雄鸟则负责觅食。雏鸟在七到八周后离巢。","identification":"夏威夷鵟是夏威夷群岛上唯一的常驻鵟，可通过其独特的叫声和颜色形态与其它猛禽相区分。","protection":"IUCN：NT（近危）","distribution":"太平洋夏威夷群岛，目前仅限于大岛。","other":"夏威夷鵟在夏威夷文化中具有重要意义，被视为王室象征，与创造神话紧密相关。"},{"name":"斯氏鵟","english_name":"Swainson's Hawk","scientific_name":"Buteo swainsoni","overview":"斯氏鵟（英文名：Swainson's Hawk，学名：Buteo swainsoni），是鹰形目鹰科鵟属的鸟类。大型鵟，以英国自然学家威廉·斯文森的名字命名。在春季和夏季主要栖息于北美的大草原和干燥草原，冬季则迁徙至南美阿根廷。斯氏鵟是北美最长距离迁徙的猛禽之一，仅次于北极繁殖的游隼。在繁殖季节依赖小型哺乳动物为食，而非繁殖季节则几乎完全以昆虫为食，尤其是蚱蜢。","appearance":"斯氏鵟是中型猛禽，体长50-55厘米，翼展120-135厘米，雄鸟体重约820克，雌鸟体重约1130克，平均寿命可达16年。相较于红尾鵟，它们体型更为修长，翼展更长，双翼较为纤细。飞行时，双翼构成轻微的V形，翼尖在滑翔时会轻微摆动。斯氏鵟有两种主要的色型：浅色型下身白色，胸部深色，有红色围兜，喉咙和面部白色；深色型则主要为深褐色，但尾巴底部有浅色斑块。","habits":"斯氏鵟无论在繁殖还是越冬时，都喜欢栖息在开阔或半开阔的乡村地带，如沙漠、草原和大草原。它们偏好野外的草原、牧场和种植小麦及紫花苜蓿的田野，因为这些地方是它们猎物的栖息地。斯氏鵟会停留在高处狩猎，然后将猎物带回给雏鸟。它们的繁殖分布与当季小型哺乳动物的分布紧密相关。","breeding":"斯氏鵟通常一夫一妻制，对配偶和领地有高度的忠诚。雄鸟会在树上、悬崖或地面上用树枝和草建造巢穴，大约需要两周时间。雌鸟孵化2-3枚椭圆形、表面光滑的蛋，孵化期为34-35天，期间由雄鸟提供食物。雏鸟在33-37天后离巢，4-5周后开始独立生活。","identification":"与红尾鵟相比，斯氏鵟体型更瘦小，翼展更长，双翼更纤细。飞行时双翼构成轻微的V形，翼尖在滑翔时会轻微摆动。浅色型斯氏鵟下身白色，胸部深色，有红色围兜，而深色型主要为深褐色，尾巴底部有浅色斑块。","protection":"IUCN：LC（无危）","distribution":"斯氏鵟的繁殖区域包括加拿大西南部、美国西部和墨西哥北部，冬季则迁徙至南美南部。在北美，它们主要分布在大草原和干燥草原。","other":"斯氏鵟具有较高的巢址忠诚度，雏鸟离巢后常返回原巢附近区域。"},{"name":"加岛鵟","english_name":"Galapagos Hawk","scientific_name":"Buteo galapagoensis","overview":"加岛鵟（英文名：Galapagos Hawk，学名：Buteo galapagoensis），是鹰形目鹰科鵟属的大型猛禽，仅见于南美的加拉帕戈斯群岛。其成鸟体色深沉，近乎黑色，在强光下显得更为明显，翅膀和尾巴具有白色的横纹。幼鸟则呈现淡褐色，带有深褐色斑点。加岛鵟的分布局限于加拉帕戈斯群岛的多个岛屿。","appearance":"成年加岛鵟体长介于45至56厘米之间，翼展可达116至140厘米。雄鸟体重在844至1137克之间，而雌鸟的体重则在1223至1578克，雌鸟通常比雄鸟大19%左右。全身呈炭灰色，两侧及腹部有赤褐色斑点。眼睛棕色，虹膜在幼鸟中更显灰黄或黄色，喙基部黄色，腿和脚黄色，幼鸟的喙基部蓝色，脚为淡绿色。","call":"发出一系列短促、高音的尖叫声，音调从模糊到嘶哑不等，无论是飞行还是栖息时都能听到，但在繁殖季节最为频繁。","habits":"加岛鵟栖息于加拉帕戈斯群岛的各种环境，从海岸线到裸露的熔岩区，开放地带至封闭的落叶林，海拔从海平面至1700米。它们是定居者，但幼鸟偶尔会在岛屿间游荡。以广泛的猎物为食，包括啮齿动物、地面鸽子、熔岩蜥蜴、鸟类巢穴中的幼鸟、海鸟幼雏、山羊幼崽、陆地及海洋鬣蜥、龟类幼体、昆虫、腐肉和人类的食物残渣。","breeding":"繁殖时间不固定，可能与气候模式相关，推测高峰期在5月至8月。主要是多配偶制，有时单配偶制。空中求偶包括高空盘旋和鸣叫。巢由树枝搭建，宽约80至100厘米，内部铺垫草、树叶或树皮，建于熔岩流、岩石突出处或低矮树木上。每窝产卵1至3枚，孵化期37至38天，雏鸟孵化后50至60天离巢，父母会在雏鸟离巢后3至4个月内将其驱逐。幼鸟至少在2至3年内远离繁殖区，约3岁时达到性成熟。","identification":"加岛鵟的成鸟与幼鸟外观差异显著，成鸟暗色，幼鸟棕褐色带斑点。与其他鵟属物种相比，加岛鵟体型较大，颜色更深，尾羽具窄黑条纹。","protection":"IUCN：VU（易危）","distribution":"加岛鵟分布在加拉帕戈斯群岛的多个岛屿，包括伊莎贝拉岛、平塔岛、马尔切纳岛、圣塔克鲁兹岛、圣塔菲岛、埃斯潘诺拉岛等。","other":"加岛鵟数量估计在400至500成年个体及300至400只幼鸟，由于栖息地丧失、非法猎杀和入侵物种威胁，其生存状况堪忧。"},{"name":"斑尾鵟","english_name":"Zone-tailed Hawk","scientific_name":"Buteo albonotatus","overview":"斑尾鵟（英文名：Zone-tailed Hawk，学名：Buteo albonotatus），是鹰形目鹰科鵟属的鸟类。主要分布在北美西南部至南美的巴拉圭。这种鵟以深色为主，拥有独特的银色条纹飞羽和白色带状尾巴。性别相似，但雌鸟略大且更健壮。在多种生境中分布，包括山地、沙漠和红树林地带。","appearance":"斑尾鵟为中型鵟，体长46至56厘米，翼展约117至140厘米，体重在565至1080克之间。成鸟主要呈黑色，飞羽有银灰色条纹，尾巴有2至4个白色带状区，最靠近尖端的第二个特别宽和显眼。黄色的蜡膜和腿脚，面颊灰白色，脸上可能有一抹白色。幼鸟胸部有小白点，尾巴带有窄的灰色和黑色条纹，末端较暗。","call":"发出响亮的尖叫，音调在结束时下降，类似典型鵟的叫声，kra kree-kree-kree-kree。在一些个体中，叫声中间音调突然上升，然后同样突然下降。","habits":"适应多种生境，包括封闭和开放环境、湿润和干燥地带。常见于岩石地带近水处，栖息于松林、橡树林、河流沿岸的林地、半干旱灌丛和沼泽。在繁殖季节开始时，会进行空中求偶展示。","breeding":"繁殖季节在每年上半年，具体时间因地理位置而异。在北美洲北部，繁殖季为4月中旬至7月；在特立尼达岛和厄瓜多尔，为2月至6月。巢通常建在树顶或主枝分叉处，高7.5至30米，由树枝构成，内衬绿叶。每窝产1至3枚，通常是2枚白色蛋，有时带有棕色斑点。孵化期约为28至35天，雌鸟主要负责孵卵，雄鸟提供食物，偶尔也会参与孵化。幼鸟在孵化后缓慢成长，约在42至50天后离巢，但直到一周后才成为自信的飞行者。","identification":"与红头美洲鹫的飞行风格相似，但体型较小，翅膀和头部形状更像典型的鵟。与黑鸡鵟相比，斑尾鵟更苗条，尾巴上的白色带状区更多。与暗色型的巨翅鵟、红尾鵟和短尾鵟相比，斑尾鵟的翅膀和尾巴比例更长更窄。","protection":"IUCN：LC（无危）","distribution":"分布于北美西南部至南美的巴拉圭，冬季一般撤退到美国和墨西哥北部，迁移到奥哈卡和尤卡坦半岛过冬。在中美洲的种群可能是季节性迁徙，但具体迁徙模式尚不清楚。","other":"斑尾鵟能模仿红头美洲鹫的飞行模式，这可能帮助它们在寻找猎物时不引起警觉。"},{"name":"红尾鵟","english_name":"Red-tailed Hawk","scientific_name":"Buteo jamaicensis","overview":"红尾鵟（英文名：Red-tailed Hawk，学名：Buteo jamaicensis），是鹰形目鹰科鵟属的鸟类。北美最广泛分布的鵟属鸟类之一，俗称鸡鹰。繁殖区域跨越北美的大部分地区，从阿拉斯加至加拿大北部，向南延伸至巴拿马和西印度群岛。拥有14个亚种，表现出显著的地域性差异。","appearance":"红尾鵟体态健壮，翼宽而圆，尾部短而宽。雄鸟体长45-56厘米，重690-1300克；雌鸟体长50-65厘米，重900-1460克。头部、脸颊、肩部、颈部、上翼覆羽、次级飞羽和三级飞羽呈深褐色，腹部有深色条纹，尾部通常是红色的，有狭窄的黑色次端带。幼鸟的尾部呈淡褐色，有数条宽度均匀的暗色横纹。","call":"红尾鵟的叫声多样，包括尖锐的哨音和响亮的啼鸣。","habits":"红尾鵟栖息于多种生境，包括沙漠、草原、森林边缘、农田和城市环境。它们是日行性猛禽，以小型哺乳动物、鸟类、爬行动物、两栖动物和昆虫为食。迁徙模式因地理位置而异，北方的个体倾向于迁徙，而南方的个体可能全年留驻。","breeding":"繁殖期通常在春季，筑巢于树上或人造结构上，高度在4-21米之间。雌雄共同筑巢，由雌鸟主要孵卵，孵化期约为28天。每窝产卵2-3枚，幼鸟在孵化后42-46天离巢。","identification":"红尾鵟与同属其他物种的区别在于其特有的红色尾部和黑色次端带。不同的亚种在羽毛颜色和图案上有显著差异。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美，从阿拉斯加至加拿大北部，向南至巴拿马和西印度群岛。冬季分布区向南扩展至中美洲。","other":"红尾鵟在北美的数量稳定或略有增加，适应力强，能够容忍人类活动，甚至在大型城市环境中成功繁殖。"},{"name":"美洲棕尾鵟","english_name":"Rufous-tailed Hawk","scientific_name":"Buteo ventralis","overview":"美洲棕尾鵟（英文名：Rufous-tailed Hawk，学名：Buteo ventralis），是鹰形目鹰科鵟属的鸟类。俗称: “土豹”，翼展45至60厘米，以尾部分明的锈红色和细窄的黑条纹为显著特征。分布于南美的智利南部和阿根廷西南部，包括整个火地岛地区。偏好温带森林、亚热带干燥灌木丛、亚热带高山灌木丛及温带草原。","appearance":"美洲棕尾鵟为中等体型的猛禽，翼展约119至139厘米，体长45至60厘米，雄鸟重约950克，雌鸟重约1140克。具长而方形的翅膀和中等长度的尾巴。有两种色型：浅色型背部深棕色至黑色，喉部白色，下体锈色至红褐色，带有黑色条纹，大腿呈红褐色，尾部锈色，有8至10条黑色条纹，最后一根最宽，尖端白色；深色型接近烟灰色，下方较浅，翅膀和尾巴下方斑驳灰白。虹膜深红棕色（幼鸟为灰棕色），蜡膜、腿和脚黄色。雌雄相似，但雌鸟比雄鸟大10%左右。幼鸟上体暗褐色，边缘红褐色和白色；下体白色，胸部和腹部两侧有黑色条纹；尾部缺乏锈色。","call":"鸣叫声为尖锐拉长的kee-ahrr。","habits":"美洲棕尾鵟生活在智利南部和阿根廷西南部的温带雨林与边缘地带，以及相邻的开阔和半开阔地区，从海平面到至少1200米，局部可达1500米。偏好有南洋杉（Nothofagus）森林和智利松（Araucaria araucana）的地区，也出现在公园草地、树木环绕的田野、开阔的沿海草地以及巴塔哥尼亚高原的灌木草原。以居民身份出现，尽管在南半球冬季可能有海拔或纬度上的移动。食谱广泛，包括哺乳动物（如鼠类、兔子）、鸟类、蛇和昆虫。","breeding":"繁殖期主要在10月至11月间，季节持续到至少1月。筑巢于高达40米的老树上，巢由树枝构成，内衬羽毛和羊毛。每窝产卵1至3枚，孵化期约为30天。幼鸟有白色绒羽。","identification":"与红背鵟在所有羽毛阶段都有混淆风险，但浅色型的美洲棕尾鵟通过其锈色的尾巴容易识别。","protection":"IUCN：VU（易危）","distribution":"南美：智利南部（自纽布莱省）和阿根廷西南部（自内乌肯省）向南至火地岛和纳瓦里诺岛。","other":"面临的主要威胁包括栖息地退化，如砍伐森林、转换为松树（Pinus）和桉树（Eucalyptus）种植园，以及过度放牧。此外，人类迫害也是威胁之一，尤其是基于对其攻击家禽的指控。"},{"name":"锈色鵟","english_name":"Ferruginous Hawk","scientific_name":"Buteo regalis","overview":"锈色鵟（英文名：Ferruginous Hawk，学名：Buteo regalis），是鹰形目鹰科鵟属的鸟类。以其独特的铁锈色羽毛著称，分布于北美中部和西部的开阔草原、灌木草原和沙漠地带。这种猛禽偏好自然草地环境，筑巢于悬崖、树木或人造结构上，如石油和天然气设施、输电塔甚至草堆。历史上，锈色鵟的巢穴常利用野牛骨骼和毛皮建造。","appearance":"体型庞大，翼展可达1.5米，拥有宽大的翅膀和头部。成年个体羽毛颜色多样，轻型羽色的成鸟上身呈明显的锈红色，背部蓝灰色，胸部白色，侧腹饰有锈色条纹。尾部非常浅淡，上部略带锈色。年轻个体缺乏成鸟的锈色色调，但同样展示出浅色尾巴和干净的白色胸部。重型羽色全身呈深棕色，尾部和飞羽下方白色。飞行时，翅膀呈现轻微的V形。","call":"报警叫声包括尖锐的kree声和刺耳的kaah声，类似于鲱鸥的某些叫声，也有描述其叫声为\"wavering\"和\"breathy\"音调，尖叫类似红尾鵟。","habits":"栖息于开阔地带，如草原、灌木草原和沙漠，以鼠类为食。冬季倾向于聚集在地松鼠和土拨鼠丰富的地区。狩猎方式为\"坐等\"，常在土拨鼠城镇周围栖息。","breeding":"繁殖期从4月至6月，具体时间受地理位置、天气和食物供应影响。筑巢由两性共同参与，巢材包括树枝、干草等。每窝产卵数量通常为3到4枚，孵化期平均32天，由双亲轮流孵化。","identification":"与北美其他鵟属物种相比，锈色鵟的白底腹面和锈色腿部形成明显的\"V\"字形，头白而背部锈色，特征性的\"锈色V\"由暗色腿部和足部在臀部下方构成。从上方观察，头部比大多数鵟更白，背部和肩部锈色，翼尖有显著的白色区域。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大中南部至美国中西部，冬季向南迁移至墨西哥北部。","other":"近年来，部分地区的锈色鵟种群有所增加，得益于保护措施，其现状较之前乐观。"},{"name":"毛脚鵟","english_name":"Rough-legged Buzzard","scientific_name":"Buteo lagopus","overview":"毛脚鵟（英文名：Rough-legged Buzzard，学名：Buteo lagopus），是鹰形目鹰科鵟属的鸟类。拥有高度可变的羽毛颜色，从深色个体到更多花纹的‘淡色型’。在北极和亚北极地区的开阔地带，如田野和沼泽中发现。毛脚鵟在广阔的北方森林带繁殖，遍布新旧世界。在北美，在北极和亚北极的阿拉斯加和加拿大繁殖，冬季迁移到南部加拿大和美国北部的开放地区。","appearance":"毛脚鵟体型较大，翼展可达120至153厘米，重量介于600至1660克之间，雌鸟略大于雄鸟。羽毛颜色主要是棕色，带有不同程度的斑点。淡色型个体有明显的暗色腕部斑块和白色的翼下部位，尾部有宽的暗色亚端带。深色型个体可能几乎全黑，仅在飞行羽毛下方有苍白的部分。","call":"毛脚鵟会发出类似红尾鵟的向下滑音哨声，但在飞行或从栖息处发出时，声音更为强烈。","habits":"毛脚鵟栖息于稀疏的针叶林、阔叶林混交区和开阔地带，如农田和草原。它们主要以小型啮齿动物为食，如田鼠、旅鼠和各种鸟类，尤其是雷鸟。它们在开阔地带狩猎，经常悬停在风中，偶尔也会在树梢或电线杆上栖息。","breeding":"毛脚鵟在5月到8月初繁殖，巢建在悬崖峭壁上或干涸河岸悬崖上，有时也在树上。每窝产卵3至4枚，孵化期为28至31天，主要由雌鸟负责，雄鸟偶尔协助。雏鸟孵化后约35天羽毛长成，41至45天左右离巢独立觅食。","identification":"毛脚鵟与欧亚鵟相比，尾部内侧白色，翼角有黑斑，头部颜色较浅。毛脚鵟初级飞羽基部更白，与黑色翼角斑形成对比。","protection":"IUCN：LC（无危）","distribution":"毛脚鵟繁殖于北极苔原和苔原森林地带，分布于北美和欧亚大陆的广阔地区。冬季，它们迁移到南部加拿大和美国北部，以及欧洲和亚洲的南部。","other":"毛脚鵟是国家二级保护动物。"},{"name":"大鵟","english_name":"Upland Buzzard","scientific_name":"Buteo hemilasius","overview":"大鵟（英文名：Upland Buzzard，学名：Buteo hemilasius），是鹰形目鹰科鵟属的大型猛禽。别名: 豪豹、白鹭豹、花豹。体长可达70厘米，体型超越欧亚鵟和毛脚鵟。广泛分布于亚洲中部、中南部至西伯利亚东南部和中国东北部，活跃于山地、山脚平原、草原、高山林缘、开阔山地草原与荒漠地带，最高可达海拔4000米以上的高原和山区。","appearance":"大鵟是鵟属中体型最大者，总长度57至72厘米，翼展143至161厘米。雄鸟体重950至1400克，雌鸟970至2050克。存在浅色和深色两种形态。浅色型上体为土黄色，下体带有白色并有变化的赭色洗涤，胸部纯白，下体有不规则分布的深棕色斑点。深色型全身几乎统一的黑棕色，翼下外缘偏浅。尾部灰底带深色条纹，具明显的亚端带。飞行时，主要覆羽变化多样，呈条纹状棕色，与强烈的黑色前肢斑形成对比。初级飞羽白色，有变化的暗色横斑，翼尖和边缘黑色。深色形态与浅色形态的特征相似，但色调更深。","call":"发出延长的鼻音喵叫，与欧亚鵟的叫声类似，但在繁殖季节更为嘈杂，不过相比欧亚鵟在巢边更安静。","habits":"栖息于开阔的高地环境，如草原、高原、山地草原，偏好有岩石区域的巢穴。主要食物为小型哺乳动物，如地松鼠、田鼠、跳鼠、鼠兔和幼年土拨鼠，偶尔也会捕食从小型到大型的鸟类和昆虫。在西藏，主要以田鼠、高原鼠兔和甘肃鼠兔为食，当这些主要猎物数量下降时，会转向捕食多种雀形目鸟类。在蒙古，依赖布兰特田鼠，数量受其猎物周期影响。迁徙时覆盖短距离，似乎为了避开积雪区域。","breeding":"繁殖期从四月持续至八月，筑巢于悬崖的岩石缝隙、岩架或植被遮蔽的陡峭草坡，巢由树枝搭建，内衬羊毛、干草、干粪等。平均产卵2至4枚，偶尔5枚，若全部卵丢失，可再产一窝。孵化期35至38天，幼鸟45天左右离巢。在蒙古西部和中部，平均孵化数为1.95只。","identification":"与棕尾鵟、毛脚鵟等其他鵟类相似，但体型更大。飞行时，翅膀下可见棕黄色的斑点。欧亚鵟跗跖仅部分被羽，毛脚鵟的被羽延伸至趾基部。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于亚洲中部、中南部至西伯利亚东南部和中国东北部。冬季迁徙至中国华中及华东地区，偶见于广西、广东和福建。","other":"在一些地区，如西藏和蒙古的猎物丰富区，大鵟的数量接近丰富，但总体而言，该物种普遍稀少。"}];
